 my $grey_steps_30_g="";
 $grey_steps_30_g=$1 if($body=~/"grey_steps_30_g"\s*:\s*"([0-9.,\s]+)"/);
 my $grey_steps_30_b="";
 $grey_steps_30_b=$1 if($body=~/"grey_steps_30_b"\s*:\s*"([0-9.,\s]+)"/);
 my $grey_steps_100_r="";
