 my $raw=&sudo($cmd,$enabled);
 chomp($raw);
 if($raw=~/^OK/) {
  return '{"status":"ok","message":"'.&_webui_json_escape($label)." ".$enabled.'"}';
 }
 $raw=~s/^ERR:?//;
 $raw=&_webui_json_escape($raw||"$label failed");
 return '{"status":"error","message":"'.$raw.'"}';
}

