   </div>
   <div class="field">
    <label>MaxFALL</label>
    <input type="number" id="max_fall" min="0" max="10000" step="1">
   </div>
  </div>
 </div>

 <!-- Dolby Vision Settings -->
 <div class="card" id="dvCard">
	  <h2><span class="dv-badge">DV</span> Dolby Vision</h2>
