 <!-- Apply Settings Bar -->
 <div class="card span2" id="applyBar" style="display:none">
  <div style="display:flex;align-items:center;justify-content:space-between">
   <span style="color:var(--text2);font-size:.85rem">Settings changed</span>
   <button class="btn btn-sm btn-primary" onclick="applySettings()">Apply &amp; Restart</button>
  </div>
 </div>

 <!-- Diagnostic Patterns -->
 <div class="card span2" data-widget="patterns" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>Diagnostic Patterns</h2>
  <div class="pat-section">
   <div class="pat-content">
    <div style="font-size:.65rem;color:var(--text2);margin-bottom:6px;line-height:1.4">Visual setup patterns for display calibration. Use these to verify your display&#39;s basic picture settings before running a full calibration.</div>
    <div class="diag-pattern-layout">
     <div class="diag-pattern-column">
      <div class="diag-pattern-title" id="diagVideoLabel" style="display:none">Videos</div>
      <div id="diagAvsHd709Section" style="display:none">
       <div class="diag-pattern-title">AVS HD 709 Videos (SDR Only)</div>
       <div class="pat-grid">
        <button class="pat-btn" onclick="showPattern('avs_hd_709_white_clipping',event)">White Clipping</button>
        <button class="pat-btn" onclick="showPattern('avs_hd_709_black_clipping',event)">Black Clipping</button>
        <button class="pat-btn" onclick="showPattern('avs_hd_709_flashing_color_bars',event)">Flashing Color Bars</button>
        <button class="pat-btn" onclick="showPattern('avs_hd_709_apl_clipping',event)">APL Clipping</button>
        <button class="pat-btn" onclick="showPattern('avs_hd_709_sharpness_overscan',event)">Sharpness & Overscan</button>
       </div>
      </div>
      <div class="diag-custom-asset" style="margin-top:10px">
       <div class="diag-custom-picker">
        <select id="diagCustomVideoSelect" class="inline-select" style="width:100%" onchange="diagHandleAssetSelect('video')">
         <option value="">Custom Diagnostic Video...</option>
         <option value="__upload__">Upload video...</option>
        </select>
        <button class="btn btn-sm btn-secondary diag-asset-icon-btn" type="button" onclick="diagPlaySelectedAsset('video')" title="Play custom diagnostic video" aria-label="Play custom diagnostic video"><span class="diag-asset-icon diag-play-icon"></span></button>
        <button class="btn btn-sm btn-secondary diag-asset-icon-btn" type="button" onclick="stopPattern()" title="Stop custom diagnostic video" aria-label="Stop custom diagnostic video"><span class="diag-asset-icon diag-stop-icon"></span></button>
       </div>
       <div style="font-size:.64rem;color:var(--text2);margin:4px 0 0 2px">Uploaded videos play through the legacy video playback path.</div>
      </div>
     </div>
     <div class="diag-pattern-column">
      <div class="diag-pattern-title">Images</div>
      <div class="pat-grid">
       <button class="pat-btn" onclick="showPattern('white_clipping',event)">White Clipping</button>
       <button class="pat-btn" onclick="showPattern('black_clipping',event)">Black Clipping</button>
       <button class="pat-btn" onclick="showPattern('color_bars',event)">Color Bars</button>
       <button class="pat-btn" onclick="showPattern('gray_ramp',event)">Gray Ramp</button>
       <button class="pat-btn" onclick="showPattern('overscan',event)">Overscan</button>
      </div>
      <div class="diag-custom-asset" style="margin-top:10px">
       <div class="diag-custom-picker">
        <select id="diagCustomImageSelect" class="inline-select" style="width:100%" onchange="diagHandleAssetSelect('image')">
         <option value="">Custom Diagnostic Image...</option>
         <option value="__upload__">Upload image...</option>
        </select>
        <button class="btn btn-sm btn-secondary diag-asset-icon-btn" type="button" onclick="diagPlaySelectedAsset('image')" title="Play custom diagnostic image" aria-label="Play custom diagnostic image"><span class="diag-asset-icon diag-play-icon"></span></button>
        <button class="btn btn-sm btn-secondary diag-asset-icon-btn" type="button" onclick="stopPattern()" title="Stop custom diagnostic image" aria-label="Stop custom diagnostic image"><span class="diag-asset-icon diag-stop-icon"></span></button>
       </div>
       <div style="font-size:.64rem;color:var(--text2);margin:4px 0 0 2px">Uploaded images render through the IMAGE pattern path.</div>
      </div>
     </div>
    </div>
    <div style="margin-top:10px">
     <input type="file" id="diagCustomVideoInput" accept="video/mp4,.mp4,.m4v,.mov,.webm,.mkv,.avi,.hevc,.h265,.h264,.ts,.m2ts" style="display:none">
     <input type="file" id="diagCustomImageInput" accept="image/png,.png,image/jpeg,.jpg,.jpeg,image/bmp,.bmp,.ppm,image/gif,.gif" style="display:none">
     <div id="diagUploadStatus" style="display:none;font-size:.68rem;color:var(--text2);margin-top:8px"></div>
    </div>
    <div id="diagInfo" style="font-size:.7rem;color:var(--text2);margin-top:8px;padding:8px 10px;background:#0d0d15;border-radius:6px;line-height:1.5;display:none"></div>
   </div>
  </div>

 </div>

<!-- Calibration -->
 <div class="card span2 meter-patterns-only" data-widget="meter" draggable="true" id="meterCard">
  <h2 id="meterCardTitle"><span class="meter-card-header-title"><span class="drag-handle">&#9776;</span><span id="meterCardTitleText">Test Patterns</span></span></h2>
  <label class="meter-header-label">Meter</label>
  <div class="meter-card-header-meter"><select id="meterMeasurementPort" class="meter-card-header-select" title="Used for Read Once, Continuous, and series measurements."><option value="">Meter</option></select><span class="meter-xyz-gear-wrap meter-profile-gear-wrap"><button type="button" id="meterProfileGear" class="meter-xyz-gear" aria-label="Meter settings" aria-expanded="false" title="Meter settings">&#9881;</button><div class="meter-xyz-gear-popover" id="meterProfileGearPopover" role="dialog" aria-label="Meter settings"><div class="meter-profile-title">Meter Settings</div><div class="field" id="meterProfileDisplayField"><label>Meter Profile <span class="meter-help-tip" title="Spectro/CCSS panel correction profile applied to the meter for its readings. Display-specific CCSS profiles appear below the generic types." aria-label="Meter profile help">?</span></label></div><div id="meterProfileRelocSlot"></div><div class="meter-profile-section" id="meterProfileLowLight"><div class="meter-profile-section-title">Low Light Handler <span class="meter-help-tip" title="For reads whose expected target luminance is below the Trigger, use the selected averaging Mode (multi-read) instead of the default single long read. Maps to spotread averaging (-Y a/aa/aaa); applies to autocal, series, and single reads." aria-label="Low light handler help">?</span></div><label class="meter-toggle"><input type="checkbox" id="meterLowLightEnabled" onchange="meterSetLowLightHandler()"> Enabled</label><div class="field"><label>Mode</label><select id="meterLowLightMode" onchange="meterSetLowLightHandler()"><option value="off" title="Single long read, no -Y flag">Off (single read)</option><option value="a" title="2-read averaging (-Y a)">2 reads (a)</option><option value="aa" title="3-read averaging (-Y aa)">3 reads (aa)</option><option value="aaa" title="5-read averaging (-Y aaa)">5 reads (aaa)</option></select></div><div class="field"><label>Trigger</label><div class="meter-inline-value"><input type="number" id="meterLowLightTrigger" onchange="meterSetLowLightHandler()" min="0.1" max="1000" step="0.1" value="5.0" title="Target luminance (cd/m^2) below which the low-light Mode kicks in. Default 5.0."><span class="meter-inline-unit">cd/m&sup2;</span></div></div></div></div></span><span class="meter-help-tip" title="Used for Read Once, Continuous, and series measurements." aria-label="Measurement meter help">?</span></div>
  <div id="meterResetRow" style="display:none;background:#3a2020;border-radius:6px;padding:8px 12px;margin-bottom:10px;align-items:center;gap:10px">
   <span style="color:var(--orange);font-size:.85rem">&#9888; Meter disconnected &mdash; USB may need a reset</span>
   <button class="btn btn-sm" style="margin-left:auto" onclick="meterResetUSB()">&#128260; Reset USB</button>
  </div>
  <div class="grid" id="meterSettingsGrid" style="margin-bottom:10px">
  <div class="field field-display">
    <select id="meterDisplayType">
     <optgroup label="Generic" id="meterDtGeneric">
      <option value="oled_generic">WRGB OLED</option>
      <option value="qdoled">QD-OLED</option>
      <option value="lcd_wled">LCD - White LED</option>
      <option value="lcd_rgbled">LCD - RGB LED</option>
      <option value="lcd_ccfl">LCD - CCFL</option>
      <option value="lcd_wgccfl">LCD - Wide Gamut CCFL</option>
      <option value="plasma">Plasma</option>
      <option value="projector_ccss">Projector</option>
      <option value="crt">CRT</option>
      <option value="lcd">None (no correction)</option>
      <option value="custom_editor">CCSS Editor...</option>
     </optgroup>
     <optgroup label="Display-specific CCSS" id="meterDtCcss"></optgroup>
    </select>
      <div id="customCcssPanel" class="custom-ccss-panel">
       <div class="custom-ccss-panel-row">
        <div class="custom-ccss-panel-copy">
         <div style="font-size:.76rem;color:#dfe6f6;font-weight:600;letter-spacing:.02em">CCSS Editor</div>
         <div id="customCcssPanelSummary" style="font-size:.7rem;color:var(--text2);margin-top:3px;line-height:1.45">Open the importer to upload CCSS, TI3, or spectral CSV files, preview curves, and manage custom profiles.</div>
        </div>
        <button id="customCcssPanelBtn" class="btn btn-sm btn-secondary custom-ccss-panel-btn" onclick="meterOpenCustomCcssEditor()">Open Editor</button>
       </div>
    </div>
	    <div class="meter-toggle-row">
	     <div class="meter-pattern-insert-block">
	      <div class="meter-pattern-insert-header">
	       <label class="meter-note-toggle" title="Insert neutral patches between measurement patterns to stabilize display response">
	        <input type="checkbox" id="meterPatchInsert" checked> Pattern Insertion
	       </label>
	       <span class="meter-pattern-insert-wrap is-hidden">
	        <button type="button" id="meterPatternInsertGear" class="meter-pattern-insert-gear" aria-label="Pattern insertion options" aria-expanded="false" title="Pattern insertion options">&#9881;</button>
	        <div class="meter-pattern-insert-popover" id="meterPatternInsertPopover" role="dialog" aria-label="Pattern insertion options">
	         <div class="meter-pattern-insert-grid">
	          <label class="meter-toggle"><input type="checkbox" id="meterPatchInsertTimeEnabled" checked> Time</label>
	          <label>Frequency <input id="meterPatchInsertTimeFrequency" type="text" value="5" inputmode="decimal" oninput="meterSecondsSyncInput(this)" onblur="this.value=meterDelayFormatSeconds(meterDelayParseSeconds(this.value,5))"><span>sec</span></label>
	          <label>Duration <input id="meterPatchInsertTimeDuration" type="text" value="5" inputmode="decimal" oninput="meterSecondsSyncInput(this)" onblur="this.value=meterDelayFormatSeconds(meterDelayParseSeconds(this.value,5))"><span>sec</span></label>
	          <label>Level <input id="meterPatchInsertTimeLevel" type="number" min="0" max="100" step="1" value="25"><span>%</span></label>
	          <label class="meter-toggle"><input type="checkbox" id="meterPatchInsertPatchEnabled" checked> Patch</label>
	          <label>Patches <input id="meterPatchInsertPatchEvery" type="number" min="1" max="999" step="1" value="1"><span>&nbsp;</span></label>
	          <label>Duration <input id="meterPatchInsertPatchDuration" type="text" value="1" inputmode="decimal" oninput="meterSecondsSyncInput(this)" onblur="this.value=meterDelayFormatSeconds(meterDelayParseSeconds(this.value,1))"><span>sec</span></label>
	          <label>Level <input id="meterPatchInsertPatchLevel" type="number" min="0" max="100" step="1" value="10"><span>%</span></label>
	         </div>
	        </div>
	       </span>
	      </div>
	     </div>
	      <div class="meter-xyz-toggle-block">
       <div class="meter-xyz-toggle-row">
        <label class="meter-toggle meter-field-label"><input type="checkbox" id="meterXyzMatrixEnabled"> XYZ Correction Matrix <span class="meter-help-tip" title="When enabled, applies the 3x3 matrix to measured XYZ before live x/y, CIE, luminance, and delta analysis. Leave matrix values blank for identity." aria-label="XYZ correction matrix help">?</span></label>
        <span class="meter-xyz-gear-wrap is-hidden">
         <button type="button" id="meterXyzGear" class="meter-xyz-gear" aria-label="XYZ correction matrix options" aria-expanded="false" title="XYZ correction matrix options">&#9881;</button>
         <div class="meter-xyz-gear-popover" id="meterXyzGearPopover" role="dialog" aria-label="XYZ correction matrix options">
          <div class="meter-xyz-action-row" id="meterXyzMatrixActionRow">
           <button class="btn btn-sm btn-secondary" type="button" onclick="meterOpenXyzMatrixImport()">Import</button>
           <button class="btn btn-sm btn-secondary" type="button" onclick="meterExportXyzMatrix()">Export</button>
          </div>
          <div class="meter-matrix-fields" id="meterXyzMatrixFields" style="margin-top:8px">
           <div class="meter-matrix-grid">
            <input type="number" id="meterXyzM11" step="0.0001" placeholder="1">
            <input type="number" id="meterXyzM12" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM13" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM21" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM22" step="0.0001" placeholder="1">
            <input type="number" id="meterXyzM23" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM31" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM32" step="0.0001" placeholder="0">
            <input type="number" id="meterXyzM33" step="0.0001" placeholder="1">
           </div>
          </div>
         </div>
        </span>
       </div>
        <div class="meter-xyz-toggle-row" id="meterCustomD65ToggleWrap">
         <label class="meter-toggle meter-field-label"><input type="checkbox" id="meterCustomD65Enabled"> Custom D65 <span class="meter-help-tip" title="Use a measured or entered whitepoint for D65 target colorspaces only." aria-label="Custom D65 help">?</span></label>
          <span class="meter-xyz-gear-wrap is-hidden">
           <button type="button" id="meterCustomD65Gear" class="meter-xyz-gear" aria-label="Custom D65 options" aria-expanded="false" title="Custom D65 options">&#9881;</button>
          <div class="meter-xyz-gear-popover" id="meterCustomD65GearPopover" role="dialog" aria-label="Custom D65 options">
           <div class="field-whitepoint" id="meterTargetWhitePointField">
            <label class="meter-field-label">Target White x / y <span class="meter-help-tip" title="Custom values update the CIE target, greyscale target white, and color analysis for D65 target colorspaces." aria-label="Target white point help">?</span></label>
            <div class="meter-whitepoint-row">
             <input type="number" id="meterTargetWhiteX" min="0.001" max="0.999" step="0.0001" placeholder="0.3127">
             <input type="number" id="meterTargetWhiteY" min="0.001" max="0.999" step="0.0001" placeholder="0.3290">
             <button class="btn btn-sm btn-secondary" type="button" onclick="meterUseMeasuredWhiteTarget()">Use measured values</button>
            </div>
           </div>
          </div>
         </span>
        </div>
        <div class="meter-target-white-row">
         <label class="meter-target-inline-label">Target White</label>
         <input type="number" id="meterTargetWhite" min="0" step="0.01" inputmode="decimal" placeholder="auto" title="White-peak luminance (cd/m^2) used as the top of the target EOTF curve. Disabled when 'Use measured' is checked." disabled>
         <span class="meter-inline-unit">cd/m&sup2;</span>
         <input type="checkbox" id="meterTargetWhiteUseMeasured" onchange="meterSetTargetLevels()" checked>
         <label for="meterTargetWhiteUseMeasured" class="meter-toggle-label">Use measured</label>
        </div>
        <div class="meter-target-black-row">
         <label class="meter-target-inline-label">Target Black</label>
         <input type="number" id="meterTargetBlack" min="0" step="0.001" inputmode="decimal" placeholder="auto" title="Black-floor luminance (cd/m^2) used as the bottom of the target EOTF curve. Disabled when 'Use measured' is checked." disabled>
         <span class="meter-inline-unit">cd/m&sup2;</span>
         <input type="checkbox" id="meterTargetBlackUseMeasured" onchange="meterSetTargetLevels()" checked>
         <label for="meterTargetBlackUseMeasured" class="meter-toggle-label">Use measured</label>
        </div>
       </div>
     </div>
    </div>
   <div class="field field-gamut">
    <label>Target Colorspace <span class="meter-help-tip" title="Affects meter target math and chart references. Dolby Vision patterns still use BT.2020 container signalling; this setting changes the analysis target, not the DV transport primaries." aria-label="Target colorspace help">?</span></label>
    <select id="meterTargetGamut">
     <option value="auto">Auto (match signal)</option>
     <option value="bt709" selected>BT.709</option>
     <option value="bt2020">BT.2020</option>
     <option value="p3d65">DCI-P3 / D65</option>
      <option value="p3dci">DCI-P3 / DCI</option>
    </select>
