	    <div id="meterDeltaEBlock" style="margin-bottom:10px">
	     <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
      <label style="font-size:.7rem;color:var(--text2);user-select:none;display:flex;align-items:center;gap:4px" title="HCFR grayscale reference mode: Relative Y normalizes each patch to its own luminance; Absolute Y w/gamma includes target gamma/EOTF luminance error; Absolute Y w/o gamma keeps the measured relative luminance while cancelling gamma error.">
       Grey ref
       <select id="meterGreyRefMode" class="inline-select" onchange="meterOnGreyRefChange()">
        <option value="absolute">Relative Y</option>
        <option value="eotf">Absolute Y w/gamma</option>
        <option value="relative" selected>Absolute Y w/o gamma (default)</option>
       </select>
      </label>
      <label style="font-size:.7rem;color:var(--text2);user-select:none;display:flex;align-items:center;gap:4px" title="Near-black luminance weighting: reduces over-sensitivity on very dark grayscale steps by scaling the luminance term before ΔE evaluation.">
       Grey World
       <select id="meterGrayWorld" class="inline-select" onchange="meterOnGreyRefChange()">
        <option value="1">Off (default)</option>
        <option value="0.15">Gray (0.15)</option>
        <option value="0.05">Near-black (0.05)</option>
       </select>
      </label>
      <label style="font-size:.7rem;color:var(--text2);user-select:none;display:flex;align-items:center;gap:4px" title="RGB balance method: Perceptual uses L* by channel; Chromaticity uses linear RGB normalized to the target white.">
       RGB bal
       <select id="meterRgbBalanceFormula" class="inline-select" onchange="meterOnGreyRefChange()">
        <option value="perceptual">Perceptual (default)</option>
        <option value="hcfr">Chromaticity</option>
       </select>
      </label>
      <label style="font-size:.7rem;color:var(--text2);user-select:none;display:flex;align-items:center;gap:4px" title="Changes the greyscale ΔE calculation.">
       Grey ΔE
       <select id="meterDeltaEForm" class="inline-select" onchange="meterOnGreyRefChange()">
        <option value="deitp" selected>ΔE ITP (default)</option>
        <option value="deluv76">ΔE76 (Luv)</option>
        <option value="de2000">ΔE2000</option>
       <option value="de94">ΔE94</option>
       <option value="de76lab">ΔE76 (Lab)</option>
       <option value="decmc">ΔE CMC(1:1)</option>
       <option value="de2000_jnd">ΔE2000 JND</option>
      </select>
      </label>
     </div>
     <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
      <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase" id="chartDeltaELabel">&Delta;E ITP</div>
      <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none">
       <input type="checkbox" id="meterIncludeLumError" onchange="meterOnGreyRefChange('checkbox')" style="vertical-align:middle"> Include luminance error
      </label>
     </div>
	    <div id="meterDeltaEScroller" class="meter-scroll-sync" style="background:#0d0d15;border-radius:6px">
	     <canvas id="chartDeltaE" width="800" height="180" style="width:100%;min-width:100%;height:180px;background:#0d0d15;border-radius:6px"></canvas>
	    </div>
	    </div>
	    </div>
	    <div style="margin-bottom:10px">
     <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
      <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase" id="chartGammaValueLabel">Gamma</div>
      <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none;margin-left:auto">
       <input type="checkbox" id="meterPerChannelGamma" onchange="if(meterReadings&&meterReadings.length)drawAllCharts(meterReadings)" style="vertical-align:middle"> Per-channel γ
      </label>
     </div>
    <div id="meterGammaValueScroller" class="meter-scroll-sync" style="background:#0d0d15;border-radius:6px">
     <canvas id="chartGammaValue" width="800" height="180" style="width:100%;min-width:100%;height:180px;background:#0d0d15;border-radius:6px"></canvas>
    </div>
    </div>
    <div id="chartTooltip" style="display:none;position:fixed;pointer-events:none;z-index:9999;background:rgba(13,13,21,0.95);border:1px solid #555;border-radius:5px;padding:6px 10px;font-size:12px;color:#ddd;white-space:nowrap;box-shadow:0 2px 8px rgba(0,0,0,0.5)"></div>
    <div style="display:grid;grid-template-columns:minmax(0,1fr) minmax(0,1fr);gap:10px;margin-bottom:10px">
     <div>
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
       <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase" id="chartEotfLabel">EOTF</div>
       <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none;margin-left:auto" title="Absolute error view: plots inverse-EOTF so a perfectly tracking display is a straight diagonal and errors deviate from it. Unchecked shows the normal bowed EOTF luminance curve.">
       <input type="checkbox" id="meterEotfAbsolute" onchange="meterRedrawEotfChart();meterSaveColorPrefs()" style="vertical-align:middle"> Absolute
       </label>
       <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none" title="Overlay separate R, G, B EOTF curves (same as the Gamma chart per-channel option).">
       <input type="checkbox" id="meterEotfPerChannel" onchange="meterRedrawEotfChart();meterSaveColorPrefs()" style="vertical-align:middle"> Per-channel
       </label>
       <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none" title="Use logarithmic vertical scaling for the EOTF chart. This changes only the chart axis, not the target calculations.">
        <input type="checkbox" id="meterEotfLogScale" onchange="meterRedrawEotfChart();meterSaveColorPrefs()" style="vertical-align:middle"> Log scale
       </label>
       <label id="meterHdrDiffuseWhiteWrap" style="font-size:.7rem;color:var(--text2);display:none;align-items:center;gap:4px;user-select:none" title="HDR/PQ projector analysis override. Blank keeps the measured/default target. A value scales the target curve relative to the 94.4 cd/m² diffuse-white reference.">
        Diffuse white
        <input type="number" id="meterHdrDiffuseWhite" class="meter-chart-inline-input" min="1" max="10000" step="0.1" placeholder="94.4" onchange="meterOnHdrDiffuseWhiteChange()" onkeydown="if(event.key==='Enter')this.blur()">
        <span>cd/m&sup2;</span>
       </label>
      </div>
      <div id="meterEotfScroller" class="meter-scroll-sync" style="width:100%;min-width:0;background:#0d0d15;border-radius:6px">
       <canvas id="chartEOTF" width="500" height="350" style="width:100%;min-width:100%;height:350px;min-height:350px;background:#0d0d15;border-radius:6px"></canvas>
      </div>
     </div>
    <div style="min-width:0">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
         <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase">Luminance</div>
         <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none;margin-left:auto" title="Use logarithmic vertical scaling for the luminance chart. This changes only the chart axis, not the target calculations.">
          <input type="checkbox" id="meterLuminanceLogScale" onchange="meterRedrawLuminanceChart();meterSaveColorPrefs()" style="vertical-align:middle"> Log scale
         </label>
        </div>
      <div id="meterLuminanceScroller" class="meter-scroll-sync" style="width:100%;min-width:0;background:#0d0d15;border-radius:6px">
       <canvas id="chartGamma" width="500" height="350" style="width:100%;min-width:100%;height:350px;min-height:350px;background:#0d0d15;border-radius:6px"></canvas>
      </div>
     </div>
    </div>
    </div>
     </div>
   <div id="chartsColorWrap" style="display:none">
    <div style="margin-bottom:10px">
     <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase;margin-bottom:4px">CIE 1931 Chromaticity</div>
     <div id="colorTopLayout" style="display:flex;gap:10px;align-items:flex-start;flex-wrap:wrap">
      <canvas id="chartCIE" width="600" height="600" style="flex:0 0 450px;width:450px;height:450px;max-width:100%;background:#0d0d15;border-radius:6px"></canvas>
      <div id="meterRGBColorWrap" style="flex:0 0 126px;width:126px;height:450px;background:#0d0d15;border-radius:6px;padding:10px;display:flex;flex-direction:column;box-sizing:border-box">
       <div style="font-size:.68rem;color:var(--text2);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;text-align:center">RGB</div>
       <canvas id="meterRGBCanvasColor" width="200" height="400" style="width:100%;flex:1;min-height:0;display:block"></canvas>
      </div>
      <div id="meterXYYColorWrap" style="flex:0 0 126px;width:126px;height:450px;background:#0d0d15;border-radius:6px;padding:10px;display:flex;flex-direction:column;box-sizing:border-box">
       <div style="font-size:.68rem;color:var(--text2);text-transform:none;letter-spacing:.06em;margin-bottom:8px;text-align:center">XyY</div>
       <canvas id="meterXYYCanvasColor" width="200" height="400" style="width:100%;flex:1;min-height:0;display:block"></canvas>
      </div>
      <div id="colorReadingDetail" style="flex:0 0 205px;width:205px;height:450px;background:#0d0d15;border-radius:6px;padding:12px;font-size:12px;color:#888;box-sizing:border-box;overflow:auto">
       <div id="colorDetailContent" style="text-align:center;padding:30px 0;color:#555">Select a color<br>to see details</div>
      </div>
     </div>
    </div>
    <div style="margin-bottom:10px">
     <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;flex-wrap:wrap">
      <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase" id="chartColorDELabel">&Delta;E 2000 (Color Accuracy)</div>
      <label style="font-size:.7rem;color:var(--text2);cursor:pointer;user-select:none;margin-left:auto" title="Include luminance error in color-series and saturation-sweep ΔE calculations.">
       <input type="checkbox" id="meterColorIncludeLumError" onchange="meterOnGreyRefChange()" style="vertical-align:middle"> Include luminance error
      </label>
      <label id="meterColorDeltaEFormWrap" style="font-size:.7rem;color:var(--text2);user-select:none;display:flex;align-items:center;gap:4px;margin-left:auto" title="Changes the color and saturation-sweep ΔE calculation.">
       Color ΔE
       <select id="meterColorDeltaEForm" class="inline-select" onchange="meterOnGreyRefChange()">
        <option value="de2000">ΔE2000</option>
        <option value="de94">ΔE94</option>
        <option value="de76lab">ΔE76 (Lab)</option>
        <option value="deluv76">ΔE76 (Luv)</option>
        <option value="decmc">ΔE CMC(1:1)</option>
        <option value="de2000_jnd">ΔE2000 JND</option>
        <option value="deitp">ΔE ITP</option>
       </select>
      </label>
     </div>
     <canvas id="chartColorDE" width="800" height="180" style="width:100%;background:#0d0d15;border-radius:6px"></canvas>
    </div>
    <div id="colorSeriesAveragesWrap" style="margin-bottom:10px;display:none">
     <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase;margin-bottom:4px">Series Averages</div>
     <div style="overflow-x:auto;border-radius:6px;background:#0d0d15">
      <table id="colorSeriesAveragesTable" style="width:100%;border-collapse:collapse;font-size:11px;color:#ccc;white-space:nowrap">
       <thead><tr style="border-bottom:1px solid #333;color:#888;text-align:right">
        <th style="text-align:left;padding:6px 8px">Group</th>
        <th style="padding:6px 6px">n</th>
        <th style="padding:6px 6px">Avg &Delta;x</th>
        <th style="padding:6px 6px">Avg &Delta;y</th>
        <th style="padding:6px 6px">Avg Y cd/m&sup2;</th>
        <th style="padding:6px 6px">Avg &Delta;E</th>
        <th style="padding:6px 6px">Max &Delta;E</th>
       </tr></thead>
       <tbody></tbody>
      </table>
     </div>
    </div>
    <div id="colorReadingsTableWrap" style="margin-bottom:10px;display:none">
     <div style="font-size:.65rem;color:var(--text2);text-transform:uppercase;margin-bottom:4px">Color Readings</div>
     <div style="overflow-x:auto;border-radius:6px;background:#0d0d15">
      <table id="colorReadingsTable" style="width:100%;border-collapse:collapse;font-size:11px;color:#ccc;white-space:nowrap">
       <thead><tr style="border-bottom:1px solid #333;color:#888;text-align:right">
        <th style="text-align:left;padding:6px 8px">Color</th>
        <th style="padding:6px 6px">Tgt x</th><th style="padding:6px 6px">x</th>
        <th style="padding:6px 6px">Tgt y</th><th style="padding:6px 6px">y</th>
        <th style="padding:6px 6px">Tgt Y</th><th style="padding:6px 6px">Y cd/m&sup2;</th>
        <th style="padding:6px 6px">&Delta;x</th><th style="padding:6px 6px">&Delta;y</th>
        <th style="padding:6px 6px">&Delta;E 2000</th>
       </tr></thead>
       <tbody></tbody>
      </table>
     </div>
    </div>
   </div>
  </div>

  <!-- Export / Report -->
  <div class="btn-row" id="meterExportRow" style="display:none">
   <button class="btn btn-sm btn-secondary" onclick="meterExportCSV()">&#128190; Export CSV</button>
   <button class="btn btn-sm btn-secondary" onclick="meterOpenReportDialog()">&#128196; Generate Report</button>
  </div>

  <div id="meterReportOverlay" style="display:none;position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:10000;align-items:center;justify-content:center;padding:16px">
   <div style="width:min(460px,96vw);background:#111522;border:1px solid #2d3348;border-radius:10px;padding:14px;box-shadow:0 12px 40px rgba(0,0,0,.45)">
    <div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:10px">
     <div style="font-size:.95rem;font-weight:700;color:var(--text)">Generate Measurement Report</div>
     <button class="btn btn-sm btn-secondary" onclick="meterCloseReportDialog()">Close</button>
    </div>
    <div style="font-size:.72rem;color:var(--text2);margin-bottom:8px">Choose which measured series to include and export as HTML or PDF.</div>
    <div style="font-size:.7rem;color:var(--text2);text-transform:uppercase;margin:10px 0 6px">Include Series Data</div>
    <div id="meterReportSeriesList" style="display:grid;gap:6px;margin-bottom:12px"></div>
    <div style="font-size:.7rem;color:var(--text2);text-transform:uppercase;margin:10px 0 6px">Output Format</div>
    <div style="display:flex;gap:14px;flex-wrap:wrap;margin-bottom:14px">
     <label style="display:flex;align-items:center;gap:6px;cursor:pointer"><input type="radio" name="meterReportFormat" value="html" checked> HTML</label>
     <label style="display:flex;align-items:center;gap:6px;cursor:pointer"><input type="radio" name="meterReportFormat" value="pdf"> PDF</label>
    </div>
    <div class="btn-row" style="justify-content:flex-end;margin:0">
     <button class="btn btn-sm btn-secondary" onclick="meterCloseReportDialog()">Cancel</button>
     <button class="btn btn-sm btn-primary" id="meterReportGenerateBtn" onclick="meterGenerateReport()">Generate</button>
    </div>
   </div>
  </div>
 </div>

 <!-- Device Info -->
 <div class="card span2" data-widget="info" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>Device Info</h2>
  <div class="stat-grid" style="margin-bottom:8px">
   <div class="stat-card">
    <div class="stat-label">CPU Usage</div>
    <div class="stat-value" id="cpuUsageValue">--%</div>
    <div class="meter"><div class="meter-fill" id="cpuUsageBar"></div></div>
    <div class="stat-sub" id="cpuUsageSub">--</div>
   </div>
   <div class="stat-card">
    <div class="stat-label">Memory Usage</div>
    <div class="stat-value" id="memUsageValue">--%</div>
    <div class="meter"><div class="meter-fill" id="memUsageBar"></div></div>
    <div class="stat-sub" id="memUsageSub">--</div>
   </div>
  </div>
  <div class="info-grid" id="infoGrid"></div>
 </div>

 <!-- WiFi Client -->
 <div class="card" data-widget="wifi" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>WiFi Client<label class="pg-switch" data-no-collapse title="Enable or disable the WiFi radio (also stops the Access Point)"><input type="checkbox" id="wifiRadioToggle" onchange="onWifiRadioToggle(this)"><span class="pg-switch-track"><span class="pg-switch-thumb"></span></span></label></h2>
  <div class="info-grid" id="wifiStatus" style="margin-bottom:8px"></div>
  <div class="btn-row" style="margin-bottom:8px">
   <button class="btn btn-sm btn-secondary" onclick="scanWifi()">Scan Networks</button>
     <button class="btn btn-sm btn-danger" id="wifiDisconnectBtn" onclick="disconnectWifi()" style="display:none">Disconnect</button>
     <button class="btn btn-sm btn-danger" id="wifiForgetBtn" onclick="forgetWifi()" style="display:none">Forget</button>
  </div>
  <div id="wifiList" class="wifi-list"></div>
  <div id="wifiConnect" class="hidden" style="margin-top:8px">
   <div class="grid">
    <div class="field">
     <label>Network</label>
     <input type="text" id="wifiSsid" readonly>
    </div>
    <div class="field">
     <label>Password</label>
     <input type="password" id="wifiPsk" placeholder="Enter password">
    </div>
   </div>
   <div class="btn-row" style="margin-top:8px">
    <button class="btn btn-sm btn-primary" onclick="connectWifi()">Connect</button>
    <button class="btn btn-sm btn-secondary" onclick="hideWifiForm()">Cancel</button>
   </div>
  </div>
 </div>

 <!-- HDMI-CEC TV Control -->
 <div class="card" data-widget="cec" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>HDMI-CEC</h2>
  <div style="display:flex;align-items:center;gap:12px;margin-bottom:8px">
   <span id="cecStatus" style="font-size:.85rem;color:var(--text2)">Checking...</span>
  </div>
  <div class="btn-row" style="margin-bottom:8px">
   <button class="btn btn-sm btn-success" onclick="cecCmd('on')" title="Wake TV and switch to PGenerator input">&#9654; Power On</button>
   <button class="btn btn-sm btn-danger" onclick="cecCmd('off')" title="Put TV in standby">&#9724; Standby</button>
   <button class="btn btn-sm btn-secondary" onclick="cecCmd('active')" title="Switch TV to PGenerator HDMI input">&#8594; Switch Input</button>
  </div>
  <div class="btn-row" style="margin-bottom:8px">
   <button class="btn btn-sm btn-secondary" onclick="cecCmd('volup')" title="Volume Up">&#128266;+</button>
   <button class="btn btn-sm btn-secondary" onclick="cecCmd('voldown')" title="Volume Down">&#128264;-</button>
   <button class="btn btn-sm btn-secondary" onclick="cecCmd('mute')" title="Toggle Mute">&#128263; Mute</button>
  </div>
  <details style="margin-top:4px">
   <summary style="cursor:pointer;font-size:.85rem;color:var(--text2)">CEC Bus Devices</summary>
   <div id="cecDevices" style="font-size:.8rem;margin-top:6px;color:var(--text2)">
    <button class="btn btn-sm btn-secondary" onclick="cecScan()" style="margin-bottom:6px">Scan CEC Bus</button>
    <div id="cecDeviceList">Not scanned yet</div>
   </div>
  </details>
 </div>

 <!-- Resolve Protocol -->
 <div class="card" data-widget="resolve" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>Resolve Protocol <span id="resolveStatusBadge" style="font-size:.7rem;padding:2px 8px;border-radius:4px;background:var(--text2);color:#000;margin-left:8px">Disconnected</span></h2>
  <div style="font-size:.7rem;color:var(--text2);margin-bottom:8px;line-height:1.4">Connect via HCFR / DisplayCAL Resolve protocol. Enter the IP of the PC running calibration software.</div>
  <div class="grid">
   <div class="field">
    <label>Calibration PC IP</label>
    <input type="text" id="resolveIp" placeholder="192.168.1.x">
   </div>
   <div class="field">
    <label>Port</label>
    <input type="number" id="resolvePort" value="20002" min="1" max="65535">
   </div>
  </div>
  <div class="btn-row" style="margin-top:8px">
   <button class="btn btn-sm btn-success" id="resolveConnectBtn" onclick="resolveConnect()">&#9654; Connect</button>
   <button class="btn btn-sm btn-danger" id="resolveDisconnectBtn" onclick="resolveDisconnect()" style="display:none">&#9724; Disconnect</button>
  </div>
 </div>

 <!-- WiFi AP (PAN) -->
 <div class="card" data-widget="ap" draggable="true">
  <h2><span class="drag-handle">&#9776;</span>WiFi Access Point<label class="pg-switch" data-no-collapse title="Start or stop the WiFi Access Point"><input type="checkbox" id="apEnableToggle" onchange="onApToggle(this)"><span class="pg-switch-track"><span class="pg-switch-thumb"></span></span></label></h2>
  <div class="info-grid" id="apStatus" style="margin-bottom:8px"></div>
  <div class="grid">
   <div class="field">
    <label>SSID</label>
    <input type="text" id="apSsid" placeholder="PGenerator">
   </div>
   <div class="field">
    <label>Password</label>
    <input type="text" id="apPass" placeholder="Min 8 characters">
   </div>
  </div>
  <div class="btn-row" style="margin-top:8px">
   <button class="btn btn-sm btn-primary" onclick="applyAP()">Save AP Settings</button>
  </div>
  <div style="margin-top:6px;font-size:.7rem;color:var(--text2)">Connect to this AP at 10.10.10.1</div>
 </div>

 <!-- Bluetooth PAN -->
 <div class="card" data-widget="bluetooth" draggable="true">
