function formatUptime(s){
 s=parseFloat(s);if(isNaN(s))return'?';
 const d=Math.floor(s/86400),h=Math.floor((s%86400)/3600),m=Math.floor((s%3600)/60);
 return(d?d+'d ':'')+(h?h+'h ':'')+(m?m+'m':'<1m');
}

