 if(r&&r.status==='ok'){
  document.getElementById('apSsid').value=r.ssid||'';
  document.getElementById('apPass').value=r.password||'';
 }
 const s=await fetchJSON('/api/wifi/ap/status',{_quiet:true,_timeoutMs:10000});
