function meterGreyDefaultSlots(points){
 if(points===100) return Array.from({length:101},(_,idx)=>idx);
 if(points===30) return [...METER_GREY_SLOTS_HDR30];
 return points===11?[...METER_GREY_SLOTS_11]:[...METER_GREY_SLOTS_21];
}

function meterUseLgGreyscale21(points){
 const normalized=(points===256)?100:Number(points);
 const manual22Enabled=(typeof METER_LG_GREY_MANUAL_22_ENABLED!=='undefined') && METER_LG_GREY_MANUAL_22_ENABLED;
 return manual22Enabled&&normalized===21&&meterGreyTvControlsActive();
}

function meterUseLgAutoCal26(points){
 const normalized=(points===256)?100:Number(points);
 return normalized===26&&meterGreyTvControlsActive();
}

function meterGreyAllowsHeadroomTargets(){
 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
 const normalized=(Number(meterActiveSeriesPoints)===256)?100:Number(meterActiveSeriesPoints);
 return meterActiveSeriesType==='greyscale'&&normalized===26&&mode==='sdr';
}

function meterLgGreyscaleUsesExtendedSdr(points){
 const normalized=(points===256)?100:Number(points);
 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
 const useLg21=(typeof meterUseLgGreyscale21==='function')&&meterUseLgGreyscale21(normalized);
 const useLg26=(typeof meterUseLgAutoCal26==='function')&&meterUseLgAutoCal26(normalized);
 return (useLg21||useLg26)&&mode==='sdr'&&meterGreyTvControlsActive();
}

function meterLgGreyscaleUsesLegalSdrDdcCodes(points){
 return false;
}

function meterLgAutoCalUsesExtendedSdr(){
 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
 return meterActiveSeriesType==='greyscale'&&(meterUseLgGreyscale21(meterActiveSeriesPoints)||meterUseLgAutoCal26(meterActiveSeriesPoints))&&mode==='sdr'&&meterGreyTvControlsActive();
}

function meterGreySeriesSlots(points){
 if(points===256) points=100;
 if(meterUseHdrGreyscale30(points)) return [...METER_GREY_SLOTS_HDR30];
 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
 if(Number(points)===26&&meterUseLgAutoCal26(points)&&mode==='hdr10') return [0,...METER_LG_GREY_HDR_AUTOCAL_SLOTS.slice().reverse()];
 if(meterUseLgAutoCal26(points)) return [...METER_LG_GREY_AUTOCAL_SERIES_SLOTS];
 if(meterUseLgGreyscale21(points)) return [...METER_LG_GREY_SERIES_SLOTS];
 return meterGreyDefaultSlots(points);
}

function meterGreyProfileSlots(points){
 const normalized=(points===256)?100:Number(points);
 if(normalized===30) return [...METER_GREY_SLOTS_HDR30];
 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
 if(normalized===26&&meterUseLgAutoCal26(normalized)&&mode==='hdr10') return [0,...METER_LG_GREY_HDR_AUTOCAL_SLOTS.slice().reverse()];
 if(meterUseLgAutoCal26(normalized)) return [...METER_LG_GREY_AUTOCAL_SERIES_SLOTS];
 if(meterUseLgGreyscale21(normalized)) return [...METER_LG_GREY_SERIES_SLOTS];
 return meterGreyDefaultSlots(normalized);
}

function meterGreyAnalysisIreFromCode(code){
 const value=Number(code);
 if(!Number.isFinite(value)) return 0;
 if(value<=0) return 0;
 if(value>=255) return 100;
 return value*100/255;
}

function meterGreyscaleStepLabel(step){
 if(!step) return '';
 if(step.name!=null && String(step.name)!=='') return String(step.name);
 if(step.ire!=null){
  const ire=Number(step.ire);
  if(Number.isFinite(ire)) return (Math.round(ire*100)/100)+'%';
 }
 return '';
}

function meterGreyscaleChartLabel(step,steps,idx){
 const label=meterGreyscaleStepLabel(step);
 return label||'';
 }

function meterGreyClampPercent(value,fallback){
 let numeric=Number(value);
 if(!Number.isFinite(numeric)) numeric=Number(fallback);
 if(!Number.isFinite(numeric)) numeric=0;
 numeric=Math.max(0,Math.min(100,numeric));
 return Math.round(numeric*10)/10;
}

function meterGreyPercentEquals(a,b){
 return Math.abs((Number(a)||0)-(Number(b)||0))<0.05;
}

function meterGreyNormalizeEntry(slot,raw){
 const hasObject=!!(raw&&typeof raw==='object');
 const hasRgb=hasObject&&(raw.r!=null||raw.g!=null||raw.b!=null);
 const stimulusSource=(hasObject&&raw.stimulus!=null)?raw.stimulus:(raw!=null&&!hasObject?raw:slot);
 const stimulus=meterGreyClampPercent(stimulusSource,slot);
 const entry={slot:slot,stimulus:stimulus,r:stimulus,g:stimulus,b:stimulus};
 if(hasRgb){
  entry.r=meterGreyClampPercent(raw.r,stimulus);
  entry.g=meterGreyClampPercent(raw.g,stimulus);
  entry.b=meterGreyClampPercent(raw.b,stimulus);
 }
 return entry;
}

function meterLgGreyDefaultEntry(slot){
 const key=meterFormatPercentValue(slot);
 const stimulus=(Object.prototype.hasOwnProperty.call(METER_LG_GREY_STIMULUS_22,key))?METER_LG_GREY_STIMULUS_22[key]:slot;
 return meterGreyNormalizeEntry(slot,stimulus);
}

function meterLgAutoCalDefaultEntry(slot){
 const code=meterLgAutoCalCodeForSlot(slot);
 const stimulus=meterLgAutoCalStimulusFromCode(code);
 return meterGreyNormalizeEntry(slot,stimulus);
}

function meterLgDdcStepHasCustomStimulus(step,slot){
 if(!step) return false;
 const target=Number(slot);
 const keys=['stimulus','signal_r_pct','signal_g_pct','signal_b_pct'];
 return keys.some(key=>step[key]!=null&&!meterGreyPercentEquals(step[key],target));
}

function meterGreyProfileStepsKey(points){
 const normalized=(points===256)?100:points;
 return 'steps_'+normalized;
}

function meterGreyProfileTemplate(){
 const makeSteps=(points)=>{
  const out={};
  meterGreyProfileSlots(points).forEach(slot=>{out[String(slot)]=meterGreyNormalizeEntry(slot,null);});
  return out;
 };
 return {enabled:false,steps_11:makeSteps(11),steps_21:makeSteps(21),steps_30:makeSteps(30),steps_100:makeSteps(100)};
}

function meterGreyModeSignature(){
 return [
  getVal('signal_mode')||'sdr',
  'fmt:'+(getVal('color_format')||'0'),
  'range:'+(getVal('rgb_quant_range')||'0'),
  'color:'+(getVal('colorimetry')||'0'),
  'prim:'+(getVal('primaries')||'0'),
  'eotf:'+(getVal('eotf')||'0')
 ].join('|');
}

function meterGreyNormalizeProfilesState(){
 if(!meterGreyPatchProfiles||typeof meterGreyPatchProfiles!=='object') meterGreyPatchProfiles={};
 meterGreyPatchProfiles.format='pgenerator-greyscale-profile-v2';
 meterGreyPatchProfiles.apply_to_all_modes=!!meterGreyPatchProfiles.apply_to_all_modes;
 if(!meterGreyPatchProfiles.profiles||typeof meterGreyPatchProfiles.profiles!=='object') meterGreyPatchProfiles.profiles={};
 const normalize=(profile)=>{
  const base=meterGreyProfileTemplate();
  const src=(profile&&typeof profile==='object')?profile:{};
  base.enabled=!!src.enabled;
  [11,21,30,100].forEach(points=>{
   const key=meterGreyProfileStepsKey(points);
   const slots=meterGreyProfileSlots(points);
   const out={};
   slots.forEach((slot,idx)=>{
    const raw=src[key]&&src[key][String(slot)];
  const entry=meterGreyNormalizeEntry(slot,raw);
  const hadCustom=!!(raw&&typeof raw==='object'&&(raw.r!=null||raw.g!=null||raw.b!=null));
    if(idx>0){
     const prev=out[String(slots[idx-1])].stimulus;
   if(entry.stimulus<prev){
    entry.stimulus=prev;
    if(!hadCustom){
     entry.r=entry.stimulus;
     entry.g=entry.stimulus;
     entry.b=entry.stimulus;
    }
   }
    }
  out[String(slot)]=entry;
   });
   base[key]=out;
  });
  return base;
 };
 Object.keys(meterGreyPatchProfiles.profiles).forEach(key=>{
  meterGreyPatchProfiles.profiles[key]=normalize(meterGreyPatchProfiles.profiles[key]);
 });
 if(!meterGreyPatchProfiles.profiles['__all__']) meterGreyPatchProfiles.profiles['__all__']=meterGreyProfileTemplate();
 return meterGreyPatchProfiles;
}

function meterGreyActiveProfileKey(){
 const state=meterGreyNormalizeProfilesState();
 return state.apply_to_all_modes?'__all__':meterGreyModeSignature();
}

function meterGreyActiveProfile(create){
 const state=meterGreyNormalizeProfilesState();
 const key=meterGreyActiveProfileKey();
 if(!state.profiles[key]&&create) state.profiles[key]=meterGreyProfileTemplate();
 return state.profiles[key]||null;
}

function meterGreyProfileEntry(points,slot,create){
 const normalized=(points===256)?100:points;
 const stepsKey=meterGreyProfileStepsKey(normalized);
 const profile=meterGreyActiveProfile(!!create);
 if(!profile) return meterGreyNormalizeEntry(slot,null);
 if(!profile[stepsKey]&&create) profile[stepsKey]=meterGreyProfileTemplate()[stepsKey]||{};
 let entry=profile[stepsKey]&&profile[stepsKey][String(slot)];
 if(!entry&&create){
  entry=meterGreyNormalizeEntry(slot,null);
  profile[stepsKey][String(slot)]=entry;
  return entry;
 }
 if(entry&&create){
  entry=meterGreyNormalizeEntry(slot,entry);
  profile[stepsKey][String(slot)]=entry;
 }
 return entry||meterGreyNormalizeEntry(slot,null);
}

function meterGreySignalEntries(points){
 const normalized=(points===256)?100:points;
 const slots=meterGreySeriesSlots(normalized);
 const profile=meterGreyActiveProfile(true);
 const useCustom=!!(profile&&profile.enabled);
 if(!useCustom&&meterUseLgGreyscale21(normalized)) return slots.map(slot=>meterLgGreyDefaultEntry(slot));
 return slots.map(slot=>useCustom?meterGreyProfileEntry(normalized,slot,true):meterGreyNormalizeEntry(slot,null));
}

function meterGreyCustomEnabled(){
 const profile=meterGreyActiveProfile(true);
 return !!(profile&&profile.enabled);
}

function meterGreyStimulusValues(points){
 return meterGreySignalEntries(points).map(entry=>entry.stimulus);
}

function meterGreyStimulusCsv(points){
 return meterGreyStimulusValues(points).map(v=>String(Math.round(v*100)/100)).join(',');
}

function meterGreyChannelValues(points,channel){
 const key=String(channel||'').toLowerCase();
 return meterGreySignalEntries(points).map(entry=>{
  const value=(key==='r'||key==='g'||key==='b')?entry[key]:entry.stimulus;
  return meterGreyClampPercent(value,entry.stimulus);
 });
}

function meterGreyChannelCsv(points,channel){
 return meterGreyChannelValues(points,channel).map(v=>String(Math.round(v*100)/100)).join(',');
}

function meterGreySyncUi(){
 meterGreyNormalizeProfilesState();
 const enabled=meterGreyCustomEnabled();
 const chk=document.getElementById('meterUseCustomGreyscale');
 if(chk) chk.checked=enabled;
 const label=document.getElementById('meterGreyProfileModeLabel');
 if(label) label.textContent=meterGreyPatchProfiles.apply_to_all_modes?'All modes':meterGreyModeSignature();
 const actions=document.getElementById('meterGreyProfileActions');
 if(actions) actions.style.display=enabled?'flex':'none';
}

function meterToggleCustomGreyscale(){
 const chk=document.getElementById('meterUseCustomGreyscale');
 const profile=meterGreyActiveProfile(true);
 if(profile) profile.enabled=!!(chk&&chk.checked);
 meterGreySyncUi();
 saveMeterSettings();
 meterRefreshActiveSeriesCharts();
}

function meterOpenGreyProfileImport(){
 const input=document.getElementById('meterGreyProfileImportInput');
 if(!input) return;
 input.value='';
 input.click();
}

function meterExportGreyProfile(){
 meterGreyNormalizeProfilesState();
 const filename=meterPromptExportFilename('greyscale-profile','pgenerator-greyscale-profile','json','Enter a file name for the custom greyscale export');
 if(!filename) return;
 const blob=new Blob([JSON.stringify(meterGreyPatchProfiles,null,2)],{type:'application/json'});
 meterDownloadBlob(blob,filename);
}

function meterImportGreyProfile(evt){
 const file=evt&&evt.target&&evt.target.files?evt.target.files[0]:null;
 if(!file) return;
 const reader=new FileReader();
 reader.onload=()=>{
  try{
   meterGreyPatchProfiles=JSON.parse(String(reader.result||'{}'));
   meterGreyNormalizeProfilesState();
   meterGreySyncUi();
   saveMeterSettings();
   meterRefreshActiveSeriesCharts();
   toast('Greyscale profile imported');
  }catch(e){
   toast('Invalid greyscale profile file',true);
  }
 };
 reader.readAsText(file);
}

function meterOpenGreyProfileEditor(points){
 meterGreyNormalizeProfilesState();
 meterGreyEditorPoints=(points===11)?11:21;
 const modal=document.getElementById('meterGreyProfileModal');
 if(!modal) return;
 const applyAll=document.getElementById('meterGreyApplyAll');
 if(applyAll) applyAll.checked=!!meterGreyPatchProfiles.apply_to_all_modes;
 const label=document.getElementById('meterGreyModalModeLabel');
 if(label) label.textContent=meterGreyModeSignature();
 meterRenderGreyProfileEditor();
 modal.style.display='flex';
 uiSyncBodyScrollLock();
}

function meterCloseGreyProfileEditor(){
 const modal=document.getElementById('meterGreyProfileModal');
 if(modal) modal.style.display='none';
 uiSyncBodyScrollLock();
}

function meterSetGreyEditorPoints(points){
 meterGreyEditorPoints=(points===11)?11:21;
 meterRenderGreyProfileEditor();
}

function meterRenderGreyProfileEditor(){
 meterGreyNormalizeProfilesState();
 const btn11=document.getElementById('meterGreyEdit11Btn');
 const btn21=document.getElementById('meterGreyEdit21Btn');
 if(btn11){btn11.classList.toggle('btn-primary',meterGreyEditorPoints===11);btn11.classList.toggle('btn-secondary',meterGreyEditorPoints!==11);}
 if(btn21){btn21.classList.toggle('btn-primary',meterGreyEditorPoints===21);btn21.classList.toggle('btn-secondary',meterGreyEditorPoints!==21);}
 const applyAll=document.getElementById('meterGreyApplyAll')&&document.getElementById('meterGreyApplyAll').checked;
 const key=applyAll?'__all__':meterGreyModeSignature();
 if(!meterGreyPatchProfiles.profiles[key]) meterGreyPatchProfiles.profiles[key]=meterGreyProfileTemplate();
 const profile=meterGreyPatchProfiles.profiles[key];
 const slots=meterGreyProfileSlots(meterGreyEditorPoints);
 const stepsKey=meterGreyProfileStepsKey(meterGreyEditorPoints);
 const body=document.getElementById('meterGreyProfileEditorBody');
 if(!body) return;
 body.innerHTML=slots.map(slot=>{
  const entry=profile[stepsKey][String(slot)]||{slot:slot,stimulus:slot};
  const val=(entry&&entry.stimulus!=null)?entry.stimulus:slot;
  return '<tr style="border-bottom:1px solid #1a1a28">'
   +'<td style="padding:6px">'+slot+'%</td>'
   +'<td style="padding:6px;color:#999">'+slot+'%</td>'
   +'<td style="padding:6px"><input type="number" min="0" max="100" step="0.1" data-grey-slot="'+slot+'" value="'+val+'" style="width:100%;background:#0d0d15;border:1px solid #2a3140;border-radius:4px;color:#eee;padding:6px;box-sizing:border-box"></td>'
   +'</tr>';
 }).join('');
}

function meterResetGreyProfileEditor(){
 const applyAll=document.getElementById('meterGreyApplyAll')&&document.getElementById('meterGreyApplyAll').checked;
 const key=applyAll?'__all__':meterGreyModeSignature();
 meterGreyPatchProfiles.profiles[key]=meterGreyProfileTemplate();
 meterRenderGreyProfileEditor();
}

function meterSaveGreyProfileEditor(){
 meterGreyNormalizeProfilesState();
 const applyAll=!!(document.getElementById('meterGreyApplyAll')&&document.getElementById('meterGreyApplyAll').checked);
 const slots=meterGreyProfileSlots(meterGreyEditorPoints);
 const vals=[];
 let prev=-1;
 for(const slot of slots){
  const input=document.querySelector('#meterGreyProfileEditorBody input[data-grey-slot="'+slot+'"]');
  let v=input?parseFloat(input.value):slot;
  if(!Number.isFinite(v)) v=slot;
  v=Math.max(0,Math.min(100,v));
  if(prev>v){ toast('Custom greyscale values must be monotonic ascending',true); return; }
  vals.push(v);
  prev=v;
 }
 meterGreyPatchProfiles.apply_to_all_modes=applyAll;
 const key=applyAll?'__all__':meterGreyModeSignature();
 if(!meterGreyPatchProfiles.profiles[key]) meterGreyPatchProfiles.profiles[key]=meterGreyProfileTemplate();
 const profile=meterGreyPatchProfiles.profiles[key];
 profile.enabled=true;
 const stepsKey=meterGreyProfileStepsKey(meterGreyEditorPoints);
 slots.forEach((slot,idx)=>{
  const prevEntry=meterGreyNormalizeEntry(slot,profile[stepsKey]&&profile[stepsKey][String(slot)]);
  const preserveCustom=!meterGreyPercentEquals(prevEntry.r,prevEntry.stimulus)||!meterGreyPercentEquals(prevEntry.g,prevEntry.stimulus)||!meterGreyPercentEquals(prevEntry.b,prevEntry.stimulus);
  const nextEntry={slot:slot,stimulus:vals[idx],r:vals[idx],g:vals[idx],b:vals[idx]};
  if(preserveCustom){
   nextEntry.r=meterGreyClampPercent(prevEntry.r,vals[idx]);
   nextEntry.g=meterGreyClampPercent(prevEntry.g,vals[idx]);
   nextEntry.b=meterGreyClampPercent(prevEntry.b,vals[idx]);
  }
  profile[stepsKey][String(slot)]=nextEntry;
 });
 const chk=document.getElementById('meterUseCustomGreyscale');
 if(chk) chk.checked=true;
 meterGreySyncUi();
 meterCloseGreyProfileEditor();
 saveMeterSettings();
 meterRefreshActiveSeriesCharts();
 toast('Custom greyscale values saved');
}
// Build steps client-side (mirrors server logic in webui_meter_series_start)
function meterBuildStepsJS(type,points){
 if(type==='greyscale' && points===256) points=100;
	 const steps=[];
	 if(type==='greyscale'){
	  if(points===2){
   const twoPoint=meterSyncTwoPointInputs();
   [
    {role:'high',value:twoPoint.high},
    {role:'low',value:twoPoint.low}
   ].forEach(entry=>{
    const c=meterCodeFromSignalPercent(entry.value);
    const label=(entry.role==='low'?'Low ':'High ')+meterFormatPercentValue(entry.value)+'%';
    const step={ire:entry.value,stimulus:entry.value,signal_r_pct:entry.value,signal_g_pct:entry.value,signal_b_pct:entry.value,r:c,g:c,b:c,name:label,point_role:entry.role,series_type:'greyscale'};
    steps.push(step);
   });
			  } else if(points===26&&meterUseLgAutoCal26(points)){
			   steps.push(...meterBuildLgAutoCalSteps([],true));
			  } else {
		   const ires=meterGreySeriesSlots(points);
		     const lgSlotLocked=meterUseLgGreyscale21(points);
		     const lgExtendedSdr=meterLgGreyscaleUsesExtendedSdr(points);
		     const lgLegalSdrDdc=meterLgGreyscaleUsesLegalSdrDdcCodes(points);
		     const entries=meterGreySignalEntries(points);
		     const entryBySlot={};
		     ires.forEach((slot,idx)=>{ entryBySlot[slot]=entries[idx]||meterGreyNormalizeEntry(slot,null); });
   // Measurement order: 100% first (white reference), then 0%→95% ascending
   const ordered=[100,...ires.filter(v=>v!==100).sort((a,b)=>a-b)];
   // 10-bit transport (HDR10/HLG/SDR-10) emits 10-bit codes from
   // meterGreyCodeRange. The 26pt HDR10 path sets input_max + preview_*
   // explicitly via previewCodesForCode; mirror that here so the server
   // (webui_pattern) doesn't interpret e.g. 0%->code 64 as 8-bit and lift
   // the black to ~22% signal, and so the patch-thumbnail swatch shows
   // the correct 0-255 normalized preview instead of the raw 10-bit code.
   const stepInputMax=meterPatchBitDepth()===10?1023:255;
   const previewForCode=(code)=>{
    const numeric=Number(code);
    if(!Number.isFinite(numeric)) return 0;
    return stepInputMax>255?Math.max(0,Math.min(255,Math.round(numeric*255/stepInputMax))):Math.max(0,Math.min(255,Math.round(numeric)));
   };
   ordered.forEach(v=>{
	    const entry=entryBySlot[v]||meterGreyNormalizeEntry(v,null);
	    const ddcSlotLocked=lgSlotLocked&&METER_LG_GREY_DDC_SLOTS_22.some(slot=>Math.abs(slot-v)<0.001);
	    const stepR=meterCodeFromSignalPercentWithOptions(entry.r,{lgExtendedSdr:lgExtendedSdr,lgLegalSdrDdc:lgLegalSdrDdc});
	    const stepG=meterCodeFromSignalPercentWithOptions(entry.g,{lgExtendedSdr:lgExtendedSdr,lgLegalSdrDdc:lgLegalSdrDdc});
	    const stepB=meterCodeFromSignalPercentWithOptions(entry.b,{lgExtendedSdr:lgExtendedSdr,lgLegalSdrDdc:lgLegalSdrDdc});
		    const step={
		     ire:v,
		     stimulus:entry.stimulus,
		     signal_r_pct:entry.r,
		     signal_g_pct:entry.g,
     signal_b_pct:entry.b,
	     r:stepR,
		     g:stepG,
		     b:stepB,
		     preview_r:previewForCode(stepR),
		     preview_g:previewForCode(stepG),
		     preview_b:previewForCode(stepB),
		     input_max:stepInputMax,
		     name:meterFormatPercentValue(v)+'%',
	     series_type:'greyscale',
		     ddc_slot_locked:ddcSlotLocked
		    };
		    const stepSignalMode=String((typeof meterChartSignalMode==='function')?meterChartSignalMode():(getVal('signal_mode')||'sdr')).toLowerCase();
	    if(stepSignalMode==='sdr'&&Number(step.r)===Number(step.g)&&Number(step.g)===Number(step.b)){
		     const targetYn=meterGreyscaleTargetYnForCode(step.g);
		     if(Number.isFinite(targetYn)&&targetYn>=0) step.target_Yn=targetYn;
		    }
			    if(lgSlotLocked){
		     const analysisIre=meterLgSdrLegalStimulusFromCode(step.g);
		     step.analysis_ire=analysisIre;
	     step.target_ire=analysisIre;
	     step.transport_stimulus=entry.stimulus;
	    }
	    steps.push(step);
	   });
	  }
 } else if(type==='colors'){
  steps.push(...meterBuildColorCheckerStepsJS());
 } else if(type==='saturations'){
  ['Red','Green','Blue','Cyan','Magenta','Yellow'].forEach(name=>{
   [25,50,75,100].forEach(sat=>{
    const rgb=meterBuildSaturationStepRgb(name,sat);
    steps.push({ire:sat,r:rgb[0],g:rgb[1],b:rgb[2],name:name+' '+sat+'%',series_color:name,sat_pct:sat,...meterBuildSaturationTargetStepMeta(name,sat)});
   });
  });
 }
	 return meterApplyColorSeriesTargetWhiteReference(steps,type,points);
}

function meterBuildLgAutoCalSteps(steps,includeWhiteReference){
	 const input=Array.isArray(steps)?steps:[];
	 const passthrough=input.filter(step=>step&&!meterSeriesStepIsGreyscale(step));
	 const black=input.find(step=>step&&meterSeriesStepIsGreyscale(step)&&Math.abs(Number(step.ire)||0)<0.001);
	 const mode=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase();
		 const previewCodesForCode=(code,inputMax)=>{
		  const max=Number(inputMax)||1023;
		  const preview=Math.max(0,Math.min(255,Math.round(max>255?Number(code||0)*255/max:Number(code||0))));
		  return {preview_r:preview,preview_g:preview,preview_b:preview,series_mode:'lg-autocal-26'};
		 };
 const inputByDdcSlot={};
	 input.forEach(step=>{
	  if(!step||!meterSeriesStepIsGreyscale(step)) return;
	  const ire=Number(step.ire);
	  const slot=METER_LG_GREY_AUTOCAL_26_SLOTS.find(v=>Math.abs(v-ire)<0.001);
	  if(slot!=null&&step.autocal_slot_locked&&meterLgDdcStepHasCustomStimulus(step,slot)) inputByDdcSlot[String(slot)]=step;
	 });
	 if(mode==='hdr10'){
	  const makeHdrStep=(slot)=>{
		   const hdrIdx=METER_LG_GREY_HDR_AUTOCAL_SLOTS.findIndex(v=>Math.abs(Number(v)-Number(slot))<0.001);
		   // Pick the HDR greyscale code table by bit-depth + quant range.
		   // The renderer runs a 10-bit pipeline when max_bpc===10, and the
		   // 8-bit-limited table there sends e.g. 27 for 5% IRE on a Full
		   // panel (clipped/over-driven). See METER_LG_GREY_HDR_AUTOCAL_*
		   // definitions at webui.pm ~18305.
		   let code;
		   if(hdrIdx>=0){
		    if(meterPatchBitDepth()===10 && !meterIsLimitedRange()){
		     code=METER_LG_GREY_HDR_AUTOCAL_CODES_10BIT_FULL[hdrIdx];
		    } else if(meterPatchBitDepth()===10 && meterIsLimitedRange()){
		     code=METER_LG_GREY_HDR_AUTOCAL_CODES_10BIT_LIMITED[hdrIdx];
		    } else {
		     code=METER_LG_GREY_HDR_AUTOCAL_CODES_8BIT_LIMITED[hdrIdx];
		    }
		   } else {
		    code=meterCodeFromSignalPercentWithOptions(slot,null);
		   }
		   const stimulus=Number(slot);
		   const ddcArrayIre=hdrIdx>=0?METER_LG_GREY_HDR_AUTOCAL_DDC_ARRAY_IRES[hdrIdx]:stimulus;
		   return {
		    ire:slot,
	    stimulus:stimulus,
	    signal_r_pct:stimulus,
	    signal_g_pct:stimulus,
	    signal_b_pct:stimulus,
	    r:code,
	    g:code,
	    b:code,
	    name:meterFormatPercentValue(slot)+'%',
	    series_type:'greyscale',
	    autocal_code:code,
	    input_max:meterPatchBitDepth()===10?1023:255,
	    ...previewCodesForCode(code,meterPatchBitDepth()===10?1023:255),
		    ddc_slot_locked:true,
		    autocal_slot_locked:true,
		    ddc_layout:'hdr20',
		    ddc_target_ire:ddcArrayIre,
		    ddc_array_ire:ddcArrayIre,
		    autocal_order_ire:ddcArrayIre
		   };
		  };
	  const zeroCode=meterCodeFromSignalPercentWithOptions(0,null);
	  const zero=black?{...black,ire:0,stimulus:0,signal_r_pct:0,signal_g_pct:0,signal_b_pct:0,r:zeroCode,g:zeroCode,b:zeroCode,input_max:meterPatchBitDepth()===10?1023:255,name:'0%',autocal_code:zeroCode,...previewCodesForCode(zeroCode,meterPatchBitDepth()===10?1023:255),autocal_slot_locked:false,autocal_read_only:true}:{ire:0,stimulus:0,signal_r_pct:0,signal_g_pct:0,signal_b_pct:0,r:zeroCode,g:zeroCode,b:zeroCode,input_max:meterPatchBitDepth()===10?1023:255,name:'0%',series_type:'greyscale',autocal_code:zeroCode,...previewCodesForCode(zeroCode,meterPatchBitDepth()===10?1023:255),autocal_slot_locked:false,autocal_read_only:true};
	  const whiteCode=meterCodeFromSignalPercentWithOptions(100,null);
	  const white={ire:100,stimulus:100,signal_r_pct:100,signal_g_pct:100,signal_b_pct:100,r:whiteCode,g:whiteCode,b:whiteCode,input_max:meterPatchBitDepth()===10?1023:255,name:'100%',series_type:'greyscale',autocal_code:whiteCode,...previewCodesForCode(whiteCode,meterPatchBitDepth()===10?1023:255),read_delay_ms:3000,autocal_white_reference:true,autocal_reference_only:true,autocal_read_only:true,autocal_target_label:'100% HDR white'};
	  // hdr20 (HDR10) carries a REAL 100% DDC slot at the top of the body
	  // (METER_LG_GREY_HDR_AUTOCAL_SLOTS[0]===100), so the pre-loop
	  // "100% HDR white" anchor would duplicate the 100% point in the
	  // greyscale chart and step strip, and would give the worker a locked
	  // twin to fight at the top. The worker derives its white reference
	  // from the top slot step itself (update_white_reference_for_step via
	  // autocal_step_is_hdr20_top_white), so the anchor is redundant.
	  // Body is reversed so the step strip is 0 -> ascending -> 100%, not
	  // 0 -> 100 -> descending.
	  const body=[...METER_LG_GREY_HDR_AUTOCAL_SLOTS].reverse().map(makeHdrStep);
	  return [zero,...body,...passthrough];
	 }
	 const makeDdcStep=(slot)=>{
	  const source=inputByDdcSlot[String(slot)];
	  const code=meterLgAutoCalCodeForSlot(slot);
	  const stimulus=meterLgAutoCalStimulusFromCode(code);
	  const targetMeta=meterLgAutoCalTargetMetaForCode(code);
		  if(source){
		   return {
		    ...source,
		    ire:slot,
		    stimulus:stimulus,
		    signal_r_pct:stimulus,
		    signal_g_pct:stimulus,
		    signal_b_pct:stimulus,
		    r:code,
		    g:code,
		    b:code,
		    name:meterFormatPercentValue(slot)+'%',
		    autocal_code:code,
		    input_max:1023,
		    ...targetMeta,
		    ...previewCodesForCode(code,1023),
		    ddc_slot_locked:true,
	    autocal_slot_locked:true
	   };
	  }
	  return {
   ire:slot,
   stimulus:stimulus,
   signal_r_pct:stimulus,
   signal_g_pct:stimulus,
   signal_b_pct:stimulus,
	   r:code,
	   g:code,
	   b:code,
	   name:meterFormatPercentValue(slot)+'%',
	   series_type:'greyscale',
		   autocal_code:code,
		   input_max:1023,
	   ...targetMeta,
	   ...previewCodesForCode(code,1023),
	   ddc_slot_locked:true,
	   autocal_slot_locked:true
	  };
	 };
			 const zeroCode=mode==='sdr'?64:meterCodeFromSignalPercentWithOptions(0,null);
			 const zeroMeta=meterLgAutoCalTargetMetaForCode(zeroCode);
			 const zero=black?{...black,ire:0,stimulus:0,signal_r_pct:0,signal_g_pct:0,signal_b_pct:0,r:zeroCode,g:zeroCode,b:zeroCode,input_max:mode==='sdr'?1023:(black.input_max||255),name:'0%',autocal_code:zeroCode,...zeroMeta,...previewCodesForCode(zeroCode,mode==='sdr'?1023:(black.input_max||255)),autocal_slot_locked:false,autocal_read_only:true}:{ire:0,stimulus:0,signal_r_pct:0,signal_g_pct:0,signal_b_pct:0,r:zeroCode,g:zeroCode,b:zeroCode,input_max:mode==='sdr'?1023:255,name:'0%',series_type:'greyscale',autocal_code:zeroCode,...zeroMeta,...previewCodesForCode(zeroCode,mode==='sdr'?1023:255),autocal_slot_locked:false,autocal_read_only:true};
 const whiteCode=mode==='sdr'?meterLgSdrLegalHeadroomCodeFromPercent(100):meterCodeFromSignalPercentWithOptions(100,null);
 const white={ire:100,stimulus:100,signal_r_pct:100,signal_g_pct:100,signal_b_pct:100,r:whiteCode,g:whiteCode,b:whiteCode,input_max:mode==='sdr'?1023:255,name:'100%',series_type:'greyscale',autocal_code:whiteCode,...meterLgAutoCalTargetMetaForCode(whiteCode),...previewCodesForCode(whiteCode,mode==='sdr'?1023:255),read_delay_ms:3000,autocal_slot_locked:true,ddc_slot_locked:true,autocal_white_reference:true,autocal_reference_only:true,autocal_read_only:true,autocal_legal_white_anchor:true,ddc_target_ire:99,autocal_order_ire:98.95,autocal_target_label:'100% legal white'};
 const body=[...METER_LG_GREY_AUTOCAL_26_SLOTS]
  .sort((a,b)=>a-b)
  .map(makeDdcStep);
 return [...(includeWhiteReference?[white]:[]),zero,...body,...passthrough];
}
// Select a series: load thumbnails + display first patch, no reading
function meterSelectSeries(type,points,opts){
 opts=opts||{};
 if(meterActionPending) return;
 if(type==='greyscale' && points===256) points=100;
 if(type==='greyscale' && Number(points)===30 && !meterHdrGreyscaleSeriesAvailable()){
  toast('Greyscale HDR 30pt is unavailable',true);
  return;
 }
 const key=type+'-'+points;
 if(!opts.preserveTab) meterSetSeriesTab(meterSeriesTabForType(type),true);
 if(meterSeriesRunning){
  if(meterActiveSeriesKey===key){
   toast('Series scan is running — stop it before reloading this chart',true);
   return;
  }
  if(!window.confirm('Leave the current series and cancel the running series read?')) return;
 }
 clearActive();
 if(meterSeriesRunning) meterStop();
 else meterStopContinuous();
 if(meterActiveSeriesKey===key){
  if(opts.preserveTab&&meterSeriesTab==='autocal'){
   meterUpdateSeriesTabUi();
   meterSetAutoCalSeriesChoice(type==='greyscale'?'greyscale':'3d-lut');
  }
  if(meterSeriesSteps&&meterSeriesSteps.length>0){
   const sortedSteps=(type==='colors'||type==='saturations')?[...meterSeriesSteps]:meterGreyscaleSeriesSteps(meterSeriesSteps);
   meterBuildPatchThumbs(sortedSteps,null);
   if(meterReadings&&meterReadings.length>0){
    const sorted=(type==='colors'||type==='saturations')?[...meterReadings]:[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
    drawAllCharts(sorted);
   } else {
    drawAllChartsPreset(sortedSteps);
   }
  }
  meterUpdateReadButtons();
  meterUpdateDeltaEFormControl();
  return;
 }
 if(meterActiveSeriesKey&&meterSeriesSteps&&meterSeriesSteps.length>0){
  meterCacheSeriesState(meterSeriesRunning?'running':'complete');
 }
 _selectedColorReadingName=null;
 _colorDetailPinned=false;
 meterCurrentPatchStep=null;
 meterSelectedThumbIre=null;
 document.getElementById('meterLiveReading').style.display='none';
