 }
 // Sort for display
 const sortedSteps=(type==='colors'||type==='saturations')?[...steps]:meterGreyscaleSeriesSteps(steps);
 // Show UI — toggle greyscale vs color chart sections
 if(type==='greyscale'){
  document.getElementById('chartsGreyscaleWrap').style.display='';
