 document.getElementById('meterExportRow').style.display='';
 document.getElementById('meterReadSeriesBtn').style.display='';
 meterSetThumbsVisible(true);
 meterHideWorkflowProgress();
 // Build thumbnails and pre-populate all charts
 meterBuildPatchThumbs(sortedSteps,null);
 drawAllChartsPreset(sortedSteps);
 // No default patch selection — user must click a thumbnail
 meterUpdateThumbStyles(document.getElementById('meterPatchThumbs'),null,null);
 meterUpdateReadButtons();
 meterUpdateDeltaEFormControl();
 toast(meterSeriesLabelFromKey(key)+' loaded');
}
function meterMeasurementSignalContext(payload){
 const body=Object.assign({},payload||{});
 body.signal_mode=getVal('signal_mode')||'sdr';
 if(body.signal_mode==='dv'){
  const dvTransport=dvTransportDefaults(getVal('dv_transport'));
  body.target_gamma=meterDvAutoTargetGamma();
  body.dv_map_mode=getVal('dv_map_mode')||((config&&config.dv_map_mode)||'2');
  body.dv_transport=dvTransport.dv_transport;
  body.dv_interface=dvTransport.dv_interface;
 }
 body.max_luma=(document.getElementById('max_luma')||{}).value||((config&&config.max_luma)||'1000');
 if(body.measurement_meter_port==null){
  const measurementPort=meterSelectedMeasurementPort();
  if(measurementPort) body.measurement_meter_port=measurementPort;
 }
 if(body.profiling_meter_port==null){
  const profilingPort=meterSelectedProfilingPort();
  if(profilingPort) body.profiling_meter_port=profilingPort;
 }
 if(body.signal_range==null) body.signal_range=getVal('rgb_quant_range');
 if(body.transport_signal_range==null) body.transport_signal_range=getVal('rgb_quant_range');
 if(body.color_format==null) body.color_format=getVal('color_format')||((config&&config.color_format)||'0');
 if(body.colorimetry==null) body.colorimetry=getVal('colorimetry')||((config&&config.colorimetry)||'0');
 if(body.primaries==null) body.primaries=getVal('primaries')||((config&&config.primaries)||'0');
   if(meterTargetWhitePointEnabled()){
    body.custom_d65_enabled=true;
    body.target_white_x=(document.getElementById('meterTargetWhiteX')||{}).value||'';
    body.target_white_y=(document.getElementById('meterTargetWhiteY')||{}).value||'';
   }
  // Target White / Target Black overrides for read/series/autocal target math.
  try{ Object.assign(body,meterTargetLevelsPayload()); }catch(e){}
  return body;
 }

function meterLgAutoCalRequestedSignalMode(){
 const mode=String((meterChartSignalMode&&meterChartSignalMode())||'sdr').toLowerCase();
 return mode==='hdr10'?'hdr10':'sdr';
}

function meterAutoCalTargetGammaValue(){
 return meterLgAutoCalRequestedSignalMode()==='hdr10'?'st2084':((document.getElementById('meterTargetGamma')||{}).value||'bt1886');
}

function meterLgAutoCalGreyscaleTargetGammaValue(){
 return meterLgAutoCalRequestedSignalMode()==='hdr10'?'2.2':meterAutoCalTargetGammaValue();
}

function meterAutoCalTargetGamutValue(){
 const mode=meterLgAutoCalRequestedSignalMode();
 if(mode==='hdr10') return 'bt2020';
 const raw=String((document.getElementById('meterTargetGamut')||{}).value||'auto').toLowerCase();
 if(raw==='bt709'||raw==='bt2020'||raw==='p3d65'||raw==='p3dci') return raw;
 return 'bt709';
}

function meterAutoCalUseFullDdcSpine(){
 const mode=meterLgAutoCalRequestedSignalMode();
 return mode==='sdr'||mode==='hdr10';
}

function meterEnsureAppliedGeneratorSettings(){
 if(!meterEnsureExtendedVideoTransport()) return false;
 if(!hasUnsavedSettings()) return true;
 const applyBar=document.getElementById('applyBar');
 if(applyBar&&applyBar.scrollIntoView){
  try{ applyBar.scrollIntoView({behavior:'smooth',block:'center'}); }catch(e){ applyBar.scrollIntoView(); }
 }
 toast('Apply & Restart before taking meter readings so the generator mode matches the chart targets',true);
 return false;
}

function meterLgAutoCalTransportReady(){
 const requested=meterLgAutoCalRequestedSignalMode();
 const base=getVal('signal_mode')===requested
  && getVal('max_bpc')==='10'
  && getVal('color_format')==='1'
  && getVal('rgb_quant_range')==='1';
 if(!base) return false;
 if(requested==='hdr10'){
  return getVal('colorimetry')==='9'&&getVal('primaries')==='2'&&getVal('eotf')==='2';
 }
 return getVal('colorimetry')==='2'&&getVal('eotf')==='0';
}

function meterLgAutoCalTransportAvailable(){
 const modeIdx=getVal('mode_idx');
 const validFmts=getValidFormats(modeIdx,10);
 const validBpc=getValidBpc(modeIdx,1);
 return validFmts.indexOf(1)>=0 && validBpc.indexOf(10)>=0;
}

function meterSetLgAutoCalTransportValues(){
 const requested=meterLgAutoCalRequestedSignalMode();
 setVal('signal_mode',requested);
 if(requested==='hdr10'){
  setVal('eotf','2');
  setVal('primaries','2');
  setVal('colorimetry','9');
 }else{
  setVal('eotf','0');
  setVal('primaries','0');
  setVal('colorimetry','2');
 }
 setVal('max_bpc','10');
 setVal('color_format','1');
 setVal('rgb_quant_range','1');
 applyMeterTargetGamutDefault(true);
 applyMeterTargetGammaDefault();
 updateModeVisibility();
 updateDropdowns();
 setVal('max_bpc','10');
 setVal('color_format','1');
 setVal('rgb_quant_range','1');
 if(requested==='hdr10'){
  setVal('colorimetry','9');
  setVal('eotf','2');
  setVal('primaries','2');
 }else{
  setVal('colorimetry','2');
  setVal('eotf','0');
  setVal('primaries','0');
 }
 checkSettingsChanged();
 saveMeterSettings();
}

async function meterEnsureLgAutoCalTransport(workflowName){
 // Popup block removed by user request on 2026-06-13: see the comment
 // on meterEnsureExtendedVideoTransport above. Same rationale -- the
 // operator wants to run autocal tests in different signal modes
 // (RGB 10-bit full, RGB 10-bit limited, YCbCr 4:4:4 limited) without
 // being forced to switch to YCbCr 4:4:4 10-bit limited.
 if(meterLgAutoCalTransportReady()&&!hasUnsavedSettings()) return true;
 return true;
}
// Display a patch on PGenerator without reading
function meterMeasurementPatchSignalRange(){
 if(meterLgGreyscaleUsesExtendedSdr(meterActiveSeriesPoints)) return '1';
 if(meterLgGreyscaleUsesLegalSdrDdcCodes(meterActiveSeriesPoints)) return '1';
 if(meterGreyscaleUsesFullSourceRange()) return '2';
 return null;
}

async function meterDisplayPatch(step,options){
	 const displayToken=++meterPatternDisplayToken;
	 if(!meterEnsureAppliedGeneratorSettings()) return;
	 const freshStep=(options&&options.fresh===false)?step:(meterFreshSeriesStep(step)||step);
	 if(!freshStep) return;
	 if(displayToken!==meterPatternDisplayToken) return;
	 meterCurrentPatchStep=freshStep;
	 const psize=getMeterPatchSize();
 const signalRange=meterMeasurementPatchSignalRange();
	 const payload=meterMeasurementSignalContext({name:'patch',r:freshStep.r,g:freshStep.g,b:freshStep.b,size:psize,input_max:meterStepInputMax(freshStep),signal_range:signalRange||undefined,pattern_session:String(displayToken)});
	 if(options&&options.allowAfterStop) payload.allow_after_stop=true;
	 if(displayToken!==meterPatternDisplayToken) return;
	 await fetchJSON('/api/pattern',{method:'POST',headers:{'Content-Type':'application/json'},
  body:JSON.stringify(payload),_quiet:true,_timeoutMs:10000});
}

let meterLgGreyState={status:'idle',picture:null,message:'',needsRepair:false};
let meterLgGreyBusy=false;
let meterLgGreyBusyStartedAt=0;
let meterLgGreyBusyLabel='';
let meterLgGreyLoadToken=0;

function meterGreyTvIreStops(){
 return [...METER_LG_GREY_DDC_SLOTS_22];
}

function meterGreyTvPictureKeys(){
	 return ['pictureMode','ddc_layout','whiteBalanceMethod','whiteBalanceIre','whiteBalancePoint','whiteBalanceRed','whiteBalanceGreen','whiteBalanceBlue','adjustingLuminance'];
}

function meterAutoCalDdcResetReadbackKeys(){
 const keys=[...meterGreyTvPictureKeys(),...meterAutoCalPanelLightCandidates().map(item=>item.key)];
 return [...new Set(keys.filter(Boolean))];
}

function meterLgPictureModeValue(fallback){
 if(typeof lgSelectedPictureModeValue==='function'){
  const selected=lgSelectedPictureModeValue();
  if(selected) return selected;
 }
 if(typeof lgPictureModeValue!=='undefined'&&lgPictureModeValue) return lgPictureModeValue;
 return fallback||'';
}

function meterGreyTvTarget(step,opts){
 const allowSeriesRunning=!!(opts&&opts.allow_series_running);
 const resolved=meterCanonicalSeriesStep(step)||step;
 if(!resolved||(!allowSeriesRunning&&meterSeriesRunning)||meterActiveSeriesType!=='greyscale'||meterIsTwoPointGreyscale()) return null;
	 if(!meterSeriesStepIsGreyscale(resolved)) return null;
	 const ire=Number(resolved.ire);
	 if(!Number.isFinite(ire)) return null;
	 const autoCal26=meterUseLgAutoCal26(meterActiveSeriesPoints);
	 const autoCalHdr=autoCal26&&String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase()==='hdr10';
	 const stops=autoCal26?(autoCalHdr?[...METER_LG_GREY_HDR_AUTOCAL_SLOTS]:[...METER_LG_GREY_AUTOCAL_26_SLOTS]):meterGreyTvIreStops();
		 let idx=stops.findIndex(v=>Math.abs(v-ire)<0.001);
	 let patchStop=null;
	 if(idx < 0 && !autoCal26 && meterUseLgGreyscale21(meterActiveSeriesPoints)){
	  idx=METER_LG_GREY_DDC_PATCH_SLOTS_22.findIndex(v=>Math.abs(v-ire)<0.001);
	  if(idx >= 0) patchStop=METER_LG_GREY_DDC_PATCH_SLOTS_22[idx];
	 }
	 if(idx < 0) {
	  if(Math.abs(ire)<0.001) return {read_only:true,key:'readonly:0',method:'readonly',ire:'0',index:null,label:'0%'};
	  const reason='This greyscale step does not map to an LG white-balance control.';
	  return {unsupported:true,key:'unsupported:'+meterFormatPercentValue(ire),reason:reason};
	 }
 const stop=stops[idx];
 return {
  key:(autoCal26?'26:':'22:')+meterFormatPercentValue(stop),
  method:'22',
	  ire:meterFormatPercentValue(stop),
	  index:idx,
	  label:meterFormatPercentValue(stop)+'%',
	  patch_ire:patchStop==null?null:meterFormatPercentValue(patchStop),
	  force_ddc:!!autoCal26
	 };
	}

function meterGreyTvTargetAdjustable(target){
 return !!(target&&!target.unsupported&&!target.read_only);
}

function meterGreyTvSettingKey(channel){
 switch(String(channel||'').toLowerCase()){
	  case 'r': return 'whiteBalanceRed';
	  case 'g': return 'whiteBalanceGreen';
	  case 'b': return 'whiteBalanceBlue';
	  case 'l':
	  case 'lum':
	  case 'brightness': return 'adjustingLuminance';
	  default: return '';
	 }
}

function meterGreyTvNormalizeChannel(channel){
 const key=String(channel||'').toLowerCase();
 if(key==='r'||key==='g'||key==='b') return key;
 if(key==='l'||key==='lum'||key==='brightness') return 'lum';
 return '';
}

function meterGreyTvChannelLabel(channel){
 const key=meterGreyTvNormalizeChannel(channel);
 if(key==='lum') return 'Brightness';
 return key?key.toUpperCase():'LG value';
}

function meterGreyTvChannelStep(channel){
 return METER_LG_GREY_TV_MENU_STEP;
}

function meterGreyTvWholeMenuValue(value){
 const numeric=Number(value);
 if(!Number.isFinite(numeric)) return 0;
 return Math.round(Math.max(-50,Math.min(50,numeric)));
}

function meterGreyTvFormatSettingValue(value){
 const numeric=Number(value);
 if(!Number.isFinite(numeric)) return '--';
 const rounded=meterGreyTvWholeMenuValue(numeric);
 const text=String(rounded).replace(/(\.\d*?)0+$/,'$1').replace(/\.$/,'');
 return (rounded>0?'+':'')+text;
}

function meterGreyTvFormatInputValue(value){
 const numeric=Number(value);
 if(!Number.isFinite(numeric)) return '';
 const rounded=meterGreyTvWholeMenuValue(numeric);
 return String(rounded).replace(/(\.\d*?)0+$/,'$1').replace(/\.$/,'');
}

function meterGreyTvFormatLiveValue(entry){
 if(!entry||entry.labelV==null) return '--';
 const numeric=Number(entry.labelV);
 if(!Number.isFinite(numeric)) return '--';
 const prefix=(entry.showPlus&&numeric>0)?'+':'';
 return prefix+numeric.toFixed(1)+'%';
}

function meterGreyTvHalfRange(spec){
 if(!spec||!Array.isArray(spec.entries)||!spec.entries.length) return 5;
 const niceHalfRange=(value)=>{
  if(!(value>0)) return 1;
  const magnitude=Math.pow(10,Math.floor(Math.log10(value)));
  const normalized=value/magnitude;
  const step=normalized<=1?1:(normalized<=2?2:(normalized<=5?5:10));
  return step*magnitude;
 };
 const minHalfRange=Math.max(1e-6,spec.minHalfRange||1);
 let maxAbs=0;
 spec.entries.forEach(entry=>{ if(entry&&entry.v!=null) maxAbs=Math.max(maxAbs,Math.abs(entry.v)); });
 const headroom=(spec.scaleHeadroom!=null)?spec.scaleHeadroom:1.6;
 return Math.max(minHalfRange,niceHalfRange(maxAbs*headroom));
}

function meterGreyTvLiveEntry(spec,key){
 if(!spec||!Array.isArray(spec.entries)) return null;
 return spec.entries.find(entry=>entry&&entry.key===key)||null;
}

function meterGreyTvSelectedValues(stateOverride){
		 const state=stateOverride||meterLgGreyState||{};
		 const picture=state.picture||{};
		 const target=state.target||meterGreyTvTarget(meterCurrentPatchStep);
 if(!target||target.unsupported) return null;
 const pickValue=(value)=>{
  if(Array.isArray(value)) {
   const numeric=Number(value[target.index]);
   return Number.isFinite(numeric)?numeric:null;
  }
  const numeric=Number(value);
  return Number.isFinite(numeric)?numeric:null;
 };
	 return {
	  r:pickValue(picture.whiteBalanceRed),
	  g:pickValue(picture.whiteBalanceGreen),
	  b:pickValue(picture.whiteBalanceBlue),
		  lum:meterGreyTvSupportsLuminance(state)?pickValue(picture.adjustingLuminance):null
		 };
		}

	function meterGreyTvStateSupportsKey(state,key){
	 state=state||meterLgGreyState||{};
	 const capabilities=state.capabilities||{};
	 const supportedList=Array.isArray(state.supportedKeys)?state.supportedKeys:(Array.isArray(state.supported_picture_keys)?state.supported_picture_keys:[]);
		 if(supportedList.length) return supportedList.indexOf(key)>=0;
		 if(capabilities.supported&&typeof capabilities.supported==='object'&&Object.prototype.hasOwnProperty.call(capabilities.supported,key)) return !!capabilities.supported[key];
		 const picture=state.picture||{};
		 if(Object.prototype.hasOwnProperty.call(picture,key)) return true;
		 if(state.source==='autocal'||((state.picture||{}).ddc_1d_lut)) return false;
		 return false;
		}

	function meterGreyTvSupportsLuminance(state){
	 return meterGreyTvStateSupportsKey(state,'adjustingLuminance');
	}

function meterGreyTvBusyActive(){
	 return !!(meterLgGreyBusy||(typeof lgIsCommandBusy==='function'&&lgIsCommandBusy()));
	}

function meterGreyTvBusyHtml(){
	 if(!meterGreyTvBusyActive()) return '';
	 const escape=(typeof lgEscapeHtml==='function')?lgEscapeHtml:(value=>String(value==null?'':value));
	 const label=meterLgGreyBusy?(meterLgGreyBusyLabel||'LG white-balance write'):((typeof lgBusyLabel==='function')?lgBusyLabel():'Communicating with LG TV');
	 const startedAt=meterLgGreyBusy?meterLgGreyBusyStartedAt:window._lgCommandBusyStartedAt;
	 const elapsed=(typeof lgFormatBusyElapsed==='function')?lgFormatBusyElapsed(startedAt):'';
	 return '<div class="meter-lg-rgb-busy" id="meterLgRgbBusy">'
	  +'<span class="spinner"></span>'
	  +'<span class="meter-lg-rgb-busy-text" id="meterLgRgbBusyText">'+escape(label)+'...</span>'
	  +'<span class="meter-lg-rgb-busy-time" id="meterLgRgbBusyElapsed">'+escape(elapsed)+'</span>'
	  +'</div>';
	}

function syncMeterLgRgbBusyIndicator(){
	 const box=document.getElementById('meterLgRgbBusy');
	 const active=meterGreyTvBusyActive();
	 if(!box){
	  if(active) meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
	  return;
	 }
	 const text=document.getElementById('meterLgRgbBusyText');
	 const elapsed=document.getElementById('meterLgRgbBusyElapsed');
	 const label=meterLgGreyBusy?(meterLgGreyBusyLabel||'LG white-balance write'):((typeof lgBusyLabel==='function')?lgBusyLabel():'Communicating with LG TV');
	 const startedAt=meterLgGreyBusy?meterLgGreyBusyStartedAt:window._lgCommandBusyStartedAt;
	 if(text) text.textContent=label+'...';
	 if(elapsed) elapsed.textContent=(typeof lgFormatBusyElapsed==='function')?lgFormatBusyElapsed(startedAt):'';
	 box.style.display=active?'flex':'none';
	}

function meterGreyTvColumnHtml(channelKey,label,color,tvValue,liveEntry,halfRange,disabled,readOnly){
	 const delta=(liveEntry&&liveEntry.v!=null)?Number(liveEntry.v):null;
 const magnitude=(delta!=null&&halfRange>0)?Math.min(50,Math.abs(delta)/halfRange*50):0;
	 const fillStyle=(delta==null)
		  ? 'display:none;'
		  : 'top:'+(delta>=0?(50-magnitude):50)+'%;height:'+magnitude+'%;background:'+color+';color:'+color+';border-radius:'+(delta>=0?'4px 4px 0 0':'0 0 4px 4px')+';';
	 const inputValue=meterGreyTvFormatInputValue(tvValue);
	 if(readOnly){
		 return `
		  <div class="meter-lg-rgb-column is-readonly">
		   <div class="meter-lg-rgb-label" style="color:${color}">${label}</div>
		   <div class="meter-lg-rgb-bar">
		    <div class="meter-lg-rgb-zero"></div>
		    <div class="meter-lg-rgb-fill" style="${fillStyle}"></div>
		   </div>
		   <div class="meter-lg-rgb-live">${meterGreyTvFormatLiveValue(liveEntry)}</div>
			  </div>`;
	 }
	 return `
	  <div class="meter-lg-rgb-column">
	   <div class="meter-lg-rgb-label" style="color:${color}">${label}</div>
	   <button class="btn btn-sm btn-secondary meter-lg-rgb-button" title="${label} up ${meterGreyTvChannelStep(channelKey)}" onclick="meterGreyAdjustCurrentStepChannel('${channelKey}',1)" ${disabled?'disabled':''}>&#9650;</button>
	   <div class="meter-lg-rgb-bar">
	    <div class="meter-lg-rgb-zero"></div>
	    <div class="meter-lg-rgb-fill" style="${fillStyle}"></div>
	   </div>
	   <button class="btn btn-sm btn-secondary meter-lg-rgb-button" title="${label} down ${meterGreyTvChannelStep(channelKey)}" onclick="meterGreyAdjustCurrentStepChannel('${channelKey}',-1)" ${disabled?'disabled':''}>&#9660;</button>
	   <div class="meter-lg-rgb-tv"><input class="meter-lg-rgb-tv-input" data-channel="${channelKey}" type="text" inputmode="decimal" value="${inputValue}" title="Set ${label} value" aria-label="Set ${label} LG RGB value" onkeydown="meterGreyTvInputKeydown(event,'${channelKey}',this)" ${disabled?'disabled':''}><button class="btn btn-sm btn-secondary meter-lg-rgb-apply" title="Apply ${label} value" aria-label="Apply ${label} LG RGB value" onclick="meterGreyTvApplyInput('${channelKey}',this)" ${disabled?'disabled':''}>&#10003;</button></div>
	   <div class="meter-lg-rgb-live">Live ${meterGreyTvFormatLiveValue(liveEntry)}</div>
		  </div>`;
}

	function meterGreyTvLuminanceHtml(tvValue,disabled,readOnly){
	 if(readOnly) return '';
	 const numeric=Number(tvValue);
 const hasValue=Number.isFinite(numeric);
 const controlDisabled=disabled||!hasValue;
 const clamped=hasValue?Math.max(-50,Math.min(50,numeric)):0;
 const magnitude=Math.min(50,Math.abs(clamped));
 const fillStyle=hasValue
  ? 'left:'+(clamped>=0?50:(50-magnitude))+'%;width:'+magnitude+'%;'
  : 'display:none;';
	 const valueText=hasValue?meterGreyTvFormatSettingValue(numeric):'--';
	 const inputValue=meterGreyTvFormatInputValue(tvValue);
	 return `
  <div class="meter-lg-rgb-luma">
   <div class="meter-lg-rgb-luma-label">Brightness <span class="meter-lg-rgb-luma-value">${valueText}</span></div>
   <button class="btn btn-sm btn-secondary meter-lg-rgb-luma-button" title="Brightness down 1" aria-label="Brightness down 1" onclick="meterGreyAdjustCurrentStepChannel('lum',-1)" ${controlDisabled?'disabled':''}><span class="meter-lg-rgb-luma-arrow meter-lg-rgb-luma-arrow-left" aria-hidden="true"></span></button>
   <div class="meter-lg-rgb-luma-track" title="LG 22pt brightness ${valueText}">
    <div class="meter-lg-rgb-luma-zero"></div>
    <div class="meter-lg-rgb-luma-fill" style="${fillStyle}"></div>
   </div>
   <button class="btn btn-sm btn-secondary meter-lg-rgb-luma-button" title="Brightness up 1" aria-label="Brightness up 1" onclick="meterGreyAdjustCurrentStepChannel('lum',1)" ${controlDisabled?'disabled':''}><span class="meter-lg-rgb-luma-arrow meter-lg-rgb-luma-arrow-right" aria-hidden="true"></span></button>
   <div class="meter-lg-rgb-tv meter-lg-rgb-luma-tv"><input class="meter-lg-rgb-tv-input" data-channel="lum" type="text" inputmode="decimal" value="${inputValue}" title="Set Brightness value" aria-label="Set LG Brightness value" onkeydown="meterGreyTvInputKeydown(event,'lum',this)" ${controlDisabled?'disabled':''}><button class="btn btn-sm btn-secondary meter-lg-rgb-apply" title="Apply Brightness value" aria-label="Apply LG Brightness value" onclick="meterGreyTvApplyInput('lum',this)" ${controlDisabled?'disabled':''}>&#10003;</button></div>
  </div>`;
}

