function meterUpdateGreyTvWidgetMode(useTvControls){
 const legacy=document.getElementById('meterGreyRgbLegacyWrap');
 const tv=document.getElementById('meterGreyTvWrap');
 const wrap=document.getElementById('chartsGreyscaleFullWrap');
 const title=document.getElementById('meterGreyTvTitle');
 const meta=document.getElementById('meterGreyTvMeta');
 if(wrap) wrap.classList.toggle('lg-calibration-mode',true);
 if(legacy) legacy.style.display='none';
 if(tv) tv.style.display='flex';
 if(title) title.textContent=useTvControls?'LG RGB':'RGB';
 if(meta) meta.style.display=useTvControls?'':'none';
 meterUpdateSeriesLabels();
}

function meterGreyscaleRgbPanelReading(reading){
 if(reading&&meterReadingHasLuminance(reading)&&meterReadingIsGreyscale(reading)) return reading;
 if(Array.isArray(meterReadings)&&meterReadings.length>0){
  const current=meterCurrentPatchStep?meterFindReadingForStep(meterCurrentPatchStep):null;
  if(current&&meterReadingHasLuminance(current)&&meterReadingIsGreyscale(current)) return current;
  for(let i=meterReadings.length-1;i>=0;i--){
   const rd=meterReadings[i];
   if(rd&&meterReadingHasLuminance(rd)&&meterReadingIsGreyscale(rd)) return rd;
  }
 }
 return null;
}

function meterRenderGreyRgbReadOnly(reading){
 const host=document.getElementById('meterGreyTvWidget');
 const meta=document.getElementById('meterGreyTvMeta');
 if(!host) return;
 const panelReading=meterGreyscaleRgbPanelReading(reading);
 const liveRgb=panelReading?meterLiveRgbData(panelReading):null;
 const spec=meterRgbDeltasForLive(panelReading,liveRgb);
 const halfRange=meterGreyTvHalfRange(spec);
 const columns=[
  meterGreyTvColumnHtml('r','R','#f44',null,meterGreyTvLiveEntry(spec,'R'),halfRange,true,true),
  meterGreyTvColumnHtml('g','G','#4caf50',null,meterGreyTvLiveEntry(spec,'G'),halfRange,true,true),
  meterGreyTvColumnHtml('b','B','#42a5f5',null,meterGreyTvLiveEntry(spec,'B'),halfRange,true,true)
 ];
 host.innerHTML='<div class="meter-lg-rgb-host meter-lg-rgb-readonly-host">'+columns.join('')+'</div>';
 if(meta){
  meta.textContent='';
  meta.style.display='none';
 }
}

function meterRenderGreyTvControls(reading){
 const host=document.getElementById('meterGreyTvWidget');
 const meta=document.getElementById('meterGreyTvMeta');
 const active=document.activeElement;
 const editingInput=(active&&host&&host.contains(active)&&active.classList&&active.classList.contains('meter-lg-rgb-tv-input'))?active:null;
 const editingChannel=editingInput?String(editingInput.getAttribute('data-channel')||''):'';
 const editingValue=editingInput?String(editingInput.value||''):'';
 let editingStart=null;
 let editingEnd=null;
 if(editingInput){
  try{ editingStart=editingInput.selectionStart; editingEnd=editingInput.selectionEnd; }catch(e){}
 }
 const connected=meterGreyTvControlsActive();
 if(!host){
  meterUpdateGreyTvWidgetMode(false);
  return;
 }
 meterUpdateGreyTvWidgetMode(connected);
 if(!connected){
  meterRenderGreyRgbReadOnly(reading);
  return;
 }
 if(meterAutoCalLuminanceSetupActive){
  host.innerHTML='<div style="height:100%;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.68rem;color:var(--text2);padding:8px">LG controls paused during luminance setup.</div>';
  if(meta) meta.textContent='LG paused';
  return;
 }
 const seriesReadOnly=!!(meterSeriesRunning&&reading&&meterReadingIsGreyscale(reading));
 const renderStep=seriesReadOnly?(meterCanonicalSeriesStep(reading)||reading):meterCurrentPatchStep;
 const target=meterGreyTvTarget(renderStep,{allow_series_running:seriesReadOnly});
 if(!target){
  host.innerHTML='<div style="height:100%;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.68rem;color:var(--text2);padding:8px">No greyscale patch selected.</div>';
  if(meta) meta.textContent='LG TV';
  return;
 }
 if(target.unsupported){
  host.innerHTML='<div style="height:100%;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.68rem;color:var(--text2);padding:8px">'+target.reason+'</div>';
  const unsupportedLabel=String(target.key||'').replace(/^unsupported:/,'');
  if(meta) meta.textContent=unsupportedLabel?('LG '+unsupportedLabel+'%'):'LG TV';
  return;
 }
 const state=meterLgGreyState||{status:'idle',picture:null,message:'',needsRepair:false};
 if((state.status==='loading'||state.status==='idle')&&!state.picture&&!seriesReadOnly){
  host.innerHTML='<div style="height:100%;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.68rem;color:var(--text2);padding:8px">Loading...</div>';
  if(meta) meta.textContent='LG '+target.label;
  return;
 }
 if(state.status==='error'&&!state.picture&&!seriesReadOnly){
  host.innerHTML='<div style="height:100%;display:flex;align-items:center;justify-content:center;text-align:center;font-size:.68rem;color:#f7b0b0;padding:8px">'+(state.message||'Unable to read LG white-balance values.')+'</div>';
  if(meta) meta.textContent=state.needsRepair?'LG pairing required':'LG read failed';
  return;
 }
 const selected=seriesReadOnly?null:meterGreyTvSelectedValues(state);
	 const liveRgb=meterLiveRgbData(reading);
	 const spec=meterRgbDeltasForLive(reading,liveRgb);
	 const halfRange=meterGreyTvHalfRange(spec);
 const busy=meterGreyTvBusyActive();
 const disabled=busy||state.status!=='ok';
 const ddcReadOnly=!!(
  seriesReadOnly ||
  (target&&target.read_only) ||
  (target&&target.force_ddc) ||
  meterAutoCalRunning ||
  state.source==='autocal' ||
  (meterCurrentPatchStep&&(meterCurrentPatchStep.ddc_slot_locked||meterCurrentPatchStep.autocal_slot_locked||String(meterCurrentPatchStep.series_mode||'')==='lg-autocal-26'))
 );
		 const columns=[
		  meterGreyTvColumnHtml('r','R','#f44',selected?selected.r:null,meterGreyTvLiveEntry(spec,'R'),halfRange,disabled,ddcReadOnly),
		  meterGreyTvColumnHtml('g','G','#4caf50',selected?selected.g:null,meterGreyTvLiveEntry(spec,'G'),halfRange,disabled,ddcReadOnly),
		  meterGreyTvColumnHtml('b','B','#42a5f5',selected?selected.b:null,meterGreyTvLiveEntry(spec,'B'),halfRange,disabled,ddcReadOnly)
		 ];
			 const lumaHtml=meterGreyTvSupportsLuminance(state)?meterGreyTvLuminanceHtml(selected?selected.lum:null,disabled,ddcReadOnly):'';
			 host.innerHTML='<div class="meter-lg-rgb-host'+(busy?' has-busy':'')+'">'+meterGreyTvBusyHtml()+columns.join('')+lumaHtml+'</div>';
	 if(editingChannel&&!busy){
	  const restore=host.querySelector('.meter-lg-rgb-tv-input[data-channel="'+editingChannel+'"]');
	  if(restore){
	   restore.value=editingValue;
	   try{ restore.focus({preventScroll:true}); }catch(e){ try{ restore.focus(); }catch(e2){} }
	   if(editingStart!=null&&editingEnd!=null&&restore.setSelectionRange){
	    try{ restore.setSelectionRange(editingStart,editingEnd); }catch(e){}
	   }
	  }
	 }
	 syncMeterLgRgbBusyIndicator();
	 const pictureMode=(state.picture&&state.picture.pictureMode)?state.picture.pictureMode:'';
 if(meta){
  if(seriesReadOnly) meta.textContent='LG '+target.label+' read-only';
  else if(state.status==='loading') meta.textContent='LG '+target.label+' applying';
  else if(state.status==='error'&&state.needsRepair) meta.textContent='LG pairing required';
  else if(state.status==='error'&&state.message) meta.textContent=state.message;
  else meta.textContent=(pictureMode?('LG '+pictureMode+' - '):'LG ')+target.label;
 }
}

async function meterLgGreySyncForCurrentStep(forceRefresh){
 const target=meterGreyTvTarget(meterCurrentPatchStep);
 if(meterAutoCalLuminanceSetupActive){
  meterLgGreyLoadToken++;
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
  return;
 }
 if(!meterGreyTvControlsActive()){
  meterLgGreyLoadToken++;
  meterLgGreyState={status:'idle',picture:null,message:'',needsRepair:false};
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
  return;
 }
 if(!target||target.unsupported||target.read_only){
  meterLgGreyLoadToken++;
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
  return;
 }
	 if(meterLgGreyState&&meterLgGreyState.source==='autocal'&&!meterAutoCalRunning&&forceRefresh!==true) forceRefresh=true;
	 if(!forceRefresh&&meterLgGreyState&&meterLgGreyState.picture&&(meterLgGreyState.status==='ok'||meterLgGreyState.status==='loading'||meterLgGreyState.status==='error')){
	  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
	  return;
	 }
 const loadToken=++meterLgGreyLoadToken;
 const previousPicture=(meterLgGreyState&&meterLgGreyState.picture)?meterLgGreyState.picture:null;
 meterLgGreyState={status:'loading',picture:previousPicture,message:'',needsRepair:false};
 meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
 try{
  const response=await fetchJSON('/api/lg/picture-settings',{
   method:'POST',
   headers:{'Content-Type':'application/json'},
   body:JSON.stringify({keys:meterGreyTvPictureKeys(),picture_mode:meterLgPictureModeValue(),force_ddc_white_balance:target.force_ddc?true:undefined}),
   _quiet:true,
   _timeoutMs:7000
  });
  if(loadToken!==meterLgGreyLoadToken) return;
  if(!response||response.status!=='ok'){
   meterLgGreyState={
    status:'error',
    picture:previousPicture,
    needsRepair:!!(response&&response.needs_repair),
    message:(response&&(response.repair_hint||response.message))||'Unable to read LG white-balance values.'
   };
   meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
   return;
  }
	  meterLgGreyState={
	   status:'ok',
	   picture:response.picture_settings||{},
	   message:'',
	   needsRepair:false,
	   source:'tv',
	   supportedKeys:Array.isArray(response.supported_picture_keys)?response.supported_picture_keys:[],
	   unsupportedKeys:(response.unsupported_picture_keys&&typeof response.unsupported_picture_keys==='object')?response.unsupported_picture_keys:{},
	   capabilities:response.picture_capabilities||null
	  };
	  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
 }catch(e){
  if(loadToken!==meterLgGreyLoadToken) return;
  meterLgGreyState={status:'error',picture:previousPicture,needsRepair:false,message:'Unable to reach the LG TV control API.'};
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
 }
}

async function meterGreyAdjustCurrentStepChannel(channel,deltaStep){
		 const key=meterGreyTvNormalizeChannel(channel);
		 if(!key) return false;
		 const absoluteProvided=arguments.length>=3;
		 const absoluteValue=absoluteProvided?Number(arguments[2]):null;
		 if(absoluteProvided&&!Number.isFinite(absoluteValue)){
		  toast('Enter a valid LG '+meterGreyTvChannelLabel(key)+' value.',true);
		  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
		  return false;
		 }
	 if(meterLgGreyBusy){toast('LG white-balance write is still finishing.',true);return false;}
	 const selectedStep=meterClonePatchStep(meterCurrentPatchStep);
	 if(selectedStep) meterCurrentPatchStep=selectedStep;
		 const targetStep=meterClonePatchStep(selectedStep);
			 const target=meterGreyTvTarget(targetStep);
			 if(!meterGreyTvTargetAdjustable(target)){toast('Select an LG-adjustable greyscale point before changing white balance.',true);return false;}
		 if(target.force_ddc){toast('LG 26pt AutoCal DDC offsets are read-only. Start AutoCal to adjust them.',true);return false;}
		 if(!meterGreyTvControlsActive()){toast('Connect the LG TV before changing white balance.',true);return false;}
				 const channelLabel=meterGreyTvChannelLabel(key);
			 const commandHandle=lgBeginCommand('LG TV '+target.label+' '+channelLabel+' adjustment');
	 const finishCommand=()=>{ lgEndCommand(commandHandle); };
	 let state=meterLgGreyState||{};
	 if(state.status!=='ok'||!state.picture){
	  await meterLgGreySyncForCurrentStep(true);
	  state=meterLgGreyState||{};
	 }
		 if(state.status!=='ok'||!state.picture){
		  toast(state.message||'Unable to read LG white-balance values.',true);
		  finishCommand();
		  return false;
		 }
			 if(key==='lum'&&!meterGreyTvSupportsLuminance(state)){
			  toast('This LG TV does not expose per-point Brightness for manual white balance.',true);
			  finishCommand();
			  return false;
			 }
	 const settingKey=meterGreyTvSettingKey(key);
 const cloneArray=(value)=>Array.isArray(value)?value.map(entry=>{
  return meterGreyTvWholeMenuValue(entry);
 }):null;
	 let arrays={
	  whiteBalanceRed:cloneArray(state.picture.whiteBalanceRed),
	  whiteBalanceGreen:cloneArray(state.picture.whiteBalanceGreen),
	  whiteBalanceBlue:cloneArray(state.picture.whiteBalanceBlue),
	  adjustingLuminance:cloneArray(state.picture.adjustingLuminance)
	 };
	 let sourceArray=arrays[settingKey];
	 if(!sourceArray||target.index>=sourceArray.length){
	  await meterLgGreySyncForCurrentStep(true);
	  state=meterLgGreyState||{};
	  arrays={
	   whiteBalanceRed:cloneArray(state.picture&&state.picture.whiteBalanceRed),
	   whiteBalanceGreen:cloneArray(state.picture&&state.picture.whiteBalanceGreen),
	   whiteBalanceBlue:cloneArray(state.picture&&state.picture.whiteBalanceBlue),
	   adjustingLuminance:cloneArray(state.picture&&state.picture.adjustingLuminance)
	  };
	  sourceArray=arrays[settingKey];
	 }
		 if(!sourceArray||target.index>=sourceArray.length){
		  toast('The LG '+channelLabel+' table does not include '+target.label+'. Refresh Display or reconnect the LG TV.',true);
		  finishCommand();
		  return false;
	 }
	 const current=meterGreyTvWholeMenuValue(sourceArray[target.index]);
	 const stepSize=meterGreyTvChannelStep(key);
	 const adjustment=Number(deltaStep||0)*stepSize;
	 const nextRaw=absoluteProvided?absoluteValue:(current+adjustment);
	 const next=meterGreyTvWholeMenuValue(nextRaw);
	 if(next===current){
	  finishCommand();
	  return false;
	 }
 const previousPicture=JSON.parse(JSON.stringify(state.picture));
 sourceArray[target.index]=next;
 const nextPicture=JSON.parse(JSON.stringify(state.picture));
	 nextPicture.whiteBalanceMethod=target.method;
		 nextPicture.whiteBalanceIre=target.ire;
		 nextPicture.whiteBalanceRed=arrays.whiteBalanceRed;
		  nextPicture.whiteBalanceGreen=arrays.whiteBalanceGreen;
		  nextPicture.whiteBalanceBlue=arrays.whiteBalanceBlue;
		  if(arrays.adjustingLuminance) nextPicture.adjustingLuminance=arrays.adjustingLuminance;
	 meterLgGreyBusy=true;
	 meterLgGreyBusyStartedAt=Date.now();
	 meterLgGreyBusyLabel='LG TV '+target.label+' '+channelLabel+' adjustment';
	 meterLgGreyState={status:'loading',picture:nextPicture,message:'',needsRepair:false,source:state.source||'tv',supportedKeys:state.supportedKeys||[],unsupportedKeys:state.unsupportedKeys||{},capabilities:state.capabilities||null};
	 meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
		 const pauseContinuous=await meterPauseContinuousForPriorityWrite(targetStep);
		 if(targetStep) meterCurrentPatchStep=meterClonePatchStep(targetStep)||targetStep;
		 meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
		 try{
	  const activeCalibration=!!(window.lgStatusState&&window.lgStatusState.calibrationMode);
	  const settingsPayload={
	   whiteBalanceMethod:target.method,
	   whiteBalanceIre:target.ire,
	   whiteBalanceRed:arrays.whiteBalanceRed,
	   whiteBalanceGreen:arrays.whiteBalanceGreen,
	   whiteBalanceBlue:arrays.whiteBalanceBlue
	  };
	  if(arrays.adjustingLuminance) settingsPayload.adjustingLuminance=arrays.adjustingLuminance;
	  const response=await fetchJSON('/api/lg/picture-settings/set',{
	   method:'POST',
	   headers:{'Content-Type':'application/json'},
	   body:JSON.stringify({
	    settings:settingsPayload,
	    picture_mode:meterLgPictureModeValue(nextPicture.pictureMode||''),
   keep_calibration_mode:true,
   calibration_mode_active:activeCalibration,
   force_ddc_white_balance:target.force_ddc?true:undefined,
   skip_readback:true
	  }),
	   _quiet:true,
		   _timeoutMs:90000
		  });
  if(!response||response.status!=='ok'){
   meterLgGreyState={
    status:'error',
    picture:previousPicture,
    needsRepair:!!(response&&response.needs_repair),
    message:(response&&(response.repair_hint||response.message))||'Unable to change LG white-balance settings.'
   };
   toast((response&&(response.repair_hint||response.message))||'Unable to change LG white-balance settings.',true);
   meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
   return false;
	  }
			  const responsePicture=(response&&response.picture_settings&&typeof response.picture_settings==='object'&&!Array.isArray(response.picture_settings))?response.picture_settings:{};
			  meterLgGreyState={
			   status:'ok',
			   picture:{...nextPicture,...responsePicture},
			   message:'',
			   needsRepair:false,
			   source:'tv',
			   supportedKeys:Array.isArray(response.supported_picture_keys)?response.supported_picture_keys:(state.supportedKeys||[]),
			   unsupportedKeys:(response.unsupported_picture_keys&&typeof response.unsupported_picture_keys==='object')?response.unsupported_picture_keys:(state.unsupportedKeys||{}),
			   capabilities:response.picture_capabilities||state.capabilities||null
			  };
			  if(window.lgStatusState){
			   window.lgStatusState.calibrationMode=!!response.calibration_mode;
			   if(response.calibration_picture_mode) window.lgStatusState.calibrationPictureMode=response.calibration_picture_mode;
			  }
		  return true;
	 }catch(e){
	  meterLgGreyState={status:'error',picture:previousPicture,needsRepair:false,message:'Unable to reach the LG TV control API.'};
	  toast('Unable to reach the LG TV control API.',true);
	  return false;
		}finally{
		  if(targetStep){
		   meterCurrentPatchStep=meterClonePatchStep(targetStep)||targetStep;
		  }
		  meterLgGreyBusy=false;
		  meterLgGreyBusyStartedAt=0;
		  meterLgGreyBusyLabel='';
		  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
		  meterResumeContinuousAfterPriorityWrite(pauseContinuous);
		  finishCommand();
		  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
		 }
		}

async function meterGreyTvApplyInput(channel,button){
 const container=(button&&button.closest)?button.closest('.meter-lg-rgb-tv'):null;
 const input=container?container.querySelector('.meter-lg-rgb-tv-input[data-channel="'+channel+'"]'):null;
 const ok=await meterGreySetCurrentStepChannel(channel,input?input.value:'');
 if(ok&&input&&input.blur) input.blur();
 return ok;
}

function meterGreySetCurrentStepChannel(channel,value){
 const text=String(value==null?'':value).trim();
 if(text===''){
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
  return false;
 }
 const numeric=Number(text);
 if(!Number.isFinite(numeric)){
	  toast('Enter a valid LG '+meterGreyTvChannelLabel(channel)+' value.',true);
	  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
	  return false;
	 }
 return meterGreyAdjustCurrentStepChannel(channel,0,numeric);
}

async function meterGreyTvInputKeydown(event,channel,input){
	 if(!event||!input) return;
	 if(event.key==='Enter'){
	  event.preventDefault();
	  const ok=await meterGreySetCurrentStepChannel(channel,input.value);
	  if(ok&&input.blur) input.blur();
	 }else if(event.key==='Escape'){
  event.preventDefault();
  meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
 }else if(event.key==='-'||event.key==='Subtract'){
  event.preventDefault();
  const raw=String(input.value||'');
  const start=(input.selectionStart!=null)?input.selectionStart:raw.length;
  const end=(input.selectionEnd!=null)?input.selectionEnd:start;
  let next=raw.slice(0,start)+'-'+raw.slice(end);
  next=next.replace(/(?!^)-/g,'');
  if(next.charAt(0)!=='-') next='-'+next.replace(/^-+/,'');
  input.value=next;
  const pos=Math.max(1,Math.min(next.length,start+1));
  if(input.setSelectionRange) setTimeout(()=>{try{input.setSelectionRange(pos,pos);}catch(e){}},0);
 }else if(event.key==='+'||event.key==='Add'){
  event.preventDefault();
  input.value=String(input.value||'').replace(/^\s*-+/,'');
  if(input.setSelectionRange) setTimeout(()=>{try{input.setSelectionRange(0,0);}catch(e){}},0);
 }
}

function initMeterGreyCanvasEditing(){
}

function meterAutoCalPanelLightCandidates(){
 const state=window.lgStatusState||{};
 const model=String(state.modelName||state.model_name||'').toLowerCase();
 const display=String((typeof getEffectiveDisplayType==='function')?getEffectiveDisplayType():'').toLowerCase();
 const oled=(model.indexOf('oled')!==-1||display.indexOf('oled')!==-1||display.indexOf('qdoled')!==-1);
 return oled
  ? [{key:'backlight',label:'OLED pixel brightness'},{key:'oledLight',label:'OLED light'},{key:'oledPixelBrightness',label:'OLED pixel brightness'}]
  : [{key:'backlight',label:'Backlight'},{key:'oledPixelBrightness',label:'OLED pixel brightness'},{key:'oledLight',label:'OLED light'}];
}

function meterAutoCalPanelLightLabel(key){
 const found=meterAutoCalPanelLightCandidates().find(item=>item.key===key);
 return found?found.label:'Panel light';
}

function meterAutoCalPanelLightQueuedValuePending(){
 return meterAutoCalPanelLightQueuedValue!==null
  && meterAutoCalPanelLightQueuedValue!==undefined
  && String(meterAutoCalPanelLightQueuedValue).trim()!==''
  && Number.isFinite(Number(meterAutoCalPanelLightQueuedValue));
}

function meterAutoCalPanelLightQueuePending(){
 return meterAutoCalPanelLightQueuedValuePending()||Math.abs(Number(meterAutoCalPanelLightQueuedDelta)||0)>0.001;
}

function meterAutoCalResetPanelLightState(){
 meterAutoCalPanelLight={key:'',value:null,label:'Panel light',pending:false,candidates:[]};
 meterAutoCalPanelLightReadPending=false;
 meterAutoCalPanelLightWritePending=false;
 meterAutoCalPanelLightQueuedDelta=0;
 meterAutoCalPanelLightQueuedValue=null;
 if(meterAutoCalPanelLightCommitTimer) clearTimeout(meterAutoCalPanelLightCommitTimer);
 meterAutoCalPanelLightCommitTimer=null;
}

function meterAutoCalSyncPanelLightPending(){
 meterAutoCalPanelLight.pending=!!(meterAutoCalPanelLightReadPending||meterAutoCalPanelLightWritePending);
 return meterAutoCalPanelLight.pending;
}

function meterAutoCalPanelLightBlocksMeterRead(){
 const lgBusy=(typeof lgIsCommandBusy==='function'&&lgIsCommandBusy());
 if(meterAutoCalLuminanceSetupActive) return !!(meterAutoCalPanelLightWritePending||meterAutoCalPanelLightQueuePending());
 return !!(meterAutoCalPanelLightWritePending||meterAutoCalPanelLightQueuePending()||(lgBusy&&!meterAutoCalPanelLightReadPending));
}

function meterAutoCalPanelLightFromPicture(picture){
 const pic=(picture&&typeof picture==='object')?picture:{};
 for(const item of meterAutoCalPanelLightCandidates()){
  const value=Number(pic[item.key]);
  if(Number.isFinite(value)) return {key:item.key,label:item.label,value:value};
 }
 return null;
}

function meterAutoCalSetPanelLight(panel){
 if(!panel) return false;
 const value=Number(panel.value);
 if(!panel.key||!Number.isFinite(value)) return false;
 meterAutoCalPanelLight.key=panel.key;
 meterAutoCalPanelLight.label=panel.label||meterAutoCalPanelLightLabel(panel.key);
 meterAutoCalPanelLight.value=value;
 if(!Array.isArray(meterAutoCalPanelLight.candidates)||!meterAutoCalPanelLight.candidates.length){
  meterAutoCalPanelLight.candidates=meterAutoCalPanelLightCandidates();
 }
 return true;
}

function meterAutoCalSeedPanelLightFromDisplayControl(){
 if(meterAutoCalPanelLight.key&&meterAutoCalPanelLight.value!=null&&Number.isFinite(Number(meterAutoCalPanelLight.value))) return true;
 if(typeof lgDisplayControlCurrentValue!=='function') return false;
 for(const item of meterAutoCalPanelLightCandidates()){
  const value=Number(lgDisplayControlCurrentValue(item.key));
  if(Number.isFinite(value)) return meterAutoCalSetPanelLight({key:item.key,label:item.label,value:value});
 }
 return false;
}

function meterAutoCalUpdatePanelLightUi(){
 meterAutoCalSyncPanelLightPending();
 const panelBusy=!!(meterAutoCalPanelLight&&meterAutoCalPanelLight.pending);
 const panelWriteBusy=!!meterAutoCalPanelLightWritePending;
 const queued=meterAutoCalPanelLightQueuePending();
 const queuedValue=meterAutoCalPanelLightQueuedValuePending()?Number(meterAutoCalPanelLightQueuedValue):null;
 const lgBusy=(typeof lgIsCommandBusy==='function'&&lgIsCommandBusy());
 const unrelatedLgBusy=meterAutoCalLuminanceSetupActive?false:lgBusy;
 const busy=panelBusy||queued||unrelatedLgBusy;
 const disablePanelLight=meterAutoCalLuminanceSetupActive?false:busy;
 const label=meterAutoCalPanelLight.label||meterAutoCalPanelLightLabel(meterAutoCalPanelLight.key);
 const value=queuedValue!=null?queuedValue:meterAutoCalPanelLight.value;
 const numericValue=Number(value);
 const displayValue=(value!=null&&Number.isFinite(numericValue))?Math.round(numericValue):'--';
 document.querySelectorAll('[data-meter-autocal-panel-light]').forEach(input=>{
  const unavailable=!meterAutoCalPanelLight.key||value==null||!Number.isFinite(numericValue);
  input.disabled=disablePanelLight||unavailable;
  input.setAttribute('aria-busy',busy?'true':'false');
 });
 const labelEl=document.getElementById('meterAutoCalPanelLightLabel');
 const valueEl=document.getElementById('meterAutoCalPanelLightValue');
 const range=document.getElementById('meterAutoCalPanelLightRange');
 const input=document.getElementById('meterAutoCalPanelLightInput');
 if(labelEl) labelEl.textContent=label;
 if(valueEl) valueEl.textContent=String(displayValue)+(panelBusy?' ...':(queued?' queued':''));
 if(range&&Number.isFinite(numericValue)&&document.activeElement!==range) range.value=String(Math.round(numericValue));
 if(input&&Number.isFinite(numericValue)&&document.activeElement!==input) input.value=String(Math.round(numericValue));
 const continueBtn=document.getElementById('meterAutoCalContinueBtn');
 if(continueBtn&&meterAutoCalPhase==='luminance'){
  const y=Number(meterReadingLuminanceNits(meterAutoCalSetupReading));
  continueBtn.disabled=panelWriteBusy||queued||(unrelatedLgBusy&&!meterAutoCalPanelLightReadPending)||!(Number.isFinite(y)&&y>0);
 }
 const text=document.getElementById('meterAutoCalBrightnessText');
 if(!text) return;
 text.textContent=label+': '+displayValue+(panelBusy?' (updating...)':(queued?' (queued...)':''));
}

function meterAutoCalPanelLightOverlayMessage(message,isError){
 const text=String(message||'').trim();
 if(!text) return;
 if(meterAutoCalRunning&&meterAutoCalPhase==='luminance'){
  meterAutoCalSetOverlay(true,{phase:'luminance',current_name:isError?'Panel light not changed':'Panel light updated',message:text});
 }else{
  toast(text,!!isError);
 }
}

async function meterAutoCalLoadPanelLightValue(force,alreadyPending){
 if(meterAutoCalPanelLight.pending&&!alreadyPending) return meterAutoCalPanelLight;
 if(!force&&meterAutoCalPanelLight.key&&meterAutoCalPanelLight.value!=null) return meterAutoCalPanelLight;
 if(meterAutoCalLuminanceSetupActive&&!force&&!alreadyPending&&!meterAutoCalPanelLightWritePending) return meterAutoCalPanelLight;
 if(!alreadyPending){
  meterAutoCalPanelLightReadPending=true;
  meterAutoCalSyncPanelLightPending();
  meterAutoCalUpdatePanelLightUi();
 }
 meterAutoCalPanelLight.candidates=meterAutoCalPanelLightCandidates();
 const commandHandle=(!alreadyPending&&typeof lgBeginCommand==='function')?lgBeginCommand('LG TV panel-light read'):null;
 try{
  for(const item of meterAutoCalPanelLight.candidates){
   const r=await fetchJSON('/api/lg/picture-settings',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({keys:[item.key],picture_mode:meterLgPictureModeValue()}),
    _quiet:true,
    _timeoutMs:10000
   });
   const found=meterAutoCalPanelLightFromPicture((r&&r.status==='ok'&&r.picture_settings)?r.picture_settings:{});
   if(found){
    meterAutoCalSetPanelLight(found);
    break;
   }
 }
 }catch(e){
 }finally{
  if(commandHandle&&typeof lgEndCommand==='function') lgEndCommand(commandHandle);
  if(!alreadyPending){
   meterAutoCalPanelLightReadPending=false;
   meterAutoCalSyncPanelLightPending();
   meterAutoCalUpdatePanelLightUi();
  }
 }
 return meterAutoCalPanelLight;
}

function meterAutoCalPanelLightWriteNeedsFallback(message){
 return /undefined|doesn'?t support the key|not support|not allowed/i.test(String(message||''));
}

async function meterAutoCalWritePanelLight(key,value,omitPictureMode){
 const settings={};
 settings[key]=value;
 const payload={
  settings:settings,
  readback_keys:[key]
 };
	 if(!omitPictureMode) payload.picture_mode=meterLgPictureModeValue();
 const r=await fetchJSON('/api/lg/picture-settings/set',{
  method:'POST',
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify(payload),
  _quiet:true,
  _timeoutMs:20000
 });
 if((!r||r.status!=='ok')&&!omitPictureMode&&meterAutoCalPanelLightWriteNeedsFallback(r&&(r.repair_hint||r.message))){
  return meterAutoCalWritePanelLight(key,value,true);
 }
 if(!r||r.status!=='ok') throw new Error((r&&(r.repair_hint||r.message))||'Unable to adjust display panel light.');
 const pic=r.picture_settings||{};
 const readback=Number(pic[key]);
 if(Number.isFinite(readback)){
  if(Math.abs(readback-value)>0.1) throw new Error('LG TV reported '+readback+' after the panel-light write.');
  return readback;
 }
 return value;
}

async function meterAutoCalApplyBrightnessDelta(delta,skipMeterStop){
 const current=Number(meterAutoCalPanelLight.value);
 if(!Number.isFinite(current)) await meterAutoCalApplyPanelLightValue(null,skipMeterStop);
 const base=Number(meterAutoCalPanelLight.value);
 if(!Number.isFinite(base)) return;
 await meterAutoCalApplyPanelLightValue(base+(Number(delta)||0),skipMeterStop);
}

async function meterAutoCalApplyPanelLightValue(value,skipMeterStop){
 meterAutoCalPanelLightWritePending=true;
 meterAutoCalSyncPanelLightPending();
 meterAutoCalUpdatePanelLightUi();
 const commandHandle=(typeof lgBeginCommand==='function')?lgBeginCommand('LG TV panel-light adjustment'):null;
 try{
  if(!skipMeterStop){
   try{ await fetchJSON('/api/meter/stop',{method:'POST',_quiet:true,_timeoutMs:5000}); }catch(e){}
  }
  await meterAutoCalLoadPanelLightValue(false,true);
  const candidates=meterAutoCalPanelLight.candidates&&meterAutoCalPanelLight.candidates.length?meterAutoCalPanelLight.candidates:meterAutoCalPanelLightCandidates();
  const startIndex=Math.max(0,candidates.findIndex(item=>item.key===meterAutoCalPanelLight.key));
  for(let offset=0;offset<candidates.length;offset++){
   const item=candidates[(startIndex+offset)%candidates.length];
   let current=(item.key===meterAutoCalPanelLight.key)?Number(meterAutoCalPanelLight.value):NaN;
   if(!Number.isFinite(current)){
    meterAutoCalPanelLight.key=item.key;
    meterAutoCalPanelLight.label=item.label;
    meterAutoCalPanelLight.value=null;
    await meterAutoCalLoadPanelLightValue(true,true);
    current=Number(meterAutoCalPanelLight.value);
   }
   if(!Number.isFinite(current)) continue;
   const requested=Number.isFinite(Number(value))?Number(value):current;
   const next=Math.max(0,Math.min(100,Math.round(requested)));
   if(next===current) return;
   try{
    const readback=await meterAutoCalWritePanelLight(item.key,next);
    meterAutoCalPanelLight.key=item.key;
    meterAutoCalPanelLight.label=item.label;
    meterAutoCalPanelLight.value=readback;
    return;
	   }catch(e){
    if(offset===candidates.length-1) meterAutoCalPanelLightOverlayMessage((e&&e.message)||'Unable to adjust display panel light',true);
	   }
	  }
 meterAutoCalPanelLightOverlayMessage('This LG TV did not expose an OLED/backlight control.',true);
 }finally{
  if(commandHandle&&typeof lgEndCommand==='function') lgEndCommand(commandHandle);
  meterAutoCalPanelLightWritePending=false;
  meterAutoCalSyncPanelLightPending();
  meterAutoCalUpdatePanelLightUi();
 }
}

function meterAutoCalPanelLightClampedValue(value){
 const numeric=Number(value);
 if(!Number.isFinite(numeric)) return null;
 return Math.max(0,Math.min(100,Math.round(numeric)));
}

function meterAutoCalSyncPanelLightNumber(value){
 const next=meterAutoCalPanelLightClampedValue(value);
 const number=document.getElementById('meterAutoCalPanelLightInput');
 const label=document.getElementById('meterAutoCalPanelLightValue');
 if(number&&document.activeElement!==number&&next!=null) number.value=String(next);
 if(label&&next!=null) label.textContent=String(next);
}

function meterAutoCalSyncPanelLightRange(value){
 const next=meterAutoCalPanelLightClampedValue(value);
 const range=document.getElementById('meterAutoCalPanelLightRange');
 const label=document.getElementById('meterAutoCalPanelLightValue');
 if(range&&document.activeElement!==range&&next!=null) range.value=String(next);
 if(label&&next!=null) label.textContent=String(next);
}

function meterAutoCalSchedulePanelLightCommit(value,immediate){
 const next=meterAutoCalPanelLightClampedValue(value);
 if(next==null) return;
 meterAutoCalSyncPanelLightNumber(next);
 meterAutoCalSyncPanelLightRange(next);
 if(meterAutoCalPanelLightCommitTimer){
  clearTimeout(meterAutoCalPanelLightCommitTimer);
  meterAutoCalPanelLightCommitTimer=null;
 }
 const delay=immediate?0:(meterAutoCalLuminanceSetupActive?160:250);
 meterAutoCalPanelLightCommitTimer=setTimeout(()=>{
  meterAutoCalPanelLightCommitTimer=null;
  meterAutoCalCommitPanelLight(next);
 },delay);
}

async function meterAutoCalCommitPanelLight(value){
 const next=meterAutoCalPanelLightClampedValue(value);
 if(next==null) return;
 meterAutoCalSyncPanelLightNumber(next);
 meterAutoCalSyncPanelLightRange(next);
 if(meterAutoCalLuminanceSetupActive){
  meterAutoCalPanelLightQueuedValue=next;
  meterAutoCalPanelLightQueuedDelta=0;
  meterAutoCalUpdatePanelLightUi();
  meterAutoCalProcessQueuedPanelLight();
  return;
 }
 if(meterAutoCalPanelLightBlocksMeterRead()) return;
 await meterAutoCalApplyPanelLightValue(next,false);
}

function meterAutoCalProcessQueuedPanelLight(){
 if(!meterAutoCalPanelLightQueuePending()||meterAutoCalPanelLightWritePending||meterAutoCalPanelLightReadPending) return false;
 const hasQueuedValue=meterAutoCalPanelLightQueuedValuePending();
 const queuedValue=hasQueuedValue?Number(meterAutoCalPanelLightQueuedValue):NaN;
 const delta=Number(meterAutoCalPanelLightQueuedDelta)||0;
 meterAutoCalPanelLightQueuedValue=null;
 meterAutoCalPanelLightQueuedDelta=0;
 meterAutoCalUpdatePanelLightUi();
 const task=hasQueuedValue?meterAutoCalApplyPanelLightValue(queuedValue,true):meterAutoCalApplyBrightnessDelta(delta,true);
 task.catch(e=>{
  meterAutoCalPanelLightOverlayMessage((e&&e.message)||'Unable to adjust display panel light',true);
 }).finally(()=>{
  if(meterAutoCalPanelLightQueuePending()) meterAutoCalProcessQueuedPanelLight();
 });
 return true;
}

async function meterAutoCalAdjustBrightness(delta){
 const numericDelta=Number(delta)||0;
 if(!numericDelta) return;
 if(meterAutoCalLuminanceSetupActive){
  meterAutoCalPanelLightQueuedDelta+=numericDelta;
  meterAutoCalUpdatePanelLightUi();
  meterAutoCalProcessQueuedPanelLight();
  return;
 }
 if(meterAutoCalPanelLightBlocksMeterRead()) return;
 await meterAutoCalApplyBrightnessDelta(numericDelta,false);
}

function meterAutoCalResultRows(status){
 const source=(status&&status.magic_wand&&status.post_series_after&&Array.isArray(status.post_series_after.readings))?status.post_series_after:status;
 const readings=(source&&Array.isArray(source.readings)?source.readings:(Array.isArray(meterReadings)?meterReadings:[]))
 .filter(rd=>rd&&meterReadingHasLuminance(rd)&&meterReadingIsGreyscale(rd));
 const greyMode=meterGreyRefMode();
 const deForm='deitp';
 const gw=meterGrayWorldWeight();
 return readings.map(rd=>{
  const de=Number(meterColorDeltaE2000(rd,greyMode,deForm,gw));
  const ire=Number(rd.ire);
  return {
   reading:rd,
   ire:Number.isFinite(ire)?ire:null,
   label:rd.name||((Number.isFinite(ire)?meterFormatPercentValue(ire):'--')+'%'),
   de:Number.isFinite(de)?de:null,
   y:meterReadingLuminanceNits(rd)
  };
	 }).filter(row=>row.de!=null);
	}

function meterAutoCalSummaryRows(status){
 return meterAutoCalResultRows(status).filter(row=>{
  const ire=Number(row.ire);
  const rd=row.reading||{};
  return !(rd.autocal_white_reference||rd.autocal_reference_only||(Number.isFinite(ire)&&Math.abs(ire-100)<0.001));
 });
}

function meterAutoCalDurationMs(status){
 if(!status) return null;
 const explicit=Number(status.elapsed_ms!=null?status.elapsed_ms:status.duration_ms);
 if(Number.isFinite(explicit)&&explicit>=0) return explicit;
 let start=Number(status.started_at!=null?status.started_at:status.start_time);
 let end=Number(status.completed_at!=null?status.completed_at:status.finished_at);
 if(!Number.isFinite(end)&&String(status.status||'')==='complete') end=Date.now();
 if(Number.isFinite(start)&&Number.isFinite(end)&&end>=start) return end-start;
 const children=[status.first_greyscale,status.lut3d,status.touchup].filter(Boolean);
 const starts=children.map(item=>Number(item.started_at)).filter(value=>Number.isFinite(value));
 const ends=children.map(item=>Number(item.completed_at)).filter(value=>Number.isFinite(value));
 if(starts.length&&ends.length){
  start=Math.min(...starts);
  end=Math.max(...ends);
  if(end>=start) return end-start;
 }
 return null;
}

function meterAutoCalFormatDuration(ms){
 const totalSeconds=Math.max(0,Math.round((Number(ms)||0)/1000));
 const hours=Math.floor(totalSeconds/3600);
 const minutes=Math.floor((totalSeconds%3600)/60);
 const seconds=totalSeconds%60;
 if(hours>0) return hours+'h '+String(minutes).padStart(2,'0')+'m '+String(seconds).padStart(2,'0')+'s';
 if(minutes>0) return minutes+'m '+String(seconds).padStart(2,'0')+'s';
 return seconds+'s';
}

function meterAutoCalRenderDuration(status){
 const duration=document.getElementById('meterAutoCalResultsDuration');
 if(!duration) return;
 const ms=meterAutoCalDurationMs(status);
 duration.textContent=ms==null?'':'Total calibration time: '+meterAutoCalFormatDuration(ms);
}

function meterAutoCalRenderResults(status){
 const summary=document.getElementById('meterAutoCalResultsSummary');
 const worst=document.getElementById('meterAutoCalResultsWorst');
 meterAutoCalRenderDuration(status);
 if(!summary&&!worst) return;
 if(status&&status.full_autocal){
  const lut=status.lut3d||{};
  const uploadText=lut.upload_verified?' 3D LUT uploaded and verified.':(lut.upload_supported===false?' 3D LUT export kept; TV upload unavailable.':'');
  const rows=meterAutoCalSummaryRows(status);
  const hasPreReport=meterFullAutoCalReportSetHasData('pre');
  let greyText='';
  if(rows.length&&!status.touchup_skipped){
   const avg=rows.reduce((sum,row)=>sum+row.de,0)/rows.length;
   const sorted=[...rows].sort((a,b)=>b.de-a.de);
   greyText=' Touch-up greyscale avg ΔE '+avg.toFixed(2)+', max '+sorted[0].de.toFixed(2)+' at '+sorted[0].label+'.';
  }
  const reportNames=meterFullAutoCalReportSeries().map(item=>item.label).join(', ');
  const reportText=hasPreReport?' Click Generate Post-Cal Report to read '+reportNames+' again and build a before/after report.':' Click Generate Post-Cal Report to read '+reportNames+' and build a post-cal report.';
  const doneText=status.touchup_skipped?'Full Auto Cal complete: greyscale and 3D LUT finished.':'Full Auto Cal complete: greyscale, 3D LUT, and greyscale touch-up finished.';
  if(summary) summary.textContent=doneText+uploadText+greyText+reportText;
  const post=lut.post_check_summary||{};
  const postText=(post.mean_delta_e_2000!=null&&post.max_delta_e_2000!=null)?('3D LUT post-check mean ΔE2000 '+Number(post.mean_delta_e_2000).toFixed(2)+', max '+Number(post.max_delta_e_2000).toFixed(2)+'.'):'';
  if(worst) worst.textContent=postText||(status.message||'');
  return;
 }
 if(status&&status.autocal3d){
  const probe=status.upload_probe||{};
  const upload=status.upload||{};
  const post=status.post_check_summary||{};
  const method=String(status.method||'ramp').toUpperCase();
  const uploadText=status.upload_verified?' Uploaded and verified.':(status.upload_supported===false?' Upload unavailable; export kept.':'');
  const deText=(post.mean_delta_e_2000!=null&&post.max_delta_e_2000!=null)?(' Post-check mean ΔE2000 '+Number(post.mean_delta_e_2000).toFixed(2)+', max '+Number(post.max_delta_e_2000).toFixed(2)+'.'):'';
  if(summary) summary.textContent=method+' 3D LUT AutoCal complete.'+uploadText;
  if(worst) worst.textContent=deText||(probe.message||upload.message||status.message||'');
  return;
 }
	 const rows=meterAutoCalSummaryRows(status);
	 if(!rows.length){
  if(summary) summary.textContent='Auto Cal finished, but no completed greyscale readings were available to summarize.';
  if(worst) worst.textContent='';
  return;
 }
 const avg=rows.reduce((sum,row)=>sum+row.de,0)/rows.length;
 const sorted=[...rows].sort((a,b)=>b.de-a.de);
 const max=sorted[0];
 const target=Number((status&&status.target_delta_e)!=null?status.target_delta_e:meterAutoCalTargetDeltaValue());
 const targetText=Number.isFinite(target)?(' Target ΔE '+target.toFixed(2)+'.'):'';
 if(summary) summary.textContent=rows.length+' readings. Avg ΔE '+avg.toFixed(2)+'. Max ΔE '+max.de.toFixed(2)+' at '+max.label+'.'+targetText;
 if(worst) worst.textContent='Highest ΔE points: '+sorted.slice(0,5).map(row=>row.label+' '+row.de.toFixed(2)).join(', ');
}

let meterAutoCalCompleteAutoCloseTimer=null;
function meterAutoCalClearCompleteAutoClose(){
 if(meterAutoCalCompleteAutoCloseTimer){
  clearTimeout(meterAutoCalCompleteAutoCloseTimer);
  meterAutoCalCompleteAutoCloseTimer=null;
 }
}

function meterAutoCalCloseComplete(){
 meterAutoCalClearCompleteAutoClose();
 meterAutoCalClearSavedState();
 const holdHdrChartContext=String((meterActiveSeriesSignalMode||meterChartSignalMode()||'sdr')).toLowerCase()==='hdr10'&&
  meterActiveSeriesType==='greyscale'&&
  typeof meterUseLgAutoCal26==='function'&&meterUseLgAutoCal26(meterActiveSeriesPoints);
 if(holdHdrChartContext) meterHdrAutoCalChartContextHeld=true;
 meterAutoCalRunning=false;
 meterAutoCalPhase='';
 meterFullAutoCalRunning=false;
 meterFullAutoCalPhase='';
 meterFullAutoCalRunId=null;
 meterFullAutoCalStartedAt=null;
	 meterFullAutoCalConfig=null;
	 meterFullAutoCalResults={first:null,lut3d:null,touchup:null};
	 meterAutoCalMagicWandActive=false;
	 meterAutoCalMagicWandBaseStatus=null;
	 meterAutoCalMagicWandFullWorkflow=false;
	 meterAutoCalStandaloneMagicWandEnabled=false;
	 meterFullAutoCalClearReportData();
	 meterAutoCalSetOverlay(false,null);
	}

async function meterAutoCalCloseCompleteAction(){
 try{ await fetchJSON('/api/pattern',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:'stop'}),_quiet:true,_timeoutMs:5000}); }catch(e){}
 meterAutoCalCloseComplete();
}

function meterAutoCalScheduleCompleteAutoClose(postReportAvailable){
 meterAutoCalClearCompleteAutoClose();
}

function meterAutoCalOverlayVisible(){
 const overlay=document.getElementById('meterAutoCalOverlay');
 return !!(overlay&&overlay.getAttribute('aria-hidden')==='false');
}

function meterAutoCalRepairOverlayPointerState(){
 if(!document.body.classList.contains('meter-autocal-active')) return;
 if(!meterAutoCalOverlayVisible()) document.body.classList.remove('meter-autocal-active');
}

function meterFullAutoCalConfirmOverlayActive(){
 const fullConfirmBox=document.getElementById('meterFullAutoCalConfirmBox');
 return !!(meterFullAutoCalConfirmResolver||(meterAutoCalOverlayVisible()&&fullConfirmBox&&fullConfirmBox.style.display!=='none'));
}

function meterAutoCalSetOverlay(active,status){
 const overlayActive=!!active;
 if(overlayActive) meterAutoCalRunning=true;
 else if(!(meterAutoCalRunning&&meterAutoCalPhase==='running')) meterAutoCalRunning=false;
 const overlay=document.getElementById('meterAutoCalOverlay');
 if(overlay) overlay.setAttribute('aria-hidden',overlayActive?'false':'true');
 document.body.classList.toggle('meter-autocal-active',meterAutoCalOverlayVisible());
 const text=document.getElementById('meterAutoCalStatusText');
 const fill=document.getElementById('meterAutoCalProgressFill');
 const disclaimerBox=document.getElementById('meterAutoCalDisclaimerBox');
 const lumBox=document.getElementById('meterAutoCalLuminanceBox');
 const confirmBox=document.getElementById('meterAutoCalConfirmBox');
 const resultsBox=document.getElementById('meterAutoCalResultsBox');
 const fullConfirmBox=document.getElementById('meterFullAutoCalConfirmBox');
 const progressBox=document.getElementById('meterAutoCalProgressBox');
 const resetBtn=document.getElementById('meterAutoCalResetBtn');
 const disclaimerBtn=document.getElementById('meterAutoCalDisclaimerContinueBtn');
 const continueBtn=document.getElementById('meterAutoCalContinueBtn');
 const startBtn=document.getElementById('meterAutoCalStartConfirmBtn');
 const backBtn=document.getElementById('meterAutoCalBackBtn');
 const fullCancelBtn=document.getElementById('meterFullAutoCalCancelBtn');
 const fullContinueBtn=document.getElementById('meterFullAutoCalContinueBtn');
 const postReportBtn=document.getElementById('meterFullAutoCalPostReportBtn');
 const skipReportBtn=document.getElementById('meterFullAutoCalSkipReportBtn');
 const stopBtn=document.getElementById('meterAutoCalStopOverlayBtn');
 const fullSkipBtn=document.getElementById('meterFullAutoCalSkipBtn');
 const phase=(status&&status.phase)||meterAutoCalPhase||'';
 const showDisclaimer=phase==='disclaimer';
 const showLuminance=phase==='luminance';
 const showOptions=phase==='options';
 const showConfirm=phase==='confirm';
 const showComplete=phase==='complete'||(status&&status.status==='complete');
 if(disclaimerBox) disclaimerBox.style.display=showDisclaimer?'':'none';
 if(lumBox) lumBox.style.display=showLuminance?'':'none';
 if(confirmBox) confirmBox.style.display=(showConfirm||showOptions)?'':'none';
 if(resultsBox) resultsBox.style.display=showComplete?'':'none';
 if(fullConfirmBox) fullConfirmBox.style.display='none';
 if(progressBox) progressBox.style.display=(showConfirm||showOptions||showDisclaimer||showComplete)?'none':'';
 if(resetBtn){
  resetBtn.style.display=(showDisclaimer&&!meterAutoCalPreflightResetDone)?'':'none';
  resetBtn.disabled=!!meterAutoCalResetInProgress;
  resetBtn.textContent=meterAutoCalResetInProgress?'Resetting...':'Reset';
 }
 if(disclaimerBtn) disclaimerBtn.style.display=(showDisclaimer&&meterAutoCalPreflightResetDone)?'':'none';
 if(continueBtn) continueBtn.style.display=showLuminance?'':'none';
 if(startBtn){
  startBtn.style.display=(showConfirm||showOptions)?'':'none';
  startBtn.textContent=showOptions?'\u25B6 Continue':'\u25B6 Start';
 }
 if(backBtn) backBtn.style.display=(showConfirm&&meterAutoCalRequiresLuminanceSetup())?'':'none';
 if(fullCancelBtn) fullCancelBtn.style.display='none';
 if(fullSkipBtn) fullSkipBtn.style.display='none';
 if(fullContinueBtn) fullContinueBtn.style.display='none';
 const postReportAvailable=!!(showComplete&&status&&status.full_autocal);
 if(postReportBtn) postReportBtn.style.display=postReportAvailable?'':'none';
 if(skipReportBtn) skipReportBtn.style.display=showComplete?'':'none';
 if(skipReportBtn&&showComplete) skipReportBtn.textContent='Close';
 if(postReportBtn&&postReportAvailable) postReportBtn.textContent='\uD83D\uDCC4 Generate Post-Cal Report';
 if(stopBtn) stopBtn.style.display=showComplete?'none':'';
 if(showComplete){
  meterAutoCalRenderResults(status||{status:'complete'});
  if(status&&status.full_autocal) meterAutoCalClearCompleteAutoClose();
  else meterAutoCalScheduleCompleteAutoClose(postReportAvailable);
 }else{
  meterAutoCalClearCompleteAutoClose();
 }
 if(status){
  const name=status.current_name||status.message||'LG Auto Cal';
  const msg=status.message&&status.message!==name?(' - '+status.message):'';
  const de=(status.current_delta_e!=null&&Number.isFinite(Number(status.current_delta_e)))?(' | \u0394E '+Number(status.current_delta_e).toFixed(2)):'';
  if(text) text.textContent=name+msg+de;
  const total=Number(status.total_steps)||0;
  const current=Math.max(0,Number(status.current_step)||0);
  if(fill) fill.style.width=(total>0?Math.min(100,Math.max(0,current/total*100)):0)+'%';
 }else{
  if(text) text.textContent='Preparing...';
  if(fill) fill.style.width='0%';
 }
 meterUpdateReadButtons();
}

function meterAutoCalSetupOverlayActive(){
 if(meterFullAutoCalConfirmOverlayActive()) return true;
 const phase=String(meterAutoCalPhase||'');
 if(phase==='running'||phase==='complete'||phase==='error') return false;
 return !!(meterAutoCalPendingConfig||meterAutoCalResetInProgress||meterAutoCalLuminanceSetupActive||phase==='options'||phase==='disclaimer'||phase==='preflight'||phase==='luminance'||phase==='confirm');
}

function meterAutoCalRequiresLuminanceSetup(){
 return meterLgAutoCalRequestedSignalMode()!=='hdr10';
}

function meterAutoCalTargetDeltaValue(){
 const input=document.getElementById('meterAutoCalTarget');
 let target=Number(input&&input.value);
 if(!Number.isFinite(target)||target<=0) target=0.5;
 target=Math.max(0.1,Math.min(10,target));
 if(input) input.value=String(Math.round(target*10)/10);
 return target;
}

function meterAutoCalTargetYValue(){
 const setup=meterAutoCalSetupYValue();
 return Math.max(10,Math.min(10000,setup));
}

function meterAutoCalSetupYValue(){
 let y=Number(meterAutoCalCapturedTargetY);
 if(!Number.isFinite(y)||y<=0) y=Number(meterReadingLuminanceNits(meterAutoCalSetupReading));
 if(!Number.isFinite(y)||y<=0) y=100;
 return Math.max(10,Math.min(10000,y));
}

function meterAutoCalHeadroomTargetYValue(setupY){
 const setup=Number.isFinite(Number(setupY))&&Number(setupY)>0?Number(setupY):meterAutoCalSetupYValue();
 const peakRatio=meterAutoCalHeadroomTargetRatio();
 return Math.max(10,Math.min(10000,setup*peakRatio));
}

function meterAutoCalHeadroomTargetRatio(){
 if(meterLgAutoCalRequestedSignalMode()==='hdr10') return 1;
 const steps=(Array.isArray(meterSeriesSteps)&&meterSeriesSteps.length)?meterSeriesSteps:meterBuildStepsJS('greyscale',26);
 const peak=(steps||[]).find(step=>step&&Number(step.ire)>=108.5);
 const ire=peak?Number(peak.ire):109;
 const code=peak?meterGreyChartTargetCode(peak):1023;
 const ratio=meterGreyTargetLuminance(ire,1,0,code);
 return (Number.isFinite(ratio)&&ratio>0)?ratio:1;
}

function meterAutoCalRoundLuminanceScale(value){
 const y=Number(value);
 if(!Number.isFinite(y)||y<=0) return 100;
 const padded=y*1.1;
 const step=padded>1000?500:(padded>250?100:50);
 return Math.max(100,Math.ceil(padded/step)*step);
}

function meterAutoCalLuminanceScaleFor(y){
 const value=Number(y);
 if(!Number.isFinite(value)||value<=0) return meterAutoCalLuminanceScaleMax||100;
 if(!Number.isFinite(Number(meterAutoCalLuminanceScaleMax))||meterAutoCalLuminanceScaleMax<=0||value>meterAutoCalLuminanceScaleMax){
  meterAutoCalLuminanceScaleMax=meterAutoCalRoundLuminanceScale(value);
 }
 return meterAutoCalLuminanceScaleMax||100;
}

function meterAutoCalLoadTargetYDefault(){
}

function meterAutoCalSleep(ms){
 return new Promise(resolve=>setTimeout(resolve,Math.max(0,Number(ms)||0)));
}

async function meterAutoCalWaitForPanelLightIdle(timeoutMs){
 const start=Date.now();
 const timeout=Math.max(1000,Number(timeoutMs)||30000);
 while(Date.now()-start<timeout){
  const busy=meterAutoCalPanelLightBlocksMeterRead();
  if(!busy) return true;
  meterAutoCalUpdatePanelLightUi();
  await meterAutoCalSleep(100);
 }
 return false;
}

function meterAutoCalContinueFromLuminanceSetup(){
 const y=Number(meterReadingLuminanceNits(meterAutoCalSetupReading));
 if(!(Number.isFinite(y)&&y>0)){
  toast('Wait for the first 100% luminance read.',true);
  return;
 }
 if(Number.isFinite(y)&&y>0) meterAutoCalCapturedTargetY=y;
 meterAutoCalLuminanceContinue=true;
 const btn=document.getElementById('meterAutoCalContinueBtn');
 if(btn) btn.disabled=true;
}

async function meterAutoCalBackToLuminance(){
 if(!meterAutoCalPendingConfig||!meterAutoCalPendingConfig.whiteStep) return;
 if(!meterAutoCalRequiresLuminanceSetup()){
  meterAutoCalShowConfirm();
  return;
 }
 meterAutoCalPhase='luminance';
 meterAutoCalLuminanceContinue=false;
 const btn=document.getElementById('meterAutoCalContinueBtn');
 if(btn) btn.disabled=false;
 meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:'Watch the live 100% white reading, then Continue.'});
 const setupReading=await meterAutoCalLuminanceSetupLoop(meterAutoCalPendingConfig.whiteStep);
 if(meterAutoCalStopRequested) return;
 if(setupReading) meterAutoCalSetupReading=setupReading;
 meterAutoCalShowConfirm();
}

function meterAutoCalSetGreyscaleOptionControls(){
	 const optionsBox=document.getElementById('meterAutoCalGreyscaleOptionsBox');
	 const magicChoice=document.getElementById('meterAutoCalMagicWandEnabled');
	 const choicesCaptured=!!(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.greyscaleOptionsCaptured);
	 if(optionsBox) optionsBox.style.display=(meterAutoCalPendingConfig&&(meterAutoCalPendingConfig.fullWorkflow||(choicesCaptured&&meterAutoCalPhase!=='options')))?'none':'';
	 if(magicChoice) magicChoice.checked=meterAutoCalPendingConfig&&Object.prototype.hasOwnProperty.call(meterAutoCalPendingConfig,'magicWandEnabled')?meterAutoCalPendingConfig.magicWandEnabled!==false:false;
}

function meterAutoCalShowPreflightOptions(){
 if(!meterAutoCalPendingConfig||meterAutoCalPendingConfig.fullWorkflow) return;
 meterAutoCalPhase='options';
 meterAutoCalLuminanceSetupActive=false;
