 if(description) description.textContent=needsLuminanceSetup
	  ? 'Choose whether the experimental Magic Wand feature should run after the greyscale Auto Cal. This choice will be carried through reset, luminance setup, and the final Auto Cal payload.'
	  : 'Choose whether the experimental Magic Wand feature should run after the greyscale Auto Cal. HDR uses the calibrated 100% point as its peak reference, so no SDR luminance setup is required.';
 if(targetRow) targetRow.style.display='none';
 if(summary) summary.textContent=needsLuminanceSetup?'The picture mode reset and 100% luminance setup will follow.':'The picture mode reset will follow.';
 meterAutoCalSetOverlay(true,{phase:'options',current_name:'Greyscale Auto Cal options',message:'Choose post-cal cleanup before reset.'});
}

function meterAutoCalAcceptPreflightOptions(){
	 if(!meterAutoCalPendingConfig||meterAutoCalPendingConfig.fullWorkflow){toast('Auto Cal setup is not ready',true);return;}
	 meterAutoCalPendingConfig.postCommitPolishEnabled=false;
	 meterAutoCalPendingConfig.magicWandEnabled=meterAutoCalMagicWandChoiceValue();
	 meterAutoCalPendingConfig.greyscaleOptionsCaptured=true;
 meterAutoCalPhase='disclaimer';
 meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:'Before LG Auto Cal',message:meterAutoCalPreflightResetPrompt()});
}

function meterAutoCalShowConfirm(){
 meterAutoCalPhase='confirm';
 meterAutoCalLuminanceSetupActive=false;
 const summary=document.getElementById('meterAutoCalConfirmSummary');
 const description=document.getElementById('meterAutoCalConfirmDescription');
 const targetRow=document.getElementById('meterAutoCalTargetRow');
 const setupY=meterAutoCalSetupYValue();
 const targetY=meterAutoCalTargetYValue();
 const headroomY=meterAutoCalHeadroomTargetYValue(setupY);
 const hdrWorkflow=meterLgAutoCalRequestedSignalMode()==='hdr10';
 meterAutoCalSetGreyscaleOptionControls();
 if(description) description.textContent=hdrWorkflow
  ? 'The active LG picture mode has been reset. HDR Auto Cal will calibrate 100% first and use that measured peak as the ST 2084 reference, then calibrate the LG greyscale DDC slots from top to bottom without the SDR super-white spine. 0% is read for black level/charts. The closest result is kept when the target cannot be reached.'
  : 'The active LG picture mode has been reset. Auto Cal will use the current 100% white luminance and selected gamma target, derive the 109% headroom reference, then calibrate the LG 26-point greyscale sequence top/body first and shadows low-to-high. 100% is used for setup and then checked internally as the legal-white anchor; 0% is read for black level/charts. The closest result is kept when the target cannot be reached.';
 if(targetRow) targetRow.style.display='flex';
 if(summary){
  const levels=meterAutoCalLevelPreflight;
  const levelText=(levels&&!levels.skipped)?(' Levels: brightness '+(levels.brightness!=null?levels.brightness:'--')+', contrast '+(levels.contrast!=null?levels.contrast:'--')+'.'):'';
  summary.textContent=hdrWorkflow
   ? 'HDR uses 100% panel light. The first calibrated 100% read sets the ST 2084 peak reference.'+levelText
   : 'Setup 100%: '+setupY.toFixed(2)+' cd/m\u00B2. Cal target 100%: '+targetY.toFixed(2)+' cd/m\u00B2. 109% target: '+headroomY.toFixed(2)+' cd/m\u00B2. Panel light: '+((meterAutoCalPanelLight.label||'Panel light')+' '+(meterAutoCalPanelLight.value!=null?Math.round(Number(meterAutoCalPanelLight.value)):'--'))+'.'+levelText;
 }
 meterAutoCalSetOverlay(true,{phase:'confirm',current_name:'Ready to start LG Auto Cal',message:'Review the workflow and choose the target error.'});
}

function meterAutoCalWhiteStep(){
 const existing=(meterSeriesSteps||[]).find(step=>meterSeriesStepIsGreyscale(step)&&Math.abs((Number(step.ire)||0)-100)<0.001);
 if(existing) return existing;
 if(meterUseLgAutoCal26(meterActiveSeriesPoints)){
  if(meterLgAutoCalRequestedSignalMode()==='hdr10'){
   const code=meterCodeFromSignalPercentWithOptions(100,null);
   return {
    ire:100,
    stimulus:100,
    signal_r_pct:100,
    signal_g_pct:100,
    signal_b_pct:100,
    r:code,
    g:code,
    b:code,
    input_max:meterPatchBitDepth()===10?1023:255,
    name:'100%',
    series_type:'greyscale',
    autocal_white_reference:true,
    autocal_reference_only:true,
    autocal_read_only:true,
    autocal_target_label:'100% HDR white'
   };
  }
  const code=meterLgSdrLegalHeadroomCodeFromPercent(100);
  return {
   ire:100,
   stimulus:100,
   signal_r_pct:100,
   signal_g_pct:100,
   signal_b_pct:100,
	   r:code,
	   g:code,
	   b:code,
	   input_max:1023,
   name:'100%',
   series_type:'greyscale',
   autocal_white_reference:true,
   autocal_reference_only:true,
   autocal_read_only:true,
   autocal_legal_white_anchor:true,
   ddc_target_ire:99,
   autocal_order_ire:98.95,
   autocal_target_label:'100% legal white'
  };
 }
 return null;
}

function meterAutoCalBuildBackendSteps(whiteStep,seriesSteps){
 const steps=Array.isArray(seriesSteps)?seriesSteps:[];
 const body=steps.filter(step=>{
  if(!step||step===whiteStep) return false;
  if(step.autocal_white_reference||step.autocal_reference_only) return false;
  return true;
 });
 return whiteStep?[whiteStep,...body]:body;
}

function meterAutoCalClipCodes(){
 const limited=String(getVal('rgb_quant_range')||'1')==='1';
 return limited
  ? {range:'1',black:[16,17,18],white:[233,234,235]}
  : {range:'0',black:[0,1,2],white:[253,254,255]};
}

function meterAutoCalIreForCode(code,range){
 const numeric=Number(code);
 if(String(range)==='1') return Math.max(0,Math.min(100,((numeric-16)/219)*100));
 return Math.max(0,Math.min(100,(numeric/255)*100));
}

function meterAutoCalReadingY(reading){
 const y=Number(reading&&(reading.luminance!=null?reading.luminance:reading.Y));
 return Number.isFinite(y)?y:0;
}

function meterAutoCalLevelThreshold(a,b,kind){
 const hi=Math.max(Math.abs(Number(a)||0),Math.abs(Number(b)||0));
 return kind==='black'?Math.max(0.0005,hi*0.08):Math.max(0.05,hi*0.0015);
}

function meterAutoCalLevelSeparated(a,b,kind){
 return (Number(b)-Number(a))>meterAutoCalLevelThreshold(a,b,kind);
}

function meterAutoCalReadTransient(message){
 return /communication|connection|init|start|fifo|timeout|unavailable|session|stale/i.test(String(message||''));
}

async function meterAutoCalReadCodePatch(code,label,range,dtype){
 const numeric=Number(code);
 const ire=meterAutoCalIreForCode(numeric,range);
 const payload=meterMeasurementSignalContext({
  display_type:dtype,
  refresh_rate:getMeterRefreshRate()||undefined,
  delay_ms:Math.max(meterDelayMs(),1200),
  patch_r:numeric,
  patch_g:numeric,
  patch_b:numeric,
  ire:ire,
  stimulus:ire,
  name:label,
  patch_size:getMeterPatchSize(),
  target_gamut:(document.getElementById('meterTargetGamut')||{}).value||'auto',
  target_gamma:meterAutoCalTargetGammaValue(),
  signal_range:range,
  transport_signal_range:range
 });
 payload.require_device_ready=meterSelectedMeasurementRequiresReady();
 const referenceBlack=(numeric<=0 || (String(range)==='1'&&numeric<=16));
 let lastMessage='';
 for(let attempt=0;attempt<3;attempt++){
  if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
  let shouldRetry=false;
  try{
   const result=await meterStartSingleReadWithTimeout(payload,referenceBlack?45000:180000,()=>meterAutoCalStopRequested);
   if(result&&result.status==='ok'&&Array.isArray(result.readings)&&result.readings[0]) return result;
   if(result&&result.status==='cancelled') return result;
   lastMessage=(result&&result.message)||'Unable to read '+label;
   shouldRetry=meterAutoCalReadTransient(lastMessage);
  }catch(e){
   lastMessage=(e&&e.message)?e.message:'Unable to read '+label;
   shouldRetry=meterAutoCalReadTransient(lastMessage);
  }
  try{ await fetchJSON('/api/meter/session/stop',{method:'POST',_quiet:true,_timeoutMs:5000}); }catch(e){}
  if(referenceBlack&&/timeout|timed out/i.test(lastMessage)) break;
  if(!shouldRetry) break;
  if(attempt<2){
   meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Retrying meter read',message:label+' - '+lastMessage});
   await new Promise(resolve=>setTimeout(resolve,800+(attempt*500)));
  }
 }
 if(referenceBlack){
  return {status:'ok',readings:[{luminance:0,Y:0,ire:ire,name:label,r_code:numeric,g_code:numeric,b_code:numeric,synthetic_black:true}]};
 }
 return {status:'error',message:lastMessage||('Unable to read '+label)};
}

async function meterAutoCalMeasureClipSet(kind,codes,dtype,range){
 const readings={};
 for(const code of codes){
  if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
  meterAutoCalSetOverlay(true,{phase:'preflight',current_name:kind==='black'?'Tuning Black Brightness':'Tuning White Contrast',message:'Reading code '+code});
  const result=await meterAutoCalReadCodePatch(code,(kind==='black'?'Black ':'White ')+code,range,dtype);
  if(!result||result.status!=='ok'||!Array.isArray(result.readings)||!result.readings[0]) throw new Error((result&&result.message)||'Unable to read '+code);
  readings[String(code)]=result.readings[0];
 }
 return readings;
}

function meterAutoCalBlackClipOk(readings,codes){
 return meterAutoCalBlackClipState(readings,codes).ok;
}

function meterAutoCalBlackClipState(readings,codes){
 const y0=meterAutoCalReadingY(readings[String(codes[0])]);
 const y1=meterAutoCalReadingY(readings[String(codes[1])]);
 const y2=meterAutoCalReadingY(readings[String(codes[2])]);
 const floorLimit=Math.max(0.001,Math.max(y1,y2)*0.25);
 const floorOk=y0<=floorLimit;
 const blackTo17Separated=meterAutoCalLevelSeparated(y0,y1,'black');
 const blackTo18Separated=meterAutoCalLevelSeparated(y0,y2,'black');
 const nearBlackSeparated=meterAutoCalLevelSeparated(y1,y2,'black');
 const firstVisible=blackTo18Separated||nearBlackSeparated;
 return {ok:floorOk&&firstVisible,floorOk:floorOk,floorRaised:!floorOk,separated:firstVisible,blackTo17Separated:blackTo17Separated,blackTo18Separated:blackTo18Separated,nearBlackSeparated:nearBlackSeparated,y0:y0,y1:y1,y2:y2};
}

function meterAutoCalBlackFloorOk(readings,codes){
 return meterAutoCalBlackClipState(readings,codes).floorOk;
}

function meterAutoCalWhiteClipOk(readings,codes){
 return meterAutoCalWhiteClipState(readings,codes).ok;
}

function meterAutoCalWhiteClipState(readings,codes){
 const values=codes.map(code=>meterAutoCalReadingY(readings[String(code)]));
 const lowerIndex=Math.max(0,values.length-3);
 const midIndex=Math.max(0,values.length-2);
 const topIndex=Math.max(0,values.length-1);
 const lowerSeparated=values.length>=3?meterAutoCalLevelSeparated(values[lowerIndex],values[midIndex],'white'):true;
 const topSeparated=meterAutoCalLevelSeparated(values[midIndex],values[topIndex],'white');
 const targetReached=lowerSeparated&&topSeparated;
 return {ok:targetReached,clipped:!targetReached,tooHigh:!targetReached,lowerSeparated:lowerSeparated,topSeparated:topSeparated,y0:values[0],y1:values[values.length-1],values:values};
}

async function meterAutoCalLoadClipControls(){
 const r=await fetchJSON('/api/lg/picture-settings',{
  method:'POST',
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify({keys:['pictureMode','brightness','contrast'],picture_mode:meterLgPictureModeValue()}),
  _quiet:true,
  _timeoutMs:10000
 });
 const picture=(r&&r.status==='ok'&&r.picture_settings)?r.picture_settings:{};
 return {
  pictureMode:picture.pictureMode||meterLgPictureModeValue(),
  brightness:Number.isFinite(Number(picture.brightness))?Number(picture.brightness):null,
  contrast:Number.isFinite(Number(picture.contrast))?Number(picture.contrast):null
 };
}

async function meterAutoCalWriteClipControl(key,value,pictureMode){
 if(key!=='brightness'&&key!=='contrast') throw new Error('Unsupported clipping control: '+key);
 if(!Number.isFinite(Number(value))) throw new Error('Invalid '+key+' value.');
 const settings={};
 settings[key]=Math.max(0,Math.min(100,Math.round(Number(value))));
 const r=await fetchJSON('/api/lg/picture-settings/set',{
  method:'POST',
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify({settings:settings,picture_mode:pictureMode||'',readback_keys:[key]}),
  _quiet:true,
  _timeoutMs:20000
 });
 if(!r||r.status!=='ok') throw new Error((r&&(r.repair_hint||r.message))||'Unable to adjust '+key);
 const pic=r.picture_settings||{};
 const readback=Number(pic[key]);
 return Number.isFinite(readback)?readback:settings[key];
}

async function meterAutoCalRunLevelPreflight(){
 const codes=meterAutoCalClipCodes();
 const dtype=meterAutoCalPendingConfig&&meterAutoCalPendingConfig.dtype?meterAutoCalPendingConfig.dtype:getEffectiveDisplayType();
 const controls=await meterAutoCalLoadClipControls();
 let brightness=controls.brightness;
 let contrast=controls.contrast;
 let blackReadings=null;
 let whiteReadings=null;
 let lastGoodBrightness=null;
 let lastGoodBlackReadings=null;
 let lastFloorSafeBrightness=null;
 let lastFloorSafeBlackReadings=null;
 for(let attempt=0;attempt<12;attempt++){
  blackReadings=await meterAutoCalMeasureClipSet('black',codes.black,dtype,codes.range);
  const blackState=meterAutoCalBlackClipState(blackReadings,codes.black);
  if(blackState.floorOk) {
   lastFloorSafeBrightness=brightness;
   lastFloorSafeBlackReadings=blackReadings;
  }
  if(blackState.ok) {
   lastGoodBrightness=brightness;
   lastGoodBlackReadings=blackReadings;
   break;
  }
  if(!Number.isFinite(Number(brightness))) throw new Error('Black clipping failed and LG brightness is not writable.');
  if(blackState.floorRaised&&lastFloorSafeBrightness!=null){
   brightness=await meterAutoCalWriteClipControl('brightness',lastFloorSafeBrightness,controls.pictureMode);
   blackReadings=lastFloorSafeBlackReadings||blackReadings;
   meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning Black Brightness',message:'Preserving black floor at brightness '+brightness});
   break;
  }
  const delta=blackState.floorRaised?-1:1;
  brightness=await meterAutoCalWriteClipControl('brightness',Number(brightness)+delta,controls.pictureMode);
  meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning Black Brightness',message:'Brightness '+brightness});
 }
 const finalBlackState=meterAutoCalBlackClipState(blackReadings,codes.black);
 if(!finalBlackState.floorOk) throw new Error('Black floor is still raised after brightness adjustment.');
 const optimizeBlackSeparation=finalBlackState.ok;
 if(Number.isFinite(Number(brightness))&&optimizeBlackSeparation){
  for(let attempt=0;attempt<6;attempt++){
   if(Number(brightness)<=0) break;
   const testBrightness=await meterAutoCalWriteClipControl('brightness',Number(brightness)-1,controls.pictureMode);
   meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning Black Brightness',message:'Brightness '+testBrightness});
   const testReadings=await meterAutoCalMeasureClipSet('black',codes.black,dtype,codes.range);
   if(meterAutoCalBlackClipOk(testReadings,codes.black)){
    brightness=testBrightness;
    blackReadings=testReadings;
    lastGoodBrightness=brightness;
    lastGoodBlackReadings=blackReadings;
    continue;
   }
   if(lastGoodBrightness!=null) {
    brightness=await meterAutoCalWriteClipControl('brightness',lastGoodBrightness,controls.pictureMode);
    blackReadings=lastGoodBlackReadings||blackReadings;
   }
   break;
  }
 }
 let lastGoodContrast=null;
 let lastGoodWhiteReadings=null;
 for(let attempt=0;attempt<36;attempt++){
  whiteReadings=await meterAutoCalMeasureClipSet('white',codes.white,dtype,codes.range);
  const whiteState=meterAutoCalWhiteClipState(whiteReadings,codes.white);
  if(whiteState.ok) {
   lastGoodContrast=contrast;
   lastGoodWhiteReadings=whiteReadings;
   break;
  }
  if(!Number.isFinite(Number(contrast))) throw new Error('White contrast tuning failed and LG contrast is not writable.');
  if(Number(contrast)<=0) break;
  contrast=await meterAutoCalWriteClipControl('contrast',Number(contrast)-1,controls.pictureMode);
  meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning White Contrast',message:'Contrast '+contrast});
 }
 if(!meterAutoCalWhiteClipOk(whiteReadings,codes.white)) throw new Error('White contrast tuning still failed after contrast adjustment.');
 if(Number.isFinite(Number(contrast))){
  for(let attempt=0;attempt<36;attempt++){
   if(Number(contrast)>=100) break;
   const testContrast=await meterAutoCalWriteClipControl('contrast',Number(contrast)+1,controls.pictureMode);
   meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning White Contrast',message:'Contrast '+testContrast});
   const testReadings=await meterAutoCalMeasureClipSet('white',codes.white,dtype,codes.range);
   if(meterAutoCalWhiteClipOk(testReadings,codes.white)){
    contrast=testContrast;
    whiteReadings=testReadings;
    lastGoodContrast=contrast;
    lastGoodWhiteReadings=whiteReadings;
    continue;
   }
   if(lastGoodContrast!=null){
    contrast=await meterAutoCalWriteClipControl('contrast',lastGoodContrast,controls.pictureMode);
    whiteReadings=lastGoodWhiteReadings||whiteReadings;
    meterAutoCalSetOverlay(true,{phase:'preflight',current_name:'Tuning White Contrast',message:'Backed off contrast to '+contrast});
   }
   break;
  }
 }
 return {brightness:brightness,contrast:contrast,range:codes.range,black_codes:codes.black,white_codes:codes.white,black_readings:blackReadings,white_readings:whiteReadings};
}

async function meterAutoCalResetDdc(){
 const hdrWorkflow=meterLgAutoCalRequestedSignalMode()==='hdr10';
 const ddcSlots=hdrWorkflow?METER_LG_GREY_HDR_AUTOCAL_SLOTS:METER_LG_GREY_AUTOCAL_26_SLOTS;
 const zero=ddcSlots.map(()=>0);
	 const pictureMode=meterLgPictureModeValue((meterLgGreyState&&meterLgGreyState.picture&&meterLgGreyState.picture.pictureMode)||'');
 meterAutoCalResetNotice='';
 let pictureModeReset=null;
 let pictureResetMessage='Unable to reset LG picture mode.';
 // For HDR picture modes the basic /api/lg/picture-settings/reset path
 // runs SDR-style resetSystemSettings commands (brightness, contrast,
 // whiteBalance, ...) that webOS rejects outright on HDR picture modes
 // (per the helper's own hdr_picture_mode detection in pgenerator-lg,
 // see lg_picture_reset_workflow) and then falls through to the HDR
 // reference reset. That wastes 1-3s of helper round-trips per attempt
 // and races the first 0% meter read. The HDR reference reset alone
 // covers everything needed for HDR -- if the series is hdr10 we
 // do not bother with the SDR-style reset at all.
 if(!hdrWorkflow){
 for(let attempt=1;attempt<=3;attempt++){
  meterAutoCalSetOverlay(true,{current_name:'Performing LG picture mode reset...',message:'Resetting the active picture mode before Auto Cal'+(attempt>1?' (retry '+attempt+'/3)':'')});
  try{
   pictureModeReset=await fetchJSON('/api/lg/picture-settings/reset',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
     picture_mode:pictureMode,
     signal_mode:'sdr',
     require_white_balance_reset:true,
     helper_timeout:170
    }),
    _quiet:true,
    _timeoutMs:180000
   });
  }catch(e){
   pictureModeReset=null;
   pictureResetMessage=(e&&e.message)?e.message:pictureResetMessage;
  }
  if(pictureModeReset&&pictureModeReset.status==='ok') break;
  pictureResetMessage=(pictureModeReset&&(pictureModeReset.repair_hint||pictureModeReset.message))||pictureResetMessage;
  if(attempt<3) await new Promise(resolve=>setTimeout(resolve,1200*attempt));
 }
 if(!pictureModeReset||pictureModeReset.status!=='ok'){
  throw new Error(pictureResetMessage||'Unable to reset LG picture mode.');
 }
 }
 let hdrCalmanReset=null;
 if(hdrWorkflow){
  hdrCalmanReset=await meterAutoCalHdrCalmanReset(pictureMode);
 }
 let response=null;
 let lastMessage='Unable to clear LG picture mode calibration state.';
 // For HDR the /api/lg/picture-settings/set 1D DPG reset is a duplicate
 // of what the HDR reference reset above already did (lg_hdr_calman_reset_
 // workflow sends 1D_DPG_DATA inside the same CAL_START/END session as
 // the 3D LUT and 3x3 matrix reset). Re-running it on HDR would issue
 // a duplicate CAL_START/1D_DPG_DATA upload/CAL_END cycle and race the
 // first 0% meter read. Build the response synthetically from the
 // HDR reference reset's confirmation flags instead.
 if(hdrWorkflow){
  response={
   status:'ok',
   picture_settings:(hdrCalmanReset&&hdrCalmanReset.picture_settings)||{},
   ddc_baseline_reset:true,
   ddc_1d_lut:true,
   ddc_reset_verified:true
  };
 } else {
 for(let attempt=1;attempt<=3;attempt++){
  meterAutoCalSetOverlay(true,{current_name:'Performing LG picture mode reset...',message:'Clearing DDC calibration data before Auto Cal'+(attempt>1?' (retry '+attempt+'/3)':'')});
  try{
   response=await fetchJSON('/api/lg/picture-settings/set',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
	     settings:{
	      whiteBalanceMethod:'22',
	      whiteBalanceIre:'109',
	      ddc_layout:'sdr26',
	      whiteBalanceRed:zero,
	      whiteBalanceGreen:zero,
	      whiteBalanceBlue:zero,
	      adjustingLuminance:zero
	     },
	     picture_mode:pictureMode,
	     reset_ddc_baseline:true,
	     force_ddc_white_balance:true,
	     helper_timeout:170,
	     readback_keys:meterAutoCalDdcResetReadbackKeys()
	    }),
    _quiet:true,
    _timeoutMs:180000
   });
  }catch(e){
   response=null;
   lastMessage=(e&&e.message)?e.message:lastMessage;
  }
  if(response&&response.status==='ok') break;
  lastMessage=(response&&(response.repair_hint||response.message))||lastMessage;
  if(attempt<3) await new Promise(resolve=>setTimeout(resolve,1200*attempt));
 }
 if(!response||response.status!=='ok'){
  throw new Error(lastMessage||'Unable to clear LG picture mode calibration state.');
 }
 if(response.ddc_baseline_reset!==true||response.ddc_1d_lut!==true){
  throw new Error('LG picture mode reset did not confirm a 1D LUT baseline reset.');
 }
 if(response.ddc_reset_verified!==true){
  throw new Error('LG picture mode reset did not verify against the TV 1D LUT readback.');
 }
 }
 response.picture_mode_reset=pictureModeReset;
 if(hdrCalmanReset) response.hdr_calman_reset=hdrCalmanReset;
 if(typeof lgDisplayControlInvalidate==='function') lgDisplayControlInvalidate();
 const resetPicture={...((pictureModeReset&&pictureModeReset.picture_settings)||{}),...((response&&response.picture_settings)||{})};
 let panel=meterAutoCalPanelLightFromPicture(resetPicture);
 if(!panel){
  meterAutoCalResetPanelLightState();
  meterAutoCalUpdatePanelLightUi();
 }
 if(panel){
  meterAutoCalSetPanelLight(panel);
  meterAutoCalUpdatePanelLightUi();
 }
 meterLgGreyState={status:'ok',picture:resetPicture,message:'',needsRepair:false};
 return response;
}

async function meterAutoCalHdrCalmanReset(pictureMode){
 let response=null;
 let lastMessage='Unable to run the LG HDR calibration reset.';
 for(let attempt=1;attempt<=3;attempt++){
  meterAutoCalSetOverlay(true,{current_name:'Performing LG HDR reset...',message:'Preparing HDR calibration state'+(attempt>1?' (retry '+attempt+'/3)':'')});
  try{
   response=await fetchJSON(METER_LG_HDR_CALMAN_RESET_ENDPOINT,{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
     picture_mode:pictureMode||meterLgPictureModeValue(),
     action:'hdr_calman_reset',
     ddc_layout:'hdr20',
     helper_timeout:170
    }),
    _quiet:true,
    _timeoutMs:180000
   });
  }catch(e){
   response=null;
   lastMessage=(e&&e.message)?e.message:lastMessage;
  }
  if(response&&response.status==='ok') return response;
  lastMessage=(response&&(response.repair_hint||response.message))||lastMessage;
  if(attempt<3) await new Promise(resolve=>setTimeout(resolve,1200*attempt));
 }
 throw new Error(lastMessage||'Unable to run the LG HDR calibration reset.');
}

async function meterAutoCalReset3dLutBaseline(){
 const hdrWorkflow=meterLgAutoCalRequestedSignalMode()==='hdr10';
 const pictureMode=meterLgPictureModeValue((meterLgGreyState&&meterLgGreyState.picture&&meterLgGreyState.picture.pictureMode)||'');
 let response=null;
 let lastMessage='Unable to reset LG 3D LUT.';
 for(let attempt=1;attempt<=3;attempt++){
  meterAutoCalSetOverlay(true,{current_name:'Resetting LG 3D LUT...',message:'Writing '+(hdrWorkflow?'BT.2020 ':'')+'unity 3D LUT baseline before greyscale'+(attempt>1?' (retry '+attempt+'/3)':'')});
  try{
   response=await fetchJSON('/api/lg/3d-lut/reset',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
     picture_mode:pictureMode,
     ...meterLg3dLutCommandPayload(hdrWorkflow?'hdr10':'sdr'),
     helper_timeout:220
    }),
    _quiet:true,
    _timeoutMs:245000
   });
  }catch(e){
   response=null;
   lastMessage=(e&&e.message)?e.message:lastMessage;
  }
  if(response&&response.status==='ok'&&response.upload_verified===true) return response;
  lastMessage=(response&&(response.repair_hint||response.message))||lastMessage;
  if(attempt<3) await new Promise(resolve=>setTimeout(resolve,1200*attempt));
 }
 throw new Error(lastMessage||'Unable to reset LG 3D LUT.');
}

function meterAutoCalPreflightResetCompleteTitle(){
 return (meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow) ? 'LG picture mode and 3D LUT reset complete' : 'LG picture mode reset complete';
}

function meterAutoCalPreflightResetPrompt(){
 return (meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)
  ? 'Click Reset to reset the LG picture mode and clear 3D LUT calibration state.'
  : 'Click Reset to reset the LG picture mode before Auto Cal.';
}

async function meterAutoCalRunPreflightReset(){
 if(!meterAutoCalPendingConfig||!meterAutoCalPendingConfig.whiteStep){toast('Auto Cal setup is not ready',true);return;}
 if(meterAutoCalResetInProgress) return;
 meterAutoCalPhase='disclaimer';
 meterAutoCalResetInProgress=true;
 meterActionPending=true;
 let resetErrorMessage='';
 try{
  const ddcReset=await meterAutoCalResetDdc();
  meterAutoCalPreflightLgGeneration=(ddcReset&&ddcReset.lg_generation)||(ddcReset&&ddcReset.picture_mode_reset&&ddcReset.picture_mode_reset.lg_generation)||null;
  let lutReset=null;
  if(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow){
   if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
   lutReset=await meterAutoCalReset3dLutBaseline();
  }
  if(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow){
   const resetSummary={
    completed_at:Date.now(),
    ddc:{
     status:ddcReset&&ddcReset.status||null,
     ddc_baseline_reset:!!(ddcReset&&ddcReset.ddc_baseline_reset),
     ddc_1d_lut:!!(ddcReset&&ddcReset.ddc_1d_lut),
     ddc_reset_verified:!!(ddcReset&&ddcReset.ddc_reset_verified),
     lg_generation:meterAutoCalPreflightLgGeneration||null,
     hdr_calman_reset:ddcReset&&ddcReset.hdr_calman_reset?{
      status:ddcReset.hdr_calman_reset.status||null,
      completed_at:Date.now()
     }:null,
     picture_mode:(ddcReset&&ddcReset.picture_settings&&ddcReset.picture_settings.pictureMode)||meterLgPictureModeValue()
    },
    lut3d:lutReset?{
     status:lutReset.status||null,
     upload_verified:!!lutReset.upload_verified,
     picture_mode:lutReset.picture_mode||meterLgPictureModeValue(),
     lg_generation:lutReset.lg_generation||null,
     completed_at:Date.now(),
     upload_command:lutReset.upload_command||'',
     get_command:lutReset.get_command||''
    }:null
   };
   meterFullAutoCalConfig={...(meterFullAutoCalConfig||meterFullAutoCalDefaultConfig()),preflightReset:resetSummary};
   meterFullAutoCalReportData=meterFullAutoCalReportData||meterFullAutoCalDefaultReportData();
   meterFullAutoCalReportData.reset=resetSummary;
   meterFullAutoCalSaveReportData();
   meterFullAutoCalArchiveReportData('preflight-reset',resetSummary);
  }
  if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
  meterAutoCalPreflightResetDone=true;
  meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:meterAutoCalPreflightResetCompleteTitle(),message:'Click Continue when ready.'});
 }catch(e){
  meterAutoCalPreflightResetDone=false;
  meterAutoCalPreflightLgGeneration=null;
  meterActionPending=false;
  if(meterAutoCalStopRequested){
   meterAutoCalSetOverlay(false,null);
   meterAutoCalRunning=false;
   toast('LG Auto Cal stopped');
  }else{
   resetErrorMessage=(e&&e.message)?e.message:'Unable to reset LG picture mode';
   meterAutoCalRunning=true;
   meterAutoCalPhase='disclaimer';
   meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:'Reset failed',message:resetErrorMessage+'. Check the TV connection, then click Reset to try again.'});
   toast(resetErrorMessage,true);
  }
 }finally{
  meterAutoCalResetInProgress=false;
  meterActionPending=false;
  meterUpdateReadButtons();
  if(meterAutoCalRunning&&meterAutoCalPhase==='disclaimer'){
   const title=meterAutoCalPreflightResetDone?meterAutoCalPreflightResetCompleteTitle():(resetErrorMessage?'Reset failed':'Before LG Auto Cal');
   const message=meterAutoCalPreflightResetDone?'Click Continue when ready.':(resetErrorMessage?(resetErrorMessage+'. Check the TV connection, then click Reset to try again.'):meterAutoCalPreflightResetPrompt());
   meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:title,message:message});
  }
 }
}

async function meterAutoCalLuminanceSetupLoop(whiteStep){
 meterAutoCalPhase='luminance';
 meterAutoCalLuminanceSetupActive=true;
 meterAutoCalLuminanceContinue=false;
 meterAutoCalLuminanceScaleMax=0;
 const initialLive=document.getElementById('meterAutoCalLiveY');
 const initialFill=document.getElementById('meterAutoCalLuminanceFill');
 if(initialLive) initialLive.textContent='--';
 if(initialFill) initialFill.style.width='0%';
 meterAutoCalSetupReading=null;
 const continueBtn=document.getElementById('meterAutoCalContinueBtn');
 if(continueBtn) continueBtn.disabled=true;
 meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:'Watch the live 100% white reading, then click Continue when ready.'});
 meterAutoCalResetPanelLightState();
 meterAutoCalUpdatePanelLightUi();
 meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:'Loading the LG panel-light control before the live white read...'});
 await meterAutoCalLoadPanelLightValue(true);
 meterAutoCalUpdatePanelLightUi();
 await meterDisplayPatch(whiteStep,{fresh:false});
 meterCurrentPatchStep=null;
 meterLgGreyLoadToken++;
 meterRenderGreyTvControls(null);
 let lastReading=null;
 while(meterAutoCalLuminanceSetupActive&&!meterAutoCalLuminanceContinue&&!meterAutoCalStopRequested){
  const startedPanelLightWrite=meterAutoCalProcessQueuedPanelLight();
  meterAutoCalUpdatePanelLightUi();
  if(startedPanelLightWrite||meterAutoCalPanelLightBlocksMeterRead()){
   meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:'Waiting for panel light change to finish before the next meter read...'});
   await meterAutoCalWaitForPanelLightIdle(30000);
   await meterAutoCalSleep(300);
   continue;
  }
  const live=document.getElementById('meterAutoCalLiveY');
  const fill=document.getElementById('meterAutoCalLuminanceFill');
	  const readPayload=meterMeasurementSignalContext({
	   display_type:getEffectiveDisplayType(),
	   refresh_rate:getMeterRefreshRate()||undefined,
	   delay_ms:meterDelayMs(),
	   patch_r:whiteStep.r,
	   patch_g:whiteStep.g,
	   patch_b:whiteStep.b,
	   ire:whiteStep.ire,
	   stimulus:whiteStep.stimulus!=null?whiteStep.stimulus:whiteStep.ire,
	   name:whiteStep.name||'100%',
	   patch_size:getMeterPatchSize(),
	   target_gamut:(document.getElementById('meterTargetGamut')||{}).value||'auto',
	   target_gamma:meterAutoCalTargetGammaValue()
	  });
	  meterApplyReadStepPayload(readPayload,whiteStep);
  const patternSignalRange=meterMeasurementPatchSignalRange();
  if(patternSignalRange!=null) readPayload.signal_range=patternSignalRange;
	  readPayload.require_device_ready=meterSelectedMeasurementRequiresReady();
	  meterAutoCalLuminanceReadBusy=true;
	  meterAutoCalUpdatePanelLightUi();
	  if(!lastReading) meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:'Starting live white meter read...'});
	  let result=null;
  try{
   result=await meterStartSingleRead(readPayload,()=>{
    if(meterAutoCalStopRequested||meterAutoCalLuminanceContinue) return true;
    return false;
   });
  }catch(e){
   result={status:'error',message:(e&&e.message)?e.message:'Unable to start meter read'};
  }finally{
   meterAutoCalLuminanceReadBusy=false;
   meterAutoCalUpdatePanelLightUi();
  }
  if(result&&result.status==='ok'&&Array.isArray(result.readings)&&result.readings[0]){
   const rd=result.readings[0];
   meterNormalizeMeasuredReading(rd);
   meterStampReadingStepMeta(rd,whiteStep);
   lastReading=rd;
   meterAutoCalSetupReading=rd;
   meterWhiteReading=rd;
   const y=meterReadingLuminanceNits(rd);
   if(live) live.textContent=(y!=null&&Number.isFinite(y))?y.toFixed(2):'--';
   if(fill){
    const scale=meterAutoCalLuminanceScaleFor(y);
    fill.style.width=(y!=null&&Number.isFinite(y)?Math.min(100,Math.max(0,y/scale*100)):0)+'%';
   }
   updateLiveReading(rd);
   meterUpsertSeriesReading(rd,whiteStep);
   meterCacheSeriesState('running');
   const msg=(y!=null&&Number.isFinite(y))?('Live white is '+y.toFixed(2)+' cd/m\u00B2. Continue when this is the luminance you want.'):('Continue when live white is the luminance you want.');
   meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:msg});
   meterAutoCalUpdatePanelLightUi();
  }else if(result&&result.status==='cancelled'){
   break;
  }else if(result&&result.status==='error'){
   meterAutoCalSetOverlay(true,{phase:'luminance',current_name:'Set 100% luminance',message:result.message||'Waiting for luminance reading'});
  }
  await new Promise(resolve=>setTimeout(resolve,250));
 }
 meterAutoCalLuminanceSetupActive=false;
 meterAutoCalLuminanceReadBusy=false;
 meterAutoCalUpdatePanelLightUi();
 if(lastReading){
  const y=meterReadingLuminanceNits(lastReading);
  if(Number.isFinite(Number(y))&&Number(y)>0) meterAutoCalCapturedTargetY=Number(y);
 }
 return lastReading;
}

function meterAutoCalCurrentKeyFromStatus(status){
			 if(!status) return null;
			 const keyForValue=value=>{
			  const numeric=Number(value);
			  if(!Number.isFinite(numeric)) return null;
			  const targetStep=(typeof meterAutoCalStepForIre==='function')?meterAutoCalStepForIre(numeric):null;
			  if(targetStep) return meterStepNameKey(targetStep);
			  const step=(meterSeriesSteps||[]).find(s=>{
			   const candidates=[s.ire,s.stimulus,s.patch_stimulus,s.signal_r_pct,s.ddc_target_ire,s.ddc_array_ire,s.autocal_order_ire];
			   return candidates.some(candidate=>Number.isFinite(Number(candidate))&&Math.abs(Number(candidate)-numeric)<0.001);
			  });
			  return step?meterStepNameKey(step):null;
			 };
			 const name=String(status.current_name||'');
			 const match=name.match(/([0-9]+(?:\.[0-9]+)?)%/);
			 const nameKey=match?keyForValue(match[1]):null;
			 const ddcTargetKey=keyForValue(status.current_ddc_target_ire);
			 if(nameKey&&ddcTargetKey&&nameKey===ddcTargetKey) return nameKey;
			 if(nameKey&&/^Auto Cal\s+/i.test(name)) return nameKey;
			 if(ddcTargetKey&&status.paired_current_name) return ddcTargetKey;
			 const numericCandidates=[
			  status.current_ire,
			  status.current_step_ire,
			  status.patch_ire,
			  status.current_stimulus,
			  status.active_stimulus,
			  status.current_ddc_target_ire,
			  status.current_ddc_array_ire
			 ];
			 for(const value of numericCandidates){
			  const key=keyForValue(value);
			  if(key) return key;
			 }
			 if(nameKey) return nameKey;
			 return null;
		}

function meterAutoCalStatusActive(){
 const status=meterAutoCalLatestStatus;
 return !!(
  meterAutoCalRunning||
  meterAutoCalPolling||
  meterAutoCalRecoveryInFlight||
  (status&&status.autocal&&String(status.status||'').toLowerCase()==='running')
 );
}

function meterAutoCalSyncLgGreyState(status,currentKey){
		 if(!status||!status.picture_settings||typeof status.picture_settings!=='object'||Array.isArray(status.picture_settings)) return;
		 let picture=status.picture_settings;
		 try{ picture=JSON.parse(JSON.stringify(status.picture_settings)); }catch(e){}
			 meterLgGreyState={status:'ok',picture:picture,message:'',needsRepair:false};
			 meterLgGreyState.source='autocal';
			 meterLgGreyState.supportedKeys=Array.isArray(status.supported_picture_keys)?status.supported_picture_keys:[];
			 meterLgGreyState.unsupportedKeys=(status.unsupported_picture_keys&&typeof status.unsupported_picture_keys==='object')?status.unsupported_picture_keys:{};
			 meterLgGreyState.capabilities=status.picture_capabilities||null;
	 if(currentKey&&Array.isArray(meterSeriesSteps)){
	  const currentStep=meterSeriesSteps.find(step=>meterStepNameKey(step)===currentKey);
	  if(currentStep) meterCurrentPatchStep=meterClonePatchStep(currentStep)||currentStep;
	 }
	 meterRenderGreyTvControls(meterFindReadingForStep(meterCurrentPatchStep));
}

function meterAutoCalSyncLgCalibrationMode(status){
 if(!status||!Object.prototype.hasOwnProperty.call(status,'calibration_mode')) return;
 const active=!!status.calibration_mode;
 if(window.lgStatusState){
  window.lgStatusState.calibrationMode=active;
  if(status.calibration_picture_mode) window.lgStatusState.calibrationPictureMode=status.calibration_picture_mode;
  else if(!active) delete window.lgStatusState.calibrationPictureMode;
 }
 const checkbox=document.getElementById('lgCalibrationMode');
 if(checkbox){
  checkbox.checked=active;
  checkbox.disabled=!!(typeof lgCalibrationModePending!=='undefined'&&lgCalibrationModePending);
 }
}

function meterAutoCalStepForIre(ire){
 const wanted=Number(ire);
 if(!Number.isFinite(wanted)||!Array.isArray(meterSeriesSteps)) return null;
 const matches=(step,values)=>{
  if(!step) return false;
  return values.some(value=>Number.isFinite(Number(value))&&Math.abs(Number(value)-wanted)<0.001);
 };
 return meterSeriesSteps.find(step=>matches(step,[step.ire,step.plot_ire,step.nominal_ire,step.patch_ire,step.stimulus,step.signal_r_pct]))
  || meterSeriesSteps.find(step=>!meterReadingIsAutoCalReferenceOnly(step)&&matches(step,[step.ddc_target_ire,step.ddc_array_ire]))
  || null;
}

function meterAutoCalBestKnownReadings(status){
 const known=status&&status.lg_autocal_26_best_known;
 if(!known||typeof known!=='object'||Array.isArray(known)) return [];
 const out=[];
 Object.keys(known).forEach(key=>{
  const entry=known[key];
  if(!entry||typeof entry!=='object'||!entry.reading) return;
  const reading=meterFullAutoCalCloneValue(entry.reading);
  if(!reading||typeof reading!=='object') return;
  if(reading.ire==null&&entry.ire!=null) reading.ire=entry.ire;
  const step=meterAutoCalStepForIre(reading.ire!=null?reading.ire:entry.ire);
  if(step) meterStampReadingStepMeta(reading,step);
  if(entry.delta_e!=null) reading.best_known_delta_e=entry.delta_e;
  if(entry.reached_target!=null) reading.best_known_reached_target=entry.reached_target;
  if(entry.target_luminance!=null) reading.target_luminance=entry.target_luminance;
  if(entry.legal_white_validation_status!=null) reading.legal_white_validation_status=entry.legal_white_validation_status;
  if(entry.paired_legal_white_delta_e!=null) reading.paired_legal_white_delta_e=entry.paired_legal_white_delta_e;
  if(entry.paired_current_name!=null) reading.paired_current_name=entry.paired_current_name;
  out.push(reading);
 });
 return out;
}

function meterAutoCalStatusChartReadings(status,currentKey){
 const raw=Array.isArray(status&&status.readings)?status.readings:[];
 const base=meterAttachSeriesMeta(meterFilterReadingsForCurrentSteps(raw,'greyscale'));
 const best=meterAttachSeriesMeta(meterAutoCalBestKnownReadings(status));
 const byKey=new Map();
 const statusRunning=String(status&&status.status||'').toLowerCase()==='running';
 const currentSlotKey=statusRunning?(currentKey||meterAutoCalCurrentKeyFromStatus(status)):null;
 const addReading=(reading,source)=>{
  if(!reading||!meterReadingHasLuminance(reading)) return;
  if(meterReadingIsAutoCalChartHidden(reading)||meterLgAutoCalChartReferenceWhite(reading)) return;
  const key=meterStepNameKey(reading)||String(reading.ire||reading.name||byKey.size);
  const currentPending=currentSlotKey&&key===currentSlotKey&&status.current_delta_e==null&&status.current_luminance==null&&status.luminance_error_pct==null;
  if(currentPending) return;
  if(source==='best'&&currentSlotKey&&key===currentSlotKey&&byKey.has(key)) return;
  byKey.set(key,reading);
 };
 base.forEach(reading=>addReading(reading,'status'));
 best.forEach(reading=>addReading(reading,'best'));
 return Array.from(byKey.values()).sort((a,b)=>(meterReadingPlotIre(a)||a.ire||0)-(meterReadingPlotIre(b)||b.ire||0));
}

async function meterAutoCalApplyStatus(status){
			 if(!status) return;
			 meterAutoCalLatestStatus=status;
		 meterAutoCalSyncLgCalibrationMode(status);
		 if(status.autocal){
	  const statusSignal=String(status.signal_mode||status.requested_signal_mode||'').toLowerCase();
	  const inferredSignal=statusSignal||(String(status.ddc_layout||'').toLowerCase()==='hdr20'?'hdr10':'');
	  if(inferredSignal) meterSetActiveSeriesChartContext({...status,signal_mode:inferredSignal});
	  if(meterActiveSeriesType!=='greyscale'||Number(meterActiveSeriesPoints)!==26){
	   meterActiveSeriesType='greyscale';
	   meterActiveSeriesPoints=26;
	   meterActiveSeriesKey='greyscale-26';
	   meterShowGreyscaleAutoCalContext();
	   meterResetSeriesButtons();
	   const activeBtn=document.querySelector('#meterSeriesBtnRow button[data-series="greyscale-26"]');
	   if(activeBtn){activeBtn.classList.remove('btn-secondary');activeBtn.classList.add('btn-primary');}
	  }
  document.getElementById('chartsGreyscaleWrap').style.display='';
  document.getElementById('chartsColorWrap').style.display='none';
  document.getElementById('meterCharts').style.display='';
  document.getElementById('meterExportRow').style.display='';
  meterSetThumbsVisible(true);
 }
	 if(Array.isArray(status.steps)&&status.steps.length>0){
		  meterSeriesSteps=meterCanonicalRecoveredSteps('greyscale',26,status.steps,status.status||'running');
		 }
		 const currentKey=meterAutoCalCurrentKeyFromStatus(status);
		 if(status.autocal&&String(status.status||'').toLowerCase()==='running') meterSelectedThumbIre=null;
		 const statusChartReadings=meterAutoCalStatusChartReadings(status,currentKey);
		 if(statusChartReadings.length){
	  meterReadings=statusChartReadings;
	  const white=meterFindSeriesWhiteReading(meterReadings);
	  const statusTargetY=Number(status.target_luminance||status.calibrated_white_luminance);
	  if(Number.isFinite(statusTargetY)&&statusTargetY>0){
	   meterStoreLgTargetWhiteReference(
	    statusTargetY,
	    status.full_workflow?'full-autocal':'greyscale-autocal',
	    status.full_autocal_run_id||status.run_id||meterFullAutoCalRunId||null
	   );
	  }
	  const synthetic=meterSyntheticGreyWhiteReading(statusTargetY);
	  if(synthetic){
	   synthetic.name='Auto Cal 100% target';
	   synthetic.ire=100;
	   synthetic.autocal_reference_only=true;
	   meterWhiteReading=synthetic;
	  }
	  else if(white) meterWhiteReading=white;
	  const completed=new Set(meterReadings.filter(r=>r&&r.luminance!=null).map(r=>meterStepNameKey(r)));
  const sorted=[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
	  if(sorted.length) {
	   drawAllCharts(sorted);
	   const currentValid=currentKey?meterReadings.find(rd=>rd&&rd.luminance!=null&&meterStepNameKey(rd)===currentKey):null;
	   const lastValid=currentValid||[...meterReadings].reverse().find(rd=>rd&&rd.luminance!=null);
	   if(lastValid) updateLiveReading(lastValid);
	   meterCacheSeriesState(status.status||'running');
	  }
  if(meterSeriesSteps){
   const sortedSteps=meterGreyscaleSeriesSteps(meterSeriesSteps);
   meterBuildPatchThumbs(sortedSteps,completed,currentKey);
  }
 }
	 if(!statusChartReadings.length&&meterSeriesSteps&&status.autocal){
  const sortedSteps=meterGreyscaleSeriesSteps(meterSeriesSteps);
	  drawAllChartsPreset(sortedSteps);
	  meterBuildPatchThumbs(sortedSteps,new Set(),currentKey);
	 }
		 if(status.status==='running'||status.status==='complete'||meterAutoCalRunning||meterActionPending) meterAutoCalSyncLgGreyState(status,currentKey);
 let progressText=status.current_name||status.message||'LG Auto Cal';
 const y=Number(status.current_luminance);
 const ty=Number(status.target_step_luminance);
 if(Number.isFinite(y)&&Number.isFinite(ty)&&ty>0) progressText+=' | Y '+y.toFixed(1)+' / '+ty.toFixed(1);
 if(status.status==='running') meterSetWorkflowProgress(status,{workflow:meterFullAutoCalRunning?'full':'greyscale',label:progressText});
 else meterHideWorkflowProgress();
	 if(status.status==='running'){
	  meterAutoCalPhase='running';
	  meterAutoCalRunning=true;
	  meterAutoCalSaveState();
	  meterAutoCalSetOverlay(false,status);
	 }else if(status.status==='complete'){
	  meterAutoCalPhase='complete';
	  meterAutoCalRunning=true;
	  meterAutoCalSaveState();
	  // Wizard-owned HDR tone-map prompt: runs BEFORE the "Greyscale Auto
	  // Cal complete" overlay so the operator gets a single, predictable
	  // decision moment with a freshly measured peak.
	  let completeStatus=status;
	  if(status.hdr20_1d_tonemap_pending){
	   const promptResult=await meterAutoCalPromptHdrToneMapUpload(status,'greyscale');
	   if(promptResult&&promptResult.finalStatus) completeStatus=promptResult.finalStatus;
	  }
	  meterAutoCalSetOverlay(true,{...completeStatus,phase:'complete'});
	 }else{
	  meterAutoCalSetOverlay(status.status==='error',status);
	 }
}

function meterFullAutoCalCloneValue(value){
 try{ return JSON.parse(JSON.stringify(value)); }catch(e){ return value; }
}

function meterFullAutoCalDefaultReportData(){
 return {pre:null,post:null,updated_at:Date.now(),run_id:null,started_at:null,signal_mode:null,pre_cal_skipped:null,stages:{},reset:null};
}

function meterFullAutoCalLoadReportData(){
 try{
  const parsed=JSON.parse(localStorage.getItem(METER_FULL_AUTOCAL_REPORT_KEY)||'null');
  if(parsed&&typeof parsed==='object'){
   meterFullAutoCalReportData=parsed;
   return parsed;
  }
 }catch(e){}
 meterFullAutoCalReportData=meterFullAutoCalDefaultReportData();
 return meterFullAutoCalReportData;
}

function meterFullAutoCalSaveReportData(){
 try{
  meterFullAutoCalReportData.updated_at=Date.now();
  if(!meterFullAutoCalReportData.run_id&&meterFullAutoCalRunId) meterFullAutoCalReportData.run_id=meterFullAutoCalRunId;
  if(!meterFullAutoCalReportData.started_at&&meterFullAutoCalStartedAt) meterFullAutoCalReportData.started_at=meterFullAutoCalStartedAt;
  if(!meterFullAutoCalReportData.signal_mode) meterFullAutoCalReportData.signal_mode=(meterFullAutoCalConfig&&meterFullAutoCalConfig.signalMode)||meterLgAutoCalRequestedSignalMode();
  if(!meterFullAutoCalReportData.stages||typeof meterFullAutoCalReportData.stages!=='object') meterFullAutoCalReportData.stages={};
  localStorage.setItem(METER_FULL_AUTOCAL_REPORT_KEY,JSON.stringify(meterFullAutoCalReportData));
 }catch(e){}
}

function meterFullAutoCalClearReportData(){
 meterFullAutoCalReportData=meterFullAutoCalDefaultReportData();
 try{ localStorage.removeItem(METER_FULL_AUTOCAL_REPORT_KEY); }catch(e){}
}

function meterFullAutoCalBeginReportData(skipPreCal){
 meterFullAutoCalReportData=meterFullAutoCalDefaultReportData();
 meterFullAutoCalReportData.run_id=meterFullAutoCalRunId||null;
 meterFullAutoCalReportData.started_at=meterFullAutoCalStartedAt||Date.now();
 meterFullAutoCalReportData.signal_mode=(meterFullAutoCalConfig&&meterFullAutoCalConfig.signalMode)||meterLgAutoCalRequestedSignalMode();
 meterFullAutoCalReportData.pre_cal_skipped=!!skipPreCal;
 meterFullAutoCalSaveReportData();
 meterFullAutoCalArchiveReportData('started');
}

function meterFullAutoCalArchiveReportData(stage,extra){
 let payload=null;
 try{
  payload={
   run_id:meterFullAutoCalRunId||(meterFullAutoCalReportData&&meterFullAutoCalReportData.run_id)||null,
   stage:stage||'state',
   saved_at:Date.now(),
   report:meterFullAutoCalLoadReportData(),
   config:meterFullAutoCalConfig||null,
   results:meterFullAutoCalResults||null,
   extra:extra||null
  };
 }catch(e){ return Promise.resolve(null); }
 if(!payload.run_id) payload.run_id='unknown';
 return fetchJSON('/api/meter/full-autocal/report-state',{
  method:'POST',
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify(payload),
  _quiet:true,
  _timeoutMs:6000
 }).catch(()=>null);
}

function meterAutoCalSaveState(){
 if(meterFullAutoCalRunning) return;
 try{
  localStorage.setItem(METER_AUTOCAL_STATE_KEY,JSON.stringify({
   active:true,
   phase:meterAutoCalPhase||'running',
   updated:Date.now()
  }));
 }catch(e){}
}

function meterAutoCalClearSavedState(){
 try{ localStorage.removeItem(METER_AUTOCAL_STATE_KEY); }catch(e){}
}

function meterAutoCalRestoreSavedState(){
 let saved=null;
 try{ saved=JSON.parse(localStorage.getItem(METER_AUTOCAL_STATE_KEY)||'null'); }catch(e){ saved=null; }
 if(!saved||!saved.active) return false;
 if(Date.now()-Number(saved.updated||0)>12*60*60*1000){
  meterAutoCalClearSavedState();
  return false;
 }
 meterAutoCalRunning=true;
 meterAutoCalPhase=String(saved.phase||'running');
 if(meterAutoCalPhase!=='complete'&&meterAutoCalPhase!=='error') meterAutoCalPhase='running';
 if(!meterAutoCalPolling) meterAutoCalPolling=setInterval(meterPollAutoCal,1500);
 meterSetWorkflowProgress({status:'running',current_step:0,total_steps:1,current_name:'Reconnecting to LG Auto Cal...'},{workflow:'greyscale',label:'Reconnecting to LG Auto Cal...'});
 return true;
}

function meterRestoreAutoCalWorkflows(){
 const restoredFull=meterFullAutoCalRestoreSavedState();
 if(!restoredFull) meterAutoCalRestoreSavedState();
}

function meterFullAutoCalSnapshotForKey(key){
 if(key===meterActiveSeriesKey&&meterSeriesSteps&&meterSeriesSteps.length>0){
  meterCacheSeriesState('complete');
 }
 const snap=(meterSeriesCache&&meterSeriesCache[key])?meterSeriesCache[key]:meterGetSeriesSnapshotByKey(key);
 if(!snap) return null;
 const clone=meterFullAutoCalCloneValue(snap);
 if(!clone||!Array.isArray(clone.readings)) return null;
 clone.readings=clone.readings.filter(rd=>meterReadingHasLuminance(rd));
 clone.status='complete';
 clone.report_key=key;
 return clone.readings.length?clone:null;
}

function meterFullAutoCalReportSetHasData(stage){
 const data=meterFullAutoCalLoadReportData();
 const set=data&&data[stage];
 const series=meterFullAutoCalReportSeries();
 return !!(set&&series.every(item=>meterSeriesSnapshotHasReadings(set[item.key])));
}

function meterFullAutoCalReportSetAnyData(stage){
 const data=meterFullAutoCalLoadReportData();
 const set=data&&data[stage];
 const series=meterFullAutoCalReportSeries();
 return !!(set&&series.some(item=>meterSeriesSnapshotHasReadings(set[item.key])));
}

function meterFullAutoCalReportStatusText(stage){
 const data=meterFullAutoCalLoadReportData();
 const set=data&&data[stage];
 if(!set) return '';
 return meterFullAutoCalReportSeries().map(item=>{
  const count=(set[item.key]&&Array.isArray(set[item.key].readings))?set[item.key].readings.filter(rd=>meterReadingHasLuminance(rd)).length:0;
  return item.label+': '+count;
 }).join(' | ');
}

