  meterBuildPatchThumbs(sortedSteps,new Set(),null);
  drawAllChartsPreset(sortedSteps);
  await meterStopContinuous();
  const post3dBody=JSON.stringify(meterMeasurementSignalContext({
    type:'greyscale',
