	    post_commit_low_shadow_committed_iterations:touchupPostCommitPolishEnabled?3:undefined,
	    post_commit_settle_ms:touchupPostCommitPolishEnabled?12000:undefined,
	    post_commit_white_resettle_ms:touchupPostCommitPolishEnabled?8000:undefined,
	    post_commit_low_shadow_settle_ms:touchupPostCommitPolishEnabled?2500:undefined,
	    post_commit_low_shadow_read_settle_ms:touchupPostCommitPolishEnabled?1200:undefined,
    full_autocal_touchup:true,
    full_workflow:true,
    full_autocal_run_id:meterFullAutoCalRunId||undefined,
    full_autocal_phase:'touchup-greyscale',
    full_autocal_post_commit_polish:touchupPostCommitPolishEnabled,
    full_autocal_magic_wand:meterFullAutoCalMagicWandEnabled(),
    low_light:meterLowLightReadState(),
    steps:autocalSteps
   }));
  let r=null;
  for(let attempt=0;attempt<5;attempt++){
   r=await fetchJSON('/api/meter/lg-autocal',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:touchupBody,
    _timeoutMs:10000
   });
   if(r&&r.status==='started') break;
   if(!meterFullAutoCalTransitionBusy(r&&r.message)) break;
   meterSetWorkflowProgress({status:'running',current_step:0,total_steps:1,current_name:'Waiting for 3D LUT AutoCal cleanup'},{workflow:'full',label:'Waiting for 3D LUT AutoCal cleanup'});
   await new Promise(resolve=>setTimeout(resolve,900+(attempt*400)));
  }
  if(!r||r.status!=='started') throw new Error((r&&r.message)||'Unable to start greyscale touch-up');
  meterActionPending=false;
  toast('Full Auto Cal greyscale touch-up started');
  meterAutoCalSetOverlay(false,{phase:'running',current_name:'Greyscale touch-up started',message:'Showing live charts'});
  if(meterAutoCalPolling) clearInterval(meterAutoCalPolling);
  meterAutoCalPolling=setInterval(meterPollAutoCal,1500);
  await meterPollAutoCal();
  return true;
 }catch(e){
  meterFullAutoCalAbort((e&&e.message)||'Full Auto Cal greyscale touch-up failed',true);
  return false;
 }finally{
  meterUpdateReadButtons();
 }
}

function meterFullAutoCalComplete(touchupStatus,options){
 const skipTouchup=!!(options&&options.skipTouchup);
 const post3dPolish=String(touchupStatus&&touchupStatus.full_autocal_phase||'')==='post-3d-polish';
 if(!skipTouchup||post3dPolish) meterFullAutoCalResults.touchup=touchupStatus||null;
 meterFullAutoCalLoadReportData();
 const offerPostReport=true;
 const completedAt=Number(touchupStatus&&touchupStatus.completed_at)||Date.now();
 const startedAt=Number(meterFullAutoCalStartedAt)||Number((meterFullAutoCalResults.first||{}).started_at)||Number(touchupStatus&&touchupStatus.started_at)||null;
 const runId=(touchupStatus&&(touchupStatus.full_autocal_run_id||touchupStatus.run_id))||meterFullAutoCalRunId||meterFullAutoCalNewRunId();
 meterFullAutoCalRunId=runId;
 const status={
  ...(touchupStatus||{}),
  full_autocal:true,
  full_workflow:true,
  full_autocal_run_id:runId,
  run_id:runId,
	  completed_at:completedAt,
	  started_at:startedAt||undefined,
	  elapsed_ms:(startedAt&&completedAt>=startedAt)?(completedAt-startedAt):undefined,
	  offer_post_report:offerPostReport,
	  touchup_skipped:skipTouchup,
	  phase:'complete',
	  current_name:'Full Auto Cal complete',
		  message:(touchupStatus&&touchupStatus.full_autocal_post_series_adjust)?'Greyscale, 3D LUT, and Magic Wand complete.':(post3dPolish?'Greyscale, 3D LUT, and committed polish complete.':(skipTouchup?'Greyscale and 3D LUT complete.':'Greyscale, 3D LUT, and greyscale touch-up complete.')),
  first_greyscale:meterFullAutoCalResults.first,
  lut3d:meterFullAutoCalResults.lut3d,
	  touchup:(skipTouchup&&!post3dPolish)?null:(touchupStatus||null)
 };
 meterFullAutoCalReportData=meterFullAutoCalReportData||meterFullAutoCalDefaultReportData();
 meterFullAutoCalReportData.run_id=runId;
 meterFullAutoCalReportData.completed_at=completedAt;
 meterFullAutoCalReportData.elapsed_ms=status.elapsed_ms||null;
 meterFullAutoCalReportData.completion_status=status;
 meterFullAutoCalSaveReportData();
 meterFullAutoCalArchiveReportData('complete',{completed_at:completedAt,elapsed_ms:status.elapsed_ms||null});
 meterFullAutoCalMarkCompletionHandled(status);
 meterFullAutoCalResetState(true);
 meterAutoCalPhase='complete';
 meterAutoCalRunning=true;
 meterAutoCalSetOverlay(true,status);
 toast('Full Auto Cal complete');
 // The greyscale autocal calibrates the 1D DPG against a 2.2 curve, so the
 // Target Gamma control sits at 2.2 during the run. Once the full workflow is
 // done, restore it to the signal-mode default (ST 2084/PQ for HDR10) so any
 // subsequent verification series -- greyscale, ColorChecker, saturation --
 // computes its target luminance against the correct EOTF instead of 2.2.
 try{ if(typeof applyMeterTargetGammaDefault==='function') applyMeterTargetGammaDefault(); }catch(e){}
}

async function meterPollAutoCal(options){
	 if(meterAutoCalPollInFlight) return;
	 if(meterFullAutoCalReportPhaseActive()){
	  if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	  meterAutoCalRunning=false;
	  if(meterAutoCalPhase==='running'||meterAutoCalPhase==='complete'||meterAutoCalPhase==='error') meterAutoCalPhase='';
	  meterUpdateReadButtons();
	  return;
	 }
	 const initial=options===true||!!(options&&options.initial);
	 const watchdog=!!(options&&options.watchdog);
	 const recover=!!(options&&options.recover);
	 const timeoutMs=Number((options&&options.timeoutMs)||0)|| (initial?15000:8000);
	 const setupOverlayActiveBeforeFetch=meterAutoCalSetupOverlayActive();
		 const fullGreyscalePhase=!!(meterFullAutoCalRunning&&(meterFullAutoCalPhase==='first-greyscale'||meterFullAutoCalPhase==='touchup-greyscale'||meterFullAutoCalPhase==='post-3d-polish'||meterFullAutoCalPhase==='magic-wand'));
	 const fullGreyscaleBackendActive=!!(fullGreyscalePhase&&(meterAutoCalPolling||meterAutoCalPhase==='running'));
	 if(setupOverlayActiveBeforeFetch&&!fullGreyscaleBackendActive) return;
	 meterAutoCalPollInFlight=true;
	 try{
	  const r=await fetchJSON('/api/meter/lg-autocal/status',{_quiet:true,_timeoutMs:timeoutMs});
	  if(!r) return;
	  if(meterFullAutoCalReportPhaseActive()){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterAutoCalRunning=false;
	   if(meterAutoCalPhase==='running'||meterAutoCalPhase==='complete'||meterAutoCalPhase==='error') meterAutoCalPhase='';
	   meterUpdateReadButtons();
	   return;
	  }
	  meterAutoCalLatestStatus=r;
	  if(r.full_workflow&&!meterFullAutoCalStatusMatchesRun(r)) return;
	  meterAutoCalSyncLgCalibrationMode(r);
	  if(r.status==='complete'&&r.full_workflow&&meterFullAutoCalCompletionHandled(r)){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterAutoCalRunning=false;
	   meterAutoCalPhase='';
	   meterAutoCalPendingConfig=null;
	   meterActionPending=false;
	   return;
	  }
	  if(watchdog&&r.status!=='running') return;
	  meterAutoCalPollErrors=0;
	  if(r.status==='running'){
	   meterAutoCalRunning=true;
	   meterAutoCalPhase='running';
	   meterActionPending=false;
	   meterAutoCalPendingConfig=null;
	   meterAutoCalStopRequested=false;
	  }
	  const setupOverlayActive=meterAutoCalSetupOverlayActive();
	  if(setupOverlayActive&&!fullGreyscaleBackendActive) return;
	  if(r.status==='complete'&&meterFullAutoCalEnsureStatusPhase(r,'first-greyscale')){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterActionPending=false;
	   meterAutoCalRunning=false;
	   meterAutoCalPhase='';
	   meterAutoCalPendingConfig=null;
	   await meterFullAutoCalStart3d(r);
	   return;
	  }
	  if(r.status==='complete'&&meterFullAutoCalEnsureStatusPhase(r,'post-3d-polish')){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterActionPending=false;
	   meterAutoCalRunning=false;
	   meterAutoCalPendingConfig=null;
	   if(r.full_autocal_post_series_adjust) await meterAutoCalFinishMagicWandAdjustment(r,{fullWorkflow:true});
	   else if(meterFullAutoCalMagicWandEnabled()) await meterAutoCalStartMagicWand(r,{fullWorkflow:true,afterPolish:true});
		   else await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'post-3d-polish');
	   return;
	  }
	  if(r.status==='complete'&&meterFullAutoCalEnsureStatusPhase(r,'magic-wand')){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterActionPending=false;
	   meterAutoCalRunning=false;
	   meterAutoCalPendingConfig=null;
	   if(r.full_autocal_post_series_adjust) await meterAutoCalFinishMagicWandAdjustment(r,{fullWorkflow:true});
		   else await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'magic-wand');
	   return;
	  }
	  if(r.status==='complete'&&meterFullAutoCalEnsureStatusPhase(r,'touchup-greyscale')){
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterActionPending=false;
	   meterAutoCalRunning=false;
	   meterAutoCalPendingConfig=null;
		   await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'touchup-greyscale');
	   return;
	  }
	  const backendGreyscaleActive=!!(r.status==='running'||meterAutoCalPolling||meterAutoCalPhase==='running');
		  const fullGreyscaleActive=!!(meterFullAutoCalRunning&&(meterFullAutoCalPhase==='first-greyscale'||meterFullAutoCalPhase==='touchup-greyscale'||meterFullAutoCalPhase==='post-3d-polish'||meterFullAutoCalPhase==='magic-wand')&&backendGreyscaleActive);
	  const localAutoCalActive=!!(backendGreyscaleActive||fullGreyscaleActive);
	  if(initial&&r.status!=='running'&&!localAutoCalActive){
	   meterAutoCalRunning=false;
	   meterAutoCalPhase='';
	   meterAutoCalPendingConfig=null;
	   meterAutoCalSetOverlay(false,r);
	   return;
	  }
	  if(r.status==='running'||localAutoCalActive) await meterAutoCalApplyStatus(r);
		  if(r.status==='running'&&!meterAutoCalPolling){
		   meterAutoCalPolling=setInterval(meterPollAutoCal,1500);
		  }
	  if(recover&&r.status==='running') meterSetWorkflowProgress(r,{workflow:meterFullAutoCalRunning?'full':'greyscale',label:r.current_name||r.message||'Reconnected to LG Auto Cal'});
	  if(r.status==='complete'||r.status==='cancelled'||r.status==='error'||r.status==='idle'){
	   const notify=localAutoCalActive||r.status==='complete';
	   if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
	   meterActionPending=false;
		   if(r.status==='complete'){
	    if(meterFullAutoCalEnsureStatusPhase(r,'first-greyscale')){
	     meterAutoCalRunning=false;
	     meterAutoCalPhase='';
	     meterAutoCalPendingConfig=null;
	     await meterFullAutoCalStart3d(r);
	     return;
	    }
		    if(meterFullAutoCalEnsureStatusPhase(r,'touchup-greyscale')){
		     meterAutoCalRunning=false;
		     meterAutoCalPendingConfig=null;
			     await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'touchup-greyscale');
		     return;
		    }
			    if(meterFullAutoCalEnsureStatusPhase(r,'post-3d-polish')){
			     meterAutoCalRunning=false;
			     meterAutoCalPendingConfig=null;
			     if(r.full_autocal_post_series_adjust) await meterAutoCalFinishMagicWandAdjustment(r,{fullWorkflow:true});
			     else if(meterFullAutoCalMagicWandEnabled()) await meterAutoCalStartMagicWand(r,{fullWorkflow:true,afterPolish:true});
				     else await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'post-3d-polish');
			     return;
			    }
				    if(meterFullAutoCalEnsureStatusPhase(r,'magic-wand')){
				     meterAutoCalRunning=false;
				     meterAutoCalPendingConfig=null;
				     if(meterAutoCalMagicWandCompletionRequiresVerification(r)) await meterAutoCalFinishMagicWandAdjustment(r,{fullWorkflow:true});
					     else if(meterAutoCalMagicWandStatusAlreadyFinal(r)) meterFullAutoCalMarkCompletionHandled(r);
					     else await meterFullAutoCalCompleteAfterHdrToneMap(r,undefined,'magic-wand');
				     return;
				    }
			    if(r.full_autocal_post_series_adjust&&meterAutoCalMagicWandActive&&!meterAutoCalMagicWandFullWorkflow){
			     meterAutoCalRunning=false;
			     meterAutoCalPendingConfig=null;
			     await meterAutoCalFinishMagicWandAdjustment(r,{fullWorkflow:false});
			     return;
			    }
				    if(!r.full_workflow&&meterAutoCalStandaloneMagicWandEnabled&&!meterAutoCalMagicWandActive){
				     meterAutoCalRunning=false;
				     meterAutoCalPendingConfig=null;
				     meterAutoCalStandaloneMagicWandEnabled=false;
				     await meterAutoCalStartMagicWand(r,{fullWorkflow:false});
				     return;
				    }
				    if(meterFullAutoCalMagicWandPendingBeforeCompletion(r)){
				     meterAutoCalRunning=false;
				     meterAutoCalPhase='';
				     meterAutoCalPendingConfig=null;
				     meterAutoCalSetOverlay(false,r);
				     return;
				    }
				    // Wizard-owned HDR tone-map prompt: only for the
				    // standalone greyscale path. The full-workflow
				    // path is already covered by
				    // meterFullAutoCalCompleteAfterHdrToneMap.
				    let completeStatus=r;
				    if(!r.full_workflow&&r.hdr20_1d_tonemap_pending){
				     const promptResult=await meterAutoCalPromptHdrToneMapUpload(r,'greyscale-poller');
				     if(promptResult&&promptResult.finalStatus) completeStatus=promptResult.finalStatus;
				    }
				    meterAutoCalPhase='complete';
		    meterAutoCalRunning=true;
	    meterAutoCalPendingConfig=null;
	    meterAutoCalSetOverlay(true,{...completeStatus,phase:'complete'});
	   }else if(r.status==='error'){
	    if(meterFullAutoCalRunning) meterFullAutoCalResetState(false);
	    meterAutoCalPhase='error';
	    meterAutoCalRunning=true;
	    meterAutoCalSetOverlay(true,{phase:'running',current_name:r.current_name||'LG Auto Cal error',message:r.message||'Auto Cal failed',status:'error',readings:r.readings||[]});
	   }else{
	    if(meterFullAutoCalRunning) meterFullAutoCalResetState(false);
	    else meterAutoCalClearSavedState();
	    meterAutoCalRunning=false;
    meterAutoCalPhase='';
	    meterAutoCalPendingConfig=null;
	    meterAutoCalSetOverlay(false,r);
	   }
	   if(notify) toast(r.status==='complete'?'LG Auto Cal complete':r.status==='error'?'LG Auto Cal error: '+(r.message||'process failed'):r.status==='cancelled'?'LG Auto Cal stopped':'LG Auto Cal idle',r.status==='error');
	  }
 }catch(e){
  const backendGreyscaleActive=!!(meterAutoCalPolling||meterAutoCalPhase==='running');
	  const fullGreyscaleActive=!!(meterFullAutoCalRunning&&(meterFullAutoCalPhase==='first-greyscale'||meterFullAutoCalPhase==='touchup-greyscale'||meterFullAutoCalPhase==='post-3d-polish'||meterFullAutoCalPhase==='magic-wand')&&backendGreyscaleActive);
  const active=!!(backendGreyscaleActive||fullGreyscaleActive);
  if(active){
   meterAutoCalPollErrors++;
   if(!meterAutoCalPolling) meterAutoCalPolling=setInterval(meterPollAutoCal,1500);
   if(meterAutoCalPollErrors>=2){
    const label=document.getElementById('meterProgressLabel');
    const progress=document.getElementById('meterProgress');
    if(progress) progress.style.display='';
    if(label) label.textContent=(fullGreyscaleActive?'Full Auto Cal: ':'')+'Reconnecting to LG Auto Cal status...';
   }
  }
 }finally{
  meterAutoCalPollInFlight=false;
  meterUpdateReadButtons();
 }
}

async function meterAutoCalBackendRecoveryWatchdog(){
 if(meterFullAutoCalReportPhaseActive()) return;
 if(meterAutoCalSetupOverlayActive()||meterAutoCalRunning||meterAutoCalPolling||meterActionPending||meterLg3dAutoCalRunning||meterLg3dAutoCalPolling) return;
 meterAutoCalRecoveryInFlight=true;
 try{
  await meterPollAutoCal({initial:true,recover:true,timeoutMs:15000});
 }finally{
  meterAutoCalRecoveryInFlight=false;
 }
}

async function meterAutoCalInitialRecoveryPoll(){
 if(meterFullAutoCalReportPhaseActive()) return;
 if(meterAutoCalSetupOverlayActive()||meterAutoCalRunning||meterAutoCalPolling||meterActionPending||meterLg3dAutoCalRunning||meterLg3dAutoCalPolling) return;
 meterAutoCalRecoveryInFlight=true;
 try{
  await meterPollAutoCal({initial:true,recover:true,timeoutMs:15000});
 }finally{
  meterAutoCalRecoveryInFlight=false;
 }
}

async function meterStartAutoCal(options){
 const fullWorkflow=!!(options&&options.fullWorkflow);
 const fail=(message)=>{
  if(message) toast(message,true);
  if(fullWorkflow) meterFullAutoCalResetState(false);
  return false;
 };
	 if(meterActionPending||meterAutoCalRunning||meterLg3dAutoCalRunning||(!fullWorkflow&&meterFullAutoCalRunning)) return fail('Meter operation already in progress');
	 if(!(await meterEnsureDetected())) return fail('No meter detected');
 if(fullWorkflow||(meterSeriesTab==='autocal'&&meterAutoCalSeriesChoice==='greyscale')){
  meterActiveSeriesType='greyscale';
  meterActiveSeriesPoints=26;
  meterActiveSeriesKey='greyscale-26';
  meterSetActiveSeriesChartContext();
 }
	 if(!meterAutoCalAvailable()) return fail(fullWorkflow?'Connect an LG TV before starting Full Auto Cal':'Connect an LG TV and select Greyscale LG 26pt AutoCal first');
	 if(!(await meterEnsureLgAutoCalTransport(fullWorkflow?'Full Auto Cal':'LG Greyscale Auto Cal'))) return fail('');
	 if(!meterEnsureLgAutoCalExtendedVideoTransport()) return fail('');
	 if(!meterEnsureAppliedGeneratorSettings()) return fail('');
 meterActiveSeriesType='greyscale';
 meterActiveSeriesPoints=26;
 meterActiveSeriesKey='greyscale-26';
 meterShowGreyscaleAutoCalContext();
 meterResetSeriesButtons();
 const autoCalSeriesBtn=document.querySelector('#meterSeriesBtnRow button[data-series="greyscale-26"]');
 if(autoCalSeriesBtn){autoCalSeriesBtn.classList.remove('btn-secondary');autoCalSeriesBtn.classList.add('btn-primary');}
 meterSetActiveSeriesChartContext();
 meterSeriesSteps=meterBuildStepsJS('greyscale',26);
	 const adjustable=meterSeriesSteps.filter(step=>meterGreyTvTargetAdjustable(meterGreyTvTarget(step)));
 if(!adjustable.length) return fail('No LG-adjustable greyscale points are available');
 const whiteStep=meterAutoCalWhiteStep();
 if(!whiteStep) return fail('100% white is required before LG Auto Cal can start');
 meterStopContinuous();
 if(meterAutoCalPolling){clearInterval(meterAutoCalPolling);meterAutoCalPolling=null;}
 if(meterLg3dAutoCalPolling){clearInterval(meterLg3dAutoCalPolling);meterLg3dAutoCalPolling=null;}
 meterAutoCalStopRequested=false;
	 meterAutoCalPhase='disclaimer';
	 meterAutoCalSetupReading=null;
	 meterAutoCalPendingConfig=null;
	 meterAutoCalStandaloneMagicWandEnabled=false;
	 meterAutoCalMagicWandActive=false;
	 meterAutoCalMagicWandBaseStatus=null;
	 meterAutoCalMagicWandFullWorkflow=false;
			 meterAutoCalCapturedTargetY=0;
		 meterAutoCalResetPanelLightState();
		 meterAutoCalLuminanceReadBusy=false;
 meterAutoCalResetNotice='';
 meterAutoCalPreflightResetDone=false;
 meterAutoCalPreflightLgGeneration=null;
 meterAutoCalResetInProgress=false;
 meterReadings=[];
 meterAutoCalLevelPreflight=null;
 meterWhiteReading=null;
 meterCurrentPatchStep=null;
 meterSelectedThumbIre=null;
 meterLastChartCount=0;
 meterLastChartSignature='';
 meterActiveSeriesType='greyscale';
 meterSetActiveSeriesChartContext();
 document.getElementById('meterExportRow').style.display='';
 meterSetWorkflowProgress({status:'running',current_step:0,total_steps:adjustable.length||26,current_name:'LG Auto Cal setup...'},{workflow:fullWorkflow?'full':'greyscale',label:'LG Auto Cal setup...'});
 const sortedSteps=meterGreyscaleSeriesSteps(meterSeriesSteps);
 meterBuildPatchThumbs(sortedSteps,new Set(),null);
 drawAllChartsPreset(sortedSteps);
 const dtype=getEffectiveDisplayType();
 const patternSignalRange=meterLgAutoCalUsesExtendedSdr()?'1':meterMeasurementPatchSignalRange();
 const wp=meterTargetWhitePoint();
 meterAutoCalPendingConfig={
  dtype,
  patternSignalRange,
	  wp,
	  adjustable,
	  whiteStep,
	  fullWorkflow:fullWorkflow,
	  postCommitPolishEnabled:fullWorkflow?meterFullAutoCalPostCommitPolishEnabled():true,
	  magicWandEnabled:false
	 };
 if(fullWorkflow) meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:'Before LG Auto Cal',message:meterAutoCalPreflightResetPrompt()});
 else meterAutoCalShowPreflightOptions();
 meterActionPending=true;
 meterUpdateReadButtons();
 return true;
}

async function meterAutoCalAcceptDisclaimer(){
 if(!meterAutoCalPendingConfig||!meterAutoCalPendingConfig.whiteStep){toast('Auto Cal setup is not ready',true);return;}
 if(!meterAutoCalPreflightResetDone){toast((meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?'Run the LG picture mode and 3D LUT reset first.':'Run the LG picture mode reset first.',true);return;}
 meterAutoCalPhase='preflight';
 meterActionPending=true;
 const whiteStep=meterAutoCalPendingConfig.whiteStep;
 try{
  if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
  if(meterAutoCalRequiresLuminanceSetup()){
   meterAutoCalLevelPreflight={skipped:true};
   const setupReading=await meterAutoCalLuminanceSetupLoop(whiteStep);
   if(meterAutoCalStopRequested) throw new Error('LG Auto Cal stopped');
   if(setupReading){
    meterAutoCalSetupReading=setupReading;
    meterUpsertSeriesReading(setupReading,whiteStep);
    meterWhiteReading=setupReading;
   }
  }else{
   meterAutoCalLevelPreflight={skipped:true};
   meterAutoCalLuminanceSetupActive=false;
   meterAutoCalSetupReading=null;
   meterAutoCalCapturedTargetY=0;
  }
  meterActionPending=false;
  meterAutoCalShowConfirm();
 }catch(e){
  meterAutoCalLuminanceSetupActive=false;
  meterActionPending=false;
  if(meterAutoCalStopRequested){
   meterAutoCalSetOverlay(false,null);
   meterAutoCalRunning=false;
   toast('LG Auto Cal stopped');
  }else{
   const message=(e&&e.message)?e.message:'Unable to start meter session';
   meterAutoCalPhase='disclaimer';
   meterAutoCalRunning=true;
   meterAutoCalSetOverlay(true,{phase:'disclaimer',current_name:'Meter setup failed',message:message+'. Check the meter, then click Continue to retry.'});
   toast(message,true);
  }
 }finally{
  meterUpdateReadButtons();
 }
}

async function meterAutoCalConfirmAndStart(){
	 if(!meterAutoCalPendingConfig){toast('Auto Cal setup is not ready',true);return;}
	 if(meterAutoCalPhase==='options'){
	  meterAutoCalAcceptPreflightOptions();
	  return;
	 }
	 const target=meterAutoCalTargetDeltaValue();
	 const deltaEFormula='deitp';
	 const fullWorkflow=!!(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow);
	 const signalMode=meterLgAutoCalRequestedSignalMode();
	 const hdrWorkflow=signalMode==='hdr10';
	 // HDR greyscale is calibrated to a 2.2 power target -> set the TARGET
	 // GAMMA selector to 2.2 as the autocal starts so the charts grade against
	 // the curve we calibrate to. SDR keeps the operator's choice.
	 if(hdrWorkflow){
	  const tgEl=document.getElementById('meterTargetGamma');
	  if(tgEl && tgEl.value!=='2.2'){ tgEl.value='2.2'; }
	  meterActiveSeriesTargetGamma='2.2';
	  try{ meterSaveColorPrefs(); }catch(e){}
	 }
	 const setupY=hdrWorkflow?undefined:meterAutoCalSetupYValue();
	 const targetY=hdrWorkflow?undefined:meterAutoCalTargetYValue();
	 const headroomY=hdrWorkflow?undefined:meterAutoCalHeadroomTargetYValue(setupY);
		 const firstFullGreyscalePass=!!(fullWorkflow&&meterFullAutoCalRunning&&meterFullAutoCalPhase==='first-greyscale');
		 const capturedGreyscaleOptions=!!(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.greyscaleOptionsCaptured);
		 const postCommitPolishEnabled=firstFullGreyscalePass?false:(capturedGreyscaleOptions?meterAutoCalPendingConfig.postCommitPolishEnabled!==false:meterAutoCalPostCommitPolishChoiceValue());
		 const postCommitVerifyEnabled=false;
		 const magicWandEnabled=(!fullWorkflow&&capturedGreyscaleOptions&&meterAutoCalPendingConfig.magicWandEnabled!==false)?true:false;
		 meterAutoCalPendingConfig.postCommitPolishEnabled=postCommitPolishEnabled;
		 meterAutoCalPendingConfig.magicWandEnabled=magicWandEnabled;
		 meterAutoCalStandaloneMagicWandEnabled=magicWandEnabled;
	 if(!hdrWorkflow&&Number.isFinite(targetY)&&targetY>0) meterStoreLgTargetWhiteReference(targetY,meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow?'full-autocal':'greyscale-autocal',meterFullAutoCalRunId||null);
 const dtype=meterAutoCalPendingConfig.dtype;
 const patternSignalRange=meterAutoCalPendingConfig.patternSignalRange;
 const wp=meterAutoCalPendingConfig.wp;
 const autocalSteps=meterAutoCalBuildBackendSteps(meterAutoCalPendingConfig.whiteStep,meterSeriesSteps);
 if(meterFullAutoCalRunning&&meterFullAutoCalPhase==='first-greyscale'){
  meterFullAutoCalConfig={
	   ...(meterFullAutoCalConfig||{}),
	   targetDelta:target,
	   deltaEFormula:deltaEFormula,
	   signalMode:signalMode,
	   targetY:hdrWorkflow?undefined:targetY,
	   setupY:hdrWorkflow?undefined:setupY,
	   headroomY:headroomY,
	   dtype:dtype,
   patternSignalRange:patternSignalRange,
   wp:wp,
   method:(meterFullAutoCalConfig&&meterFullAutoCalConfig.method)||meterFullAutoCalMethodValue(),
   upload:meterFullAutoCalConfig?!!meterFullAutoCalConfig.upload:meterFullAutoCalUploadValue()
  };
  meterFullAutoCalSaveState();
 }
 meterAutoCalPhase='running';
 meterActionPending=true;
 meterAutoCalSetOverlay(true,{
  current_name:'Starting RGB Auto Cal...',
  message:hdrWorkflow
   ? 'HDR 100% will set the ST 2084 peak reference'
   : 'Using 100% target '+targetY.toFixed(2)+' cd/m\u00B2 and 109% target '+headroomY.toFixed(2)+' cd/m\u00B2',
  total_steps:meterAutoCalPendingConfig.adjustable.length,
  current_step:0
 });
 try{
  const r=await fetchJSON('/api/meter/lg-autocal',{
   method:'POST',
   headers:{'Content-Type':'application/json'},
   body:JSON.stringify(meterMeasurementSignalContext({
    type:'greyscale',
    points:26,
    display_type:dtype,
    delay_ms:meterDelayMs(),
    patch_size:getMeterPatchSize(),
    signal_range:getVal('rgb_quant_range'),
    pattern_signal_range:patternSignalRange||undefined,
    lg_greyscale_21:false,
    lg_autocal_26:true,
    lg_autocal_26_full_ddc_spine:meterAutoCalUseFullDdcSpine(),
    lg_autocal_26_anchor_predrive:false,
    lg_extended_sdr_16_255:meterLgAutoCalUsesExtendedSdr(),
    ...meterPatternInsertionPayload(),
    target_delta_e:target,
    delta_e_formula:deltaEFormula,
    target_luminance:hdrWorkflow?undefined:targetY,
    setup_luminance_reference:hdrWorkflow?undefined:setupY,
    headroom_target_luminance:headroomY,
    target_gamma:meterLgAutoCalGreyscaleTargetGammaValue(),
    target_white:{x:wp.x,y:wp.y},
    picture_mode:meterLgPictureModeValue(),
    ...meterLgAutoCalBodyLumaBiasPayload(dtype),
		    force_ddc_white_balance:true,
		    restore_factory_levels:false,
		    reset_ddc_baseline:false,
		    full_workflow:(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?true:undefined,
		    full_autocal_run_id:(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?meterFullAutoCalRunId||undefined:undefined,
		    full_autocal_phase:(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?'first-greyscale':undefined,
		    full_autocal_post_commit_polish:(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?meterFullAutoCalPostCommitPolishEnabled():undefined,
		    full_autocal_magic_wand:(meterAutoCalPendingConfig&&meterAutoCalPendingConfig.fullWorkflow)?meterFullAutoCalMagicWandEnabled():undefined,
		    post_commit_polish:postCommitPolishEnabled,
		    post_commit_verify:postCommitVerifyEnabled,
		    post_commit_body_polish:postCommitPolishEnabled?undefined:false,
		    post_commit_top_window:postCommitPolishEnabled?undefined:false,
		    post_commit_body_verify:postCommitVerifyEnabled,
		    post_commit_final_all_level_verify:postCommitVerifyEnabled,
		    post_commit_final_top_window:postCommitVerifyEnabled,
		    post_commit_polish_iterations:undefined,
		    post_commit_low_shadow_iterations:undefined,
		    post_commit_true_low_shadow:postCommitPolishEnabled?undefined:false,
		    post_commit_low_shadow_committed_iterations:undefined,
		    post_commit_settle_ms:undefined,
		    post_commit_white_resettle_ms:undefined,
		    post_commit_low_shadow_settle_ms:undefined,
		    post_commit_low_shadow_read_settle_ms:undefined,
	    refresh_rate:getMeterRefreshRate()||undefined,
    require_device_ready:false,
    max_iterations:36,
    headroom_max_iterations:60,
    max_polish_iterations:16,
    precision_polish_iterations:18,
    low_light:meterLowLightReadState(),
    steps:autocalSteps
   })),
   _timeoutMs:10000
  });
  if(!r||r.status!=='started'){
   meterActionPending=false;
   meterAutoCalPhase='error';
   meterAutoCalClearSavedState();
   if(meterFullAutoCalRunning) meterFullAutoCalResetState(false);
   meterAutoCalSetOverlay(true,{phase:'running',current_name:'LG Auto Cal error',message:(r&&r.message)?r.message:'Unable to start LG Auto Cal',status:'error'});
   toast(r&&r.message?r.message:'Unable to start LG Auto Cal',true);
   return;
  }
  meterAutoCalRunning=true;
  meterAutoCalPollErrors=0;
  meterActionPending=false;
  meterAutoCalSaveState();
  toast('LG Auto Cal started');
  meterAutoCalSetOverlay(false,{phase:'running',current_name:'LG Auto Cal started',message:'Showing live charts'});
  if(meterAutoCalPolling) clearInterval(meterAutoCalPolling);
	  meterAutoCalPolling=setInterval(meterPollAutoCal,1500);
 await meterPollAutoCal();
 }catch(e){
 meterAutoCalRunning=false;
 meterActionPending=false;
 meterAutoCalPhase='error';
 meterAutoCalClearSavedState();
 if(meterFullAutoCalRunning) meterFullAutoCalResetState(false);
 meterAutoCalSetOverlay(true,{phase:'running',current_name:'LG Auto Cal error',message:(e&&e.message)?e.message:'Unable to start LG Auto Cal',status:'error'});
  toast((e&&e.message)?e.message:'Unable to start LG Auto Cal',true);
 }finally{
  meterUpdateReadButtons();
 }
}

