}

// Run full automated series (Read Series button)
async function meterRunSeries(){
 if(meterActionPending){toast('Meter operation already in progress',true);return false;}
 if(!(await meterEnsureDetected())){toast('No meter detected',true);return false;}
 if(!meterSeriesSteps||!meterActiveSeriesType){toast('Select a series first',true);return false;}
 if(!meterEnsureAppliedGeneratorSettings()) return false;
 meterHdrAutoCalChartContextHeld=false;
	 // Rebuild the local preview steps from the current UI state before starting.
	 // Without this, rerunning the same series key can keep stale step codes from
	 // a previous mode/range selection and then stamp them back onto fresh reads.
	 meterSetActiveSeriesChartContext();
	 meterSeriesSteps=meterBuildStepsJS(meterActiveSeriesType,meterActiveSeriesPoints);
 meterStopContinuous();
 meterSelectedThumbIre=null;
 meterReadings=[];
 meterWhiteReading=null;
 meterCurrentPatchStep=null;
 _selectedColorReadingName=null;
 _colorDetailPinned=false;
 meterSeriesRunning=true;
 meterSeriesAwaitingReady=false;
 meterSeriesSpectroSetupActive=false;
 meterReadySignalPending=false;
 meterLastChartCount=0;
 meterGreyscaleLowEndPinned=false;
 meterGreyscaleLastCurrentKey=null;
 meterSharedSeriesId=null;
 document.getElementById('meterExportRow').style.display='';
 document.getElementById('meterProgress').style.display='';
 document.getElementById('meterProgressLabel').textContent='Connecting to meter...';
 document.getElementById('meterReadSeriesBtn').innerHTML='&#9209; Reading Series';
 document.getElementById('meterReadSeriesBtn').classList.remove('btn-secondary');
 document.getElementById('meterReadSeriesBtn').classList.add('btn-success');
 const sortedSteps=(meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations')?[...meterSeriesSteps]:meterGreyscaleSeriesSteps(meterSeriesSteps);
 meterBuildPatchThumbs(sortedSteps,new Set(),null);
 drawAllChartsPreset(sortedSteps);
 meterClearLiveReading();
 showColorReadingDetail(null,{pin:false});
 meterActionPending=true;
 meterUpdateReadButtons();
 const dtype=getEffectiveDisplayType();
 const delay=meterDelayMs();
 const psize=getMeterPatchSize();
 const patternSignalRange=meterMeasurementPatchSignalRange();
 const requireDeviceReady=meterSelectedMeasurementRequiresReady();
 const recoverStartedSeries=async()=>{
  try{
   const s=await fetchJSON('/api/meter/series/status',{_quiet:true,_timeoutMs:8000});
   const state=String((s&&s.status)||'').toLowerCase();
   if(s&&s.series_id&&(state==='running'||state==='setup')){
    meterSetActiveSeriesChartContext(s);
    meterSharedSeriesId=String(s.series_id);
    if(meterSeriesPolling) clearInterval(meterSeriesPolling);
    meterSeriesPolling=setInterval(meterPollSeries,meterSeriesPollIntervalMs);
    await meterPollSeries();
    return true;
   }
  }catch(_e){}
  return false;
 };
 try{
	  const _seriesBody=meterMeasurementSignalContext({type:meterActiveSeriesType,points:meterActiveSeriesPoints,display_type:dtype,target_gamut:(document.getElementById('meterTargetGamut')||{}).value||'auto',target_gamma:meterAutoCalTargetGammaValue(),picture_mode:meterLgPictureModeValue(),delay_ms:delay,patch_size:psize,signal_range:getVal('rgb_quant_range'),pattern_signal_range:patternSignalRange||undefined,...meterPatternInsertionPayload(),refresh_rate:getMeterRefreshRate()||undefined,series_target_white_y:meterColorSeriesTargetWhiteForRun(meterActiveSeriesType,meterActiveSeriesPoints)||undefined,grey_custom_enabled:meterGreyCustomEnabled(),lg_greyscale_21:meterUseLgGreyscale21(meterActiveSeriesPoints),lg_autocal_26:meterUseLgAutoCal26(meterActiveSeriesPoints),lg_extended_sdr_16_255:meterLgGreyscaleUsesExtendedSdr(meterActiveSeriesPoints),grey_steps_11:meterGreyStimulusCsv(11),grey_steps_21:meterGreyStimulusCsv(21),grey_steps_30:meterGreyStimulusCsv(30),grey_steps_100:meterGreyStimulusCsv(100),grey_steps_11_r:meterGreyChannelCsv(11,'r'),grey_steps_11_g:meterGreyChannelCsv(11,'g'),grey_steps_11_b:meterGreyChannelCsv(11,'b'),grey_steps_21_r:meterGreyChannelCsv(21,'r'),grey_steps_21_g:meterGreyChannelCsv(21,'g'),grey_steps_21_b:meterGreyChannelCsv(21,'b'),grey_steps_30_r:meterGreyChannelCsv(30,'r'),grey_steps_30_g:meterGreyChannelCsv(30,'g'),grey_steps_30_b:meterGreyChannelCsv(30,'b'),grey_steps_100_r:meterGreyChannelCsv(100,'r'),grey_steps_100_g:meterGreyChannelCsv(100,'g'),grey_steps_100_b:meterGreyChannelCsv(100,'b'),grey_two_point_low:meterTwoPointValues().low,grey_two_point_high:meterTwoPointValues().high,require_device_ready:requireDeviceReady});
	  // Pass the calibration-card low-light handler through to the
	  // server so series reads honor the same gear as autocal/single.
	  // Without this, the series start body has no low_light field and
	  // the server-side parser coerces the missing value to "off" (and
	  // the launch command is identical to no-handler at all).
	  const _ll=meterLowLightReadState();
	  if(_ll) _seriesBody.low_light=_ll;
	  const r=await fetchJSON('/api/meter/series',{method:'POST',headers:{'Content-Type':'application/json'},
		   body:JSON.stringify(_seriesBody),_timeoutMs:10000});
	  if(!r||r.status!=='started'){
   if(await recoverStartedSeries()) return true;
	   toast(r&&r.message?r.message:'Failed to start series',true);
	   meterSeriesRunning=false;
	   meterSeriesAwaitingReady=false;
	   meterReadySignalPending=false;
   document.getElementById('meterReadSeriesBtn').innerHTML='&#9654; Read Series';
   document.getElementById('meterReadSeriesBtn').classList.add('btn-secondary');
   document.getElementById('meterReadSeriesBtn').classList.remove('btn-success');
   return false;
	  }
	  toast('Series started: '+r.total_steps+' steps');
	  meterSetActiveSeriesChartContext(r);
	  if(r.series_id) meterSharedSeriesId=String(r.series_id);
  if(meterSeriesPolling) clearInterval(meterSeriesPolling);
  meterSeriesPolling=setInterval(meterPollSeries,meterSeriesPollIntervalMs);
	  await meterPollSeries();
	  return true;
 }catch(e){
  if(await recoverStartedSeries()) return true;
  toast((e&&e.message)?('Failed to start series: '+e.message):'Failed to start series',true);
  meterSeriesRunning=false;
  meterSeriesAwaitingReady=false;
  meterSeriesSpectroSetupActive=false;
  meterReadySignalPending=false;
  meterSpectroSetupApply(null);
  document.getElementById('meterReadSeriesBtn').innerHTML='&#9654; Read Series';
  document.getElementById('meterReadSeriesBtn').classList.add('btn-secondary');
  document.getElementById('meterReadSeriesBtn').classList.remove('btn-success');
  return false;
	 } finally {
	  meterActionPending=false;
	  meterUpdateReadButtons();
	 }
}

async function meterPollSeries(){
 if(meterSeriesPollInFlight) return;
 meterSeriesPollInFlight=true;
 try{
 const r=await fetchJSON('/api/meter/series/status',{_quiet:true,_timeoutMs:5000});
 if(!r) return;
 if(!meterSeriesRunning&&r.status!=='cleared'){
  if(meterSeriesPolling){
   clearInterval(meterSeriesPolling);
   meterSeriesPolling=null;
  }
  meterSeriesAwaitingReady=false;
  meterSeriesSpectroSetupActive=false;
  meterReadySignalPending=false;
  meterSpectroSetupApply(null);
  return;
 }
		 meterSeriesAwaitingReady=!!r.awaiting_ready;
		 meterSeriesSpectroSetupApplyFromStatus(r);
		 meterSetActiveSeriesChartContext(r);
		 if(Array.isArray(r.steps)&&r.steps.length>0){
	  meterSeriesSteps=meterCanonicalRecoveredSteps(meterActiveSeriesType,meterActiveSeriesPoints,r.steps,r.status||'running');
	  meterSeriesSteps=meterApplyColorSeriesTargetWhiteReference(meterSeriesSteps,meterActiveSeriesType);
	 }
 if(r.white_reading&&r.white_reading.luminance!=null){
  meterWhiteReading=r.white_reading;
  if(meterWhiteReading.synthetic_target) meterWhiteReading=meterSyntheticGreyWhiteReading(meterColorReferenceNits());
  else meterNormalizeMeasuredReading(meterWhiteReading);
 }
 if(r.status==='cleared'){
  if(meterSeriesPolling){
   clearInterval(meterSeriesPolling);
   meterSeriesPolling=null;
  }
  meterSeriesRunning=false;
  meterSeriesAwaitingReady=false;
  meterSeriesSpectroSetupActive=false;
  meterReadySignalPending=false;
  meterSpectroSetupApply(null);
    meterGreyscaleLowEndPinned=false;
    meterGreyscaleLastCurrentKey=null;
  meterSharedSeriesId=null;
  meterApplyClearedState(false);
  return;
 }
 // If the UI is no longer in active series mode, ignore ALL series snapshots
 // so stale pollers can never overwrite newer Read Once / Continuous data.
 if(!meterSeriesRunning){
  if(meterSeriesPolling){
   clearInterval(meterSeriesPolling);
   meterSeriesPolling=null;
  }
  meterSeriesAwaitingReady=false;
  meterSeriesSpectroSetupActive=false;
  meterReadySignalPending=false;
  meterSpectroSetupApply(null);
  return;
 }
 // Build set of completed IRE values for thumbnail highlighting
 const completedIres=new Set();
 let currentIre=null;

	 if(r.readings&&r.readings.length>0) {
	  meterReadings=meterAttachSeriesMeta(meterFilterReadingsForCurrentSteps(r.readings,meterActiveSeriesType));
  // Only set white reference from actual 100% reading — never use
  // "brightest so far" during a running series, because that changes
  // every poll cycle and causes all ΔE / RGB balance values to shift.
  const white=meterFindSeriesWhiteReading(meterReadings);
  if(white) meterWhiteReading=white;
  // If we don't yet have an actual 100% measurement, use the same mode-aware
  // synthetic reference as one-off reads. In SDR this must not inherit HDR
  // metadata max_luma.
  if(!meterWhiteReading||meterWhiteReading.synthetic_target){
   meterWhiteReading=meterSyntheticGreyWhiteReading(meterColorReferenceNits());
  }
  meterReadings.forEach(rd=>{if(rd.luminance!=null) completedIres.add(meterStepNameKey(rd));});
  // Only redraw charts when reading count changes (avoids flicker)
  const validCount=meterReadings.filter(rd=>rd.luminance!=null).length;
  const chartSignature=JSON.stringify(meterReadings.map(rd=>[
   meterStepNameKey(rd),
   rd.luminance!=null?Number(rd.luminance).toFixed(4):'',
   rd.X!=null?Number(rd.X).toFixed(5):'',
   rd.Y!=null?Number(rd.Y).toFixed(5):'',
   rd.Z!=null?Number(rd.Z).toFixed(5):''
  ]));
  if(validCount!==meterLastChartCount || chartSignature!==meterLastChartSignature){
   meterLastChartCount=validCount;
   meterLastChartSignature=chartSignature;
   const isColor=meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations';
   const sorted=isColor?[...meterReadings]:[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
   drawAllCharts(sorted);
   meterCacheSeriesState(r.status||'running');
  }
 }

 if(r.total_steps>0){
  const label=r.current_name||('Step '+r.current_step+'/'+r.total_steps);
  if(meterInternalSeriesWorkflow&&meterInternalSeriesWorkflow.workflow){
   meterSetWorkflowProgress(r,{workflow:meterInternalSeriesWorkflow.workflow,label:meterInternalSeriesWorkflow.label||label});
  }else{
   document.getElementById('meterProgressLabel').textContent=label;
  }
  currentIre=meterCurrentSeriesStepKeyFromStatus(r);
  const currentStep=meterFindCurrentSeriesStep(currentIre);
  if(currentStep&&meterActiveSeriesType==='greyscale') meterCurrentPatchStep=meterClonePatchStep(currentStep)||currentStep;
 }

 // Update patch thumbnails with completion state
 if(meterSeriesSteps){
  const isColor2=meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations';
  const sortedSteps=isColor2?[...meterSeriesSteps]:meterGreyscaleSeriesSteps(meterSeriesSteps);
  meterBuildPatchThumbs(sortedSteps,completedIres,currentIre);
 }

 // Update live reading with the status-current patch when its reading has
 // landed; otherwise keep showing the latest completed patch during the
 // in-flight read.
 let liveSeriesReading=null;
 if(meterReadings&&meterReadings.length>0){
  const currentReading=meterCurrentPatchStep?meterFindReadingForStep(meterCurrentPatchStep):null;
  const lastValid=[...meterReadings].reverse().find(rd=>rd.luminance!=null);
  liveSeriesReading=currentReading||lastValid||null;
  if(liveSeriesReading) updateLiveReading(liveSeriesReading);
 }
 if(!liveSeriesReading&&meterSeriesRunning&&meterActiveSeriesType==='greyscale'&&meterCurrentPatchStep){
  meterRenderGreyTvControls(meterCurrentPatchStep);
 }

 if(r.status==='complete'||r.status==='cancelled'||r.status==='error'){
  clearInterval(meterSeriesPolling);
  meterSeriesPolling=null;
  meterSeriesRunning=false;
  meterSeriesAwaitingReady=false;
  meterSeriesSpectroSetupActive=false;
  meterReadySignalPending=false;
  meterSpectroSetupApply(null);
    meterGreyscaleLowEndPinned=false;
    meterGreyscaleLastCurrentKey=null;
  document.getElementById('meterDot').style.background=meterDetected?'var(--green)':'var(--text2)';
  document.getElementById('meterReadSeriesBtn').innerHTML='&#9654; Read Series';
  document.getElementById('meterReadSeriesBtn').classList.add('btn-secondary');
  document.getElementById('meterReadSeriesBtn').classList.remove('btn-success');
  // Clear the "currently reading" pulse on the last-polled thumb.
  if(meterSeriesSteps){
   const isColor3=meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations';
   const sortedSteps2=isColor3?[...meterSeriesSteps]:meterGreyscaleSeriesSteps(meterSeriesSteps);
   meterBuildPatchThumbs(sortedSteps2,completedIres,null);
  }
  if(!(meterInternalSeriesWorkflow&&meterFullAutoCalRunning)){
   document.getElementById('meterProgress').style.display='none';
  }
  toast(r.status==='complete'?'Series complete!':r.status==='error'?'Series error: '+(r.current_name||'process died'):'Series cancelled');
 }
 meterUpdateReadButtons();
 } finally {
  meterSeriesPollInFlight=false;
 }
}

let meterSelectedThumbIre=null;
let meterThumbsBuilt=false; // track if thumbnails are already built for current series
let meterGreyscaleScrollRatio=0;
let meterGreyscaleScrollSyncing=false;
let meterGreyscaleScrollFrame=0;
let meterGreyscaleLowEndPinned=false;
let meterGreyscaleLastCurrentKey=null;

function meterGreyscaleScrollSource(){
 return document.getElementById('meterThumbsRow');
}

function meterThumbsWrap(){
 return document.getElementById('meterThumbsWrap');
}

function meterSetThumbsVisible(visible){
 const wrap=meterThumbsWrap();
 if(!wrap) return;
 wrap.style.display=visible?'flex':'none';
 meterUpdateThumbScrollButtons();
}

function meterThumbsPage(direction){
 const row=meterGreyscaleScrollSource();
 if(!row) return;
 const max=meterGreyscaleScrollMax(row);
 if(max<=0) return;
 const current=row.scrollLeft||0;
 const delta=Math.max(120,Math.round((row.clientWidth||0)*0.82))*(direction<0?-1:1);
 const next=Math.max(0,Math.min(max,current+delta));
 row.scrollLeft=next;
 meterUpdateThumbScrollButtons();
}

function meterUpdateThumbScrollButtons(){
 const wrap=meterThumbsWrap();
 const row=meterGreyscaleScrollSource();
 const left=document.getElementById('meterThumbsLeftBtn');
 const right=document.getElementById('meterThumbsRightBtn');
 if(!wrap||!row||!left||!right) return;
 const wrapVisible=getComputedStyle(wrap).display!=='none';
 const max=meterGreyscaleScrollMax(row);
 const hasOverflow=wrapVisible&&max>4;
 left.style.display=hasOverflow?'inline-flex':'none';
 right.style.display=hasOverflow?'inline-flex':'none';
 const pos=row.scrollLeft||0;
 left.disabled=!hasOverflow||pos<=1;
 right.disabled=!hasOverflow||pos>=max-1;
}

function meterSeriesThumbsUseScroll(stepCount){
 const count=Math.max(0,Number(stepCount)||0);
 const mobile=(window.matchMedia&&window.matchMedia('(max-width:800px)').matches) || window.innerWidth<=800;
 if(meterActiveSeriesType==='colors' || meterActiveSeriesType==='saturations') return true;
 if(count>64) return true;
 return !!(mobile && count>11);
}

function meterSeriesThumbWidth(step){
 const isColorSeries=(meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations');
 if(isColorSeries){
  const name=String((step&&step.name)||'').trim();
  if(name.length>12) return 60;
  if(name.length>8) return 54;
  return 46;
 }
 return 34;
}

function meterSeriesThumbContentWidth(sortedSteps,row){
 const steps=Array.isArray(sortedSteps)?sortedSteps:[];
 const viewport=Math.max(320,Math.round((row&&row.clientWidth)||0)||800);
 let total=0;
 steps.forEach((step,idx)=>{
  total+=meterSeriesThumbWidth(step);
  if(idx<steps.length-1) total+=2;
 });
 return Math.max(viewport,total);
}

function meterGreyscaleScrollTargets(){
 const ids=['meterRgbChartScroller','meterDeltaEScroller','meterGammaValueScroller'];
 return ids.map(id=>document.getElementById(id)).filter(Boolean);
}

function meterGreyscaleScrollElements(){
 const source=meterGreyscaleScrollSource();
 return (source?[source]:[]).concat(meterGreyscaleScrollTargets());
}

function meterGreyscaleCanvasPairs(){
 return [
  ['meterRgbChartScroller','chartRGB'],
  ['meterDeltaEScroller','chartDeltaE'],
  ['meterGammaValueScroller','chartGammaValue']
 ];
}

function meterGreyscaleStaticCanvasPairs(){
 return [
  ['meterEotfScroller','chartEOTF'],
  ['meterLuminanceScroller','chartGamma']
 ];
}

function meterGreyscaleScrollMax(el){
 if(!el) return 0;
 return Math.max(0,(el.scrollWidth||0)-(el.clientWidth||0));
}

function meterGreyscaleScrollRatioFor(el){
 const max=meterGreyscaleScrollMax(el);
 return max>0 ? Math.max(0,Math.min(1,el.scrollLeft/max)) : 0;
}

function meterSetGreyscaleScrollRatio(el,ratio){
 if(!el) return;
 const max=meterGreyscaleScrollMax(el);
 el.scrollLeft=max>0 ? Math.max(0,Math.min(1,ratio))*max : 0;
 if(el===meterGreyscaleScrollSource()) meterUpdateThumbScrollButtons();
}

function meterGreyscaleStepPercent(key){
 if(key==null) return null;
 const match=String(key).trim().match(/^(-?\d+(?:\.\d+)?)%$/);
 if(!match) return null;
 const value=parseFloat(match[1]);
 return Number.isFinite(value) ? value : null;
}

function meterGreyscaleLowEndGracePercent(row,thumb){
 const viewport=Math.max(1,Math.round((row&&row.clientWidth)||0));
 const thumbWidth=Math.max(1,Math.round((thumb&&thumb.offsetWidth)||34));
 return Math.min(100,Math.max(8,Math.ceil(viewport/thumbWidth)+6)-1);
}

function meterUpdateGreyscaleLowEndPin(key,row,thumb){
 const currentPct=meterGreyscaleStepPercent(key);
 const lastPct=meterGreyscaleStepPercent(meterGreyscaleLastCurrentKey);
 if(currentPct==null){
  meterGreyscaleLastCurrentKey=key;
  return false;
 }
 const gracePct=meterGreyscaleLowEndGracePercent(row,thumb);
 if(lastPct!=null&&lastPct>=95&&currentPct<=gracePct) meterGreyscaleLowEndPinned=true;
 if(meterGreyscaleLowEndPinned&&currentPct>gracePct) meterGreyscaleLowEndPinned=false;
 meterGreyscaleLastCurrentKey=key;
 return meterGreyscaleLowEndPinned;
}

function meterEnsureThumbVisible(container,key){
 if(!container||!key) return;
 const row=meterGreyscaleScrollSource();
 if(!row) return;
 const thumb=Array.from(container.children||[]).find(child=>(child.dataset.key||'')===key);
 if(!thumb) return;
 if(meterUpdateGreyscaleLowEndPin(key,row,thumb)){
  meterGreyscaleScrollRatio=0;
  row.scrollLeft=0;
  meterUpdateThumbScrollButtons();
  meterQueueGreyscaleTargetSync();
  return;
 }
 const max=meterGreyscaleScrollMax(row);
 const rowLeft=row.scrollLeft||0;
 const rowRight=rowLeft+(row.clientWidth||0);
 const thumbLeft=thumb.offsetLeft||0;
 const thumbRight=thumbLeft+(thumb.offsetWidth||0);
 let nextLeft=rowLeft;
 if(thumbLeft < rowLeft) nextLeft=thumbLeft;
 else if(thumbRight > rowRight) nextLeft=thumbRight-(row.clientWidth||0);
 nextLeft=Math.max(0,Math.min(max,nextLeft));
 const nextRatio=max>0 ? nextLeft/max : 0;
 if(Math.abs(nextLeft-rowLeft)<1){
  meterGreyscaleScrollRatio=nextRatio;
  meterQueueGreyscaleTargetSync();
  meterUpdateThumbScrollButtons();
  return;
 }
 meterGreyscaleScrollRatio=nextRatio;
 row.scrollLeft=nextLeft;
 meterUpdateThumbScrollButtons();
 meterQueueGreyscaleTargetSync();
}

function meterCurrentSeriesStepKeyFromStatus(status){
 if(!status) return null;
 const steps=(Array.isArray(status.steps)&&status.steps.length>0)
  ? status.steps
  : (Array.isArray(meterSeriesSteps)&&meterSeriesSteps.length>0 ? meterSeriesSteps : null);
 const stepIndex=(Number(status.current_step)||0)-1;
 if(steps&&stepIndex>=0&&stepIndex<steps.length) return meterStepNameKey(steps[stepIndex]);
 const name=String(status.current_name||'').trim();
 if(!name) return null;
 const stripped=name.replace(/\s+\((displaying|reading|click Device Ready when positioned|reposition meter and click Device Ready|complete meter setup\/calibration and click Device Ready)\)$/i,'');
 return stripped||name;
}

function meterFindCurrentSeriesStep(key){
 if(!key||!Array.isArray(meterSeriesSteps)||!meterSeriesSteps.length) return null;
 const text=String(key);
 return meterSeriesSteps.find(step=>{
  if(meterStepNameKey(step)===text) return true;
  if(String(step&&step.name||'')===text) return true;
  return meterReadingPatchLabel(step)===text;
 })||null;
}

function meterQueueGreyscaleTargetSync(){
 if(meterGreyscaleScrollFrame) return;
 meterGreyscaleScrollFrame=window.requestAnimationFrame(()=>{
  meterGreyscaleScrollFrame=0;
  meterGreyscaleScrollTargets().forEach(el=>meterSetGreyscaleScrollRatio(el,meterGreyscaleScrollRatio));
 });
}

function meterGreyscaleChartContentWidth(stepCount,viewportWidth){
 const count=Math.max(0,Number(stepCount)||0);
 const viewport=Math.max(320,Number(viewportWidth)||0);
 return Math.max(viewport,Math.round(count*36+90));
}

function meterGreyscaleRotateXLabels(stepCount){
 return Number(stepCount)>=21;
}

function meterNiceAxisStep(value){
 if(!(value>0)) return 1;
 const magnitude=Math.pow(10,Math.floor(Math.log10(value)));
 const normalized=value/magnitude;
 const step=normalized<=1?1:(normalized<=2?2:(normalized<=2.5?2.5:(normalized<=5?5:10)));
 return step*magnitude;
}

function meterNiceLinearAxis(minValue,maxValue,steps,options){
 const opts=options||{};
 const stepCount=Math.max(1,Number(steps)||4);
 let min=Number(minValue);
 let max=Number(maxValue);
 if(!Number.isFinite(min)||!Number.isFinite(max)){
  min=0;
  max=1;
 }
 if(max<min){ const swap=min; min=max; max=swap; }
 const minSpan=Number.isFinite(opts.minSpan)?opts.minSpan:0;
 if(max-min<minSpan){
  const mid=(min+max)/2;
  min=mid-minSpan/2;
  max=mid+minSpan/2;
 }
 const rawStep=Math.max((max-min)/stepCount,1e-6);
 const step=meterNiceAxisStep(rawStep);
 let niceMin=Math.floor(min/step)*step;
 let niceMax=Math.ceil(max/step)*step;
 if(Number.isFinite(opts.clampMin)) niceMin=Math.max(opts.clampMin,niceMin);
 if(Number.isFinite(opts.clampMax)) niceMax=Math.min(opts.clampMax,niceMax);
 if(Number.isFinite(opts.preferMin)) niceMin=Math.min(niceMin,opts.preferMin);
 if(Number.isFinite(opts.preferMax)) niceMax=Math.max(niceMax,opts.preferMax);
 if(niceMax-niceMin<step*stepCount){
  niceMax=niceMin+step*stepCount;
  if(Number.isFinite(opts.clampMax) && niceMax>opts.clampMax){
   niceMax=opts.clampMax;
   niceMin=niceMax-step*stepCount;
  }
 }
 if(Number.isFinite(opts.clampMin) && niceMin<opts.clampMin) niceMin=opts.clampMin;
 if(Number.isFinite(opts.clampMax) && niceMax>opts.clampMax) niceMax=opts.clampMax;
 if(!(niceMax>niceMin)) niceMax=niceMin+step*stepCount;
 return {min:niceMin,max:niceMax,step:step};
}

function meterGreyscaleChartPad(basePad,stepCount){
 const pad=Object.assign({},basePad||{t:34,r:15,b:30,l:55});
 if(meterGreyscaleRotateXLabels(stepCount)) pad.b=Math.max(pad.b||0,60);
 return pad;
}

function meterBindGreyscaleScrollSync(){
 const source=meterGreyscaleScrollSource();
 if(!source||source.dataset.greyscaleScrollBound==='1') return;
 source.dataset.greyscaleScrollBound='1';
 source.addEventListener('scroll',()=>{
  if(meterGreyscaleScrollSyncing) return;
  const nextRatio=meterGreyscaleScrollRatioFor(source);
  if(Math.abs(nextRatio-meterGreyscaleScrollRatio)<0.0005) return;
  meterGreyscaleScrollRatio=nextRatio;
  meterUpdateThumbScrollButtons();
  meterQueueGreyscaleTargetSync();
 },{passive:true});
}

function meterUpdateGreyscaleChartScrollLayout(stepCount){
 const count=Math.max(0,Number(stepCount)||0);
 const scrollMode=(meterActiveSeriesType==='greyscale'&&count>64);
 const thumbRow=document.getElementById('meterThumbsRow');
 const fallbackViewport=Math.max(320,Math.round((thumbRow&&thumbRow.clientWidth)||0)||800);
 meterGreyscaleCanvasPairs().forEach(pair=>{
  const scroller=document.getElementById(pair[0]);
  const canvas=document.getElementById(pair[1]);
  if(!scroller||!canvas) return;
  const viewport=Math.max(320,Math.round(scroller.clientWidth||fallbackViewport));
  if(scrollMode){
   const desired=meterGreyscaleChartContentWidth(count,viewport);
   canvas.style.width=desired+'px';
   canvas.style.minWidth=desired+'px';
   scroller.style.overflowX='hidden';
  } else {
   canvas.style.width='100%';
   canvas.style.minWidth='100%';
   scroller.style.overflowX='hidden';
   scroller.scrollLeft=0;
  }
 });
 meterGreyscaleStaticCanvasPairs().forEach(pair=>{
  const scroller=document.getElementById(pair[0]);
  const canvas=document.getElementById(pair[1]);
  if(!scroller||!canvas) return;
  canvas.style.width='100%';
  canvas.style.minWidth='100%';
  scroller.style.overflowX='hidden';
  scroller.scrollLeft=0;
 });
 if(!scrollMode) meterGreyscaleScrollRatio=0;
 if(meterGreyscaleScrollFrame){
  window.cancelAnimationFrame(meterGreyscaleScrollFrame);
  meterGreyscaleScrollFrame=0;
 }
 meterBindGreyscaleScrollSync();
 meterGreyscaleScrollSyncing=true;
 meterGreyscaleScrollElements().forEach(el=>meterSetGreyscaleScrollRatio(el,meterGreyscaleScrollRatio));
 meterGreyscaleScrollSyncing=false;
 meterUpdateThumbScrollButtons();
}

function meterBuildPatchThumbs(sortedSteps,completedIres,currentIre){
 const container=document.getElementById('meterPatchThumbs');
 if(!container) return;
 const visibleSteps=meterFilterLgAutoCalChartItems(sortedSteps);
 const row=meterGreyscaleScrollSource();
 const scrollMode=meterSeriesThumbsUseScroll(visibleSteps.length);
 container.style.flexWrap='nowrap';
 container.dataset.scrollMode=scrollMode?'1':'0';
 if(scrollMode){
  const contentWidth=meterSeriesThumbContentWidth(visibleSteps,row);
  container.style.width=contentWidth+'px';
  container.style.minWidth=contentWidth+'px';
 } else {
  container.style.width='100%';
  container.style.minWidth='100%';
 }
	 const needsRebuild=(container.children.length!==visibleSteps.length)||visibleSteps.some((step,idx)=>{
	  const child=container.children[idx];
	  const isGrey=meterSeriesStepIsGreyscale(step);
	  const label=isGrey?meterGreyscaleStepLabel(step):(step.name||'');
	  const thumbWidth=scrollMode?String(meterSeriesThumbWidth(step)):'';
	  const colorKey=[step.r,step.g,step.b,step.preview_r,step.preview_g,step.preview_b].join(',');
	  return !child||(child.dataset.key||'')!==meterStepNameKey(step)||(child.textContent||'')!==label||(child.dataset.thumbWidth||'')!==thumbWidth||(child.dataset.colorKey||'')!==colorKey;
 });
 if(needsRebuild){
  container.innerHTML='';
  meterThumbsBuilt=true;
  visibleSteps.forEach(step=>{
   const thumb=document.createElement('div');
    const isGrey=meterSeriesStepIsGreyscale(step);
   const bgColor=meterPreviewColorForStep(step);
   const textColor=meterContrastTextColor(bgColor);
   const textShadow=textColor==='#eee'?'0 1px 2px rgba(0,0,0,.75)':'0 1px 1px rgba(255,255,255,.18)';
  const label=isGrey?meterGreyscaleStepLabel(step):(step.name||'');
  const thumbWidth=scrollMode?meterSeriesThumbWidth(step):0;
  const padX=isGrey?'2px':'1px';
  const flexStyle=scrollMode?('flex:0 0 '+thumbWidth+'px;min-width:'+thumbWidth+'px;'):'flex:1 1 0;min-width:0;';
  thumb.style.cssText=flexStyle+'display:flex;align-items:center;justify-content:center;height:28px;border-radius:3px;cursor:pointer;box-sizing:border-box;font-size:8px;font-weight:700;user-select:none;transition:box-shadow .2s;color:'+textColor+';background:'+bgColor+';text-align:center;line-height:1.1;padding:0 '+padX+';text-shadow:'+textShadow;
   thumb.textContent=label;
   thumb.dataset.ire=step.ire;
   thumb.dataset.r=step.r;
   thumb.dataset.g=step.g;
   thumb.dataset.b=step.b;
   thumb.dataset.name=step.name||'';
  thumb.dataset.thumbWidth=scrollMode?String(thumbWidth):'';
  thumb.dataset.key=meterStepNameKey(step);
	  thumb.dataset.colorKey=[step.r,step.g,step.b,step.preview_r,step.preview_g,step.preview_b].join(',');
	   thumb.addEventListener('click',function(){
	    if(meterSeriesRunning||meterAutoCalStatusActive()) return;
	    meterSelectPatchFromInteraction(step,meterFindReadingForStep(step),{pin:true});
	   });
   container.appendChild(thumb);
  });
 }
 meterUpdateThumbStyles(container,completedIres,currentIre);
 meterUpdateThumbScrollButtons();
 if(currentIre!=null) meterEnsureThumbVisible(container,currentIre);
}
function meterUpdateThumbStyles(container,completedIres,currentIre){
 const hasReadings=completedIres&&completedIres.size>0;
 for(let i=0;i<container.children.length;i++){
  const thumb=container.children[i];
  const key=thumb.dataset.key||thumb.dataset.name||String(thumb.dataset.ire||'');
  const done=completedIres&&completedIres.has(key);
  // All thumbs fully visible always; completed ones get a checkmark overlay
  thumb.style.opacity='1';
	  const isReading=(currentIre!=null&&key===currentIre);
	  const isSelected=(!meterAutoCalStatusActive()&&meterSelectedThumbIre!=null&&key===meterSelectedThumbIre);
  if(isReading){
   thumb.style.boxShadow='';
   thumb.style.animation='thumbPulse 1s ease-in-out infinite';
   thumb.style.zIndex='1';
  } else if(isSelected){
   thumb.style.animation='none';
    thumb.style.boxShadow='inset 0 0 0 3px #fff';
   thumb.style.zIndex='1';
  } else if(done){
   thumb.style.animation='none';
    thumb.style.boxShadow='inset 0 0 0 2px #4caf50';
   thumb.style.zIndex='';
  } else {
   thumb.style.animation='none';
   thumb.style.boxShadow='none';
   thumb.style.zIndex='';
  }
 }
}

// Pre-populate ALL charts with grids and placeholder points before readings
function meterGreyChartX(step,steps,idx){
 if(step && step.ire!=null){
  const ire=Math.max(0,Math.min(100,parseFloat(step.ire)||0));
  return ire/100;
 }
 if(Array.isArray(steps) && steps.length>1) return idx/(steps.length-1);
 return 0.5;
}
function meterGreyCategoryChartX(steps,idx){
 if(Array.isArray(steps) && steps.length>1) return idx/(steps.length-1);
 return 0.5;
}

function meterEotfLuminanceAxisMax(items){
 const list=Array.isArray(items)?items:[];
 let maxIre=100;
 list.forEach(item=>{
  if(!item) return;
  const ire=meterGreyEotfLuminancePlotIre(item);
  if(Number.isFinite(ire)) maxIre=Math.max(maxIre,ire);
 });
 const top=meterGreyAllowsHeadroomTargets()?110:100;
 return Math.max(100,Math.min(top,Math.ceil(maxIre/10)*10));
}

function meterGreyEotfLuminancePlotIre(item){
 if(!item) return null;
 const plot=meterGreyChartPlotIre(item);
 if(Number.isFinite(Number(plot))) return Number(plot);
 const stimulus=meterGreyChartStimulusIre(item);
 return Number.isFinite(Number(stimulus))?Number(stimulus):null;
}

function meterEotfLuminanceMeasuredStepAllowed(mode,step){
 if(!meterEotfLuminanceLogScaleEnabledForMode(mode)) return true;
 const plot=Number(meterGreyEotfLuminancePlotIre(step));
 if(Number.isFinite(plot)&&plot<0) return false;
 const stimulus=Number(meterGreyChartStimulusIre(step));
 if(Number.isFinite(stimulus)&&stimulus<0) return false;
 const code=meterGreyChartTargetCode(step);
 const targetIre=Number.isFinite(stimulus)?stimulus:plot;
 const signal=meterGreyTargetSignal(targetIre,code);
 return !(Number.isFinite(Number(signal))&&Number(signal)<0);
}

function meterGreyEotfLuminanceChartX(step,steps,idx,axisMax){
 const maxPct=Math.max(1,Number(axisMax)||meterEotfLuminanceAxisMax(steps));
 if(step){
  const ire=meterGreyEotfLuminancePlotIre(step);
  if(Number.isFinite(ire)) return Math.max(0,Math.min(maxPct,ire))/maxPct;
 }
 if(Array.isArray(steps) && steps.length>1) return idx/(steps.length-1);
 return 0.5;
}

function meterFilterEotfLuminanceChartItems(items){
 const list=Array.isArray(items)?items:[];
 const maxIre=meterEotfLuminanceAxisMax(list);
 return list.filter(item=>{
  if(typeof meterLgAutoCalChartReferenceWhite==='function'&&meterLgAutoCalChartReferenceWhite(item)) return false;
  const ire=meterGreyEotfLuminancePlotIre(item);
  return Number.isFinite(ire)&&ire<=maxIre+0.001;
 });
}

function meterAnchorOriginPoint(points){
 const pts=Array.isArray(points)?points.slice():[];
 if(!pts.length || pts[0][0] > 0.0001) pts.unshift([0,0]);
 return pts;
}

function meterGammaValueAnchorPoints(points){
 const pts=Array.isArray(points)?points.slice():[];
 // Gamma charts should start at the first real measured step rather than
 // adding an artificial 0% origin point, which makes the curve look pinned
 // to black in a misleading way.
 return pts;
}

function meterUseLgAutoCal26GammaAxis(){
 return meterActiveSeriesType==='greyscale' && meterUseLgAutoCal26(meterActiveSeriesPoints);
}

function meterFilterGammaChartItems(items){
 const list=Array.isArray(items)?items:[];
 if(!meterUseLgAutoCal26GammaAxis()) return list;
 return list.filter(item=>{
  const rawIre=(item&&item.plot_ire!=null)?item.plot_ire:(item&&item.ire);
  const ire=Number(rawIre);
  return Number.isFinite(ire) && ire>0 && ire<99;
 });
}

function meterGammaChartX(step,steps,idx){
 return meterUseLgAutoCal26GammaAxis()?meterGreyChartX(step,steps,idx):meterGreyCategoryChartX(steps,idx);
}

function meterGreyscaleInteractionStepsForChart(canvasId,steps){
 const list=Array.isArray(steps)?steps:[];
 if(canvasId==='chartEOTF'||canvasId==='chartGamma') return meterFilterEotfLuminanceChartItems(list);
 if(canvasId==='chartGammaValue') return meterFilterGammaChartItems(list);
 return list;
}

function meterGreyscaleInteractionPadForChart(canvasId,stepCount){
 if(canvasId==='chartRGB') return meterGreyscaleChartPad(null,stepCount);
 if(canvasId==='chartDeltaE') return meterGreyscaleChartPad({t:20,r:15,b:30,l:55},stepCount);
 if(canvasId==='chartGammaValue') return meterGreyscaleChartPad({t:34,r:15,b:30,l:55},stepCount);
 if(canvasId==='chartEOTF') return {t:34,r:15,b:30,l:55};
 if(canvasId==='chartGamma') return {t:20,r:15,b:30,l:55};
 return {t:20,r:15,b:30,l:45};
}

function meterGreyscaleInteractionXForChart(canvasId,step,steps,idx){
 if(canvasId==='chartEOTF'||canvasId==='chartGamma') return meterGreyEotfLuminanceChartX(step,steps,idx,meterEotfLuminanceAxisMax(steps));
 if(canvasId==='chartGammaValue') return meterGammaChartX(step,steps,idx);
 return meterGreyCategoryChartX(steps,idx);
}

function meterSeriesMeasuredSegments(steps,readingMap,pointBuilder){
 const segments=[];
 let current=[];
 (steps||[]).forEach((step,idx)=>{
  const reading=readingMap?readingMap[step.ire]:null;
  if(!reading){
   if(current.length) segments.push(current);
   current=[];
   return;
  }
  const point=pointBuilder(reading,step,idx);
  if(!point){
   if(current.length) segments.push(current);
   current=[];
   return;
  }
  current.push(point);
 });
 if(current.length) segments.push(current);
 return segments;
}

function meterTargetShapedCurveFraction(a,b,signal,targetValueForSignal,t){
 if(!a||!b||typeof targetValueForSignal!=='function') return t;
 const aSignal=Number(a.signal);
 const bSignal=Number(b.signal);
 const midSignal=Number(signal);
 if(!Number.isFinite(aSignal)||!Number.isFinite(bSignal)||!Number.isFinite(midSignal)) return t;
 const mid={signal:midSignal};
 ['stimulus','ire','code'].forEach(key=>{
  const av=Number(a[key]);
  const bv=Number(b[key]);
  if(Number.isFinite(av)&&Number.isFinite(bv)) mid[key]=av+(bv-av)*(Number(t)||0);
 });
 const rawA=targetValueForSignal(aSignal,a);
 const rawB=targetValueForSignal(bSignal,b);
 const rawM=targetValueForSignal(midSignal,mid);
 const av=rawA==null?NaN:Number(rawA);
 const bv=rawB==null?NaN:Number(rawB);
 const mv=rawM==null?NaN:Number(rawM);
 if(!Number.isFinite(av)||!Number.isFinite(bv)||!Number.isFinite(mv)||Math.abs(bv-av)<1e-12) return t;
 return Math.max(0,Math.min(1,(mv-av)/(bv-av)));
}

function meterDensifyTargetShapedMeasuredSegment(rows,axisMax,targetValueForSignal,mode,scaleLuminance){
 const list=Array.isArray(rows)?rows:[];
 if(list.length<2) return list.map(row=>[row.x,row.y]);
 const out=[[list[0].x,list[0].y]];
 const maxPct=Math.max(1,Number(axisMax)||100);
 for(let i=0;i<list.length-1;i++){
  const a=list[i];
  const b=list[i+1];
  const spanPct=Math.abs((Number(b.x)||0)-(Number(a.x)||0))*maxPct;
  const segments=Math.max(1,Math.min(80,Math.ceil(spanPct*6)));
  for(let j=1;j<=segments;j++){
   const t=j/segments;
   if(j===segments){
    out.push([b.x,b.y]);
    continue;
   }
   const signal=(Number.isFinite(Number(a.signal))&&Number.isFinite(Number(b.signal)))
    ? a.signal+(b.signal-a.signal)*t
    : null;
   const shaped=meterTargetShapedCurveFraction(a,b,signal,targetValueForSignal,t);
   const x=(Number(a.x)||0)+((Number(b.x)||0)-(Number(a.x)||0))*t;
   let y=null;
   const rawA=Number(a.rawY);
   const rawB=Number(b.rawY);
   if(Number.isFinite(rawA)&&Number.isFinite(rawB)&&typeof scaleLuminance==='function'){
    const rawY=rawA+(rawB-rawA)*shaped;
    const scaled=scaleLuminance(rawY);
    if(scaled!=null&&Number.isFinite(Number(scaled))) y=Number(scaled);
   }
   if(y==null) y=(Number(a.y)||0)+((Number(b.y)||0)-(Number(a.y)||0))*shaped;
   out.push([x,y]);
  }
 }
 return out;
}

function meterUniqueMeasuredRowsByPlotX(rows){
 const out=[];
 const indexByX={};
 (Array.isArray(rows)?rows:[]).forEach(row=>{
  if(!row) return;
  const x=Number(row.x);
  if(!Number.isFinite(x)) return;
  const key=x.toFixed(6);
  if(indexByX[key]!=null) out[indexByX[key]]=row;
  else {
   indexByX[key]=out.length;
   out.push(row);
  }
 });
 return out;
}

function meterUseTargetShapedMeasuredEotfLuminanceCurve(mode){
 // HDR/DV measured traces should connect measured points directly. Bending
 // them along the target curve between samples can create visible chart kinks
 // even when the measured points themselves are smooth.
 if((typeof meterChartIsHdr==='function' && meterChartIsHdr()) || (typeof meterChartIsDv==='function' && meterChartIsDv())) return false;
 return true;
}

function meterDirectMeasuredEotfLuminanceSegments(steps,readingMap,axisMax,scaleLuminance,mode){
 const segments=[];
 let current=[];
 const flushCurrent=()=>{
  if(current.length){
   const unique=meterUniqueMeasuredRowsByPlotX(current);
   if(unique.length) segments.push(unique.map(row=>[row.x,row.y]));
  }
  current=[];
 };
 (steps||[]).forEach((step,idx)=>{
  const reading=readingMap?readingMap[step.ire]:null;
  if(!reading){
   flushCurrent();
   return;
  }
  if(!meterEotfLuminanceMeasuredStepAllowed(mode,step)){
   flushCurrent();
   return;
  }
  const lum=meterReadingLuminanceNits(reading);
  if(!(lum!=null&&Number.isFinite(Number(lum))&&lum>=0)){
   flushCurrent();
   return;
  }
  const x=meterGreyEotfLuminanceChartX(step,steps,idx,axisMax);
  const y=typeof scaleLuminance==='function'?scaleLuminance(lum):lum;
  if(!(y!=null&&Number.isFinite(Number(y)))){
   flushCurrent();
   return;
  }
  current.push({x,y:Number(y),luminance:Number(lum)});
 });
 flushCurrent();
 return segments;
}

function meterTargetShapedMeasuredSegments(steps,readingMap,axisMax,targetValueForSignal,scaleLuminance,mode,rawMeasuredValue){
 const segments=[];
 let current=[];
 const flushCurrent=()=>{
  if(current.length){
   const unique=meterUniqueMeasuredRowsByPlotX(current);
   if(unique.length) segments.push(unique);
  }
  current=[];
 };
 (steps||[]).forEach((step,idx)=>{
  const reading=readingMap?readingMap[step.ire]:null;
  if(!reading){
   flushCurrent();
   return;
  }
  if(!meterEotfLuminanceMeasuredStepAllowed(mode,step)){
   flushCurrent();
   return;
  }
  const lum=meterReadingLuminanceNits(reading);
  if(!(lum!=null&&Number.isFinite(Number(lum))&&lum>=0)){
   flushCurrent();
   return;
  }
  const stimulus=meterGreyChartStimulusIre(step);
  const code=meterGreyChartTargetCode(step);
  const targetIre=Number.isFinite(Number(stimulus))?Number(stimulus):meterGreyEotfLuminancePlotIre(step);
  const signal=meterGreyTargetSignal(targetIre,code);
  const x=meterGreyEotfLuminanceChartX(step,steps,idx,axisMax);
  const y=typeof scaleLuminance==='function'?scaleLuminance(lum):lum;
  if(!(y!=null&&Number.isFinite(Number(y)))){
   flushCurrent();
   return;
  }
  const rawY=typeof rawMeasuredValue==='function'?rawMeasuredValue(lum,step,reading):Number(lum);
  current.push({
   x,
   y:Number(y),
   rawY:Number.isFinite(Number(rawY))?Number(rawY):null,
   luminance:Number(lum),
   signal,
   stimulus:targetIre,
   ire:targetIre,
   code
  });
 });
 flushCurrent();
 return segments.map(seg=>meterDensifyTargetShapedMeasuredSegment(seg,axisMax,targetValueForSignal,mode,scaleLuminance));
}

function meterMeasuredEotfLuminanceSegments(steps,readingMap,axisMax,targetValueForSignal,scaleLuminance,mode,rawMeasuredValue){
 if(meterUseTargetShapedMeasuredEotfLuminanceCurve(mode)){
  return meterTargetShapedMeasuredSegments(steps,readingMap,axisMax,targetValueForSignal,scaleLuminance,mode,rawMeasuredValue);
 }
 return meterDirectMeasuredEotfLuminanceSegments(steps,readingMap,axisMax,scaleLuminance,mode);
}

function meterGammaPlotAnchorStep(steps,idx){
 if(!Array.isArray(steps)||idx<0||idx>=steps.length) return null;
 return idx>0 ? steps[idx-1] : steps[idx];
}

// Redraws only the EOTF chart (used by log-scale toggle so the ΔE chart is
// not recomputed and its values don't flicker due to FP reordering).
function meterRedrawEotfChart(){
 if(!meterReadings||!meterReadings.length) return;
 const allSteps=meterSeriesSteps?meterGreyscaleSeriesSteps(meterSeriesSteps):null;
 const readingMap=meterGreyscaleReadingMap(meterReadings);
 const gs=meterGreyscaleReadings(meterReadings);
 if(gs.length>0) drawEOTFChart(gs,allSteps,readingMap);
}

function meterRedrawLuminanceChart(){
 if(!meterReadings||!meterReadings.length) return;
 const allSteps=meterSeriesSteps?meterGreyscaleSeriesSteps(meterSeriesSteps):null;
 const readingMap=meterGreyscaleReadingMap(meterReadings);
 const gs=meterGreyscaleReadings(meterReadings);
 if(gs.length>0) drawGammaChart(gs,allSteps,readingMap);
}

function meterResolveTwoPointSeriesState(steps,readings){
 const stepList=meterGreyscaleSeriesSteps(steps);
 const readingList=meterGreyscaleReadings(readings);
 const findReading=(step)=>{
  if(!step) return null;
  return readingList.find(rd=>meterStepNameKey(rd)===meterStepNameKey(step)||meterGreyscaleReadingMatchesStep(rd,step))||null;
 };
 const lowStep=stepList[0]||null;
 const highStep=stepList[stepList.length-1]||null;
 return {
  lowStep:lowStep,
  highStep:highStep,
  lowReading:findReading(lowStep),
  highReading:findReading(highStep)
 };
}

function meterTwoPointMetaHtml(role,step,reading){
 const label=step?meterGreyscaleStepLabel(step):(role==='low'?'Low':'High');
 if(!reading||!meterReadingHasLuminance(reading)) return label+' patch not read yet.';
 const parts=['<strong>'+label+'</strong>'];
 if(role==='high'){
  const lum=meterReadingLuminanceNits(reading);
  parts.push('Luminance: <strong>'+(lum!=null?lum.toFixed(2):'--')+'</strong> cd/m&sup2;');
 }
 if(reading.cct) parts.push('CCT: <strong>'+reading.cct+'K</strong>');
 if(reading.x!=null&&reading.y!=null) parts.push('x / y: <strong>'+reading.x.toFixed(4)+'</strong> / <strong>'+reading.y.toFixed(4)+'</strong>');
 return parts.join('<br>');
}

function drawTwoPointPreset(gsSteps){
 meterUpdateGreyscaleChartMode();
 const state=meterResolveTwoPointSeriesState(gsSteps,[]);
 const lowLabel=document.getElementById('meterTwoPointLowLabel');
 const highLabel=document.getElementById('meterTwoPointHighLabel');
 const lowMeta=document.getElementById('meterTwoPointLowMeta');
 const highMeta=document.getElementById('meterTwoPointHighMeta');
 const highLum=document.getElementById('meterTwoPointHighLuminance');
 if(lowLabel) lowLabel.textContent=state.lowStep?meterGreyscaleStepLabel(state.lowStep):'Low';
 if(highLabel) highLabel.textContent=state.highStep?meterGreyscaleStepLabel(state.highStep):'High';
 if(lowMeta) lowMeta.innerHTML=meterTwoPointMetaHtml('low',state.lowStep,null);
 if(highMeta) highMeta.innerHTML=meterTwoPointMetaHtml('high',state.highStep,null);
 if(highLum) highLum.textContent='--';
 drawDeltaBarsVertical('meterTwoPointLowCanvas',null);
 drawDeltaBarsVertical('meterTwoPointHighCanvas',null);
}

function drawTwoPointCharts(gs,allSteps){
 meterUpdateGreyscaleChartMode();
 const state=meterResolveTwoPointSeriesState(allSteps&&allSteps.length?allSteps:gs,gs);
 const lowLabel=document.getElementById('meterTwoPointLowLabel');
 const highLabel=document.getElementById('meterTwoPointHighLabel');
 const lowMeta=document.getElementById('meterTwoPointLowMeta');
 const highMeta=document.getElementById('meterTwoPointHighMeta');
 const highLum=document.getElementById('meterTwoPointHighLuminance');
 if(lowLabel) lowLabel.textContent=state.lowStep?meterGreyscaleStepLabel(state.lowStep):'Low';
 if(highLabel) highLabel.textContent=state.highStep?meterGreyscaleStepLabel(state.highStep):'High';
 drawDeltaBarsVertical('meterTwoPointLowCanvas',state.lowReading?meterRgbDeltasForLive(state.lowReading,meterLiveRgbData(state.lowReading)):null);
 drawDeltaBarsVertical('meterTwoPointHighCanvas',state.highReading?meterRgbDeltasForLive(state.highReading,meterLiveRgbData(state.highReading)):null);
 if(lowMeta) lowMeta.innerHTML=meterTwoPointMetaHtml('low',state.lowStep,state.lowReading);
 if(highMeta) highMeta.innerHTML=meterTwoPointMetaHtml('high',state.highStep,state.highReading);
 if(highLum){
  const lum=state.highReading?meterReadingLuminanceNits(state.highReading):null;
  highLum.textContent=lum!=null?lum.toFixed(2):'--';
 }
}

function drawAllChartsPreset(sortedSteps){
 if(meterActiveSeriesType==='greyscale'||!meterActiveSeriesType){
  const gsSteps=meterFilterLgAutoCalChartItems(meterGreyscaleSeriesSteps(sortedSteps));
  if(gsSteps.length===0) return;
  meterUpdateGreyscaleChartMode();
  if(meterIsTwoPointGreyscale()){
   drawTwoPointPreset(gsSteps);
   return;
  }
  meterUpdateGreyscaleChartScrollLayout(gsSteps.length);
  drawRGBChartPreset(gsSteps);
  drawDeltaEPreset(gsSteps);
  drawDeltaE2000Preset(gsSteps);
  drawGammaValuePreset(gsSteps);
  drawEOTFPreset(gsSteps);
  drawGammaPreset(gsSteps);
 } else {
  drawCIEChartPreset(sortedSteps);
  drawColorDeltaE2000Preset(sortedSteps);
  const wrap=document.getElementById('colorReadingsTableWrap');
  if(wrap) wrap.style.display='none';
  const avgWrap=document.getElementById('colorSeriesAveragesWrap');
  if(avgWrap) avgWrap.style.display='none';
  _selectedColorReadingName=null;
  showColorReadingDetail(null);
 }
}
function drawRGBChartPreset(gsSteps){
 const ctx=getChartCtx('chartRGB');
 if(!ctx) return;
 if(gsSteps.length===0) return;
 let yMin=95,yMax=105;
 ({min:yMin,max:yMax}=meterApplyLinearYZoom('chartRGB',yMin,yMax,100));
 const rotateX=meterGreyscaleRotateXLabels(gsSteps.length);
 const chart=drawChartGrid(ctx,{
  pad:meterGreyscaleChartPad(null,gsSteps.length),
  xSteps:gsSteps.length-1||1,ySteps:4,
  xLabel:(i,n)=>i<gsSteps.length?meterGreyscaleChartLabel(gsSteps[i],gsSteps,i):'',
  yLabel:(i,n)=>(yMin+(yMax-yMin)*i/n).toFixed(0),
  rotateX:rotateX
 });
 const refY=(100-yMin)/(yMax-yMin);
 drawDashedLine(ctx,chart,[[0,refY],[1,refY]],'#555');
}
function drawDeltaEPreset(gsSteps){
 const ctx=getChartCtx('chartDeltaE');
 if(!ctx) return;
 let yMax=5;
 yMax=meterApplyTopYZoom('chartDeltaE',yMax,0).max;
 const rotateX=meterGreyscaleRotateXLabels(gsSteps.length);
 const chart=drawChartGrid(ctx,{
  pad:meterGreyscaleChartPad({t:20,r:15,b:30,l:55},gsSteps.length),
  xSteps:gsSteps.length-1||1,ySteps:5,
  xLabel:(i)=>i<gsSteps.length?meterGreyscaleChartLabel(gsSteps[i],gsSteps,i):'',
  yLabel:(i,n)=>(yMax*i/n).toFixed(1),
  rotateX:rotateX
 });
 if(1/yMax<=1) drawDashedLine(ctx,chart,[[0,1/yMax],[1,1/yMax]],'#4caf5080');
 if(3/yMax<=1) drawDashedLine(ctx,chart,[[0,3/yMax],[1,3/yMax]],'#ff980080');
}
function drawEOTFPreset(gsSteps){
 const ctx=getChartCtx('chartEOTF');
 if(!ctx) return;
 meterUpdateEotfChartLabel();
 const plotSteps=meterFilterEotfLuminanceChartItems(gsSteps);
 const axisMax=meterEotfLuminanceAxisMax(plotSteps);
 const Lw=(meterWhiteReading&&meterWhiteReading.luminance>0)?meterWhiteReading.luminance:100;
 const refPeak=meterGreyTargetPeak(Lw);
 const allVals=[meterGreyMeasuredEotfChartValue(Lw,Lw)];
 for(let pct=0;pct<=axisMax;pct+=1) allVals.push(meterGreyTargetEotfChartValue(pct,refPeak,0,null));
 let yTop=meterEotfChartTop(allVals);
 yTop=meterApplyTopYZoom('chartEOTF',yTop,0).max;
 const _ax=meterNiceAxisTop(yTop,0.2,10); yTop=_ax.top;
 const chart=drawChartGrid(ctx,{
  pad:{t:34,r:15,b:30,l:55},
  xSteps:axisMax/10,ySteps:_ax.steps,
  xLabel:(i)=>(i*10)+'',
  yLabel:(i,n)=>meterEotfAxisLabel(meterEotfUnscaleValue(i/n,yTop))
 });
 const tgtPts=meterGreyNominalTargetCurvePoints(refPeak,0,yTop,'eotf',axisMax,plotSteps);
 drawDashedLine(ctx,chart,tgtPts,'#666',1.8);
}
function drawGammaPreset(gsSteps){
 const ctx=getChartCtx('chartGamma');
 if(!ctx) return;
 const plotSteps=meterFilterEotfLuminanceChartItems(gsSteps);
 const axisMax=meterEotfLuminanceAxisMax(plotSteps);
 const Lw=(meterWhiteReading&&meterWhiteReading.luminance>0)?meterWhiteReading.luminance:100;
 const refPeak=Lw>0?Lw:(meterChartIsHdr()?meterChartHdrPeak():100);
 const curveMax=meterGreyTargetChartValue(axisMax,refPeak,0,null);
 let yTop=Math.ceil(Math.max(Lw,refPeak,curveMax)*1.1/10)*10||Math.max(Lw,refPeak,curveMax);
 yTop=meterApplyTopYZoom('chartGamma',yTop,0).max;
 const _ax=meterNiceAxisTop(yTop,50,10); yTop=_ax.top;
 const chart=drawChartGrid(ctx,{
  pad:{t:20,r:15,b:30,l:55},
  xSteps:axisMax/10,ySteps:_ax.steps,
  xLabel:(i)=>(i*10)+'',
  yLabel:(i,n)=>meterLuminanceAxisLabel(meterLuminanceUnscaleValue(i/n,yTop))
 });
 const tgtPts=meterGreyNominalTargetCurvePoints(refPeak,0,yTop,'luminance',axisMax,plotSteps);
 drawDashedLine(ctx,chart,tgtPts,'#666',1.8);
 drawGammaContrastLabel(ctx,chart,[]);
}

function drawGammaLegend(ctx,chart,targetLabel,avgText){
 const left=chart.pad.l;
 const right=chart.pad.l+chart.w;
 const y1=Math.max(12,chart.pad.t-16);
 const y2=y1+14;
 const targetText='Target: '+targetLabel;
 const measuredText='Measured';
 ctx.save();
 ctx.font='11px sans-serif';
 ctx.textAlign='left';
 const avgWidth=avgText?ctx.measureText(avgText).width:0;
 const targetWidth=ctx.measureText(targetText).width;
 const measuredWidth=ctx.measureText(measuredText).width;
 const targetBlock=24+targetWidth;
 const measuredBlock=24+measuredWidth;
 const gap=18;
 let targetX=left;
 let measuredX=left+targetBlock+gap;
 let targetY=y1;
 let measuredY=y1;
 if(measuredX+measuredBlock > right-avgWidth-12){
  measuredX=left;
  measuredY=y2;
 }
 ctx.setLineDash([4,4]);
 ctx.strokeStyle='#ffb74d';
 ctx.lineWidth=2;
 ctx.beginPath();
 ctx.moveTo(targetX,targetY-3);
 ctx.lineTo(targetX+18,targetY-3);
 ctx.stroke();
 ctx.setLineDash([]);
 ctx.fillStyle='#ffb74d';
 ctx.fillText(targetText,targetX+24,targetY);
 ctx.strokeStyle='#7ecbff';
 ctx.beginPath();
 ctx.moveTo(measuredX,measuredY-3);
 ctx.lineTo(measuredX+18,measuredY-3);
 ctx.stroke();
 ctx.fillStyle='#7ecbff';
 ctx.fillText(measuredText,measuredX+24,measuredY);
 if(avgText){
  ctx.textAlign='right';
  ctx.fillStyle='#aaa';
  ctx.fillText(avgText,right,y1);
 }
 ctx.restore();
}

function drawGammaValuePreset(gsSteps){
	 const ctx=getChartCtx('chartGammaValue');
	 if(!ctx) return;
	 const lbl=document.getElementById('chartGammaValueLabel');
	 if(lbl) lbl.textContent=meterChartIsHlg()?'Gamma (HLG-equivalent)':'Gamma';
 const targetLabel=meterTargetGammaLabel();
 const gammaFixedAxis=meterUseLgAutoCal26GammaAxis();
 const sourceSteps=Array.isArray(gsSteps)?gsSteps:[];
 const steps=meterFilterGammaChartItems(sourceSteps).filter(s=>{
  const targetIre=meterGreyChartStimulusIre(s);
  return (targetIre||0)>0&&(targetIre||0)<100;
 });
 const targetVals=steps.map(s=>meterGreyTargetGamma(meterGreyChartStimulusIre(s),100,0,s.r_code!=null?s.r_code:s.r)).filter(v=>v!=null&&isFinite(v));
	 const axis=meterGammaAxisCenteredOnTarget([],targetVals,meterGreyTargetUsesPq()||meterChartIsHlg());
 let yMin=axis.min;
 let yMax=axis.max;
 ({min:yMin,max:yMax}=meterApplyLinearYZoom('chartGammaValue',yMin,yMax,(yMin+yMax)/2));
 const chartSteps=gammaFixedAxis?steps:sourceSteps;
 const rotateX=!gammaFixedAxis && meterGreyscaleRotateXLabels(chartSteps.length);
 const chart=drawChartGrid(ctx,{
  pad:meterGreyscaleChartPad({t:34,r:15,b:30,l:55},chartSteps.length),
  xSteps:gammaFixedAxis?10:(chartSteps.length-1||1),ySteps:4,
  xLabel:(i)=>gammaFixedAxis?String(i*10):(i<chartSteps.length?meterGreyscaleChartLabel(chartSteps[i],chartSteps,i):''),
  yLabel:(i,n)=>(yMin+(yMax-yMin)*i/n).toFixed(2),
  rotateX:rotateX
 });
 const tgtPts=[];
 chartSteps.forEach((s,idx)=>{
  const targetIre=meterGreyChartStimulusIre(s);
  if(!((targetIre||0)>0&&(targetIre||0)<100)) return;
  const g=meterGreyTargetGamma(targetIre,100,0,s.r_code!=null?s.r_code:s.r);
  if(g!=null&&isFinite(g)) tgtPts.push([meterGammaChartX(s,chartSteps,idx),Math.max(0,Math.min(1,(g-yMin)/(yMax-yMin)))]);
 });
 const tgtPtsAnchored=meterGammaValueAnchorPoints(tgtPts);
 if(tgtPtsAnchored.length>1) drawDashedLine(ctx,chart,tgtPtsAnchored,'#ffb74d');
 drawGammaLegend(ctx,chart,targetLabel,'');
}

function drawGammaValueChart(gs,allSteps,readingMap){
	 const ctx=getChartCtx('chartGammaValue');
	 if(!ctx) return;
	 const lbl=document.getElementById('chartGammaValueLabel');
	 if(lbl) lbl.textContent=meterChartIsHlg()?'Gamma (HLG-equivalent)':(meterGreyTargetUsesPq()?'Gamma (PQ-equivalent)':'Gamma');
 const targetLabel=meterTargetGammaLabel();
 const gammaFixedAxis=meterUseLgAutoCal26GammaAxis();
 const sortedAll=[...gs].sort((a,b)=>(a.ire||0)-(b.ire||0));
 const white=meterGreyscaleChartWhiteReference(sortedAll);
 const sorted=gammaFixedAxis?meterFilterGammaChartItems(sortedAll):sortedAll;
 const Yw=white?(meterReadingLuminanceNits(white)||0):0;
 const Lb=meterChartBlackLevel(sorted);
 const rawXSteps=allSteps||sortedAll.map(r=>({ire:r.ire||0,r:r.r_code}));
 const measuredPeak=meterFilterEotfLuminanceChartItems(sortedAll).reduce((mx,r)=>Math.max(mx,meterReadingLuminanceNits(r)||0),0);
 const gammaYw=meterGammaValueReferenceY(sortedAll);
 const chartYw=gammaYw||Yw||measuredPeak;
 if(!(chartYw>0)){
  if(allSteps) drawGammaValuePreset(allSteps);
  return;
 }
 const xSteps=gammaFixedAxis?meterFilterGammaChartItems(rawXSteps):rawXSteps;
 const gammaMap={};
 const targetMap={};
	 sorted.forEach((rd,idx)=>{
	  const y=rd.luminance!=null?rd.luminance:rd.Y;
	  const topGamma=(Number(rd.ire)||0)>=100;
	  if(topGamma) return;
	  const analysisIre=meterReadingGammaAnalysisIre(rd)||rd.ire;
	  const prev=topGamma
	   ? (meterGammaPreviousSeriesReading(rd,xSteps,readingMap)||(!allSteps&&idx>0?sorted[idx-1]:null))
	   : (idx>0?sorted[idx-1]:null);
	  const prevY=prev?(prev.luminance!=null?prev.luminance:prev.Y):null;
	  const prevIre=prev?(meterReadingGammaAnalysisIre(prev)||prev.ire||0):null;
	  if(!(topGamma&&allSteps&&!prev)){
	  const g=((topGamma && (meterChartIsHdr()||meterChartIsDv()))
	      ? effectiveGammaTopSlope(y,chartYw,analysisIre,prevY,prevIre)
	      : meterGreyscaleGammaValue(rd,chartYw));
	   if(g!=null&&isFinite(g)) gammaMap[rd.ire]=g;
	  }
	  const tg=meterGreyTargetGamma(analysisIre,chartYw,Lb,rd.r_code,prevIre,prev?(prev.r_code!=null?prev.r_code:prev.r):null);
	  if(tg!=null&&isFinite(tg)) targetMap[rd.ire]=tg;
	 });
 xSteps.forEach((step,idx)=>{
	  const prev=idx>0?xSteps[idx-1]:null;
	  const rd=readingMap?readingMap[step.ire]:null;
	  const prevRd=(readingMap&&prev)?readingMap[prev.ire]:null;
	  const targetIre=rd?(meterReadingGammaAnalysisIre(rd)||step.ire):meterGreyscaleTargetIreForStep(step,readingMap);
	  if((Number(step.ire)||0)>=100 || (targetIre||0)>=100) return;
	  const targetCode=rd&&rd.r_code!=null?rd.r_code:meterGreyscaleTargetCodeForStep(step,readingMap);
	  const prevIre=prevRd?(meterReadingGammaAnalysisIre(prevRd)||prev.ire):(prev?meterGreyscaleTargetIreForStep(prev,readingMap):null);
	  const prevCode=prevRd&&prevRd.r_code!=null?prevRd.r_code:(prev?meterGreyscaleTargetCodeForStep(prev,readingMap):null);
	  const tg=meterGreyTargetGamma(targetIre,chartYw,Lb,targetCode,prevIre,prevCode);
	  if(tg!=null&&isFinite(tg)) targetMap[step.ire]=tg;
	 });
 const measuredVals=Object.values(gammaMap).filter(v=>v!=null&&isFinite(v));
 const targetVals=Object.values(targetMap).filter(v=>v!=null&&isFinite(v));
 const allVals=[...measuredVals,...targetVals];
 if(allVals.length===0){ drawGammaValuePreset(xSteps); return; }
 // HDR/PQ measured "gamma" has much wider range than SDR (0.3–4+), so we
 // can't clamp at 1.6–2.8 there. Fit the visible axis to actual data.
	 const isHdr=meterGreyTargetUsesPq()||meterChartIsHlg();
 let yMin,yMax;
 const axis=meterGammaAxisCenteredOnTarget(measuredVals,targetVals,isHdr);
 yMin=axis.min;
 yMax=axis.max;
 ({min:yMin,max:yMax}=meterApplyLinearYZoom('chartGammaValue',yMin,yMax,(yMin+yMax)/2));
 const rotateX=!gammaFixedAxis && meterGreyscaleRotateXLabels(xSteps.length);
 const chart=drawChartGrid(ctx,{
  pad:meterGreyscaleChartPad({t:34,r:15,b:30,l:55},xSteps.length),
  xSteps:gammaFixedAxis?10:(xSteps.length-1||1),ySteps:4,
  xLabel:(i)=>gammaFixedAxis?String(i*10):(i<xSteps.length?meterGreyscaleChartLabel(xSteps[i],xSteps,i):''),
  yLabel:(i,n)=>(yMin+(yMax-yMin)*i/n).toFixed(2),
  rotateX:rotateX
 });
 const tgtPts=[],mPts=[];
 xSteps.forEach((step,idx)=>{
  const x=meterGammaChartX(step,xSteps,idx);
  const tg=targetMap[step.ire];
  if(tg!=null&&isFinite(tg)){
   const ty=Math.max(0,Math.min(1,(tg-yMin)/(yMax-yMin)));
   tgtPts.push([x,ty]);
  }
  const mg=gammaMap[step.ire];
  if(mg!=null&&isFinite(mg)) mPts.push([x,Math.max(0,Math.min(1,(mg-yMin)/(yMax-yMin)))]);
 });
 if(tgtPts.length>1) drawDashedLine(ctx,chart,tgtPts,'#ffb74d');
 if(mPts.length>1) drawLine(ctx,chart,mPts,'#7ecbff',2);
 // Optional per-channel gamma overlay (R/G/B from the cached
 // meterPerChannelGamma computed in drawAllCharts).
 const pcToggle=document.getElementById('meterPerChannelGamma');
 if(pcToggle && pcToggle.checked){
  const rPts=[],gPts=[],bPts=[];
  xSteps.forEach((step,idx)=>{
   const rd=readingMap[step.ire];
   if(!rd || !rd._gamma_rgb) return;
   const gr=rd._gamma_rgb;
   const x=meterGammaChartX(step,xSteps,idx);
   const toY=(v)=>(v!=null&&isFinite(v))?Math.max(0,Math.min(1,(v-yMin)/(yMax-yMin))):null;
   const yr=toY(gr.r), yg=toY(gr.g), yb=toY(gr.b);
   if(yr!=null) rPts.push([x,yr]);
   if(yg!=null) gPts.push([x,yg]);
   if(yb!=null) bPts.push([x,yb]);
  });
  if(rPts.length>1) drawLine(ctx,chart,rPts,'#ff5555',1.5);
  if(gPts.length>1) drawLine(ctx,chart,gPts,'#55dd55',1.5);
  if(bPts.length>1) drawLine(ctx,chart,bPts,'#5588ff',1.5);
 }
 let avgText='';
 if(mPts.length>0){
  const avg=measuredVals.reduce((s,v)=>s+v,0)/measuredVals.length;
  avgText='Avg: '+avg.toFixed(2);
 }
 drawGammaLegend(ctx,chart,targetLabel,avgText);
}

///////////////////////////////////////////////
//           Canvas Chart Drawing            //
///////////////////////////////////////////////
function drawAllCharts(readings){
 if(!readings||readings.length===0) return;
 meterUpdateHdrConfigVisibility();
 meterEnsureDeltaECache(readings);
 meterEnsureChannelGammaCache(readings);
 if(meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations'){
  // Color/saturation series — CIE chromaticity + color ΔE + readings table
  const cr=readings.filter(r=>meterReadingHasLuminance(r)&&!meterIsWhiteReferenceReading(r));
  if(cr.length>0){
   drawCIEChart(cr);
   drawColorDeltaE2000Chart(cr);
   drawColorReadingsTable(cr);
   colorChartRegisterInteraction(cr);
   if(_colorDetailPinned&&_selectedColorReadingName){
    const sel=cr.find(r=>r.name===_selectedColorReadingName);
    if(sel) showColorReadingDetail(sel,{pin:true});
    else showColorReadingDetail(cr[cr.length-1],{pin:false});
   } else {
    showColorReadingDetail(cr[cr.length-1],{pin:false});
   }
  }
  return;
 }
 // Greyscale series
 const allStepsRaw=meterSeriesSteps?meterGreyscaleSeriesSteps(meterSeriesSteps):null;
 const allSteps=allStepsRaw?meterFilterLgAutoCalChartItems(allStepsRaw):null;
 const rawGs=meterGreyscaleReadings(readings);
 const gs=meterFilterLgAutoCalChartItems(rawGs);
 const readingMap=meterGreyscaleReadingMap(gs);
 meterUpdateGreyscaleChartMode();
 if(meterIsTwoPointGreyscale()){
  if(gs.length>0) drawTwoPointCharts(gs,allSteps);
  else if(allSteps&&allSteps.length>0) drawTwoPointPreset(allSteps);
  return;
 }
 if(gs.length>0){
  meterUpdateGreyscaleChartScrollLayout((allSteps&&allSteps.length)||gs.length);
  drawRGBChart(gs,allSteps,readingMap);
  drawDeltaEChart(gs,allSteps,readingMap,rawGs);
  drawGammaValueChart(gs,allSteps,readingMap);
  drawEOTFChart(gs,allSteps,readingMap);
  drawGammaChart(gs,allSteps,readingMap);
  chartRegisterInteraction();
 }
}

function getChartCtx(id){
 const c=document.getElementById(id);
 if(!c) return null;
 meterEnsureChartYZoomInput(c);
 const dpr=window.devicePixelRatio||1;
 const rect=c.getBoundingClientRect();
 // Guard: if canvas not visible (VS Code webview, hidden panel), skip
 if(rect.width<10||rect.height<10) return null;
 const newW=Math.round(rect.width*dpr), newH=Math.round(rect.height*dpr);
 // Only resize canvas buffer if dimensions actually changed (avoids unnecessary clear)
 if(c.width!==newW||c.height!==newH){ c.width=newW; c.height=newH; }
 const ctx=c.getContext('2d');
 ctx.setTransform(dpr,0,0,dpr,0,0);
 ctx.w=rect.width;
 ctx.h=rect.height;
 ctx.canvasId=id;
 return ctx;
}

let meterChartYZoom={};
let meterChartYZoomActive={};
let meterChartYZoomTouch=null;
let _chartYZoomHelpZones=[];
const METER_CHART_Y_ZOOM_HELP_TEXT='Scroll on the Y axis to zoom. Drag the Y axis on touch screens. Double-click the Y axis to reset.';

function meterChartCanYZoom(id){
 return /^chart/.test(String(id||'')) && id!=='chartCIE';
}

function meterChartYZoomAxisPad(id){
 const stepCount=(meterSeriesSteps&&meterSeriesSteps.length)?meterSeriesSteps.length:0;
 if(id==='chartRGB') return meterGreyscaleChartPad(null,stepCount);
 if(id==='chartDeltaE') return meterGreyscaleChartPad({t:20,r:15,b:30,l:55},stepCount);
 if(id==='chartGammaValue') return meterGreyscaleChartPad({t:34,r:15,b:30,l:55},stepCount);
 if(id==='chartEOTF') return {t:34,r:15,b:30,l:55};
 if(id==='chartGamma') return {t:20,r:15,b:30,l:55};
 if(id==='chartColorDE'||id==='chartDeltaE2000') return {t:20,r:15,b:30,l:55};
 return {t:20,r:15,b:30,l:45};
}

function meterChartPointerIsOnYAxis(canvas,e){
 if(!canvas||!e||!meterChartCanYZoom(canvas.id)) return false;
 const rect=canvas.getBoundingClientRect();
 if(!rect||rect.width<=0||rect.height<=0) return false;
 const x=Number(e.clientX)-rect.left;
 const y=Number(e.clientY)-rect.top;
 if(!Number.isFinite(x)||!Number.isFinite(y)||y<0||y>rect.height) return false;
 const pad=meterChartYZoomAxisPad(canvas.id);
 const axisLimit=Math.max(48,Math.min(rect.width*0.35,(pad.l||55)+12));
 return x>=0 && x<=axisLimit;
}

function meterChartYZoomHelpRect(id,pad){
 if(!meterChartCanYZoom(id)) return null;
 const radius=7;
 const inset=10;
 return {cx:inset,cy:inset,radius:radius};
}

function meterChartRegisterYZoomHelp(id,rect){
 _chartYZoomHelpZones=_chartYZoomHelpZones.filter(z=>z.canvasId!==id);
 if(rect) _chartYZoomHelpZones.push({canvasId:id,cx:rect.cx,cy:rect.cy,radius:rect.radius});
}

function meterChartYZoomHelpHit(e,canvasId){
 const canvas=document.getElementById(canvasId);
 if(!canvas||!e) return null;
 const rect=canvas.getBoundingClientRect();
 if(!rect||rect.width<=0||rect.height<=0) return null;
 const mx=Number(e.clientX)-rect.left;
 const my=Number(e.clientY)-rect.top;
 if(!Number.isFinite(mx)||!Number.isFinite(my)) return null;
 const zone=_chartYZoomHelpZones.find(z=>z.canvasId===canvasId);
 if(!zone) return null;
 const dx=mx-zone.cx,dy=my-zone.cy;
 return Math.sqrt(dx*dx+dy*dy)<=zone.radius+4 ? zone : null;
}

function meterShowChartYZoomHelpTooltip(e){
 const tip=document.getElementById('chartTooltip');
 if(!tip) return;
 tip.innerHTML=METER_CHART_Y_ZOOM_HELP_TEXT;
 tip.style.display='block';
 const tx=e.clientX+14,ty=e.clientY-10;
 tip.style.left=Math.min(tx,window.innerWidth-tip.offsetWidth-10)+'px';
 tip.style.top=Math.min(ty,window.innerHeight-tip.offsetHeight-10)+'px';
}

function meterChartYZoomValue(id){
 const v=Number(meterChartYZoom[id]);
 return Number.isFinite(v)&&v>0 ? Math.max(0.25,Math.min(8,v)) : 1;
}

function meterChartYZoomIsActive(id){
 return !!(meterChartYZoomActive&&meterChartYZoomActive[id]);
}

function meterSetChartYZoom(id,value){
 if(!meterChartCanYZoom(id)) return;
 meterChartYZoomActive[id]=true;
 meterChartYZoom[id]=Math.max(0.25,Math.min(8,Number(value)||1));
}

function meterLoadChartYZoom(){
 meterChartYZoom={};
 meterChartYZoomActive={};
 try{ localStorage.removeItem('pgen.meter.chartYZoom'); }catch(e){}
}

function meterChartYZoomReset(id){
 if(id){
  delete meterChartYZoom[id];
  delete meterChartYZoomActive[id];
 }
 meterRedrawForChartYZoom(id);
}

function meterAdjustChartYZoom(id,steps){
 const current=meterChartYZoomValue(id);
 const next=current*Math.pow(1.18,steps||0);
 meterSetChartYZoom(id,next);
 meterRedrawForChartYZoom(id);
}

function meterRedrawForChartYZoom(id){
 _chartHitZones=[];
 meterLastChartSignature='';
 meterLastChartCount=0;
 if(meterReadings&&meterReadings.length){
  drawAllCharts(meterReadings);
 } else if(meterSeriesSteps&&meterSeriesSteps.length){
  drawAllChartsPreset(meterSeriesSteps);
 }
}

function meterApplyLinearYZoom(id,min,max,center){
 const lo=Number(min), hi=Number(max);
 if(!Number.isFinite(lo)||!Number.isFinite(hi)||!(hi>lo)) return {min,max};
 if(!meterChartYZoomIsActive(id)) return {min:lo,max:hi};
 const zoom=meterChartYZoomValue(id);
 const mid=Number.isFinite(Number(center))?Number(center):(lo+hi)/2;
 const half=(hi-lo)/(2*zoom);
 return {min:mid-half,max:mid+half};
}

function meterApplyTopYZoom(id,max,min){
 const lo=Number.isFinite(Number(min))?Number(min):0;
 const hi=Number(max);
 if(!Number.isFinite(hi)||!(hi>lo)) return {min:lo,max:hi};
 if(!meterChartYZoomIsActive(id)) return {min:lo,max:hi};
 const span=(hi-lo)/meterChartYZoomValue(id);
 return {min:lo,max:lo+span};
}

function meterEnsureChartYZoomInput(canvas){
 if(!canvas||canvas._meterYZoomBound||!meterChartCanYZoom(canvas.id)) return;
 canvas._meterYZoomBound=1;
 canvas.style.touchAction='none';
 canvas.removeAttribute('title');
 canvas.addEventListener('mousemove',e=>{
  if(!meterChartYZoomHelpHit(e,canvas.id)) return;
  e.stopImmediatePropagation();
  meterShowChartYZoomHelpTooltip(e);
 },true);
 canvas.addEventListener('mouseleave',()=>{ const tip=document.getElementById('chartTooltip'); if(tip) tip.style.display='none'; });
 canvas.addEventListener('wheel',e=>{
  if(!meterChartPointerIsOnYAxis(canvas,e)) return;
  e.preventDefault();
  meterAdjustChartYZoom(canvas.id,e.deltaY<0?1:-1);
 },{passive:false});
 canvas.addEventListener('dblclick',e=>{
  if(!meterChartPointerIsOnYAxis(canvas,e)) return;
  e.preventDefault();
  meterChartYZoomReset(canvas.id);
 });
 canvas.addEventListener('touchstart',e=>{
  if(!e.touches||e.touches.length!==1) return;
  if(!meterChartPointerIsOnYAxis(canvas,e.touches[0])) return;
  meterChartYZoomTouch={id:canvas.id,y:e.touches[0].clientY};
 },{passive:true});
 canvas.addEventListener('touchmove',e=>{
  if(!meterChartYZoomTouch||meterChartYZoomTouch.id!==canvas.id||!e.touches||e.touches.length!==1) return;
  const y=e.touches[0].clientY;
  const dy=meterChartYZoomTouch.y-y;
  if(Math.abs(dy)<8) return;
  e.preventDefault();
  meterChartYZoomTouch.y=y;
  meterAdjustChartYZoom(canvas.id,dy/48);
 },{passive:false});
 canvas.addEventListener('touchend',()=>{ if(meterChartYZoomTouch&&meterChartYZoomTouch.id===canvas.id) meterChartYZoomTouch=null; },{passive:true});
 canvas.addEventListener('touchcancel',()=>{ if(meterChartYZoomTouch&&meterChartYZoomTouch.id===canvas.id) meterChartYZoomTouch=null; },{passive:true});
}

function meterDrawChartYZoomHelp(ctx,pad){
 if(!ctx||!ctx.canvasId||!meterChartCanYZoom(ctx.canvasId)) return;
 const rect=meterChartYZoomHelpRect(ctx.canvasId,pad);
 meterChartRegisterYZoomHelp(ctx.canvasId,rect);
 if(!rect) return;
 ctx.save();
 ctx.beginPath();
 ctx.arc(rect.cx,rect.cy,rect.radius,0,Math.PI*2);
 ctx.fillStyle='rgba(28,31,43,0.96)';
 ctx.fill();
 ctx.lineWidth=1;
 ctx.strokeStyle='rgba(136,144,168,0.85)';
 ctx.stroke();
 ctx.fillStyle='#cfd6e6';
 ctx.font='bold 10px sans-serif';
 ctx.textAlign='center';
 ctx.textBaseline='middle';
 ctx.fillText('?',rect.cx,rect.cy+0.5);
 ctx.restore();
 ctx.textBaseline='alphabetic';
}

function setupCanvasHiDPI(canvas){
 if(!canvas||!canvas.id) return null;
 return getChartCtx(canvas.id);
}

function drawChartGrid(ctx,opts){
 const pad=opts.pad||{t:20,r:15,b:30,l:45};
 const w=ctx.w-pad.l-pad.r, h=ctx.h-pad.t-pad.b;
 const xIn=opts.xInset||0, dw=w-2*xIn;
 // Background
 ctx.fillStyle='#0d0d15';
 ctx.fillRect(0,0,ctx.w,ctx.h);
 // Grid
 ctx.strokeStyle='#1d1d29';
 ctx.lineWidth=1;
 const xSteps=opts.xSteps||10, ySteps=opts.ySteps||5;
 for(let i=0;i<=xSteps;i++){
  const x=pad.l+xIn+dw*(i/xSteps);
  ctx.beginPath();ctx.moveTo(x,pad.t);ctx.lineTo(x,pad.t+h);ctx.stroke();
 }
 for(let i=0;i<=ySteps;i++){
  const y=pad.t+h*(i/ySteps);
  ctx.beginPath();ctx.moveTo(pad.l,y);ctx.lineTo(pad.l+w,y);ctx.stroke();
 }
 // Axes
 ctx.strokeStyle='#3a3a4a';
 ctx.beginPath();ctx.moveTo(pad.l,pad.t);ctx.lineTo(pad.l,pad.t+h);ctx.lineTo(pad.l+w,pad.t+h);ctx.stroke();
 // X labels. When opts.rotateX is set, draw them angled so long names
 // (e.g. "Magenta 100%") don't overlap on dense series.
 ctx.fillStyle='#888898';ctx.font='11px sans-serif';
 if(opts.rotateX){
  for(let i=0;i<=xSteps;i++){
   const lbl=opts.xLabel?opts.xLabel(i,xSteps):(i*100/xSteps).toFixed(0);
   if(!lbl) continue;
   const x=pad.l+xIn+dw*(i/xSteps);
   ctx.save();
   ctx.translate(x,pad.t+h+6);
   ctx.rotate(-Math.PI/4);
   ctx.textAlign='right';
   ctx.fillText(lbl,0,4);
   ctx.restore();
  }
 } else {
  ctx.textAlign='center';
  for(let i=0;i<=xSteps;i++){
   const lbl=opts.xLabel?opts.xLabel(i,xSteps):(i*100/xSteps).toFixed(0);
   ctx.fillText(lbl,pad.l+xIn+dw*(i/xSteps),pad.t+h+14);
  }
 }
 // Y labels
 ctx.textAlign='right';
 for(let i=0;i<=ySteps;i++){
  const lbl=opts.yLabel?opts.yLabel(i,ySteps):'';
  ctx.fillText(lbl,pad.l-4,pad.t+h-h*(i/ySteps)+3);
 }
 meterDrawChartYZoomHelp(ctx,pad);
 return {pad,w,h,dw,toX:v=>pad.l+xIn+v*dw, toY:v=>pad.t+h-v*h};
}

function drawLine(ctx,chart,points,color,width){
 if(points.length<2) return;
 ctx.strokeStyle=color;ctx.lineWidth=width||1.5;
 ctx.beginPath();
 points.forEach((p,i)=>{
  const x=chart.toX(p[0]),y=chart.toY(p[1]);
  if(i===0) ctx.moveTo(x,y); else ctx.lineTo(x,y);
 });
 ctx.stroke();
}

function drawDots(ctx,chart,points,color,radius){
 ctx.fillStyle=color;
 points.forEach(p=>{
  ctx.beginPath();
  ctx.arc(chart.toX(p[0]),chart.toY(p[1]),radius||2.5,0,Math.PI*2);
  ctx.fill();
 });
}

function drawDashedLine(ctx,chart,points,color,width){
 ctx.setLineDash([4,4]);
 drawLine(ctx,chart,points,color,width||1);
 ctx.setLineDash([]);
}

// Annotate the 0% IRE data point on an EOTF/Gamma chart with the actual
// measured black level (Lb). The chart's Y axis spans 0 to peak, so a lifted
// black (e.g. 0.05 cd/m^2 on a 1000 nit panel) is plotted at y ~ 0.00005 --
// visually indistinguishable from true black and labelled "0.0" by the
// axis. Without this annotation, the only signal of a real black lift is
// the existing "Min cd/m^2: Lb" footer text, which is easy to miss while
// the chart is in motion. Draws a small yellow callout next to the 0% dot.
function meterDrawLiftedBlackLabel(ctx,chart,axisMax,yTop,Lb,measureSteps,scaleFn){
 if(!(Lb>0) || !ctx || !chart) return;
 const zeroStep=(measureSteps||[]).find(s=>Math.abs(Number((s&&s.ire!=null)?s.ire:0))<0.5);
 if(!zeroStep) return;
 const zeroX=meterGreyEotfLuminanceChartX(zeroStep,measureSteps,measureSteps.indexOf(zeroStep),axisMax);
 const scaled=scaleFn(Lb);
 if(!(Number.isFinite(zeroX)) || !(Number.isFinite(scaled))) return;
 const px=chart.toX(zeroX);
 const py=chart.toY(Math.max(0,Math.min(1,scaled)));
 // The 0% point sits on the X axis. Place the label 14px above and offset
 // right so it doesn't collide with the Y axis tick or the point itself.
 const labelX=Math.min(ctx.w-chart.pad.r-44, px+10);
 const labelY=Math.max(chart.pad.t+12, py-8);
 ctx.save();
 ctx.font='bold 10px sans-serif';
 ctx.textAlign='left';
 ctx.textBaseline='alphabetic';
 // Filled pill for legibility against grid lines and the measured curve.
 const text='0% = '+Lb.toFixed(Lb<1?3:1)+' cd/m\u00B2';
 const w=ctx.measureText(text).width+8;
 ctx.fillStyle='rgba(255,235,59,0.92)';
 ctx.fillRect(labelX-4,labelY-9,w,14);
 ctx.fillStyle='#1a1a22';
 ctx.fillText(text,labelX,labelY+2);
 ctx.restore();
}

function meterGreyscaleRgbBalanceReference(gs){
 let effectiveWhiteRGB=meterEffectiveGreyscaleWhiteReference(gs);
 // For manual single reads before 100% is measured, still plot RGB balance
 // using a stable white level inferred from the brightest available grey
 // patch when no measured/cached/mode fallback reference exists.
 if((!effectiveWhiteRGB||effectiveWhiteRGB.Y<=0) && gs && gs.length>0){
  const brightest=[...gs].sort((a,b)=>(b.luminance||0)-(a.luminance||0))[0];
  if(brightest && (brightest.luminance||brightest.Y||0)>0){
   let inferredYw=brightest.luminance||brightest.Y;
   const ire=Math.max(1,brightest.ire||100);
   if(ire<100){
    const frac=Math.max(targetEotf(ire/100,1,0),0.02);
    inferredYw=inferredYw/frac;
   }
   effectiveWhiteRGB=meterSyntheticGreyWhiteReading(inferredYw);
  }
 }
 return effectiveWhiteRGB;
}

function drawRGBChart(gs,allSteps,readingMap){
 const ctx=getChartCtx('chartRGB');
 if(!ctx) return;
 let effectiveWhiteRGB=meterGreyscaleRgbBalanceReference(gs);
 if(!effectiveWhiteRGB||effectiveWhiteRGB.Y<=0){
  if(allSteps) drawRGBChartPreset(allSteps);
  return;
 }
 // Use all series steps for x-axis (include 0%)
 const xSteps=allSteps?[...allSteps]:gs.sort((a,b)=>a.ire-b.ire);
 if(xSteps.length===0) return;
 // Compute RGB balance for all available readings (include 0%)
 const balMap={};
 const greyMode=meterGreyRefMode();
 gs.forEach(rd=>{balMap[rd.ire]=rgbBalance(rd,effectiveWhiteRGB,greyMode);});
 // Auto-scale Y axis based on actual data, but keep the chart centered on 100.
 const allVals=Object.values(balMap).flatMap(b=>[b.R,b.G,b.B]);
 let yMin,yMax;
 if(allVals.length>0){
  const dataMin=Math.min(...allVals),dataMax=Math.max(...allVals);
  const margin=Math.max(1,(dataMax-dataMin)*0.15);
  const halfRange=Math.max(5,Math.ceil(Math.max(100-(dataMin-margin),(dataMax+margin)-100)));
  yMin=100-halfRange;
  yMax=100+halfRange;
 } else {yMin=95;yMax=105;}
 ({min:yMin,max:yMax}=meterApplyLinearYZoom('chartRGB',yMin,yMax,100));
   const rotateX=meterGreyscaleRotateXLabels(xSteps.length);
 const chart=drawChartGrid(ctx,{
    pad:meterGreyscaleChartPad(null,xSteps.length),
  xInset:15,
  xSteps:xSteps.length-1||1,ySteps:4,
    xLabel:(i)=>i<xSteps.length?meterGreyscaleChartLabel(xSteps[i],xSteps,i):'',
    yLabel:(i,n)=>(yMin+(yMax-yMin)*i/n).toFixed(1),
    rotateX:rotateX
 });
 // Reference line at 100%
 const refY=(100-yMin)/(yMax-yMin);
 drawDashedLine(ctx,chart,[[0,refY],[1,refY]],'#555');
 const rPts=[],gPts=[],bPts=[];
 xSteps.forEach((step,idx)=>{
  const x=meterGreyCategoryChartX(xSteps,idx);
  const bal=balMap[step.ire];
  if(bal){
   rPts.push([x,Math.max(0,Math.min(1,(bal.R-yMin)/(yMax-yMin)))]);
   gPts.push([x,Math.max(0,Math.min(1,(bal.G-yMin)/(yMax-yMin)))]);
   bPts.push([x,Math.max(0,Math.min(1,(bal.B-yMin)/(yMax-yMin)))]);
  }
 });
 if(rPts.length>1){drawLine(ctx,chart,rPts,'#f44',2);drawLine(ctx,chart,gPts,'#4caf50',2);drawLine(ctx,chart,bPts,'#42a5f5',2);}
 // R/G/B label at right
 if(rPts.length>0){
  const last=rPts.length-1;
  ctx.font='11px sans-serif';ctx.textAlign='left';
  const xOff=chart.toX(rPts[last][0])+6;
  ctx.fillStyle='#f44';ctx.fillText('R',xOff,chart.toY(rPts[last][1])+3);
  ctx.fillStyle='#4caf50';ctx.fillText('G',xOff,chart.toY(gPts[last][1])+3);
  ctx.fillStyle='#42a5f5';ctx.fillText('B',xOff,chart.toY(bPts[last][1])+3);
 }
}

function drawEOTFChart(gs,allSteps,readingMap){
 const ctx=getChartCtx('chartEOTF');
 if(!ctx) return;
 meterUpdateEotfChartLabel();
 const sorted=[...gs].sort((a,b)=>(a.ire||0)-(b.ire||0));
 const white=meterGreyscaleChartWhiteReference(sorted);
 const refWhite=white?(white.luminance||white.Y||0):0;
 const Lb=meterChartBlackLevel(sorted);
 let targetPeak=meterGreyTargetPeak(refWhite);
 if(!(Math.max(refWhite,targetPeak)>0)) return;
 const targetSteps=allSteps||sorted.map(r=>({ire:r.ire||0,r:r.r_code}));
 const plotSteps=meterFilterEotfLuminanceChartItems(targetSteps);
 const axisMax=meterEotfLuminanceAxisMax(plotSteps.length?plotSteps:targetSteps);
 targetPeak=meterGreyTargetPeakForReadings(sorted,plotSteps.length?plotSteps:targetSteps,targetPeak,Lb);
 // Anchor the EOTF target to the measured peak: with headroom (109%) solve the
 // implied peak from that reading so the target passes through it; otherwise
 // keep the measured-white target. The Y axis (1.0==200 nits) is just a display
 // reference and does not affect this target calculation.
 const _eotfHeadroom=meterAutoCalGreyscaleTargetWhiteReferenceActive(sorted)?meterGreyHeadroomReferenceReading(sorted):null;
 if(_eotfHeadroom){
  const _eotfSolved=meterGreySolvePeakFromHeadroomReading(_eotfHeadroom,plotSteps.length?plotSteps:targetSteps,targetPeak,Lb);
  if(_eotfSolved>0&&isFinite(_eotfSolved)) targetPeak=_eotfSolved;
 }
 const valid=meterFilterEotfLuminanceChartItems(sorted).filter(r=>r.luminance!=null && r.luminance>=0);
 const eotfMeasuredRef=targetPeak||refWhite;
 const allValues=[meterGreyMeasuredEotfChartValue(refWhite,eotfMeasuredRef)];
 valid.forEach(r=>allValues.push(meterGreyMeasuredEotfChartValue(r.luminance||0,eotfMeasuredRef)));
 for(let pct=0;pct<=axisMax;pct+=1) allValues.push(meterGreyTargetEotfChartValue(pct,targetPeak,Lb,null));
 let yTop=meterEotfChartTop(allValues);
 yTop=meterApplyTopYZoom('chartEOTF',yTop,0).max;
 const _ax=meterNiceAxisTop(yTop,0.2,10); yTop=_ax.top;
 const chart=drawChartGrid(ctx,{
  pad:{t:34,r:15,b:30,l:55},
  xSteps:axisMax/10,ySteps:_ax.steps,
  xLabel:(i)=>(i*10)+'',
  yLabel:(i,n)=>meterEotfAxisLabel(meterEotfUnscaleValue(i/n,yTop))
 });
 const tgtPts=meterGreyNominalTargetCurvePoints(targetPeak,Lb,yTop,'eotf',axisMax,plotSteps);
 drawDashedLine(ctx,chart,tgtPts,'#666',1.8);
 const directMeasured=!meterUseTargetShapedMeasuredEotfLuminanceCurve();
 const measureSteps=(directMeasured&&plotSteps.length)?plotSteps:(directMeasured&&valid.length)?valid:(plotSteps.length?plotSteps:valid);
 let mSegments=meterMeasuredEotfLuminanceSegments(
  measureSteps,
  readingMap,
  axisMax,
  (signal,point)=>{
   return meterGreyTargetLuminanceForChartPoint(signal,targetPeak,Lb||0,point);
  },
  lum=>{
   const value=Number(lum);
   if(!Number.isFinite(value)) return null;
   return meterScaleEotfLuminancePlotValue('eotf',meterGreyMeasuredEotfChartValue(value,eotfMeasuredRef),yTop,null,value);
  },
  'eotf',
  lum=>{
   const value=Number(lum);
   return Number.isFinite(value)?value:null;
  }
 );
 // Draw measured EOTF curve. HDR/DV live AutoCal spine anchors are sparse,
 // so single-point segments still need visible dots until adjacent anchors exist.
 mSegments.forEach(seg=>{
  if(seg.length>1) drawLine(ctx,chart,seg,'#ffeb3b',1.25);
  else drawDots(ctx,chart,seg,'#ffeb3b',2.5);
 });
 // Annotate the 0% IRE point with the actual measured Lb (cd/m^2) so a
 // lifted black is visible even though the Y axis spans 0 to peak and
 // the plotted 0% point sits on the X axis.
 meterDrawLiftedBlackLabel(ctx,chart,axisMax,yTop,Lb,measureSteps,lum=>{
  const value=Number(lum);
  if(!Number.isFinite(value)) return null;
  return meterScaleEotfLuminancePlotValue('eotf',meterGreyMeasuredEotfChartValue(value,eotfMeasuredRef),yTop,null,value);
 });
 // Optional per-channel R/G/B EOTF overlay (mirrors the Gamma chart's
 // per-channel option). Each channel's measured linear value is normalized to
 // the white reference's same channel, rescaled to the chart reference, then
 // run through the active EOTF transfer (bowed when Absolute is off, diagonal
 // when on) so it shares the same Y axis as the luminance curve.
 const eotfPcToggle=document.getElementById('meterEotfPerChannel');
 if(eotfPcToggle && eotfPcToggle.checked && white){
  const pcGamut=meterAnalysisGamut();
  const whiteXYZ=meterReadingXYZ(white);
  const rw=whiteXYZ?xyzToLinRgb(whiteXYZ.X,whiteXYZ.Y,whiteXYZ.Z,pcGamut.xyzToRgb):null;
  if(rw){
   const pcSteps=plotSteps.length?plotSteps:targetSteps;
   [{i:0,c:'#ff5555'},{i:1,c:'#55dd55'},{i:2,c:'#5588ff'}].forEach(ch=>{
    const pts=[];
    pcSteps.forEach((step,idx)=>{
     const rd=readingMap[step.ire];
     if(!rd) return;
     const xyz=meterReadingXYZ(rd);
     if(!xyz) return;
     const lin=xyzToLinRgb(xyz.X,xyz.Y,xyz.Z,pcGamut.xyzToRgb);
     const wc=rw[ch.i];
     if(!(wc>0)) return;
     const chanLum=(lin[ch.i]/wc)*eotfMeasuredRef;
     const val=meterGreyMeasuredEotfChartValue(chanLum,eotfMeasuredRef);
     const x=meterGreyEotfLuminanceChartX(step,pcSteps,idx,axisMax);
     const scaled=meterScaleEotfLuminancePlotValue('eotf',val,yTop,null,chanLum);
     if(scaled!=null) pts.push([x,scaled]);
    });
    const apts=meterAnchorOriginPoint(pts);
    if(apts.length>1) drawLine(ctx,chart,apts,ch.c,1.25);
   });
  }
 }
 ctx.fillText('Measured max: '+Math.max(...valid.map(r=>r.luminance||0),0).toFixed(1)+' cd/m\u00B2',ctx.w-chart.pad.r,chart.pad.t-8);
}

function meterDrawDeltaSummary(ctx,chart,values){
 const vals=(values||[]).filter(v=>Number.isFinite(v));
 if(!vals.length) return;
 const avg=vals.reduce((s,v)=>s+v,0)/vals.length;
 const min=Math.min(...vals);
 const max=Math.max(...vals);
 ctx.fillStyle='#888';ctx.font='11px sans-serif';ctx.textAlign='right';
 ctx.fillText('Min: '+min.toFixed(2)+'  Avg: '+avg.toFixed(2)+'  Max: '+max.toFixed(2),chart.pad.l+chart.w,chart.pad.t-4);
}

function drawGammaChart(gs,allSteps,readingMap){
 const ctx=getChartCtx('chartGamma');
 if(!ctx) return;
 const sorted=[...gs].sort((a,b)=>(a.ire||0)-(b.ire||0));
 const white=meterGreyscaleChartWhiteReference(sorted);
 const refWhite=white?(meterReadingLuminanceNits(white)||0):0;
 const measuredMax=meterFilterEotfLuminanceChartItems(sorted).reduce((mx,r)=>Math.max(mx,r.luminance||0),0);
 const Lb=meterChartBlackLevel(sorted);
 const rawTargetPeak=meterGreyTargetPeak(refWhite||measuredMax);
 let targetPeak=(meterChartIsDv() && meterDvMapModeValue()==='1' && refWhite>0) ? refWhite : rawTargetPeak;
 if(!(Math.max(measuredMax,targetPeak)>0)) return;
 const targetSteps=allSteps||sorted.map(r=>({ire:r.ire||0,r:r.r_code}));
 const plotSteps=meterFilterEotfLuminanceChartItems(targetSteps);
 const axisMax=meterEotfLuminanceAxisMax(plotSteps.length?plotSteps:targetSteps);
 targetPeak=meterGreyTargetPeakForReadings(sorted,plotSteps.length?plotSteps:targetSteps,targetPeak,Lb);
 const curveMax=meterGreyTargetChartValue(axisMax,targetPeak,Lb,null);
 let yTop=Math.ceil(Math.max(measuredMax,targetPeak,curveMax)*1.1/10)*10||Math.max(measuredMax,targetPeak,curveMax);
 yTop=meterApplyTopYZoom('chartGamma',yTop,0).max;
 const _ax=meterNiceAxisTop(yTop,50,10); yTop=_ax.top;
 const chart=drawChartGrid(ctx,{
  pad:{t:20,r:15,b:30,l:55},
  xSteps:axisMax/10,ySteps:_ax.steps,
  xLabel:(i)=>(i*10)+'',
  yLabel:(i,n)=>meterLuminanceAxisLabel(meterLuminanceUnscaleValue(i/n,yTop))
 });
 // In DV absolute, the luminance chart should track the measured absolute-white
 // target curve rather than the mastering-peak label used elsewhere.
 const tgtPts=meterGreyNominalTargetCurvePoints(targetPeak,Lb,yTop,'luminance',axisMax,plotSteps);
 drawDashedLine(ctx,chart,tgtPts,'#666',1.8);
 drawGammaContrastLabel(ctx,chart,(Array.isArray(meterReadings)&&meterReadings.length)?meterReadings:gs);
 const validG=meterFilterEotfLuminanceChartItems(sorted).filter(r=>r.luminance!=null && r.luminance>=0);
 const directMeasured=!meterUseTargetShapedMeasuredEotfLuminanceCurve();
 const measureSteps=(directMeasured&&plotSteps.length)?plotSteps:(directMeasured&&validG.length)?validG:(plotSteps.length?plotSteps:validG);
 const scaleMeasuredLuminance=lum=>{
  const value=Number(lum);
  if(!Number.isFinite(value)) return null;
  return meterScaleEotfLuminancePlotValue('luminance',value,yTop,null,value);
 };
 let mSegments=meterMeasuredEotfLuminanceSegments(
  measureSteps,
  readingMap,
  axisMax,
  (signal,point)=>{
   return meterGreyTargetLuminanceForChartPoint(signal,targetPeak,Lb||0,point);
  },
  scaleMeasuredLuminance,
  'luminance',
  lum=>{
   const value=Number(lum);
   return Number.isFinite(value)?value:null;
  }
 );
 mSegments.forEach(seg=>{
  if(seg.length>1) drawLine(ctx,chart,seg,'#ffeb3b',1.25);
  else drawDots(ctx,chart,seg,'#ffeb3b',2.5);
 });
 // Annotate the 0% IRE point with the actual measured Lb (cd/m^2) so a
 // lifted black is visible even though the Y axis spans 0 to peak and
 // the plotted 0% point sits on the X axis.
 meterDrawLiftedBlackLabel(ctx,chart,axisMax,yTop,Lb,measureSteps,scaleMeasuredLuminance);
 ctx.fillStyle='#aaa';ctx.font='11px sans-serif';
 ctx.textAlign='left';
 ctx.fillText('Min cd/m\u00B2: '+Lb.toFixed(2),chart.pad.l,ctx.h-2);
 const diffuse=meterHdrDiffuseWhiteOverride();
 const targetLabel='100% target: '+targetPeak.toFixed(1)+' cd/m\u00B2'+((diffuse!=null&&meterChartIsPq())?' (DW '+diffuse.toFixed(1)+')':'');
 ctx.fillText(targetLabel,chart.pad.l,chart.pad.t+14);
 ctx.textAlign='right';
 ctx.fillText('Max cd/m\u00B2: '+measuredMax.toFixed(2),ctx.w-chart.pad.r,ctx.h-2);
}

function drawDeltaEChart(gs,allSteps,readingMap,rawGs){
 const ctx=getChartCtx('chartDeltaE');
 if(!ctx) return;
 const greyMode=meterGreyRefMode();
 const inclLum=(greyMode==='eotf');
 const deForm=meterDeltaEForm();
 const deLabel=meterDeltaEFormLabel(deForm);
 const gw=meterGrayWorldWeight();
 const gwTag=gw<1 ? (' · GW '+gw) : '';
 // Primary greyscale ΔE chart follows the selected formula.
 const lbl=document.getElementById('chartDeltaELabel');
 if(lbl) lbl.textContent = deLabel+" ("+meterGreyRefModeLabel(greyMode)+gwTag+")";
 const whiteR=meterGreyscaleChartWhiteReference(gs);
 // If the 100% measurement isn't present yet, use the same mode-aware
 // fallback as the greyscale target helpers so SDR one-off reads do not
 // inherit stale HDR metadata luminance.
 let effectiveWhite=whiteR;
 if(!effectiveWhite||effectiveWhite.Y<=0){
  const synthetic=meterSyntheticGreyWhiteReading(meterColorReferenceNits());
  if(synthetic) effectiveWhite=synthetic;
 }
 if(!effectiveWhite||effectiveWhite.Y<=0){
  if(allSteps) drawDeltaEPreset(allSteps);
  return;
 }
 const Lw=effectiveWhite.luminance||effectiveWhite.Y;
 const Lb=meterChartBlackLevel(gs);
 const gwWeight=meterGrayWorldWeight();
 // Use all series steps for x-axis
 const xSteps=allSteps||[...gs].sort((a,b)=>a.ire-b.ire);
 // Compute deltaE for available readings
 const deMap={};
 gs.forEach(rd=>{
  if((rd.Y||0)<=0){deMap[rd.ire]=0;return;}
  deMap[rd.ire]=meterGreyDeltaResult(rd,greyMode,deForm,gwWeight).value;
 });
 const deValues=Object.values(deMap);
 // Auto-scale Y: zoom to fit tightest range
 let yMax;
 if(deValues.length>0){
  const maxDE=Math.max(...deValues);
  yMax=Math.max(2,Math.ceil(maxDE*1.2*2)/2);
 } else {yMax=5;}
 yMax=meterApplyTopYZoom('chartDeltaE',yMax,0).max;
 const n=xSteps.length;
 const rawW=ctx.w-55-15;
 const estBarW=Math.max(8,Math.min(30,rawW/(n*1.5)));
 const rotateX=meterGreyscaleRotateXLabels(n);
 const chart=drawChartGrid(ctx,{
  pad:meterGreyscaleChartPad({t:20,r:15,b:30,l:55},n),
  xInset:estBarW/2+4,
  xSteps:n-1||1,ySteps:Math.min(5,Math.ceil(yMax)),
  xLabel:(i)=>i<n?meterGreyscaleChartLabel(xSteps[i],xSteps,i):'',
  yLabel:(i,nn)=>(yMax*i/nn).toFixed(yMax>5?0:1),
  rotateX:rotateX
 });
 // Reference lines
 if(1/yMax<=1) drawDashedLine(ctx,chart,[[0,1/yMax],[1,1/yMax]],'#4caf5080');
 if(3/yMax<=1) drawDashedLine(ctx,chart,[[0,3/yMax],[1,3/yMax]],'#ff980080');
 // Draw bars for each x-axis step
 const barW=Math.max(8,Math.min(30,(chart.dw||chart.w)/(n*1.5)));
 xSteps.forEach((step,i)=>{
  const cx=chart.toX(meterGreyCategoryChartX(xSteps,i));
  const dE=deMap[step.ire];
  if(dE!=null){
   const barH=Math.max(0.005,Math.min(dE/yMax,1));
   const y=chart.pad.t+chart.h-barH*chart.h;
   ctx.fillStyle=dE<1?'#4caf50':dE<3?'#ff9800':'#f44';
   ctx.fillRect(cx-barW/2,y,barW,Math.max(2,barH*chart.h));
   ctx.fillStyle='#ccc';ctx.font='11px sans-serif';
   ctx.textAlign='center';
   ctx.fillText(dE.toFixed(2),cx,y-4);
  } else {
   // Placeholder: thin grey line
   ctx.fillStyle='#33333380';
   ctx.fillRect(cx-1,chart.pad.t+chart.h-2,2,2);
  }
 });
 // Average dE line
 meterDrawDeltaSummary(ctx,chart,deValues);
 // White point info (CCT, Δxy from D65)
 if(whiteR&&whiteR.x>0&&whiteR.y>0){
  const wp=meterTargetWhitePoint();
  const dxy=Math.sqrt(Math.pow(whiteR.x-wp.x,2)+Math.pow(whiteR.y-wp.y,2));
  ctx.fillStyle='#888';ctx.font='11px sans-serif';ctx.textAlign='left';
  const wpText=(whiteR.cct?whiteR.cct+'K  ':'')+'\u0394xy '+dxy.toFixed(4);
  ctx.fillText(wpText,chart.pad.l,chart.pad.t-4);
 }
}

function drawDeltaE2000Chart(gs,allSteps,readingMap){
 const ctx=getChartCtx('chartDeltaE2000');
 if(!ctx) return;
 const greyMode=meterGreyRefMode();
 const inclLum=(greyMode==='eotf');
 const lbl=document.getElementById('chartDeltaE2000Label');
 if(lbl) lbl.textContent = "Reference ΔE 2000 ("+meterGreyRefModeLabel(greyMode)+")";
 const whiteR=meterGreyscaleChartWhiteReference(gs);
 // Use the same mode-aware synthetic white when 100% is not yet measured.
 let effectiveWhite2000=whiteR;
 if(!effectiveWhite2000||effectiveWhite2000.Y<=0){
  const synthetic=meterSyntheticGreyWhiteReading(meterColorReferenceNits());
  if(synthetic) effectiveWhite2000=synthetic;
 }
 if(!effectiveWhite2000||effectiveWhite2000.Y<=0){
  if(allSteps) drawDeltaE2000Preset(allSteps);
  return;
 }
 const Lw=effectiveWhite2000.luminance||effectiveWhite2000.Y;
 const Lb=meterChartBlackLevel(gs);
 const gwWeight=meterGrayWorldWeight();
 const xSteps=allSteps||[...gs].sort((a,b)=>a.ire-b.ire);
 // Lab normalization: Xn = D65.X * YWhite, Yn = YWhite, Zn = D65.Z * YWhite.
 // Reference Y per hcfrGreyRef's HCFR mode 0/1/2 semantics.
 const deMap={};
 gs.forEach(rd=>{
	  const X=rd.X||0,Y=rd.Y||0,Z=rd.Z||0;
	  if(Y<=0){deMap[rd.ire]=0;return;} // true black: no chroma target
	  let targetYOverride=null;
	  try{
	   const targetXYZ=meterTargetXYZForReading(rd);
	   if(targetXYZ&&targetXYZ.Y!=null&&targetXYZ.Y>=0) targetYOverride=targetXYZ.Y;
	  }catch(e){}
	  const ref=hcfrGreyRef(meterReadingAnalysisIre(rd)||rd.ire, Y, Lw, Lb, greyMode, rd.r_code, gwWeight, targetYOverride);
    const wp=meterTargetWhitePoint();
    const XnM=(ref.wxN||wp.X)*ref.YWhite, YnM=ref.YWhite, ZnM=(ref.wzN||wp.Z)*ref.YWhite;
    const XnR=(ref.wxN||wp.X)*ref.YWhiteRef, YnR=ref.YWhiteRef, ZnR=(ref.wzN||wp.Z)*ref.YWhiteRef;
  const labM=xyzToLab(X,Y,Z,XnM,YnM,ZnM);
  const labR=xyzToLab(ref.refX,ref.refY,ref.refZ,XnR,YnR,ZnR);
  deMap[rd.ire]=deltaE2000(labM,labR);
 });
 const deValues=Object.values(deMap);
 let yMax;
 if(deValues.length>0){
  const maxDE=Math.max(...deValues);
  yMax=Math.max(2,Math.ceil(maxDE*1.2*2)/2);
 } else {yMax=5;}
 const n=xSteps.length;
 const rawW=ctx.w-55-15;
 const estBarW=Math.max(8,Math.min(30,rawW/(n*1.5)));
 const chart=drawChartGrid(ctx,{
  pad:{t:20,r:15,b:30,l:55},
  xInset:estBarW/2+4,
  xSteps:n-1||1,ySteps:Math.min(5,Math.ceil(yMax)),
  xLabel:(i)=>i<n?meterGreyscaleChartLabel(xSteps[i],xSteps,i):'',
  yLabel:(i,nn)=>(yMax*i/nn).toFixed(yMax>5?0:1)
 });
 if(1/yMax<=1) drawDashedLine(ctx,chart,[[0,1/yMax],[1,1/yMax]],'#4caf5080');
 if(3/yMax<=1) drawDashedLine(ctx,chart,[[0,3/yMax],[1,3/yMax]],'#ff980080');
 const barW=Math.max(8,Math.min(30,(chart.dw||chart.w)/(n*1.5)));
 xSteps.forEach((step,i)=>{
  const cx=chart.toX(meterGreyCategoryChartX(xSteps,i));
  const dE=deMap[step.ire];
  if(dE!=null){
   const barH=Math.max(0.005,Math.min(dE/yMax,1));
   const y=chart.pad.t+chart.h-barH*chart.h;
   ctx.fillStyle=dE<1?'#4caf50':dE<3?'#ff9800':'#f44';
   ctx.fillRect(cx-barW/2,y,barW,Math.max(2,barH*chart.h));
   ctx.fillStyle='#ccc';ctx.font='11px sans-serif';
   ctx.textAlign='center';
   ctx.fillText(dE.toFixed(2),cx,y-4);
  } else {
   ctx.fillStyle='#33333380';
   ctx.fillRect(cx-1,chart.pad.t+chart.h-2,2,2);
  }
 });
 meterDrawDeltaSummary(ctx,chart,deValues);
}

function drawDeltaE2000Preset(gsSteps){
 const ctx=getChartCtx('chartDeltaE2000');
 if(!ctx) return;
 let yMax=5;
 yMax=meterApplyTopYZoom('chartDeltaE2000',yMax,0).max;
 const chart=drawChartGrid(ctx,{
  xSteps:gsSteps.length-1||1,ySteps:5,
  xLabel:(i)=>i<gsSteps.length?meterGreyscaleChartLabel(gsSteps[i],gsSteps,i):'',
  yLabel:(i,n)=>(yMax*i/n).toFixed(1)
 });
 if(1/yMax<=1) drawDashedLine(ctx,chart,[[0,1/yMax],[1,1/yMax]],'#4caf5080');
 if(3/yMax<=1) drawDashedLine(ctx,chart,[[0,3/yMax],[1,3/yMax]],'#ff980080');
}

