// Display type → gamma auto-selection + custom CCSS panel
let customCcssFile=null;
let meterCcssLibrary=[];
let ccssPreviewActiveValue='';
let meterCcssOptionsPromise=loadMeterCcssOptions();
function meterDisplayTypeCcssEntry(value){
 const current=String(value||'');
 const lower=current.toLowerCase();
 if(!(lower.startsWith('ccss_')||lower.startsWith('custom_'))) return null;
 const source=lower.startsWith('custom_')?'custom':'system';
 const name=current.replace(/^(?:ccss|custom)_/i,'');
 return (meterCcssLibrary||[]).find(item=>
  String(item&&item.source||'').toLowerCase()===source &&
  String(item&&item.name||'').toLowerCase()===name.toLowerCase()
 )||null;
}

function meterDisplayTypeMetaText(value){
 const current=String(value||'');
 const entry=meterDisplayTypeCcssEntry(current);
 const name=current.replace(/^(?:ccss|custom)_/i,'');
 return [entry&&entry.display,entry&&entry.technology,entry&&entry.name,name,current].filter(Boolean).join(' ').replace(/[_-]+/g,' ');
}

function meterDisplayTypePatchSizeDefault(value){
 const current=String(value||'').toLowerCase();
 if(current.startsWith('oled')||current.startsWith('qdoled')) return '10';
 if(current==='lcd'||current.startsWith('lcd_')||current==='projector'||current==='projector_ccss') return '100';
 if(current.startsWith('ccss_')||current.startsWith('custom_')){
  const meta=meterDisplayTypeMetaText(value);
  if(/\b(?:qd[-\s]*oled|wrgb[-\s]*oled|rgb[-\s]*oled|woled|amoled|oled)\b/i.test(meta)) return '10';
  if(/(?:\bprojector\b|\blcd\b|\bwled\w*\b|white\s*led|mini\s*led|\bqled\b|\bccfl\w*\b|\bwgccfl\b|rgb\s*led|pfs\s*phosphor|rg\s*phosphor)/i.test(meta)) return '100';
 }
 return null;
}

function meterApplyDisplayTypePatchSizeDefault(value){
 const sel=document.getElementById('meterPatchSize');
 const next=meterDisplayTypePatchSizeDefault(value);
 if(sel&&next) sel.value=next;
}

function meterApplyDisplayTypeSelection(v,opts){
 opts=opts||{};
 applyMeterTargetGammaDefault();
 // Emissive if selecting an emissive generic type, any display-specific CCSS,
 // or the custom-upload panel.
 const vl=v.toLowerCase();
 const ccssEmissive=(vl.startsWith('ccss_')||vl.startsWith('custom_'))&&/(oled|plasma|crt)/i.test(vl);
 const emissive=v.startsWith('oled')||v.startsWith('qdoled')||v==='plasma'||v==='crt'||v==='custom'||ccssEmissive;
 const showCcssPanel=v==='custom'||vl.startsWith('ccss_')||vl.startsWith('custom_');
 document.getElementById('meterPatchInsert').checked=emissive;
 if(opts.patchSizeDefault) meterApplyDisplayTypePatchSizeDefault(v);
 document.getElementById('customCcssPanel').style.display=showCcssPanel?'':'none';
 meterUpdateHdrDiffuseWhiteVisibility(v);
 meterUpdateCustomCcssPanel(v);
 if(showCcssPanel) loadCustomCcssList();
 if(v.startsWith('ccss_')) ccssPreviewLoadByValue('system\t'+v.slice(5),true);
 else if(v.startsWith('custom_')) ccssPreviewLoadByValue('custom\t'+v.slice(7),true);
 // Re-apply Target White/Black display-type defaults for any side the
 // operator has not manually overridden (e.g. OLED-class -> black = 0).
 try{ if(typeof meterApplyTargetLevelsDisplayDefaults==='function') meterApplyTargetLevelsDisplayDefaults(false); }catch(e){}
}

function meterUpdateCustomCcssPanel(value){
 const panel=document.getElementById('customCcssPanel');
 const summary=document.getElementById('customCcssPanelSummary');
 const button=document.getElementById('customCcssPanelBtn');
 if(!panel) return;
 const current=String(value||document.getElementById('meterDisplayType').value||'');
 const visible=current==='custom'||current.toLowerCase().startsWith('custom_')||current.startsWith('ccss_');
 panel.style.display=visible?'':'none';
 if(!visible) return;
 let summaryText='Open the importer to upload CCSS, TI3, or spectral CSV files, preview curves, and manage custom profiles.';
 if(current==='custom'){
  summaryText=customCcssFile
   ? ('Active custom profile: '+ccssPreviewDisplayLabelForValue('custom\t'+customCcssFile)+'.')
   : 'No custom profile selected yet. Open the editor to upload or choose one.';
 }else if(current.startsWith('custom_')){
  summaryText='Selected profile: '+ccssPreviewDisplayLabelForValue('custom\t'+current.slice(7))+'.';
 }else if(current.startsWith('ccss_')){
  summaryText='Selected installed CCSS: '+ccssPreviewDisplayLabelForValue('system\t'+current.slice(5))+'.';
 }
 if(summary) summary.textContent=summaryText;
 if(button) button.textContent=(current.startsWith('ccss_')?'Open CCSS Viewer':'Open CCSS Editor');
}

function meterSelectCustomCcssValue(filename){
 const sel=document.getElementById('meterDisplayType');
 if(!sel||!filename) return;
 const nextValue='custom_'+filename;
 sel.dataset.pendingValue=nextValue;
 sel.value=nextValue;
 if(sel.value===nextValue){
  delete sel.dataset.pendingValue;
  sel.dataset.lastStableValue=nextValue;
  meterApplyDisplayTypeSelection(nextValue,{patchSizeDefault:true});
  return;
 }
 delete sel.dataset.pendingValue;
 sel.value='custom';
 sel.dataset.lastStableValue='custom';
 meterApplyDisplayTypeSelection('custom');
}

function meterOpenCustomCcssEditor(){
 const modal=document.getElementById('customCcssEditorModal');
 if(!modal) return;
 loadCustomCcssList();
 modal.style.display='flex';
 uiSyncBodyScrollLock();
 requestAnimationFrame(()=>{
  const active=ccssPreviewActiveValue||ccssPreviewCurrentDisplayValue()||(customCcssFile?('custom\t'+customCcssFile):'');
  if(active) ccssPreviewLoadByValue(active,true);
  else ccssPreviewClear('Select any built-in or custom CCSS profile to inspect its spectral curves.');
 });
}

function meterCloseCustomCcssEditor(){
 const modal=document.getElementById('customCcssEditorModal');
 if(modal) modal.style.display='none';
 uiSyncBodyScrollLock();
}

const meterDisplayTypeEl=document.getElementById('meterDisplayType');
meterDisplayTypeEl.dataset.lastStableValue=meterDisplayTypeEl.value||'lcd';
meterDisplayTypeEl.addEventListener('change',function(){
 const v=this.value;
 if(v==='custom_editor'){
  const stable=this.dataset.lastStableValue||'lcd';
  this.value=stable;
  meterApplyDisplayTypeSelection(stable);
  meterOpenCustomCcssEditor();
  return;
 }
 this.dataset.lastStableValue=v;
 meterApplyDisplayTypeSelection(v,{patchSizeDefault:true});
 if(v==='custom'||String(v).toLowerCase().startsWith('custom_')) meterOpenCustomCcssEditor();
});

// Custom CCSS file input
document.getElementById('ccssFileInput').addEventListener('change',function(){
 const file=this.files[0];
 const nameInput=document.getElementById('ccssName');
 const btn=document.getElementById('ccssUploadBtn');
 if(file){
  let baseName=file.name.replace(/\.(ccss|csv|ti3)$/i,'');
  nameInput.value=baseName;
  btn.disabled=false;
 } else {
  nameInput.value='';
  btn.disabled=true;
 }
});

document.getElementById('ccssUploadBtn').addEventListener('click',async function(){
 const file=document.getElementById('ccssFileInput').files[0];
 const name=document.getElementById('ccssName').value.trim();
 if(!file||!name){toast('Select a file and enter a name',true);return;}
 const status=document.getElementById('ccssUploadStatus');
 status.textContent='Uploading...';
 this.disabled=true;
 try{
  const buf=await file.arrayBuffer();
  const b64=btoa(String.fromCharCode(...new Uint8Array(buf)));
  const currentDisplayType=((document.getElementById('meterDisplayType')||{}).dataset.lastStableValue
   || (document.getElementById('meterDisplayType')||{}).value || 'lcd');
  const r=await fetchJSON('/api/ccss/upload',{method:'POST',headers:{'Content-Type':'application/json'},
   body:JSON.stringify({name:name,content:b64,filename:file.name,display_type:currentDisplayType}),_timeoutMs:15000});
  if(r&&r.status==='ok'){
   status.textContent=r.message||'Uploaded';
   status.style.color='var(--green)';
   customCcssFile=r.filename;
   document.getElementById('ccssFileInput').value='';
   document.getElementById('ccssName').value='';
    await refreshMeterCcssCatalog();
    await loadCustomCcssList();
    meterSelectCustomCcssValue(r.filename);
    await ccssPreviewLoadByValue('custom\t'+r.filename,false);
    meterUpdateCustomCcssPanel(document.getElementById('meterDisplayType').value);
    saveMeterSettings();
   toast(r.message||'CCSS profile saved');
  } else {
   status.textContent=r&&r.message?r.message:'Upload failed';
   status.style.color='var(--red)';
   toast(r&&r.message?r.message:'Upload failed',true);
  }
 }catch(e){
  status.textContent='Upload error';
  status.style.color='var(--red)';
 }
 this.disabled=false;
 setTimeout(()=>{status.textContent='';status.style.color='var(--text2)';},5000);
});

async function loadCustomCcssList(){
 const r=await fetchJSON('/api/ccss/list',{_quiet:true,_timeoutMs:5000});
 meterUpdateCustomCcssPanel(document.getElementById('meterDisplayType').value);
 const el=document.getElementById('customCcssList');
 if(!r||!r.files||r.files.length===0){el.innerHTML='<div style="font-size:.7rem;color:var(--text2)">No custom profiles</div>';return;}
 el.innerHTML=r.files.map(f=>{
  const label=f.replace(/\.ccss$/i,'');
  const active=customCcssFile===f;
  return '<div style="display:flex;align-items:center;gap:6px;margin-bottom:3px">'
  +'<button class="btn btn-sm '+(active?'btn-success':'btn-secondary')+'" style="flex:1;font-size:.7rem;padding:2px 6px;text-align:left" onclick="selectCustomCcss(\''+f+'\')">'+(active?'\u2713 ':'')+label+'</button>'
  +'<button class="btn btn-sm" style="font-size:.68rem;padding:2px 6px;color:var(--red)" onclick="deleteCustomCcss(\''+f+'\')">\u2715</button></div>';
 }).join('');
}

async function selectCustomCcss(filename){
 // Dry-run validate before marking the file as the active selection.
 // Bad files get flagged in a toast; the selection is still applied so
 // the user can delete or replace it.
 try{
  const v=await fetchJSON('/api/ccss/validate',{
   method:'POST',
   headers:{'Content-Type':'application/json'},
   body:JSON.stringify({ccss_file:'custom/'+filename}),
   _quiet:true,_timeoutMs:5000
  });
  if(v && v.ok===false){ toast('CCSS invalid: '+(v.error||'parse failed'), true); }
  else if(v && v.ok && v.description){ toast('CCSS: '+v.description); }
 }catch(e){}
 customCcssFile=filename;
   meterSelectCustomCcssValue(filename);
 ccssPreviewLoadByValue('custom\t'+filename,true);
 loadCustomCcssList();
 saveMeterSettings();
}

function ccssCleanLabelPart(text){
 return String(text||'').replace(/\.ccss$/i,'').replace(/_/g,' ').replace(/\s+/g,' ').trim();
}

function ccssPrettyTechnology(text){
 let tech=ccssCleanLabelPart(text)
  .replace(/\bQD OLED\b/gi,'QD-OLED')
  .replace(/\bWRGB OLED\b/gi,'WRGB OLED')
  .replace(/\bRGB OLED\b/gi,'RGB OLED')
  .replace(/\bJOLED\b/g,'JOLED')
  .replace(/\bWLED\b/g,'W-LED')
  .replace(/\bQD Mini LED\b/gi,'QD-Mini LED')
  .replace(/\bMini LED\b/gi,'Mini-LED')
  .replace(/\bGB R LED\b/gi,'GB-R LED')
  .replace(/\bRG Phosphor\b/gi,'RG Phosphor')
  .replace(/\bPFS Phosphor\b/gi,'PFS Phosphor')
  .replace(/\bLCD White LED IPS\b/gi,'W-LED IPS LCD');
 return tech;
}

function ccssDisplayStartsWithType(display){
 return /^(?:white led|w-?led|qd-?oled|wrgb oled|rgb qd-?oled|rgb oled|oled|lcd|plasma|projector|crt|ccfl|rgb led|pfs phosphor|rg phosphor)\b/i.test(String(display||'').trim());
}

function ccssDisplayLooksIncomplete(display){
 const text=String(display||'').trim();
 if(!text) return true;
 const open=(text.match(/\(/g)||[]).length;
 const close=(text.match(/\)/g)||[]).length;
 if(open!==close) return true;
 if(/\((?:RGB|WRGB|QD|W|GB|VA|IPS)\s*$/i.test(text)) return true;
 return false;
}

function ccssLabelLooksGeneric(label){
 return ccssDisplayStartsWithType(label) || /(?:^|\s)(?:generic|family)(?:\s|$)/i.test(String(label||''));
}

function ccssIsGenericProfile(entry){
 const name=String((entry&&entry.name)||'');
 const display=String((entry&&entry.display)||'');
 return /^(?:WRGB_OLED_LG|QD-OLED_Generic|WLEDFamily_07Feb11|CCFLFamily_07Feb11|WGCCFLFamily_07Feb11|RGBLEDFamily_07Feb11|PlasmaFamily_20Jul12|ProjectorFamily_07Feb11|CRT)\.ccss$/i.test(name)
  || /^(?:White_LED|RGB_LED|CCFL|Wide_Gamut_CCFL|PFS_Phosphor|RG_Phosphor|Plasma|Projector)_/i.test(name)
  || /(?:^|\s)(?:Generic|Family)(?:\s|$)/i.test(display);
}

function ccssFormatNameFromFilename(name){
 const base=String(name||'').replace(/\.ccss$/i,'').replace(/_-_.*/,'');
 let match=base.match(/^(.*)_\(([^)]+)\)$/);
 if(match){
  return ccssCleanLabelPart(match[1])+' ('+ccssPrettyTechnology(match[2])+')';
 }
 match=base.match(/^(QD-OLED|WRGB_OLED|RGB_OLED|LCD|CRT|Plasma|Projector|White_LED|RGB_LED|CCFL|Wide_Gamut_CCFL|PFS_Phosphor|RG_Phosphor)_(.+)$/i);
 if(match){
  return ccssCleanLabelPart(match[2])+' ('+ccssPrettyTechnology(match[1])+')';
 }
 return ccssCleanLabelPart(base);
}

  function ccssLegacyTechFirstName(name){
   return /^(?:QD-OLED|WRGB_OLED|RGB_OLED|LCD|CRT|Plasma|Projector|White_LED|RGB_LED|CCFL|Wide_Gamut_CCFL|PFS_Phosphor|RG_Phosphor)_/i.test(String(name||''));
  }

function ccssFormatDropdownLabel(entry){
 const display=ccssCleanLabelPart(entry&&entry.display);
 const technology=ccssPrettyTechnology(entry&&entry.technology);
 const filenameLabel=ccssFormatNameFromFilename(entry&&entry.name);
 const hasKnownTechnology=technology && !/^unknown$/i.test(technology);
 const displayHasCompleteType=/\([^)]*\)\s*$/.test(display) && !ccssDisplayLooksIncomplete(display);
 const metadataLabel=displayHasCompleteType ? display : (display && hasKnownTechnology ? display+' ('+technology+')' : display);
 const metadataBad=!display || ccssDisplayLooksIncomplete(display) || ccssLabelLooksGeneric(display);
 const filenameBetter=filenameLabel && /\([^)]*\)/.test(filenameLabel) && (!metadataLabel || ccssDisplayLooksIncomplete(metadataLabel) || ccssLabelLooksGeneric(metadataLabel) || filenameLabel.length>metadataLabel.length);
 if(filenameBetter || metadataBad) return filenameLabel||metadataLabel||display;
 if(metadataLabel) return metadataLabel;
 return filenameLabel;
}

function ccssPreviewValue(entry){
 return String((entry&&entry.source)||'system')+'\t'+String((entry&&entry.name)||'');
}

function ccssPreviewFindEntry(value){
 return (meterCcssLibrary||[]).find(entry=>ccssPreviewValue(entry)===String(value||''))||null;
}

function ccssPreviewEscapeHtml(text){
 return String(text==null?'':text).replace(/[&<>"']/g,ch=>({
  '&':'&amp;',
  '<':'&lt;',
  '>':'&gt;',
  '"':'&quot;',
  "'":'&#39;'
 }[ch]||ch));
}

function ccssPreviewCurrentDisplayValue(){
 const sel=document.getElementById('meterDisplayType');
 const value=String(sel&&sel.value||'');
 if(value.startsWith('custom_')) return 'custom\t'+value.slice(7);
 if(value.startsWith('ccss_')) return 'system\t'+value.slice(5);
 return '';
}

function ccssPreviewDisplayLabelForValue(value){
 const entry=ccssPreviewFindEntry(value);
 return entry ? ccssFormatDropdownLabel(entry) : 'CCSS profile';
}

function ccssExportSetStatus(message,isError){
 const el=document.getElementById('ccssExportStatus');
 if(!el) return;
 el.textContent=message||'';
 el.style.color=isError?'var(--red)':'var(--text2)';
}

function ccssExportCurrentEntry(){
 const active=ccssPreviewActiveValue||ccssPreviewCurrentDisplayValue()||(customCcssFile?('custom\t'+customCcssFile):'');
 return ccssPreviewFindEntry(active);
}

function ccssExportSyncControls(message,isError){
 const entry=ccssExportCurrentEntry();
 const btn=document.getElementById('ccssExportBtn');
 const format=document.getElementById('ccssExportFormat');
 const deleteBtn=document.getElementById('ccssDeleteSelectedBtn');
 const enabled=!!entry;
 const canDelete=!!(entry&&entry.source==='custom');
 if(btn) btn.disabled=!enabled;
 if(format) format.disabled=!enabled;
 if(deleteBtn) deleteBtn.disabled=!canDelete;
 if(message!==undefined){
  ccssExportSetStatus(message,!!isError);
 }else if(!enabled){
  ccssExportSetStatus('Select a CCSS profile to download. Custom profiles can also be deleted here.',false);
 }
}

async function ccssExportSelected(){
 const entry=ccssExportCurrentEntry();
 if(!entry){
  ccssExportSyncControls('Select a CCSS profile to download.',false);
  toast('Select a CCSS profile first',true);
  return;
 }
 const btn=document.getElementById('ccssExportBtn');
 const formatSelect=document.getElementById('ccssExportFormat');
 const format=String(formatSelect&&formatSelect.value||'ccss');
 const prevText=btn?btn.textContent:'Export';
 if(btn) btn.disabled=true;
 if(btn) btn.textContent='Preparing...';
 ccssExportSetStatus('Building '+format.toUpperCase()+' download...',false);
 try{
  const res=await fetch('/api/ccss/export',{
   method:'POST',
   headers:{'Content-Type':'application/json'},
   body:JSON.stringify({filename:entry.name,source:entry.source,format:format})
  });
  if(res.ok){
   const blob=await res.blob();
   const cd=res.headers.get('Content-Disposition')||'';
   const match=cd.match(/filename="([^"]+)"/i);
   const fallback=(String(entry.name||'').replace(/\.[^.]+$/,'')||'ccss_profile')+'.'+format;
   const filename=match?match[1]:fallback;
   const href=URL.createObjectURL(blob);
   const link=document.createElement('a');
   link.href=href;
   link.download=filename;
   document.body.appendChild(link);
   link.click();
   link.remove();
   setTimeout(()=>URL.revokeObjectURL(href),1000);
   ccssExportSetStatus('Downloaded '+filename,false);
   toast('Downloaded '+filename);
  }else{
   const payload=await res.json().catch(()=>null);
   const message=(payload&&payload.message)||'Export failed';
   ccssExportSetStatus(message,true);
   toast(message,true);
  }
 }catch(e){
  ccssExportSetStatus('Export error: '+e.message,true);
  toast('Export error: '+e.message,true);
 }finally{
  if(btn) btn.textContent=prevText;
  ccssExportSyncControls();
 }
}

async function deleteSelectedCustomCcss(){
 const entry=ccssExportCurrentEntry();
 if(!entry||entry.source!=='custom'){
  ccssExportSyncControls('Only custom CCSS profiles can be deleted.',true);
  toast('Select a custom CCSS profile first',true);
  return;
 }
 const btn=document.getElementById('ccssDeleteSelectedBtn');
 const prevText=btn?btn.textContent:'Delete Profile';
 if(btn) btn.disabled=true;
 if(btn) btn.textContent='Deleting...';
 try{
  const ok=await deleteCustomCcss(entry.name);
  if(ok) ccssExportSetStatus('Deleted '+entry.name,false);
 }finally{
  if(btn) btn.textContent=prevText;
  ccssExportSyncControls();
 }
}

function ccssPreviewSampleColor(index){
 const colors=['#ff6b6b','#67d36f','#6fb6ff','#f6ef9a','#ff9f68','#d29cff'];
 return colors[index%colors.length];
}

function ccssPreviewClear(message){
 const meta=document.getElementById('ccssPreviewMeta');
 const legend=document.getElementById('ccssPreviewLegend');
 const canvas=document.getElementById('ccssPreviewCanvas');
 ccssExportSyncControls();
 if(meta) meta.textContent=message||'Select any built-in or custom CCSS profile to inspect its spectral curves.';
 if(legend) legend.innerHTML='';
 if(!canvas) return;
 const ctx=setupCanvasHiDPI(canvas);
 if(!ctx) return;
 ctx.fillStyle='#0d0d15';
 ctx.fillRect(0,0,ctx.w,ctx.h);
 ctx.fillStyle='#80889a';
 ctx.font='14px sans-serif';
 ctx.textAlign='center';
 ctx.textBaseline='middle';
 ctx.fillText(message||'Select a CCSS profile to preview',ctx.w/2,ctx.h/2);
}

function ccssPreviewPopulateOptions(files){
 const select=document.getElementById('ccssPreviewSelect');
 if(!select) return;
 const previous=select.value||ccssPreviewActiveValue||ccssPreviewCurrentDisplayValue()||(customCcssFile?('custom\t'+customCcssFile):'');
 select.innerHTML='<option value="">Choose installed CCSS profile...</option>';
 const customGroup=document.createElement('optgroup');
 customGroup.label='Custom';
 const systemGroup=document.createElement('optgroup');
 systemGroup.label='Installed';
 (Array.isArray(files)?files:[])
  .slice()
  .sort((a,b)=>ccssFormatDropdownLabel(a).localeCompare(ccssFormatDropdownLabel(b)))
  .forEach(entry=>{
   const option=document.createElement('option');
   option.value=ccssPreviewValue(entry);
   option.textContent=ccssFormatDropdownLabel(entry)+(entry.source==='custom'?' (custom)':'');
   if(entry.source==='custom') customGroup.appendChild(option);
   else systemGroup.appendChild(option);
  });
 if(customGroup.children.length) select.appendChild(customGroup);
 if(systemGroup.children.length) select.appendChild(systemGroup);
 select.value=previous;
 if(select.value!==previous) select.value='';
 ccssPreviewActiveValue=select.value||'';
 ccssExportSyncControls();
 if(ccssPreviewActiveValue) ccssPreviewLoadByValue(ccssPreviewActiveValue,true);
 else ccssPreviewClear('Select any built-in or custom CCSS profile to inspect its spectral curves.');
 meterUpdateHdrDiffuseWhiteVisibility();
}

async function ccssPreviewLoadByValue(value,quiet){
 const select=document.getElementById('ccssPreviewSelect');
 const entry=ccssPreviewFindEntry(value);
 if(!entry){
  ccssPreviewActiveValue='';
  if(select) select.value='';
  ccssPreviewClear('Select any built-in or custom CCSS profile to inspect its spectral curves.');
  return;
 }
 ccssPreviewActiveValue=ccssPreviewValue(entry);
 if(select) select.value=ccssPreviewActiveValue;
 ccssExportSyncControls();
 const meta=document.getElementById('ccssPreviewMeta');
 if(meta) meta.textContent='Loading '+ccssFormatDropdownLabel(entry)+'...';
 const payload=await fetchJSON('/api/ccss/preview',{
  method:'POST',
  headers:{'Content-Type':'application/json'},
  body:JSON.stringify({filename:entry.name,source:entry.source}),
  _quiet:!!quiet,
  _timeoutMs:12000
 });
 if(!payload||payload.ok===false){
  ccssPreviewClear((payload&&payload.error)||'Unable to load spectral data for this CCSS profile.');
  if(!quiet) toast((payload&&payload.error)||'Unable to load spectral data',true);
  return;
 }
 ccssPreviewRender(payload);
}

function ccssPreviewRender(payload){
 const meta=document.getElementById('ccssPreviewMeta');
 const legend=document.getElementById('ccssPreviewLegend');
 const canvas=document.getElementById('ccssPreviewCanvas');
 if(!canvas) return;
 const wavelengths=Array.isArray(payload&&payload.wavelengths)?payload.wavelengths:[];
 const samples=Array.isArray(payload&&payload.samples)?payload.samples:[];
 if(!wavelengths.length||!samples.length){
  ccssPreviewClear('No spectral data found in this CCSS profile.');
  return;
 }
 const minNm=Number(payload.start_nm)||Number(wavelengths[0])||380;
 const maxNm=Number(payload.end_nm)||Number(wavelengths[wavelengths.length-1])||780;
 let maxValue=Number(payload.max_value)||0;
 if(!(maxValue>0)){
  samples.forEach(sample=>{
   (sample.values||[]).forEach(value=>{
    const numeric=Number(value)||0;
    if(numeric>maxValue) maxValue=numeric;
   });
  });
 }
 if(!(maxValue>0)) maxValue=1;

 const ctx=setupCanvasHiDPI(canvas);
 if(!ctx) return;
 const chart=drawChartGrid(ctx,{
  pad:{t:20,r:18,b:36,l:50},
  xSteps:8,
  ySteps:5,
  xLabel:(step,total)=>String(Math.round(minNm+((maxNm-minNm)*(step/total)))),
  yLabel:(step,total)=>{
   const value=maxValue*(step/total);
   if(value>=10) return value.toFixed(0);
   if(value>=1) return value.toFixed(1).replace(/\.0$/,'');
   return value.toFixed(3).replace(/0+$/,'').replace(/\.$/,'');
  }
 });

 const plotLeft=chart.pad.l;
 const plotTop=chart.pad.t;
 const plotWidth=chart.w;
 const plotHeight=chart.h;
 const spectrum=ctx.createLinearGradient(plotLeft,0,plotLeft+plotWidth,0);
 spectrum.addColorStop(0.00,'rgba(91,58,197,0.22)');
 spectrum.addColorStop(0.14,'rgba(58,94,220,0.18)');
 spectrum.addColorStop(0.28,'rgba(45,170,240,0.16)');
 spectrum.addColorStop(0.43,'rgba(60,210,155,0.14)');
 spectrum.addColorStop(0.58,'rgba(210,214,82,0.14)');
 spectrum.addColorStop(0.76,'rgba(245,164,58,0.16)');
 spectrum.addColorStop(1.00,'rgba(226,84,84,0.18)');
 ctx.save();
 ctx.fillStyle=spectrum;
 ctx.fillRect(plotLeft,plotTop,plotWidth,plotHeight);
 ctx.restore();
 ctx.strokeStyle='rgba(132,148,178,0.85)';
 ctx.lineWidth=1.2;
 ctx.beginPath();
 ctx.moveTo(plotLeft,plotTop);
 ctx.lineTo(plotLeft,plotTop+plotHeight);
 ctx.lineTo(plotLeft+plotWidth,plotTop+plotHeight);
 ctx.stroke();

 samples.forEach((sample,index)=>{
  const values=Array.isArray(sample.values)?sample.values:[];
  const pointCount=Math.min(values.length,wavelengths.length);
  if(pointCount<2) return;
  const color=ccssPreviewSampleColor(index);
  const points=[];
  for(let i=0;i<pointCount;i++){
   const nm=Number(wavelengths[i]);
   const value=Number(values[i])||0;
   const x=maxNm!==minNm ? ((nm-minNm)/(maxNm-minNm)) : 0;
   const y=maxValue>0 ? (value/maxValue) : 0;
   points.push([Math.max(0,Math.min(1,x)),Math.max(0,Math.min(1,y))]);
  }
  drawLine(ctx,chart,points,color,2);
 });

 ctx.fillStyle='#aeb8cd';
 ctx.font='12px sans-serif';
 ctx.textAlign='center';
 ctx.fillText('Wavelength (nm)',plotLeft+(plotWidth/2),ctx.h-8);
 ctx.save();
 ctx.translate(15,plotTop+(plotHeight/2));
 ctx.rotate(-Math.PI/2);
 ctx.fillText('Relative spectral power',0,0);
 ctx.restore();

 if(meta){
  const parts=[];
  const title=payload.description||payload.display||payload.name||'CCSS profile';
  parts.push('<strong style="color:#dfe6f6">'+ccssPreviewEscapeHtml(title)+'</strong>');
  if(payload.technology) parts.push(ccssPreviewEscapeHtml(payload.technology));
  if(payload.reference) parts.push('Ref: '+ccssPreviewEscapeHtml(payload.reference));
  if(payload.bands) parts.push(String(payload.bands)+' bands');
  if(minNm||maxNm) parts.push(ccssPreviewEscapeHtml(String(Math.round(minNm))+'-'+String(Math.round(maxNm))+' nm'));
  meta.innerHTML=parts.join(' &middot; ');
 }
 if(legend){
  legend.innerHTML=samples.map((sample,index)=>{
   const color=ccssPreviewSampleColor(index);
   const label=ccssPreviewEscapeHtml(sample.label||('Set '+(index+1)));
   const peakNm=Number(sample.peak_nm)||0;
   const peakValue=Number(sample.peak_value)||0;
   const peakText=peakNm>0
    ? ('Peak '+Math.round(peakNm)+' nm'+(peakValue>0?' / '+peakValue.toFixed(3):''))
    : '';
   return '<div style="display:flex;align-items:center;gap:6px;font-size:.68rem;color:var(--text2);padding:4px 8px;background:#111723;border:1px solid #2a3140;border-radius:999px">'
    +'<span style="width:10px;height:10px;border-radius:999px;background:'+color+';display:inline-block"></span>'
    +'<span>'+label+'</span>'
    +(peakText?'<span style="color:#8d97ab">'+ccssPreviewEscapeHtml(peakText)+'</span>':'')
    +'</div>';
  }).join('');
 }
}

async function refreshMeterCcssCatalog(){
 meterCcssOptionsPromise=loadMeterCcssOptions();
 await meterCcssOptionsPromise;
}

// Populate the display-specific CCSS optgroup with all .ccss files on the device,
// sorted alphabetically. Option value is "ccss_FILENAME" (for system) or
// "custom_FILENAME" (for user-uploaded). The backend's resolve_display_type()
// handles both prefixes identically.
async function loadMeterCcssOptions(){
 const r=await fetchJSON('/api/ccss/all',{_quiet:true,_timeoutMs:5000});
 const grp=document.getElementById('meterDtCcss');
 if(!grp) return;
 grp.innerHTML='';
 meterCcssLibrary=(r&&Array.isArray(r.files))?r.files:[];
 ccssPreviewPopulateOptions(meterCcssLibrary);
 if(!meterCcssLibrary.length) return;
 const sel=document.getElementById('meterDisplayType');
 const prev=sel.value;
 const byLabel=new Map();
 meterCcssLibrary.forEach(f=>{
  if(f.source==='system'&&ccssIsGenericProfile(f)) return;
  const label=ccssFormatDropdownLabel(f);
  if(!label) return;
  const score=(f.source==='custom'?1000:0)
   +(ccssLegacyTechFirstName(f.name)?0:100)
   +((f.display&&f.technology)?20:0)
   +(String(f.name||'').length>0?Math.min(String(f.name).length,50):0);
  const current=byLabel.get(label);
  if(!current||score>current.score){
   byLabel.set(label,{entry:f,label:label,score:score});
  }
 });
 [...byLabel.values()].sort((a,b)=>a.label.localeCompare(b.label)).forEach(item=>{
  const f=item.entry;
  const prefix=f.source==='custom'?'custom_':'ccss_';
  const opt=document.createElement('option');
  opt.value=prefix+f.name;
  opt.textContent=item.label+(f.source==='custom'?' (custom)':'');
  grp.appendChild(opt);
 });
 // restore previous or pending selection if still present
 const restore=sel.dataset.pendingValue||prev;
 if(restore){
  sel.value=restore;
  if(sel.value===restore) delete sel.dataset.pendingValue;
 }
}

document.getElementById('ccssPreviewSelect').addEventListener('change',function(){
