  return;
 }
 ccssPreviewLoadByValue(value,false);
});

function getMeterPatchSize(){
 // Accepts plain integer ("10", "18", ...) or APL-prefixed ("apl_18").
 // 5%/10% APL stay black windows; grey-surround APL presets use the
 // daemon-style 100+APL token so the shared patch renderer can compute a
 // dynamic background while keeping the foreground window at 10%.
 const raw=document.getElementById('meterPatchSize').value;
 const m=String(raw).match(/^apl_(\d+)/i);
 if(m){
  const apl=parseInt(m[1],10);
  return apl>10 ? 100+apl : apl;
 }
 return parseInt(raw,10);
}

function getEffectiveDisplayType(){
 const v=document.getElementById('meterDisplayType').value;
 if(v==='custom'&&customCcssFile) return 'custom_'+customCcssFile;
 return v;
}

function meterNormalizeStoredDisplayType(value,ccssFile){
 const current=String(value||'');
 if(current!=='custom') return current;
 return ccssFile?('custom_'+ccssFile):'lcd';
}

function getMeterRefreshRate(){
 const sel=document.getElementById('meterRefreshRate');
 // Auto: send no refresh override -- the meter auto-detects (no -Y r|n, no -Y R:rate).
 if(sel&&sel.value==='auto') return '';
 if(sel&&sel.value) return sel.value;
 // "Match Display Setting" (value="") — resolve the current output mode's
 // refresh so spotread gets -Y R:<rate>, which makes it SKIP its mandatory
 // (and on a sample-and-hold OLED, unreliable) "read 80% white to calibrate
 // refresh frequency" step. Try several sources for the current mode index,
 // since config.mode_idx can be stale/undefined at read time.
 const arr=(typeof modes!=='undefined'&&Array.isArray(modes))?modes:[];
 const candidates=[];
 if(typeof config!=='undefined'&&config.mode_idx!=null) candidates.push(String(config.mode_idx));
 const selMode=document.getElementById('mode_idx');
 if(selMode&&selMode.value!=null&&selMode.value!=='') candidates.push(String(selMode.value));
 for(const c of candidates){
  const m=arr.find(m=>String(m.idx)===c);
  if(m&&m.refresh) return m.refresh;
 }
 return '';
}

function meterDelaySanitize(raw){
 raw=String(raw==null?'':raw).replace(/[^\d.]/g,'');
 const dot=raw.indexOf('.');
 if(dot>=0) raw=raw.slice(0,dot+1)+raw.slice(dot+1).replace(/\./g,'');
 return raw;
}

function meterDelayParseSeconds(raw,fallbackSeconds){
 const fallback=(fallbackSeconds!=null)?fallbackSeconds:1.0;
 const sanitized=meterDelaySanitize(raw);
 if(!sanitized||sanitized==='.') return fallback;
 const value=parseFloat(sanitized);
 if(!(Number.isFinite(value)&&value>=0)) return fallback;
 return value;
}

function meterDelayFormatSeconds(seconds,fallbackSeconds){
 const fallback=(fallbackSeconds!=null)?fallbackSeconds:1.0;
 let value=Number(seconds);
 if(!(Number.isFinite(value)&&value>=0)) value=fallback;
 value=Math.round(value*1000)/1000;
 return String(value).replace(/(\.\d*?)0+$/,'$1').replace(/\.$/,'');
}

function meterDelaySyncInput(el){
 meterDelayExplicit=true;
 if(!el) return;
 el.value=meterDelaySanitize(el.value);
}

function meterSecondsSyncInput(el){
 if(!el) return;
 el.value=meterDelaySanitize(el.value);
}

function meterDelayMs(){
 const el=document.getElementById('meterDelay');
 return Math.round(meterDelayParseSeconds(el?el.value:'',1.0)*1000);
}

function meterSecondsInputMs(id,fallbackSeconds){
 const el=document.getElementById(id);
 return Math.round(meterDelayParseSeconds(el?el.value:'',fallbackSeconds)*1000);
}

function meterSecondsLoadValue(id,raw,fallbackSeconds){
 const el=document.getElementById(id);
 if(!el) return;
 const fallback=(fallbackSeconds!=null)?fallbackSeconds:0;
 if(raw==null||raw===''){
  el.value=meterDelayFormatSeconds(fallback);
  return;
 }
 const numeric=Number(raw);
 if(Number.isFinite(numeric)&&numeric>=0){
  const seconds=numeric>99?(numeric/1000):numeric;
  el.value=meterDelayFormatSeconds(seconds,fallback);
  return;
 }
 el.value=meterDelayFormatSeconds(meterDelayParseSeconds(raw,fallback),fallback);
}

function meterNumberInput(id,fallback,min,max){
 const el=document.getElementById(id);
 let value=Number(el?el.value:'');
 if(!Number.isFinite(value)) value=fallback;
 if(min!=null&&value<min) value=min;
 if(max!=null&&value>max) value=max;
 return value;
}

function meterPatternInsertionPayload(){
 const master=document.getElementById('meterPatchInsert');
 return {
  pattern_delay_ms:meterSecondsInputMs('meterPatternDelay',0),
  patch_insert:!!(master&&master.checked),
  patch_insert_patch_enabled:!!(master&&master.checked&&document.getElementById('meterPatchInsertPatchEnabled')&&document.getElementById('meterPatchInsertPatchEnabled').checked),
  patch_insert_patch_every:Math.round(meterNumberInput('meterPatchInsertPatchEvery',1,1,999)),
  patch_insert_patch_duration_ms:meterSecondsInputMs('meterPatchInsertPatchDuration',1),
  patch_insert_patch_level:meterNumberInput('meterPatchInsertPatchLevel',10,0,100),
  patch_insert_time_enabled:!!(master&&master.checked&&document.getElementById('meterPatchInsertTimeEnabled')&&document.getElementById('meterPatchInsertTimeEnabled').checked),
  patch_insert_time_frequency_ms:meterSecondsInputMs('meterPatchInsertTimeFrequency',5),
  patch_insert_time_duration_ms:meterSecondsInputMs('meterPatchInsertTimeDuration',5),
  patch_insert_time_level:meterNumberInput('meterPatchInsertTimeLevel',25,0,100)
 };
}

function meterDelayLoadValue(raw,explicit){
 const el=document.getElementById('meterDelay');
 if(!el) return;
 meterDelayExplicit=!!explicit;
 if(raw==null||raw===''){
  el.value=meterDelayFormatSeconds(1.0);
  return;
 }
 const numeric=Number(raw);
 if(Number.isFinite(numeric)&&numeric>=0){
  const seconds=numeric>99?(numeric/1000):numeric;
  if(!meterDelayExplicit&&Math.abs(seconds-1.0)>0.0005) meterDelayExplicit=true;
  el.value=meterDelayFormatSeconds(seconds);
  return;
 }
 el.value=meterDelayFormatSeconds(meterDelayParseSeconds(raw,1.0));
}

async function deleteCustomCcss(filename){
 if(!confirm('Delete '+filename+'?')) return false;
 try{
  const r=await fetchJSON('/api/ccss/delete/'+encodeURIComponent(filename),{method:'POST',_timeoutMs:5000});
  if(r&&r.status==='ok'){
   if(customCcssFile===filename) customCcssFile=null;
   if(ccssPreviewActiveValue==='custom\t'+filename) ccssPreviewActiveValue='';
   await refreshMeterCcssCatalog();
   await loadCustomCcssList();
   if(!ccssPreviewActiveValue) ccssPreviewClear('Select any built-in or custom CCSS profile to inspect its spectral curves.');
   ccssExportSyncControls();
   toast('Deleted');
   return true;
  }
  toast(r&&r.message?r.message:'Delete failed',true);
 }catch(e){
  toast('Delete error: '+e.message,true);
 }
 return false;
}

