function meterRefreshActiveSeriesCharts(){
	 if(!meterActiveSeriesType||!meterActiveSeriesPoints||meterSeriesRunning||meterAutoCalStatusActive()) return;
	 const hasReadingContext=Array.isArray(meterReadings)&&meterReadings.some(rd=>rd&&(rd.signal_mode||rd.target_gamma||rd.max_luma||rd.dv_map_mode));
	 meterSetActiveSeriesChartContext(hasReadingContext?{steps:meterSeriesSteps||[],readings:meterReadings}:null);
	 meterSeriesSteps=meterBuildStepsJS(meterActiveSeriesType,meterActiveSeriesPoints);
	 const isColor=meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations';
	 const sortedSteps=isColor?[...meterSeriesSteps]:meterGreyscaleSeriesSteps(meterSeriesSteps);
	 meterReadings=meterAttachSeriesMeta(meterFilterReadingsForCurrentSteps(meterReadings||[],meterActiveSeriesType));
 // The attach step stamps each reading's target_Yn from its matched step,
 // which carries the value baked at series-load time. Override that with
 // the live target-gamma computation so any active gamma change (e.g. the
 // TARGET GAMMA dropdown) is reflected on the charts without a re-read.
 meterRegradeActiveSeriesTargets();
 const white=meterFindSeriesWhiteReading(meterReadings);
 if(white) meterWhiteReading=white;
 else if(meterWhiteReading&&!meterWhiteReading.synthetic_target) meterNormalizeMeasuredReading(meterWhiteReading);
 if(meterCurrentPatchStep) meterCurrentPatchStep=meterCanonicalSeriesStep(meterCurrentPatchStep);
 const done=new Set();
 (meterReadings||[]).forEach(r=>{
  if(r){
   delete r._dE_cache_key;
   delete r._dE_raw;
   delete r._dE_lc;
   delete r._gamma_rgb;
   if(r.luminance!=null) done.add(meterStepNameKey(r));
  }
 });
 meterBuildPatchThumbs(sortedSteps,done,meterCurrentPatchStep?meterStepNameKey(meterCurrentPatchStep):null);
 if(meterReadings&&meterReadings.length){
  const sorted=isColor?[...meterReadings]:[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
  drawAllCharts(sorted);
 } else {
  drawAllChartsPreset(sortedSteps);
 }
 meterUpdateSeriesTabUi();
   if(meterCurrentPatchStep) meterLgGreySyncForCurrentStep(false);
   else meterRenderGreyTvControls(null);
}

let meterGreyscaleResizeTimer=null;
window.addEventListener('resize',()=>{
 if(meterActiveSeriesType!=='greyscale') return;
 if(meterGreyscaleResizeTimer) clearTimeout(meterGreyscaleResizeTimer);
 meterGreyscaleResizeTimer=setTimeout(()=>{
  if(meterAutoCalStatusActive()&&!meterAutoCalLatestStatus) return;
  if(meterReadings&&meterReadings.length){
   const sorted=[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
   drawAllCharts(sorted);
  } else if(meterSeriesSteps&&meterSeriesSteps.length){
   const sorted=meterGreyscaleSeriesSteps(meterSeriesSteps);
   drawAllChartsPreset(sorted);
  }
 },80);
});

document.getElementById('meterTargetGamut').addEventListener('change',()=>{
 updateMeterTargetWhitepointVisibility();
 meterOnGreyRefChange();
 meterRefreshActiveSeriesCharts();
});

document.getElementById('meterTargetGamma').addEventListener('change',()=>{
 if(getVal('signal_mode')==='dv'){
  applyMeterTargetGammaDefault();
  meterActiveSeriesTargetGamma=null;
  meterRefreshActiveSeriesCharts();
  return;
 }
 // Re-grade the currently displayed series against the newly selected target
 // gamma. meterGreyTargetGammaSelection() prefers meterActiveSeriesTargetGamma
 // (locked to the loaded snapshot at series-load time), so changing the
 // dropdown alone would NOT re-grade the charts. Override it with the dropdown
 // choice so the operator can compare e.g. 2.2 vs ST.2084 grading live.
 const sel=String((document.getElementById('meterTargetGamma')||{}).value||'').toLowerCase();
 meterActiveSeriesTargetGamma=sel||null;
 // Persist the new selection alongside the other color-science prefs.
 try{ meterSaveColorPrefs(); }catch(e){}
 // Invalidate per-reading analysis caches (the dE cache key includes the
 // active gamma, but we also drop the cached raw/lc values + per-channel
 // gamma here so the first chart redraw cannot pick up stale numbers), and
 // recompute each greyscale reading's target_Yn from the live gamma.
 if(meterReadings && meterReadings.length){
  meterReadings.forEach(r=>{
   if(!r) return;
   delete r._dE_cache_key;
   delete r._dE_raw;
   delete r._dE_lc;
   delete r._gamma_rgb;
  });
  _chartHitZones=[];
  meterLastChartSignature='';
  meterLastChartCount=0;
  meterRegradeActiveSeriesTargets();
 }
 // Trigger the chart redraw. If the refresh function would early-return
 // (autocal running, series in progress, no active series), fall through
 // to a manual drawAllCharts on the regraded readings so the change is
 // still visible on a completed manual series read.
 const refreshWouldEarlyReturn=!meterActiveSeriesType||!meterActiveSeriesPoints||meterSeriesRunning||(typeof meterAutoCalStatusActive==='function'&&meterAutoCalStatusActive());
 if(refreshWouldEarlyReturn){
  if(meterReadings && meterReadings.length){
   const isColor=meterActiveSeriesType==='colors'||meterActiveSeriesType==='saturations';
   const sorted=isColor?[...meterReadings]:[...meterReadings].sort((a,b)=>(a.ire||0)-(b.ire||0));
   drawAllCharts(sorted);
  } else {
   meterRefreshActiveSeriesCharts();
  }
 } else {
  meterRefreshActiveSeriesCharts();
 }
});

['meterTargetWhiteX','meterTargetWhiteY'].forEach(id=>{
 const el=document.getElementById(id);
 if(!el) return;
 el.addEventListener('input',()=>{
  meterOnGreyRefChange();
  meterRefreshActiveSeriesCharts();
 });
});

function meterRefreshAfterXyzMatrixChange(){
 meterUpdateXyzMatrixVisibility();
 meterOnGreyRefChange();
 meterRefreshActiveSeriesCharts();
 const live=meterFindReadingForStep(meterCurrentPatchStep)||[...meterReadings].reverse().find(rd=>meterReadingHasLuminance(rd));
 if(live) updateLiveReading(live);
}

['meterXyzM11','meterXyzM12','meterXyzM13','meterXyzM21','meterXyzM22','meterXyzM23','meterXyzM31','meterXyzM32','meterXyzM33'].forEach(id=>{
